import express, { Request, Response } from 'express';
import cors from 'cors';
import handler from './api/consultar-guia-alvara.ts';

const app = express();
app.use(cors());
app.use(express.json());

// Rota para a consulta de guias
app.post('/api/consultar-guia-alvara', async (req: Request, res: Response) => {
  try {
    console.log('Recebendo requisição para consulta de guia:', req.body);
    // @ts-ignore - Mocking VercelReq/Res simple parts
    await handler(req, res);
  } catch (error) {
    console.error('Erro no dev-server:', error);
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

const PORT = 3000;
app.listen(PORT, () => {
  console.log(`API Local rodando em http://localhost:${PORT}`);
});

import type { VercelRequest, VercelResponse } from '@vercel/node';
import puppeteer, { Browser, Page, Target } from 'puppeteer';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { cnpj } = req.body;

  if (!cnpj) {
    return res.status(400).json({ error: 'CNPJ é obrigatório' });
  }

  let browser: Browser | undefined;

  try {
    // Nota: Em ambiente de produção Vercel, recomenda-se o uso de puppeteer-core + @sparticuz/chromium
    // devido às limitações de tamanho de 50MB do Serverless Function.
    // Para rodar localmente, o puppeteer padrão funciona.
    browser = await puppeteer.launch({ 
      headless: true,
      args: ['--no-sandbox', '--disable-setuid-sandbox'] 
    });

    const page = await browser.newPage();
    await page.setViewport({ width: 1280, height: 800 });

    // 1. Acessa o portal da prefeitura de Fazenda Rio Grande (Entidade 66, Estado 21)
    await page.goto('https://e-gov.betha.com.br/cdweb/03114-546/contribuinte/con_situacaocontribuinte.faces', { waitUntil: 'networkidle2' });

    // Verifica se já está na página de consulta ou se precisa selecionar a entidade
    const isLoginPage = await page.$('select[name="mainForm:estados"]');
    if (isLoginPage) {
      // Seleciona o estado PR (21)
      await page.select('select[name="mainForm:estados"]', '21');

      // Aguarda o combobox de cidades ser habilitado
      await page.waitForFunction(() => {
        const el = document.querySelector('select[name="mainForm:municipios"]');
        return el && !(el as HTMLSelectElement).disabled;
      });

      // Pega o ID da Fazenda Rio Grande dinamicamente
      const cityId = await page.evaluate(() => {
        const options = Array.from(document.querySelectorAll('select[name="mainForm:municipios"] option'));
        const prOption = options.find(o => o.textContent?.includes('Fazenda Rio Grande'));
        return prOption ? (prOption as HTMLOptionElement).value : null;
      });

      if (!cityId) throw new Error("Não foi possível encontrar a entidade Fazenda Rio Grande.");

      await page.select('select[name="mainForm:municipios"]', cityId);
      await page.evaluate((id) => (window as any).verifyCity(document.querySelector('select[name="mainForm:municipios"]')), cityId);
      await new Promise(r => setTimeout(r, 1000));

      const btnAcessar = await page.$('a#mainForm\\:selecionar');
      if (btnAcessar) {
        await btnAcessar.click();
        await page.waitForNavigation({ waitUntil: 'networkidle2' }).catch(() => {});
      }
    }

    // 2. Vai para a página de situação do contribuinte (se já não estiver nela)
    if (!page.url().includes('con_situacaocontribuinte.faces')) {
      await page.goto('https://e-gov.betha.com.br/cdweb/03114-546/contribuinte/con_situacaocontribuinte.faces', { waitUntil: 'networkidle2' });
    }

    // Fecha popups de pesquisa se existirem
    await page.evaluate(() => {
      const closeBtn = document.querySelector('button[title="Não responder"]') as HTMLButtonElement;
      if (closeBtn) closeBtn.click();
    }).catch(() => {});

    // 3. Seleciona CNPJ e preenche
    await page.click('.cnpj.btModo'); // Clica no rádio CNPJ (que é um link no Betha)
    await page.waitForSelector('#mainForm\\:cnpj', { visible: true });
    await page.type('#mainForm\\:cnpj', cnpj.replace(/\D/g, ''));
    await page.click('#mainForm\\:btCnpj');

    await page.waitForNavigation({ waitUntil: 'networkidle2' }).catch(() => {});

    // 4. Seleciona as guias em aberto
    // Verifica se existem débitos
    const hasDebits = await page.evaluate(() => {
      return document.querySelectorAll('input[id^="P"]').length > 0;
    });

    if (!hasDebits) {
      throw new Error("Não foram encontrados débitos em aberto para este CNPJ.");
    }

    // Seleciona todos os débitos (geralmente o checkbox P0 seleciona o grupo)
    await page.evaluate(() => {
      const checks = document.querySelectorAll('input[id^="P"]') as NodeListOf<HTMLInputElement>;
      checks.forEach(c => { if (!c.checked) c.click(); });
    });

    // O Betha abre o PDF em uma nova aba. Vamos interceptar isso.
    const newPagePromise = new Promise<Page | null>((x) => {
      if (browser) {
        browser.once('targetcreated', async (target: Target) => {
          x(await target.page());
        });
      } else {
        x(null);
      }
    });

    await page.click('#mainForm\\:emitirUnificada');

    const popup = await newPagePromise;
    if (!popup) {
      throw new Error("Não foi possível gerar o PDF das guias.");
    }

    await popup.waitForNetworkIdle();
    const pdfBuffer = await popup.pdf({ format: 'A4', printBackground: true });

    await browser.close();

    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', `attachment; filename="Guias_Alvara_${cnpj.replace(/\D/g, '')}.pdf"`);
    return res.end(pdfBuffer);

  } catch (error: any) {
    if (browser) await browser.close();
    console.error("Erro na automação Betha:", error);

    // Tratamento específico para erros esperados de negócio
    if (error.message?.includes('Não foram encontrados débitos')) {
      return res.status(400).json({ error: error.message });
    }

    return res.status(500).json({ error: 'Falha na comunicação com a prefeitura: ' + error.message });
  }
}

import React from 'react';
import {
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend
} from 'recharts';
import { useNavigate } from 'react-router-dom';
import { Building2, Activity } from 'lucide-react';

interface ChartData {
  regimes: { name: string; value: number }[];
  processos: { name: string; value: number }[];
}

interface DashboardChartsProps {
  data: ChartData;
}

const COLORS = ['#2563EB', '#10B981', '#F59E0B', '#6366F1', '#8B5CF6'];

export const DashboardCharts: React.FC<DashboardChartsProps> = ({ data }) => {
  const navigate = useNavigate();

  const handleRegimeClick = (entry: any) => {
    const regimeMap: Record<string, string> = {
      'Simples Nacional': 'simples',
      'Lucro Presumido': 'lucro_presumido',
      'Lucro Real': 'lucro_real',
      'MEI': 'mei',
      'Outros': 'todos'
    };
    const regime = regimeMap[entry.name] || 'todos';
    navigate(`/societario?view=empresas&regime=${regime}&aba=${regime === 'mei' ? 'mei' : 'ativas'}`);
  };

  const handleProcessoClick = (entry: any) => {
    navigate(`/societario?view=processos`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-8">
      {/* Donut Chart: Regimes Tributários */}
      <div className="module-card flex flex-col items-center">
        <h3 className="text-lg font-bold text-card-foreground flex items-center gap-2 mb-6 w-full px-2">
           <Building2 size={20} className="text-primary" /> Distribuição por Regime (Ativas)
        </h3>
        
        {data.regimes.length === 0 ? (
           <div className="h-64 flex items-center justify-center text-muted-foreground w-full">
             Sem dados suficientes
           </div>
        ) : (
          <div className="h-72 w-full cursor-pointer">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={data.regimes}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                  onClick={handleRegimeClick}
                >
                  {data.regimes.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={COLORS[index % COLORS.length]} 
                      className="hover:opacity-80 transition-opacity outline-none"
                    />
                  ))}
                </Pie>
                <Tooltip 
                   formatter={(value: number) => [`${value} Empresas`, 'Quantidade']}
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>

      {/* Bar Chart: Processos Societários */}
      <div className="module-card flex flex-col items-center">
        <h3 className="text-lg font-bold text-card-foreground flex items-center gap-2 mb-6 w-full px-2">
           <Activity size={20} className="text-primary" /> Processos Societários
        </h3>
        
        {data.processos.length === 0 ? (
           <div className="h-64 flex items-center justify-center text-muted-foreground w-full">
             Sem dados suficientes
           </div>
        ) : (
          <div className="h-72 w-full cursor-pointer">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={data.processos}
                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                onClick={(data) => {
                  if (data && data.activePayload) {
                    handleProcessoClick(data.activePayload[0].payload);
                  }
                }}
              >
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#6B7280', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#6B7280', fontSize: 12}} />
                <Tooltip
                  cursor={{fill: '#F3F4F6'}}
                  formatter={(value: number) => [`${value} Processos`, 'Quantidade']}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="value" fill="#2563EB" radius={[4, 4, 0, 0]} maxBarSize={50}>
                  {data.processos.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={entry.name === 'Concluídos' ? '#10B981' : entry.name === 'Em Exigência' ? '#EF4444' : '#2563EB'} 
                      className="hover:opacity-80 transition-opacity"
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>
    </div>
  );
};

import React from "react";
import { Filter, Check, User, MessageSquare } from "lucide-react";
import { Processo } from "@/types/societario";
import { passosConfig } from "@/constants/societario";
import { ControlledInput, ControlledTextarea } from "./SocietarioInputs";
import { toast } from "sonner";

interface ProcessoTimelineProps {
  processo: Processo;
  onUpdatePasso: (id: string, campo: string, value: string | number | boolean | null) => void;
  onUpdateDetalhePasso: (id: string, stepId: string, field: string, value: string) => void;
}

export const ProcessoTimeline = ({ 
  processo, 
  onUpdatePasso, 
  onUpdateDetalhePasso 
}: ProcessoTimelineProps) => {
  return (
    <div className="space-y-8">
      {processo.tipo === 'alteracao' && processo.eventos && processo.eventos.length > 0 && (
        <div className="bg-muted/30 p-4 rounded-xl border border-dashed border-border mb-6">
          <h5 className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mb-2 flex items-center gap-1">
            <Filter size={10} /> Eventos de Alteração
          </h5>
          <div className="flex flex-wrap gap-2">
            {processo.eventos.map(ev => <span key={ev} className="px-2 py-1 bg-background border border-border rounded text-[10px] font-medium">{ev}</span>)}
          </div>
        </div>
      )}

      <div className="space-y-6">
        {passosConfig.map((step, idx) => {
          const isDone = !!(processo as Record<string, any>)[step.id];
          const prevStepId = idx > 0 ? passosConfig[idx - 1].id : null;
          const isPrevDone = prevStepId ? !!(processo as Record<string, any>)[prevStepId] : true;
          
          const isDBE = step.id === 'envio_dbe_at';
          const isSignature = step.id === 'assinatura_contrato_at';
          const hasApprovalGate = processo.tipo === 'alteracao' || processo.tipo === 'abertura' || processo.tipo === 'abertura_mei';
          
          const isBlockedByExigencia = step.id === 'arquivamento_junta_at' && (processo.tipo === 'abertura' || processo.tipo === 'abertura_mei') && !processo.foi_deferido && !processo.exigencia_respondida;
          const canComplete = !isDone && isPrevDone && !isBlockedByExigencia;

          const detalhes = (processo.detalhes_passos && processo.detalhes_passos[step.id]) || {};

          return (
            <div key={step.id} className="relative pl-10">
              {idx < passosConfig.length - 1 && (
                <div className={`absolute left-4 top-8 bottom-0 w-0.5 -ml-px ${isDone ? "bg-primary" : "bg-muted"}`} />
              )}

              <div className={`absolute left-0 top-0 w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${isDone ? "bg-primary border-primary text-primary-foreground" : isPrevDone ? "border-primary/50 text-primary" : "border-muted text-muted-foreground"}`}>
                {isDone ? <Check size={16} strokeWidth={3} /> : <span className="text-xs font-bold">{idx + 1}</span>}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-start">
                <div className="md:col-span-4">
                  <h5 className={`font-bold transition-colors ${isDone ? "text-primary" : "text-card-foreground"}`}>{step.label}</h5>
                  <div className="flex flex-col gap-2 mt-1">
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => {
                          if (isDone) return;
                          if (!isPrevDone) { toast.error("Conclua a etapa anterior"); return; }
                          if (isBlockedByExigencia) { toast.error("Aguardando Deferimento ou Resposta de Exigência"); return; }
                          if (hasApprovalGate && isDBE && processo.dbe_deferido === undefined) {
                            toast.error("Marque se o DBE foi deferido ou não"); return;
                          }
                          onUpdatePasso(processo.id, step.id, new Date().toISOString());
                        }}
                        className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase transition-all ${isDone ? "bg-green-500 text-white" : canComplete ? "bg-primary text-white hover:scale-105 cursor-pointer" : "bg-muted text-muted-foreground cursor-not-allowed"}`}
                      >
                        {isDone ? "Concluído" : "Marcar Concluído"}
                      </button>
                      {isDone && <span className="text-[10px] font-mono text-muted-foreground">{new Date((processo as any)[step.id]).toLocaleString()}</span>}
                    </div>

                    {hasApprovalGate && isDBE && !isDone && isPrevDone && (
                      <div className="flex gap-2 p-2 bg-muted/50 rounded-lg border border-border">
                        <button 
                          onClick={() => onUpdatePasso(processo.id, 'dbe_deferido', true)}
                          className={`px-3 py-1 rounded text-[10px] font-bold transition-all ${processo.dbe_deferido === true ? "bg-green-500 text-white" : "bg-background text-muted-foreground"}`}
                        >
                          DEFERIDO
                        </button>
                        <button 
                          onClick={() => {
                            if (window.confirm("Reiniciar todo o processo?")) {
                              onUpdatePasso(processo.id, 'dbe_deferido', false);
                            }
                          }}
                          className={`px-3 py-1 rounded text-[10px] font-bold transition-all ${processo.dbe_deferido === false ? "bg-destructive text-white" : "bg-background text-muted-foreground"}`}
                        >
                          NÃO DEFERIDO
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                <div className="md:col-span-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-muted-foreground flex items-center gap-1 uppercase tracking-tighter">
                      <User size={10} /> Enviado por
                    </label>
                    <ControlledInput
                      value={detalhes.enviado_por || ''}
                      onBlur={val => onUpdateDetalhePasso(processo.id, step.id, 'enviado_por', val)}
                      placeholder="Quem enviou?"
                      className="w-full px-3 py-1.5 border border-border rounded-lg bg-background text-sm focus:ring-1 focus:ring-primary outline-none"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-muted-foreground flex items-center gap-1 uppercase tracking-tighter">
                      <MessageSquare size={10} /> Observações
                    </label>
                    <ControlledTextarea
                      value={detalhes.observacoes || ''}
                      onBlur={val => onUpdateDetalhePasso(processo.id, step.id, 'observacoes', val)}
                      placeholder="Ocorrências..."
                      rows={1}
                      className="w-full px-3 py-1.5 border border-border rounded-lg bg-background text-sm focus:ring-1 focus:ring-primary outline-none resize-none"
                    />
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React from "react";
import KanbanBoard, { KanbanColumn, KanbanItem } from "../KanbanBoard";
import { Processo } from "@/types/societario";
import { passosConfig, tipoProcessoLabels } from "@/constants/societario";
import { format } from "date-fns";
import { Building2, Calendar, MoreVertical } from "lucide-react";

interface SocietarioKanbanProps {
  processos: Processo[];
  onUpdateStatus: (itemId: string, newStatus: string) => void;
  onViewDetails: (processo: Processo) => void;
}

export const SocietarioKanban: React.FC<SocietarioKanbanProps> = ({ 
  processos, 
  onUpdateStatus,
  onViewDetails
}) => {
  const columns: KanbanColumn[] = [
    { id: "pending", title: "Novos / Pendentes", colorClass: "bg-blue-500/10 text-blue-600" },
    ...passosConfig.map(p => ({
      id: p.id,
      title: p.label,
      colorClass: "bg-primary/10 text-primary"
    })),
    { id: "concluido", title: "Concluídos", colorClass: "bg-emerald-500/10 text-emerald-600" }
  ];

  const getProcessoStatus = (p: Processo): string => {
    if (p.foi_arquivado) return "concluido";
    
    // Find the latest completed step
    const completedSteps = passosConfig.filter(step => !!(p as Record<string, any>)[step.id]);
    if (completedSteps.length === 0) return "pending";
    
    return completedSteps[completedSteps.length - 1].id;
  };

  const kanbanItems: KanbanItem[] = processos.map(p => ({
    id: p.id,
    status: getProcessoStatus(p),
    renderContent: () => (
      <div 
        className="p-4 space-y-3 cursor-pointer"
        onClick={() => onViewDetails(p)}
      >
        <div className="flex items-start justify-between gap-2">
          <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${
            p.tipo === 'abertura' ? 'bg-blue-100 text-blue-700' : 'bg-purple-100 text-purple-700'
          }`}>
            {tipoProcessoLabels[p.tipo] || p.tipo}
          </span>
          <button className="text-muted-foreground hover:text-foreground">
            <MoreVertical size={14} />
          </button>
        </div>

        <div>
          <h4 className="text-sm font-bold text-foreground line-clamp-2 leading-tight">
            {p.nome_empresa || "Sem Nome"}
          </h4>
          {p.numero_processo && (
            <p className="text-[10px] font-mono text-muted-foreground mt-1">
              Prot: {p.numero_processo}
            </p>
          )}
        </div>

        <div className="flex items-center justify-between pt-2 border-t border-border/50">
          <div className="flex items-center gap-1.5 text-muted-foreground">
            <Calendar size={12} />
            <span className="text-[10px] font-bold">
              {format(new Date(p.data_inicio), "dd/MM")}
            </span>
          </div>
          
          <div className="flex -space-x-2">
            <div className="w-6 h-6 rounded-full bg-primary/20 border-2 border-card flex items-center justify-center text-[10px] font-bold text-primary">
              {p.nome_empresa?.charAt(0) || "?"}
            </div>
          </div>
        </div>
        
        {p.em_exigencia && (
          <div className="bg-destructive/10 text-destructive text-[10px] font-black p-2 rounded-lg flex items-center gap-2">
             <div className="w-1.5 h-1.5 rounded-full bg-destructive animate-pulse" />
             EM EXIGÊNCIA
          </div>
        )}
      </div>
    )
  }));

  const handleDragEnd = (itemId: string, newStatus: string) => {
    // If dropping to "concluido", we set foi_arquivado to true
    if (newStatus === "concluido") {
      onUpdateStatus(itemId, "foi_arquivado");
    } else if (newStatus === "pending") {
      // Logic to clear steps? Maybe just set current_step
       onUpdateStatus(itemId, "pending");
    } else {
      onUpdateStatus(itemId, newStatus);
    }
  };

  return (
    <div className="h-[calc(100vh-250px)]">
      <KanbanBoard 
        columns={columns}
        items={kanbanItems}
        onDragEnd={handleDragEnd}
      />
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light" | "system";

type ThemeProviderProps = {
    children: React.ReactNode;
    defaultTheme?: Theme;
    storageKey?: string;
};

type ThemeProviderState = {
    theme: Theme;
    setTheme: (theme: Theme) => void;
};

const initialState: ThemeProviderState = {
    theme: "system",
    setTheme: () => null,
};

const ThemeProviderContext = createContext<ThemeProviderState>(initialState);

export function ThemeProvider({
    children,
    defaultTheme = "system",
    storageKey = "vite-ui-theme",
    ...props
}: ThemeProviderProps) {
    const [theme, setTheme] = useState<Theme>(
        () => (localStorage.getItem(storageKey) as Theme) || defaultTheme
    );

    useEffect(() => {
        const root = window.document.documentElement;

        root.classList.remove("light", "dark");

        if (theme === "system") {
            const systemTheme = window.matchMedia("(prefers-color-scheme: dark)")
                .matches
                ? "dark"
                : "light";

            root.classList.add(systemTheme);
            return;
        }

        root.classList.add(theme);
    }, [theme]);

    const value = {
        theme,
        setTheme: (theme: Theme) => {
            localStorage.setItem(storageKey, theme);
            setTheme(theme);
        },
    };

    return (
        <ThemeProviderContext.Provider {...props} value={value}>
            {children}
        </ThemeProviderContext.Provider>
    );
}

export const useTheme = () => {
    const context = useContext(ThemeProviderContext);

    if (context === undefined)
        throw new Error("useTheme must be used within a ThemeProvider");

    return context;
};

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
