import React, { createContext, useContext, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "./AuthContext";
import { toast } from "sonner";

type AlertasContextType = {
    checkAlerts: () => Promise<void>;
};

const AlertasInteligentesContext = createContext<AlertasContextType | null>(null);

export const useAlertasInteligentes = () => {
    const context = useContext(AlertasInteligentesContext);
    if (!context) {
        throw new Error("useAlertasInteligentes deve ser usado dentro de um AlertasInteligentesProvider");
    }
    return context;
};

export const AlertasInteligentesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, userData } = useAuth();
    const isCheckingRef = useRef(false);
    const hasCheckedThisSession = useRef(false);
    const emitInProcessRef = useRef<Set<string>>(new Set());

    const checkAlerts = async () => {
        // Only run for authenticated users
        if (!user || hasCheckedThisSession.current) return;
        if (isCheckingRef.current) return;

        console.log("Sistema de Alertas: Iniciando verificação geral...");
        isCheckingRef.current = true;

        try {
            const today = new Date();

            // Optimized: We'll collect IDs of companies with alerts and fetch names on-demand
            // to avoid loading thousands of companies in memory at start.
            const empNamesCache = new Map<string, string>();
            const getEmpName = async (id: string) => {
                if (empNamesCache.has(id)) return empNamesCache.get(id);
                const { data } = await (supabase as any).from("empresas").select("nome_empresa").eq("id", id).maybeSingle();
                const name = data?.nome_empresa || 'Empresa';
                empNamesCache.set(id, name);
                return name;
            };

            // --- 1. CERTIFICADOS EXPIRANDO ---
            // Only admins or people with "certificados" module should probably receive this, 
            // but for safety, we alert admins or the creator of the company.
            // Simplified logic: Alert users who have access to the company.
            if (userData?.modules?.certificados || userData?.isAdmin) {
                // Find certificates expiring in the next 15 days or already expired
                const fifteenDaysFromNow = new Date();
                fifteenDaysFromNow.setDate(today.getDate() + 15);
                const limitDateStr = fifteenDaysFromNow.toISOString().split('T')[0];

                const { data: certificados } = await (supabase as any)
                    .from("certificados_digitais")
                    .select("id, empresa_id, data_vencimento")
                    .lte("data_vencimento", limitDateStr);


                if (certificados && certificados.length > 0) {
                    for (const cert of certificados) {
                        const vencimento = new Date(cert.data_vencimento);
                        const isExpired = vencimento < today;
                        const diasRestantes = Math.ceil((vencimento.getTime() - today.getTime()) / (1000 * 3600 * 24));

                        const empName = await getEmpName(cert.empresa_id);
                        const title = isExpired
                            ? `⚠️ Certificado Expirado: ${empName}`
                            : `⏳ Certificado Expirando: ${empName}`;

                        const message = isExpired
                            ? `O certificado digital venceu em ${cert.data_vencimento.split('-').reverse().join('/')}.`
                            : `O certificado digital vencerá em ${diasRestantes} dias (${cert.data_vencimento.split('-').reverse().join('/')}).`;



                        // Generate unique signature for this alert
                        const signature = `alert_cert_${cert.id}`;
                        await emitSystemAlert(user.id, title, message, "/certificados", signature);
                    }
                }
            }

            // --- 2. AGENDAMENTOS PENDENTES/ATRASADOS ---
            if (userData?.modules?.agendamentos || userData?.isAdmin) {
                // Find incomplete appointments scheduled for the past
                const { data: agendamentos } = await (supabase as any)
                    .from("agendamentos")
                    .select("id, assunto, data, horario")
                    .eq("usuario_id", user.id)
                    .neq("status", "concluido")
                    .eq("arquivado", false);

                if (agendamentos && agendamentos.length > 0) {
                    for (const agenda of agendamentos) {
                        const scheduledTime = new Date(`${agenda.data}T${agenda.horario}`);
                        if (scheduledTime < today) {
                            const title = `🚨 Agendamento Atrasado: ${agenda.assunto}`;
                            const message = `O agendamento marcado para ${agenda.data.split('-').reverse().join('/')} às ${agenda.horario.slice(0, 5)} está pendente.`;

                            // Unique signature per appointment
                            const signature = `alert_agenda_${agenda.id}`;
                            await emitSystemAlert(user.id, title, message, "/agendamentos", signature);
                        }
                    }
                }
            }

            // --- 3. LICENÇAS VENCENDO ---
            if (userData?.modules?.licencas || userData?.isAdmin) {
                const thirtyDaysFromNow = new Date();
                thirtyDaysFromNow.setDate(today.getDate() + 30);
                const limitDateStr = thirtyDaysFromNow.toISOString().split('T')[0];

                const { data: licencas } = await (supabase as any)
                    .from("licencas")
                    .select("id, tipo_licenca, vencimento, empresa_id")
                    .lte("vencimento", limitDateStr)
                    .eq("status", "com_vencimento");

                if (licencas && licencas.length > 0) {
                    for (const licenca of licencas) {
                        const vData = new Date(licenca.vencimento);
                        const isExpired = vData < today;
                        const diasRestantes = Math.ceil((vData.getTime() - today.getTime()) / (1000 * 3600 * 24));

                        const razaoSocial = await getEmpName(licenca.empresa_id);
                        const title = isExpired
                            ? `⚠️ Licença Vencida: ${licenca.tipo_licenca}`
                            : `⏳ Licença Expirando: ${licenca.tipo_licenca}`;

                        const message = isExpired
                            ? `A licença de ${licenca.tipo_licenca} da empresa ${razaoSocial} venceu.`
                            : `A licença de ${licenca.tipo_licenca} da empresa ${razaoSocial} vencerá em ${diasRestantes} dias.`;

                        const signature = `alert_licenca_${licenca.id}`;
                        await emitSystemAlert(user.id, title, message, "/licencas", signature);
                    }
                }
            }

            hasCheckedThisSession.current = true;
        } catch (error) {
            console.error("Erro ao verificar Alertas Inteligentes:", error);
        } finally {
            isCheckingRef.current = false;
        }
    };

    // Helper function to emit atomic notifications safely without duplicates
    const emitSystemAlert = async (userId: string, title: string, message: string, link: string, signature: string) => {
        if (emitInProcessRef.current.has(signature)) return;
        emitInProcessRef.current.add(signature);

        try {
            const newId = crypto.randomUUID();
            const { error: errRpc } = await (supabase as any).rpc('emit_system_alert', {
                p_notification_id: newId,
                p_title: title,
                p_message: message,
                p_link: link,
                p_signature: signature,
                p_user_id: userId
            });

            if (errRpc) {
                console.error("Erro ao gerar alerta via RPC:", errRpc);
            } else {
                // Show a toast only if no error occurred
                toast.info(title, {
                    description: message
                });
            }
        } catch (e) {
            console.error("Error emitting system alert:", e);
        } finally {
            // Keep in memory for a while to prevent very fast re-runs from breaking the atomicity
            setTimeout(() => {
                emitInProcessRef.current.delete(signature);
            }, 10000);
        }
    };

    // Run automatically exactly ONCE after Authentication
    useEffect(() => {
        if (user && userData !== undefined && !hasCheckedThisSession.current) {
            // Small delay to prevent blocking the main UI thread during login render
            const timer = setTimeout(() => {
                checkAlerts();
            }, 3000);
            return () => clearTimeout(timer);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [user, userData]);

    return (
        <AlertasInteligentesContext.Provider value={{ checkAlerts }}>
            {children}
        </AlertasInteligentesContext.Provider>
    );
};

import React, { createContext, useContext, useEffect, useState, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import type { User, Session } from "@supabase/supabase-js";

export interface UserPermissions {
  isAdmin: boolean;
  isClient: boolean;
  empresaId?: string;
  userId?: string;
  modules: {
    societario: boolean;
    fiscal: boolean;
    pessoal: boolean;
    certificados: boolean;
    procuracoes: boolean;
    vencimentos: boolean;
    parcelamentos: boolean;
    recalculos: boolean;
    honorarios: boolean;
    licencas: boolean;
    certidoes: boolean;
    declaracoes_mensais: boolean;
    declaracoes_anuais: boolean;
    agendamentos: boolean;
  };
  nome?: string;
  email?: string;
  cpf?: string;
  departamento?: string;
  profileCompleted?: boolean;
  termsAccepted?: boolean;
  firstAccessDone?: boolean;
  foto_url?: string;
  favoritos?: string[];
}

interface AuthContextType {
  user: User | null;
  session: Session | null;
  userData: UserPermissions | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshUserData: () => Promise<void>;
  loginAsClient: (cnpj: string, password: string) => Promise<void>;
  toggleFavorito: (moduleId: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
};

const allModulesTrue = {
  societario: true, fiscal: true, pessoal: true, certificados: true,
  procuracoes: true, vencimentos: true, parcelamentos: true, recalculos: true,
  honorarios: true, licencas: true, certidoes: true, declaracoes_mensais: true,
  declaracoes_anuais: true, agendamentos: true,
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [userData, setUserData] = useState<UserPermissions | null>(null);
  const [loading, setLoading] = useState(true);
  const loadingUserRef = useRef<string | null>(null);

  const loadUserData = async (currentUser: User) => {
    if (loadingUserRef.current === currentUser.id) return;
    loadingUserRef.current = currentUser.id;

    try {
      const { data: roles } = await supabase.from("user_roles").select("role").eq("user_id", currentUser.id);

      const { data: profile, error: profileError } = await supabase
        .from("profiles")
        .select("*")
        .eq("user_id", currentUser.id)
        .maybeSingle();

      const { data: access } = await supabase
        .from("empresa_acessos")
        .select("empresa_id")
        .eq("user_id", currentUser.id)
        .maybeSingle();

      if (profileError && profileError.name !== 'AbortError') {
        console.error("AuthProvider: Error fetching profile for user", currentUser.id, profileError);
      }

      // Robust state derivation
      const profileData = profile as any;
      const profileCompleted = !!profileData?.profile_completed;
      const termsAccepted = !!profileData?.terms_accepted_at;
      const firstAccessDone = !!profileData?.first_access_done;

      const metadata = currentUser.user_metadata || {};
      const isAdmin = (roles?.some(r => r.role === "admin") || profileData?.role === "admin" || metadata.role === "admin") || false;
      const metaRole = metadata.role || profileData?.role;
      const mappedRoles = roles?.map(r => r.role) || [];
      const isClient = (metaRole === "client" || mappedRoles.includes("client") || (!!access && !isAdmin && !mappedRoles.includes("user"))) || false;
      const empresaId = access?.empresa_id || metadata.empresa_id || profileData?.empresa_id || undefined;

      if (isAdmin) {
        setUserData({
          isAdmin: true,
          isClient: false,
          empresaId: undefined,
          userId: currentUser.id,
          modules: allModulesTrue,
          nome: profileData?.nome_completo || currentUser.user_metadata?.full_name || currentUser.email || "Admin",
          email: currentUser.email || "",
          cpf: profileData?.cpf || "",
          departamento: profileData?.departamento || "Administração",
          profileCompleted,
          termsAccepted,
          firstAccessDone,
          foto_url: profileData?.foto_url || currentUser.user_metadata?.avatar_url || "",
          favoritos: profileData?.favoritos || [],
        });
      } else {
        const { data: perms } = await supabase.from("user_module_permissions").select("module_name").eq("user_id", currentUser.id);
        const moduleSet = new Set(perms?.map(p => p.module_name) || []);
        setUserData({
          isAdmin: false,
          isClient: isClient,
          empresaId: empresaId,
          userId: currentUser.id,
          modules: {
            societario: moduleSet.has("societario"),
            fiscal: moduleSet.has("fiscal"),
            pessoal: moduleSet.has("pessoal"),
            certificados: moduleSet.has("certificados"),
            procuracoes: moduleSet.has("procuracoes"),
            vencimentos: moduleSet.has("vencimentos"),
            parcelamentos: moduleSet.has("parcelamentos"),
            recalculos: moduleSet.has("recalculos"),
            honorarios: moduleSet.has("honorarios"),
            licencas: moduleSet.has("licencas"),
            certidoes: moduleSet.has("certidoes"),
            declaracoes_mensais: moduleSet.has("declaracoes_mensais"),
            declaracoes_anuais: moduleSet.has("declaracoes_anuais"),
            agendamentos: moduleSet.has("agendamentos"),
          },
          nome: profileData?.nome_completo || currentUser.user_metadata?.full_name || currentUser.email || "Usuário",
          email: currentUser.email || "",
          cpf: profileData?.cpf || "",
          departamento: profileData?.departamento || "",
          profileCompleted,
          termsAccepted,
          firstAccessDone,
          foto_url: profileData?.foto_url || currentUser.user_metadata?.avatar_url || "",
          favoritos: profileData?.favoritos || [],
        });
      }
    } catch (err) {
      console.error("AuthProvider: Critical error loading user data", err);
    } finally {
      setTimeout(() => { loadingUserRef.current = null; }, 1000); // Allow refreshing after a second
    }
  };

  const refreshUserData = async () => {
    if (user) await loadUserData(user);
  };

  const toggleFavorito = async (moduleId: string) => {
    if (!user || !userData) return;

    const currentFavoritos = userData.favoritos || [];
    let newFavoritos;

    if (currentFavoritos.includes(moduleId)) {
      newFavoritos = currentFavoritos.filter((id) => id !== moduleId);
    } else {
      newFavoritos = [...currentFavoritos, moduleId];
    }

    // Otimista local
    setUserData({ ...userData, favoritos: newFavoritos });

    // Salvar no banco de dados
    const { error } = await supabase
      .from("profiles")
      .update({ favoritos: newFavoritos })
      .eq("user_id", user.id);

    if (error) {
      console.error("Erro ao salvar favoritos:", error);
      // Reverter em caso de erro
      setUserData({ ...userData, favoritos: currentFavoritos });
    }
  };

  // Decoupled effect to fetch user data whenever `user` state changes.
  // This breaks the deadlock caused by fetching inside `onAuthStateChange` callback.
  useEffect(() => {
    let mounted = true;

    if (user && !userData) {
      loadUserData(user).then(() => {
        if (mounted) setLoading(false);
      });
    } else if (!user) {
      if (mounted) {
        setUserData(null);
        setLoading(false);
      }
    }

    return () => { mounted = false; };
  }, [user]);

  useEffect(() => {
    let mounted = true;

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      if (!mounted) return;
      setSession(newSession);
      const newUser = newSession?.user ?? null;
      setUser(newUser);

      // Trava de segurança para links de recuperação de senha enviados por e-mail
      if (event === "PASSWORD_RECOVERY" && window.location.pathname !== "/reset-password") {
        window.location.href = "/reset-password";
      }
    });

    supabase.auth.getSession().then(({ data: { session: existing } }) => {
      if (!mounted) return;
      setSession(existing);
      setUser(existing?.user ?? null);
      if (!existing?.user) {
        setLoading(false);
      }
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const login = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const logout = async () => {
    await supabase.auth.signOut();
    setUserData(null);
  };

  const loginAsClient = async (email: string, password: string) => {
    if (!email || !email.includes("@")) {
      throw new Error("E-mail inválido.");
    }

    const cleanPassword = password.replace(/\D/g, "");

    // Tenta primeiro com a senha como digitada
    let { error } = await supabase.auth.signInWithPassword({ email, password });

    // Se falhar e a senha parecer um CNPJ com máscara, tenta com a senha limpa
    if (error && cleanPassword.length === 14 && password !== cleanPassword) {
      const { error: error2 } = await supabase.auth.signInWithPassword({
        email,
        password: cleanPassword
      });
      if (!error2) error = null;
    }

    if (error) {
      console.error("Login Error:", error);
      if (error.message === "Invalid login credentials" || error.message === "Invalid credentials") {
        throw new Error("E-mail ou senha inválidos. Utilize o E-mail RFB da empresa e o CNPJ (apenas números) como senha inicial.");
      }
      if (error.message.includes("Email not confirmed")) {
        throw new Error("O e-mail deste acesso ainda não foi confirmado. Por favor, solicite ao administrador para sincronizar os acessos.");
      }
      throw error;
    }
  };

  return (
    <AuthContext.Provider value={{ user, session, userData, loading, login, logout, refreshUserData, loginAsClient, toggleFavorito }}>
      {children}
    </AuthContext.Provider>
  );
};

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { subMonths, format, startOfMonth, endOfMonth } from "date-fns";

import { ptBR } from "date-fns/locale";

export const useDashboard = (userId?: string) => {
  // 1. Basic Stats
  const { data: stats = { totalEmpresas: 0, ativas: 0, processosAtivos: 0 }, isLoading: loadingStats } = useQuery({
    queryKey: ["dashboard_stats"],
    queryFn: async () => {
      const [{ count: total }, { count: ativas }, { count: processos }] = await Promise.all([
        supabase.from("empresas").select("*", { count: "exact", head: true }),
        supabase.from("empresas").select("*", { count: "exact", head: true }).eq("situacao", "ativa"),
        supabase.from("processos_societarios").select("*", { count: "exact", head: true }).neq("status", "concluido"),
      ]);

      return {
        totalEmpresas: total || 0,
        ativas: ativas || 0,
        processosAtivos: processos || 0,
      };
    },
  });

  // 1.5. Analytics Data (Charts)
  const { data: analytics = { regimes: [], processos: [] }, isLoading: loadingAnalytics } = useQuery({
    queryKey: ["dashboard_analytics"],
    queryFn: async () => {
      // Fetch distribution of Regimes Tributários for Active Companies
      const { data: empresas } = await supabase
        .from("empresas")
        .select("regime_tributario")
        .eq("situacao", "ativa");
        
      const regimeCount: Record<string, number> = {
        'Simples Nacional': 0,
        'Lucro Presumido': 0,
        'Lucro Real': 0,
        'MEI': 0,
        'Outros': 0
      };

      empresas?.forEach(emp => {
        if (emp.regime_tributario === 'simples') regimeCount['Simples Nacional']++;
        else if (emp.regime_tributario === 'lucro_presumido') regimeCount['Lucro Presumido']++;
        else if (emp.regime_tributario === 'lucro_real') regimeCount['Lucro Real']++;
        else if (emp.regime_tributario === 'mei') regimeCount['MEI']++;
        else regimeCount['Outros']++;
      });

      const regimesData = Object.entries(regimeCount)
        .filter(([_, count]) => count > 0)
        .map(([name, value]) => ({ name, value }));

      // Fetch distribution of Processos Societários statuses
      const { data: procData } = await supabase
        .from("processos_societarios")
        .select("status");

      const procCount: Record<string, number> = {
        'Pendentes': 0,
        'Em Andamento': 0,
        'Em Exigência': 0,
        'Concluídos': 0
      };

      procData?.forEach(p => {
        if ((p as any).status === 'concluido' || (p as any).foi_arquivado) procCount['Concluídos']++;
        else if ((p as any).em_exigencia) procCount['Em Exigência']++;
        else if ((p as any).status === 'em_andamento') procCount['Em Andamento']++;
        else procCount['Pendentes']++;
      });

      const processosData = Object.entries(procCount).map(([name, value]) => ({ name, value }));

      return {
        regimes: regimesData,
        processos: processosData
      };
    }
  });

  // 2. Revenue Trend (last 6 months)
  const { data: revenueTrend = [], isLoading: loadingTrend } = useQuery({
    queryKey: ["dashboard_revenue_trend"],
    queryFn: async () => {
      const months = Array.from({ length: 6 }).map((_, i) => format(subMonths(new Date(), 5 - i), "yyyy-MM"));
      
      const { data } = await supabase
        .from("honorarios_mensal")
        .select("competencia, valor_total, pago")
        .in("competencia", months);

      return months.map(m => {
        const monthData = data?.filter(d => d.competencia === m) || [];
        return {
          month: format(new Date(m + "-01"), "MMM", { locale: ptBR }),
          total: monthData.reduce((acc, curr) => acc + (curr.valor_total || 0), 0),
          pago: monthData.filter(d => d.pago).reduce((acc, curr) => acc + (curr.valor_total || 0), 0)
        };
      });
    }
  });


  // 4. Alerts (Certificates and Deadlines)
  const { data: alerts = [], isLoading: loadingAlerts } = useQuery({
    queryKey: ["dashboard_alerts", userId],
    queryFn: async () => {
      const today = new Date();
      const todayStr = format(today, "yyyy-MM-dd");
      const next30Days = format(new Date(today.getTime() + 30 * 24 * 60 * 60 * 1000), "yyyy-MM-dd");

      const certificatesQuery = supabase.from("certificados_digitais").select("*, empresas(nome_empresa)").lte("data_vencimento", next30Days);
      
      let agendamentosQuery = supabase.from("agendamentos")
        .select("*")
        .eq("data", todayStr)
        .neq("status", "concluido"); // For appointments, show all non-completed today
      
      let tarefasQuery = supabase.from("tarefas" as any)
        .select("*")
        .eq("data", todayStr)
        .neq("status", "concluido");

      if (userId) {
        agendamentosQuery = agendamentosQuery.eq("usuario_id", userId);
        tarefasQuery = tarefasQuery.eq("usuario_id", userId);
      }

      const [certificados, agendamentos, tarefas] = await Promise.all([
        certificatesQuery,
        agendamentosQuery,
        tarefasQuery as any
      ]);

      const combined = [
        ...(certificados.data || []).map(c => ({
          id: c.id,
          type: 'expiring' as const,
          title: 'Certificado Expirando',
          description: `${(c.empresas as any)?.nome_empresa || 'Empresa'} - Vence em ${format(new Date(c.data_vencimento!), "dd/MM")}`,
          date: c.data_vencimento
        })),
        ...(agendamentos.data || []).map(a => ({
          id: a.id,
          type: 'deadline' as const,
          title: 'Agendamento Hoje',
          description: a.assunto,
          date: a.data
        })),
        ...(tarefas.data || []).map((t: any) => ({
          id: t.id,
          type: 'deadline' as const,
          title: 'Tarefa Hoje',
          description: t.assunto,
          date: t.data
        }))
      ];

      return combined.sort((a, b) => (a.date || '').localeCompare(b.date || ''));
    },
    enabled: !!userId || true // Enable even if no userId (it will just not filter if not passed, but we pass it)
  });

  return {
    stats,
    analytics,
    revenueTrend,
    alerts,
    loading: loadingStats || loadingAnalytics || loadingTrend || loadingAlerts
  };
};

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export const useEmpresas = (moduloId: string) => {
    const { user } = useAuth();
    const [empresas, setEmpresas] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let mounted = true;

        const fetchEmpresas = async () => {
            setLoading(true);
            try {
                if (!user) return;

                let query = supabase.from("empresas").select("*").order("nome_empresa");

                if (moduloId && moduloId !== "declaracoes_mensais") {
                    query = query.contains("modulos_ativos", [moduloId]);
                }

                const { data: emps, error: empsError } = await query;

                if (empsError) throw empsError;
                if (!emps) {
                    if (mounted) { setEmpresas([]); setLoading(false); }
                    return;
                }

                // 2. Fetch specific access records for the current user
                const { data: acessos } = await supabase
                    .from("empresa_acessos")
                    .select("empresa_id, modulos_permitidos")
                    .eq("user_id", user.id);

                const acessosMap = new Map<string, string[]>();
                if (acessos) {
                    acessos.forEach((a) => {
                        acessosMap.set(a.empresa_id, a.modulos_permitidos);
                    });
                }

                // 3. Filter the companies
                const filtered = emps.filter((emp) => {
                    const modulosPermitidos = acessosMap.get(emp.id);
                    // If no row exists in empresa_acessos for this user, they have full access (return true)
                    // If row exists, check if modulos_permitidos includes the current moduloId
                    if (!modulosPermitidos) return true;
                    return modulosPermitidos.includes(moduloId);
                });

                if (mounted) {
                    setEmpresas(filtered);
                }
            } catch (err) {
                console.error("Error fetching empresas:", err);
            } finally {
                if (mounted) setLoading(false);
            }
        };

        fetchEmpresas();

        return () => {
            mounted = false;
        };
    }, [moduloId, user]);

    return { empresas, loading };
};

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { FiscalRecord } from "@/types/fiscal";
import { toast } from "sonner";

export function useFiscal(competencia: string) {
  const [fiscalData, setFiscalData] = useState<Record<string, FiscalRecord>>({});
  const [loading, setLoading] = useState(true);

  const loadFiscalData = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase.from("fiscal").select("*").eq("competencia", competencia);
      if (error) throw error;
      const map: Record<string, FiscalRecord> = {};
      data?.forEach(f => { map[f.empresa_id] = f as unknown as FiscalRecord; });
      setFiscalData(map);
    } catch (e) {
      console.error(e);
      toast.error("Erro ao carregar dados fiscais");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadFiscalData();
  }, [competencia]);

  const saveFiscalRecord = async (record: Partial<FiscalRecord> & { empresa_id: string, competencia: string }) => {
    try {
      const { data: existing } = await supabase
        .from("fiscal")
        .select("id")
        .eq("empresa_id", record.empresa_id)
        .eq("competencia", record.competencia)
        .maybeSingle();

      let error;
      if (existing) {
        const { error: err } = await supabase.from("fiscal").update(record).eq("id", existing.id);
        error = err;
      } else {
        const { error: err } = await supabase.from("fiscal").insert([record]);
        error = err;
      }

      if (error) throw error;
      loadFiscalData();
      return true;
    } catch (e) {
      console.error(e);
      toast.error("Erro ao salvar dados fiscais");
      return false;
    }
  };

  return { fiscalData, loading, loadFiscalData, saveFiscalRecord };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { HonorarioConfig, HonorarioMensal, ServicoEsporadico } from "@/types/honorarios";
import { toast } from "sonner";
import { subMonths, format } from "date-fns";
import { ptBR } from "date-fns/locale";

export const useHonorarios = (competencia?: string) => {
  const queryClient = useQueryClient();

  // Monthly Fees (General View)
  const { data: listGeral = [], isLoading: loadingGeral } = useQuery({
    queryKey: ["honorarios_mensal_geral", competencia],
    queryFn: async () => {
      if (!competencia) return [];
      const { data, error } = await supabase
        .from("honorarios_mensal")
        .select("*, empresas (nome_empresa)")
        .eq("competencia", competencia);
      if (error) throw error;
      
      // Map JSON fields to match our interfaces
      return (data as any[]).map(item => ({
        ...item,
        detalhes_calculo: item.detalhes_calculo || [],
        observacoes: item.observacoes || { texto: "" }
      })) as HonorarioMensal[];
    },
    enabled: !!competencia
  });

  // Sporadic Services
  const { data: listEsporadicos = [], isLoading: loadingEsporadicos } = useQuery({
    queryKey: ["servicos_esporadicos", competencia],
    queryFn: async () => {
      if (!competencia) return [];
      const { data, error } = await (supabase as any)
        .from("servicos_esporadicos")
        .select("*")
        .eq("competencia", competencia);
      if (error) throw error;
      return data as ServicoEsporadico[];
    },
    enabled: !!competencia
  });

  // Historical Revenue Trend (last 6 months)
  const { data: revenueTrend = [], isLoading: loadingTrend } = useQuery({
    queryKey: ["honorarios_revenue_trend"],
    queryFn: async () => {
      const months = Array.from({ length: 6 }).map((_, i) => format(subMonths(new Date(), 5 - i), "yyyy-MM"));
      
      const { data } = await supabase
        .from("honorarios_mensal")
        .select("competencia, valor_total, pago")
        .in("competencia", months);

      return months.map(m => {
        const monthData = data?.filter(d => d.competencia === m) || [];
        return {
          month: format(new Date(m + "-01"), "MMM", { locale: ptBR }),
          total: monthData.reduce((acc, curr) => acc + (curr.valor_total || 0), 0),
          pago: monthData.filter(d => d.pago).reduce((acc, curr) => acc + (curr.valor_total || 0), 0)
        };
      });
    }
  });

  const saveConfig = useMutation({
    mutationFn: async (payload: HonorarioConfig) => {
      const { id, ...data } = payload;
      if (id) {
        // Assume jsonb compatible format for outros_servicos
        const { error } = await supabase.from("honorarios_config").update(data as any).eq("id", id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("honorarios_config").insert([data as any]);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      toast.success("Configuração de honorários salva!");
      queryClient.invalidateQueries({ queryKey: ["honorarios_config"] });
    },
    onError: (err: any) => toast.error("Erro ao salvar: " + err.message)
  });

  const saveMensal = useMutation({
    mutationFn: async (payload: Partial<HonorarioMensal>) => {
      const { id, empresas, detalhes_calculo, observacoes, ...data } = payload;
      
      // Keep exact DB structure, removing nested objects like 'empresas' before sending
      const updateData = {
          ...data,
          detalhes_calculo: detalhes_calculo as unknown as any,
          observacoes: observacoes as unknown as any
      };
      
      if (id) {
        const { error } = await supabase.from("honorarios_mensal").update(updateData as any).eq("id", id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("honorarios_mensal").insert([updateData as any]);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      toast.success("Controle mensal salvo!");
      queryClient.invalidateQueries({ queryKey: ["honorarios_mensal"] });
      queryClient.invalidateQueries({ queryKey: ["honorarios_mensal_geral"] });
      queryClient.invalidateQueries({ queryKey: ["honorarios_revenue_trend"] });
    },
    onError: (err: any) => toast.error("Erro ao salvar: " + err.message)
  });

  const saveEsporadico = useMutation({
    mutationFn: async (payload: ServicoEsporadico) => {
      const { id, ...data } = payload;
      if (id) {
        const { error } = await supabase.from("servicos_esporadicos").update(data).eq("id", id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("servicos_esporadicos").insert([data]);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      toast.success("Serviço esporádico salvo!");
      queryClient.invalidateQueries({ queryKey: ["servicos_esporadicos"] });
    },
    onError: (err: any) => toast.error("Erro ao salvar: " + err.message)
  });

  const deleteEsporadico = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("servicos_esporadicos").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Excluído");
      queryClient.invalidateQueries({ queryKey: ["servicos_esporadicos"] });
    }
  });

  return {
    listGeral,
    listEsporadicos,
    revenueTrend,
    loading: loadingGeral || loadingEsporadicos || loadingTrend,
    saveConfig,
    saveMensal,
    saveEsporadico,
    deleteEsporadico
  };
};

