    const [{ data: licData }, { data: certData }, { data: procData }, { data: certidoesData }, { data: taxasData }] = await Promise.all([
      fieldsToInclude.some(f => f.startsWith("licenca_")) ? supabase.from("licencas").select("*").eq("status", "com_vencimento").not("vencimento", "is", null) : Promise.resolve({ data: [] }),
      fieldsToInclude.includes("certificados") ? supabase.from("certificados_digitais").select("*").not("data_vencimento", "is", null) : Promise.resolve({ data: [] }),
      fieldsToInclude.includes("procuracoes") ? supabase.from("procuracoes").select("*").not("data_vencimento", "is", null) : Promise.resolve({ data: [] }),
      fieldsToInclude.includes("certidoes") ? supabase.from("certidoes").select("*").not("vencimento", "is", null) : Promise.resolve({ data: [] }),
      fieldsToInclude.some(f => f.startsWith("taxa_")) ? (supabase.from("licencas_taxas" as any).select("*").not("data_vencimento", "is", null) as any) : Promise.resolve({ data: [] }),
    ]);

    const compiled: any[] = [];
    licData?.forEach((l: any) => {
      if (fieldsToInclude.includes(licMap[l.tipo_licenca])) {
        compiled.push({ empresa_id: l.empresa_id, tipo: `Licença: ${licencaLabels[l.tipo_licenca] || l.tipo_licenca}`, data: l.vencimento, status: calcStatus(l.vencimento) });
      }
    });

    if (fieldsToInclude.includes("certificados")) {
      certData?.forEach((c: any) => compiled.push({ empresa_id: c.empresa_id, tipo: "Certificado Digital", data: c.data_vencimento, status: calcStatus(c.data_vencimento) }));
    }
    if (fieldsToInclude.includes("procuracoes")) {
      procData?.forEach((p: any) => compiled.push({ empresa_id: p.empresa_id, tipo: "Procuração", data: p.data_vencimento, status: calcStatus(p.data_vencimento) }));
    }
    if (fieldsToInclude.includes("certidoes")) {
      certidoesData?.forEach((c: any) => compiled.push({ empresa_id: c.empresa_id, tipo: `Certidão: ${c.tipo_certidao}`, data: c.vencimento, status: calcStatus(c.vencimento) }));
    }
    taxasData?.forEach((t: any) => {
      if (fieldsToInclude.includes(taxaMap[t.tipo_licenca])) {
        compiled.push({ empresa_id: t.empresa_id, tipo: `Taxa: ${licencaLabels[t.tipo_licenca] || t.tipo_licenca}`, data: t.data_vencimento, status: calcStatus(t.data_vencimento), status_taxa: t.status ? t.status.charAt(0).toUpperCase() + t.status.slice(1) : "Pendente", data_envio: safeFormatDate(t.data_envio), forma_envio: t.forma_envio || "—" });
      }
    });
    return compiled;
  };

  const fetchIRPF = async (competencia: string) => {
    const ano = competencia.split('-')[0];
    const { data: irpfClientes } = await (supabase.from("controle_irpf" as any).select("*").eq("ano_exercicio", ano) as any);
    const { data: irpfSocios } = await supabase.from("declaracoes_irpf" as any).select(`*, socios(nome, cpf, empresas(nome_empresa))`).eq("ano", ano);

    const unified: any[] = [];
    if (irpfClientes) {
      (irpfClientes as any[]).forEach(c => unified.push({ categoria: "IRPF Clientes", nome_completo: c.nome_completo, cpf: c.cpf, empresa: "—", ano_exercicio: c.ano_exercicio, valor_a_pagar: c.valor_a_pagar, status_pago: c.status_pago, data_pagamento: c.data_pagamento, status_transmissao: c.status_transmissao, data_transmissao: c.data_transmissao, transmitido_por: c.transmitido_por }));
    }
    if (irpfSocios) {
      (irpfSocios as any[]).forEach((s: any) => unified.push({ categoria: "IRPF Clientes Empresa", nome_completo: s.socios?.nome || "—", cpf: s.socios?.cpf || "—", empresa: s.socios?.empresas?.nome_empresa || "—", ano_exercicio: s.ano, valor_a_pagar: null, status_pago: null, data_pagamento: null, status_transmissao: s.transmitida ? "transmitida" : "pendente", data_transmissao: s.data_transmissao, transmitido_por: s.quem_transmitiu }));
    }
    return unified;
  };

  const generateReport = async (
    competencia: string,
    selectedModules: string[],
    selectedFields: Record<string, string[]>,
    selectedCompanyFields: string[],
    selectedSituations: string[],
    headerConfig?: HeaderConfig,
    format: 'pdf' | 'excel' = 'pdf'
  ) => {
    setLoadingType(format);
    try {
      // 1. Fetch Companies
      const isMeiSelected = selectedSituations.includes("mei");
      const situacoesWithoutMei = selectedSituations.filter(s => s !== "mei");
      let query = supabase.from("empresas").select("*").order("nome_empresa");
      if (isMeiSelected) {
        if (situacoesWithoutMei.length > 0) {
          const situacaoEqs = situacoesWithoutMei.map(s => `situacao.eq.${s.toLowerCase()}`).join(',');
          query = query.or(`${situacaoEqs},regime_tributario.eq.mei`);
        } else query = query.or("regime_tributario.eq.mei");
      } else query = query.in("situacao", situacoesWithoutMei.map(s => s.toLowerCase()) as any);

      const { data: allCompanies, error: companiesError } = await query;
      if (companiesError) throw companiesError;

      // 2. Doc Init
      let doc: jsPDF | null = null;
      let currentY = 60;
      const excelAoA: any[][] = [];
      if (format === 'pdf') {
        doc = new jsPDF({ orientation: 'landscape' });
        await generatePDFHeader(doc, headerConfig);
        doc.setFontSize(14);
        doc.setFont("Ubuntu", "bold");
        doc.text(`RELATÓRIO PERSONALIZADO - ${formatMonthYearBR(competencia)}`, doc.internal.pageSize.getWidth() / 2, 50, { align: "center" });
      }

      // 3. Modules Loop
      for (const modId of selectedModules) {
        const mod = MODULES_CONFIG.find(m => m.id === modId)!;
        const fieldsToInclude = selectedFields[modId] || [];
        if (fieldsToInclude.length === 0) continue;

        let moduleData: any[] = [];
        if (modId === "societario") moduleData = allCompanies;
        else if (modId === "vencimentos") moduleData = await fetchVencimentos(fieldsToInclude);
        else if (modId === "irpf") moduleData = await fetchIRPF(competencia);
        else {
          let mQuery = supabase.from(mod.table as any).select("*");
          if (["fiscal", "pessoal", "declaracoes_mensais", "honorarios", "recalculos", "licencas_taxas", "agendamentos"].includes(modId)) mQuery = mQuery.eq("competencia", competencia);
          const { data } = await mQuery;
          moduleData = data || [];
        }

        // IRPF Special Handling
        if (modId === "irpf") {
          const categorias = ["IRPF Clientes", "IRPF Clientes Empresa"];
          for (const cat of categorias) {
            const catData = moduleData.filter(d => d.categoria === cat);
            if (catData.length === 0) continue;
            const activeFields = mod.fields.filter(f => fieldsToInclude.includes(f.id));
            const head = [activeFields.map(f => f.label)];
            const body = catData.map(item => activeFields.map(f => f.accessor ? f.accessor(item) : (item[f.id] ?? "—")));

            if (format === 'pdf' && doc) {
              currentY = applyAutoTable(doc, head, body, currentY, `${cat.toUpperCase()} (${competencia.split('-')[0]})`);
            } else if (format === 'excel') {
              excelAoA.push([], [`--- IRPF: ${cat.toUpperCase()} ---`], head[0], ...body);
            }
          }
          continue;
        }

        // Processos orphaned
        if (modId === "processos_societarios") {
          const orphaned = moduleData.filter(d => !d.empresa_id);
          if (orphaned.length > 0) {
            const activeFields = mod.fields.filter(f => fieldsToInclude.includes(f.id));
            const head = [["Referência", ...activeFields.map(f => f.label)]];
            const body = orphaned.map(p => [p.nome_empresa || "—", ...activeFields.map(f => f.accessor ? f.accessor(p) : (p[f.id] ?? "—"))]);
            if (format === 'pdf' && doc) currentY = applyAutoTable(doc, head, body, currentY, "PROCESSOS SEM EMPRESA VINCULADA");
            else if (format === 'excel') excelAoA.push([], ["--- PROCESSOS SEM EMPRESA ---"], head[0], ...body);
          }
        }

        // Situation Grouping
        for (const sit of SITUATIONS) {
          if (!selectedSituations.includes(sit.id.toLowerCase())) continue;
          const situationCompanies = allCompanies.filter(c => {
            const isMei = c.regime_tributario?.toLowerCase() === "mei";
            if (sit.id.toLowerCase() === "mei") return isMei;
            return c.situacao?.toLowerCase() === sit.id.toLowerCase() && !isMei;
          });
          if (situationCompanies.length === 0) continue;

          const activeFields = mod.id === "vencimentos" 
             ? [{id:"tipo", label:"Item"}, {id:"status", label:"Situação"}, {id:"data", label:"Vencimento", accessor:(i:any)=>safeFormatDate(i.data)}, ...(fieldsToInclude.some(f=>f.startsWith("taxa_")) ? [{id:"status_taxa", label:"Status Taxa"}, {id:"data_envio", label:"Data Env."}, {id:"forma_envio", label:"Forma Env."}] : [])]
             : mod.fields.filter(f => fieldsToInclude.includes(f.id));
          
          const extraHeaders = COMPANY_FIELDS.filter(f => selectedCompanyFields.includes(f.id));
          const head = [["Empresa", ...extraHeaders.map(f => f.label), ...activeFields.map(f => f.label)]];
          
          const body: any[] = [];
          situationCompanies.forEach(company => {
            const companyRecords = moduleData.filter(d => (modId === "societario" ? d.id : d.empresa_id) === company.id);
            const compValues = extraHeaders.map(f => f.accessor ? f.accessor(company) : (company[f.id] ?? "—"));
            if (companyRecords.length > 0) {
              companyRecords.forEach(r => body.push([company.nome_empresa, ...compValues, ...activeFields.map(f => f.accessor ? f.accessor(r) : (r[f.id] ?? "—"))]));
            } else {
              body.push([company.nome_empresa, ...compValues, ...activeFields.map(() => "—")]);
            }
          });

          if (format === 'pdf' && doc) currentY = applyAutoTable(doc, head, body, currentY, `MÓDULO: ${mod.label} | SITUAÇÃO: ${sit.label}`);
          else if (format === 'excel') excelAoA.push([], [`--- ${mod.label} | ${sit.label} ---`], head[0], ...body);
        }
      }

      // 4. Save
      if (format === 'pdf' && doc) doc.save(`Relatorio_${formatMonthYearBR(competencia).replace('/', '-')}.pdf`);
      else if (format === 'excel') {
        const ws = XLSX.utils.aoa_to_sheet(excelAoA);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Relatorio");
        XLSX.writeFile(wb, `Relatorio_${formatMonthYearBR(competencia).replace('/', '-')}.xlsx`);
      }
      toast.success("Relatório gerado!");
    } catch (e) {
      console.error(e);
      toast.error("Erro ao gerar relatório");
    } finally {
      setLoadingType(null);
    }
  };

  return { loadingType, generateReport };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Empresa, Processo } from "@/types/societario";
import { toast } from "sonner";

export const useSocietario = () => {
  const queryClient = useQueryClient();

  const { data: listEmpresas = [], isLoading: loadingEmpresas } = useQuery({
    queryKey: ["empresas"],
    queryFn: async () => {
      // Keeping original listEmpresas for backward compatibility in forms/dropdowns
      const { data } = await supabase.from("empresas").select("*").order("nome_empresa");
      const { data: sociosData } = await supabase.from("socios").select("empresa_id");
      const sociosCounts: Record<string, number> = {};
      sociosData?.forEach(s => {
        sociosCounts[s.empresa_id] = (sociosCounts[s.empresa_id] || 0) + 1;
      });
      return (data || []).map(e => ({ ...e, socios_count: sociosCounts[e.id] || 0 })) as Empresa[];
    }
  });

  const getPaginatedEmpresas = async (page: number, limit: number, search: string, situacao: string, regime: string, moduloId?: string, userId?: string) => {
    let query = supabase.from("empresas").select("*", { count: 'exact' });

    if (moduloId && moduloId !== "declaracoes_mensais") {
      query = query.contains("modulos_ativos", [moduloId]);
    }

    if (search) {
      query = query.or(`nome_empresa.ilike.%${search}%,cnpj.ilike.%${search}%`);
    }

    if (situacao && situacao !== 'todas') {
      const situacaoMap: Record<string, string> = {
        'ativas': 'ativa',
        'paralisadas': 'paralisada',
        'baixadas': 'baixada',
        'entregue': 'entregue',
        'mei': 'mei'
      };

      const mappedSituacao = situacaoMap[situacao] || situacao;

      if (situacao === 'mei') {
         // Filter by regime MEI OR situation MEI
         query = query.or(`regime_tributario.eq.mei,situacao.eq.mei`);
      } else if (mappedSituacao === 'ativa') {
         query = query.eq("situacao", "ativa");
      } else {
         query = query.eq("situacao", mappedSituacao as any);
      }
    }

    if (regime && regime !== 'todos') {
      query = query.eq("regime_tributario", regime as any);
    }

    const from = page * limit;
    const to = from + limit - 1;

    const { data: empresasData, count, error } = await query
      .order('nome_empresa')
      .range(from, to);

    if (error) throw error;

    // Get socio count map for these specific companies
    const empIds = (empresasData || []).map(e => e.id);
    const { data: sociosData } = await supabase.from("socios").select("empresa_id").in("empresa_id", empIds);
    const sociosCounts: Record<string, number> = {};
    sociosData?.forEach(s => {
      sociosCounts[s.empresa_id] = (sociosCounts[s.empresa_id] || 0) + 1;
    });

    const enrichedData = (empresasData || []).map(e => ({ ...e, socios_count: sociosCounts[e.id] || 0 })) as Empresa[];

    if (userId && moduloId) {
      const { data: acessos } = await supabase
        .from("empresa_acessos")
        .select("empresa_id, modulos_permitidos")
        .eq("user_id", userId);

      if (acessos && acessos.length > 0) {
        const acessosMap = new Map(acessos.map(a => [a.empresa_id, a.modulos_permitidos]));
        const filtered = enrichedData.filter(emp => {
          const modulosPermitidos = acessosMap.get(emp.id);
          if (!modulosPermitidos) return true; // Full access if no specific rule
          return modulosPermitidos.includes(moduloId);
        });
        return { data: filtered, count: count || 0 };
      }
    }
    
    return { data: enrichedData, count: count || 0 };
  };

  const { data: listProcessos = [], isLoading: loadingProcessos } = useQuery({
    queryKey: ["processos_societarios"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("processos_societarios" as any)
        .select(`
          *,
          historico:processos_societarios_historico(*)
        `)
        .order("created_at", { ascending: false });

      if (error) throw error;
      return (data as unknown as Processo[]) || [];
    }
  });

  const addHistorico = async (processoId: string, acao: string, detalhes?: string) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    await supabase.from("processos_societarios_historico" as any).insert({
      processo_id: processoId,
      usuario_id: user.id,
      acao,
      detalhes
    });
  };

  const deleteProcesso = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("processos_societarios" as any).delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Processo excluído!");
      queryClient.invalidateQueries({ queryKey: ["processos_societarios"] });
    },
    onError: (error: any) => {
      toast.error("Erro ao excluir: " + error.message);
    }
  });

  const updateProcesso = useMutation({
    mutationFn: async ({ id, updates, acao, detalhes }: { id: string, updates: any, acao?: string, detalhes?: string }) => {
      const { error } = await supabase.from("processos_societarios" as any).update(updates).eq("id", id);
      if (error) throw error;
      if (acao) {
        await addHistorico(id, acao, detalhes);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["processos_societarios"] });
    },
    onError: (error: any) => {
      toast.error("Erro: " + error.message);
    }
  });

  return {
    empresas: listEmpresas,
    processos: listProcessos,
    isLoading: loadingEmpresas || loadingProcessos,
    addHistorico,
    deleteProcesso,
    updateProcesso,
    getPaginatedEmpresas
  };
};

import { supabase } from "@/integrations/supabase/client";

export type AuditAction = 'VIEW' | 'CREATE' | 'EDIT' | 'DELETE' | 'LOGIN' | 'DOWNLOAD';

export const logAction = async (
    userId: string | undefined,
    action: AuditAction,
    tableName: string,
    recordId: string,
    oldData: any = null,
    newData: any = null
) => {
    if (!userId) return;

    try {
        const { error } = await supabase.from('audit_logs' as any).insert([
            {
                user_id: userId,
                action,
                table_name: tableName,
                record_id: recordId,
                old_data: oldData,
                new_data: newData,
            },
        ]);

        if (error) {
            console.error('AuditLog Error:', error.message);
        }
    } catch (err) {
        console.error('AuditLog critical error:', err);
    }
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { HeaderConfig, DEFAULT_HEADER } from "@/constants/reports";
import { UbuntuRegular, UbuntuBold } from "@/lib/fonts/ubuntu-base64";
import logoCaduceu from "@/assets/logo-caduceu.png";

export const generatePDFHeader = async (doc: jsPDF, headerConfig?: HeaderConfig) => {
    doc.addFileToVFS("Ubuntu-Regular.ttf", UbuntuRegular);
    doc.addFont("Ubuntu-Regular.ttf", "Ubuntu", "normal");
    doc.addFileToVFS("Ubuntu-Bold.ttf", UbuntuBold);
    doc.addFont("Ubuntu-Bold.ttf", "Ubuntu", "bold");

    const config: HeaderConfig = headerConfig || DEFAULT_HEADER;
    const pageWidth = doc.internal.pageSize.getWidth();

    // Header - Logo and Text
    try {
        const logoToUse = config.logoUrl || logoCaduceu;

        // Safe image loading via DOM Image
        const imgData = await new Promise<HTMLImageElement | string>((resolve, reject) => {
            if (logoToUse.startsWith('data:')) {
                resolve(logoToUse);
            } else {
                const img = new Image();
                if (logoToUse.startsWith('http')) {
                    img.crossOrigin = 'Anonymous';
                }
                img.onload = () => resolve(img);
                img.onerror = () => reject(new Error("Image failed to load (CORS or Invalid URL)"));
                img.src = logoToUse;
            }
        });

        let format = 'PNG';
        if (typeof imgData === 'string') {
            if (imgData.startsWith('data:image/jpeg') || imgData.startsWith('data:image/jpg')) format = 'JPEG';
            else if (imgData.startsWith('data:image/webp')) format = 'WEBP';
        }

        doc.addImage(imgData, format, config.logoX, config.logoY, config.logoWidth, config.logoHeight);
    } catch (e) {
        console.warn("Logo blocked by CORS or invalid. Generating PDF without custom logo.", e);
        // Fallback to default if custom url failed
        try {
            if (config.logoUrl) {
                doc.addImage(logoCaduceu, 'PNG', config.logoX, config.logoY, config.logoWidth, config.logoHeight);
            }
        } catch (fallbackError) {
            console.warn("Fallback logo failed", fallbackError);
        }
    }

    doc.setFont("Ubuntu", "bold");
    doc.setFontSize(config.titleFontSize);
    doc.text(config.title, pageWidth / 2 + 10, 20, { align: "center" });

    doc.setFontSize(config.subtitleFontSize);
    doc.setFont("Ubuntu", "normal");
    doc.text(config.subtitle, pageWidth / 2 + 10, 26, { align: "center" });

    doc.setFontSize(config.infoFontSize);
    doc.text(config.address, pageWidth / 2, 34, { align: "center" });
    doc.text(config.contact, pageWidth / 2, 38, { align: "center" });

    // Separator line
    doc.setDrawColor(0);
    doc.setLineWidth(0.5);
    doc.line(10, 42, pageWidth - 10, 42);
};

export const applyAutoTable = (doc: jsPDF, head: any[][], body: any[][], startY: number, title?: string) => {
    if (title) {
        doc.setFontSize(10);
        doc.setFont("Ubuntu", "bold");
        doc.setTextColor(100, 100, 100);
        doc.text(title, 14, startY + 5);
        startY += 8;
        doc.setTextColor(0, 0, 0);
    }

    autoTable(doc, {
        startY: startY,
        head: head,
        body: body,
        theme: 'grid',
        headStyles: { fillColor: [240, 240, 240], textColor: 0, fontStyle: 'bold', fontSize: 10 },
        bodyStyles: { fontSize: 9, cellPadding: 2 },
        styles: { font: 'Ubuntu' },
        margin: { horizontal: 5 },
    });

    return (doc as any).lastAutoTable.finalY + 10;
};

import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

/**
 * Utility to sync all active companies from the 'empresas' table
 * to the 'auth.users' and 'profiles' tables as client users.
 */
export const syncCompanyClients = async (onProgress?: (current: number, total: number) => void) => {
    try {
        // 1. Fetch all companies
        const { data: companies, error: empError } = await supabase
            .from("empresas")
            .select("id, nome_empresa, cnpj, email_rfb");

        if (empError) throw empError;
        if (!companies) return;

        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.access_token) throw new Error("Não autenticado");

        let synced = 0;
        let errors = 0;

        for (let i = 0; i < companies.length; i++) {
            const company = companies[i];
            if (onProgress) onProgress(i + 1, companies.length);

            if (!company.cnpj) continue;
            if (!company.email_rfb) {
                console.warn(`Skipping ${company.nome_empresa} - missing email_rfb`);
                continue;
            }

            const cleanCNPJ = company.cnpj.replace(/\D/g, "");
            if (!cleanCNPJ) continue;

            const email = company.email_rfb;
            const password = cleanCNPJ; // Default password is CNPJ

            try {
                const { error } = await supabase.functions.invoke("create-user", {
                    body: {
                        email,
                        nome: company.nome_empresa,
                        password,
                        role: 'client',
                        empresa_id: company.id
                    }
                });

                if (error) {
                    console.error(`Error invoking function for ${company.nome_empresa}:`, error);
                    let msg = error.message;
                    try {
                        const body = await (error as any).context?.json();
                        if (body?.code === "user_already_exists") {
                            synced++; // Consider it as success/synced
                            continue;
                        }
                        if (body?.error) msg = body.error;
                    } catch (e) {
                        // Ignore parsing errors for error body
                    }
                    console.error(`Detail for ${company.nome_empresa}: ${msg}`);
                    errors++;
                } else {
                    synced++;
                }
            } catch (err) {
                console.error(`Fatal error syncing ${company.nome_empresa}:`, err);
                errors++;
            }
        }

        return { synced, errors, total: companies.length };
    } catch (error) {
        console.error("Error syncing clients:", error);
        throw error;
    }
};

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { Calendar, Clock, User, Save, ArrowLeft, ClipboardList } from "lucide-react";
import { toast } from "sonner";

const AgendamentoFormPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [usuarios, setUsuarios] = useState<{ id: string; nome: string }[]>([]);
    const [form, setForm] = useState({
        data: new Date().toISOString().split('T')[0],
        horario: "09:00",
        usuario_id: "",
        assunto: "",
        informacoes_adicionais: ""
    });

    useEffect(() => {
        const loadUsers = async () => {
            try {
                const { data: profiles } = await supabase.from("profiles").select("id, full_name, nome_completo, user_id").eq("ativo", true);
                if (!profiles) return;

                const userIds = profiles.map(p => p.user_id || p.id);

                const [{ data: roles }, { data: access }] = await Promise.all([
                    supabase.from("user_roles").select("user_id, role").in("user_id", userIds),
                    supabase.from("empresa_acessos").select("user_id").in("user_id", userIds)
                ]);

                const clientIds = new Set([
                    ...(roles?.filter(r => (r.role as any) === 'client').map(r => r.user_id) || []),
                    ...(access?.map(a => a.user_id) || [])
                ]);

                const mapped = profiles
                    .filter(u => !clientIds.has(u.user_id || u.id))
                    .map((u: any) => ({
                        id: u.user_id || u.id,
                        nome: u.nome_completo || u.full_name || "Sem Nome"
                    }));

                setUsuarios(mapped);
            } catch (err) {
                console.error(err);
            }
        };
        loadUsers();
    }, []);

    const handleSave = async () => {
        if (!form.data || !form.usuario_id || !form.assunto) {
            toast.error("Preencha os campos obrigatórios!");
            return;
        }

        setLoading(true);
        try {
            const payload = {
                ...form,
                criado_por: user?.id,
                competencia: form.data.slice(0, 7)
            };

            const { error } = await (supabase.from("agendamentos" as any).insert(payload) as any);
            if (error) throw error;

            // --- Send notification to assigned user ---
            try {
                const assignedUser = usuarios.find(u => u.id === form.usuario_id);
                const assignedName = assignedUser?.nome || "você";
                const formattedDate = new Date(form.data + "T" + form.horario).toLocaleString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });

                // 1. Create the notification record
                const { data: notifData, error: notifErr } = await (supabase as any).from("notifications").insert({
                    title: "📅 Novo Agendamento Atribuído",
                    message: `Você tem uma agenda agendada: "${form.assunto}" em ${formattedDate}.`,
                    type: "agendamento",
                    link: "/agendamentos",
                }).select("id").single();

                if (!notifErr && notifData?.id) {
                    // 2. Create recipient entry for the assigned user
                    const recipients = [{ notification_id: notifData.id, user_id: form.usuario_id }];
                    // 3. Also notify creator if different
                    if (user?.id && user.id !== form.usuario_id) {
                        recipients.push({ notification_id: notifData.id, user_id: user.id });
                    }
                    await (supabase as any).from("notification_recipients").insert(recipients);
                }
            } catch {
                // Notification failure should not block the main flow
                console.warn("Falha ao enviar notificação de agendamento");
            }

            toast.success("Agendamento criado com sucesso!");
            navigate("/agendamentos");
        } catch (err: any) {
            toast.error("Erro ao salvar: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    const inputCls = "w-full px-4 py-3 border border-border rounded-xl bg-card text-foreground focus:ring-2 focus:ring-primary outline-none transition-all";
    const labelCls = "block text-sm font-semibold text-muted-foreground mb-1.5 ml-1";

    return (
        <div className="max-w-2xl mx-auto space-y-6 animate-fade-in pb-10">
            <div className="flex items-center gap-4">
                <button
                    onClick={() => navigate("/agendamentos")}
                    className="p-2.5 rounded-xl hover:bg-muted transition-colors text-muted-foreground"
                    title="Voltar"
                >
                    <ArrowLeft size={20} />
                </button>
            </div>

            <div className="bg-card border border-border rounded-2xl shadow-sm overflow-hidden p-6 md:p-8 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className={labelCls}>Data do Agendamento *</label>
                        <div className="relative">
                            <Calendar size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="date"
                                value={form.data}
                                onChange={e => setForm({ ...form, data: e.target.value })}
                                className={inputCls + " pl-11"}
                            />
                        </div>
                    </div>
                    <div>
                        <label className={labelCls}>Horário *</label>
                        <div className="relative">
                            <Clock size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="time"
                                value={form.horario}
                                onChange={e => setForm({ ...form, horario: e.target.value })}
                                className={inputCls + " pl-11"}
                            />
                        </div>
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Responsável pelo Agendamento *</label>
                    <div className="relative">
                        <User size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <select
                            value={form.usuario_id}
                            onChange={e => setForm({ ...form, usuario_id: e.target.value })}
                            className={inputCls + " pl-11 appearance-none"}
                        >
                            <option value="">Selecione quem receberá o agendamento...</option>
                            {usuarios.map(u => (
                                <option key={u.id} value={u.id}>{u.nome} {u.id === user?.id ? "(Eu)" : ""}</option>
                            ))}
                        </select>
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Assunto *</label>
                    <div className="relative">
                        <ClipboardList size={18} className="absolute left-3.5 top-4 text-muted-foreground" />
                        <input
                            placeholder="Ex: Reunião com cliente Alpha"
                            value={form.assunto}
                            onChange={e => setForm({ ...form, assunto: e.target.value })}
                            className={inputCls + " pl-11"}
                        />
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Demais Informações</label>
                    <textarea
                        rows={5}
                        placeholder="Detalhes adicionais, pauta da reunião, links, etc..."
                        value={form.informacoes_adicionais}
                        onChange={e => setForm({ ...form, informacoes_adicionais: e.target.value })}
                        className={inputCls + " resize-none"}
                    />
                </div>

                <div className="flex gap-4 pt-4 border-t border-border">
                    <button
                        onClick={() => navigate("/agendamentos")}
                        className="flex-1 px-6 py-3.5 rounded-xl border border-border text-sm font-bold hover:bg-muted transition-colors disabled:opacity-50"
                        disabled={loading}
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={loading}
                        className="flex-1 button-premium flex items-center justify-center gap-2 shadow-lg disabled:opacity-50"
                    >
                        {loading ? (
                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ) : (
                            <><Save size={20} /> Salvar Agendamento</>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default AgendamentoFormPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Search, Calendar, Clock, User, Plus, Save, X, ClipboardList, CheckCircle, Circle, RefreshCw, Trash2, LayoutDashboard, List } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useNavigate } from "react-router-dom";
import KanbanBoard, { KanbanColumn, KanbanItem } from "@/components/KanbanBoard";

interface Agendamento {
    id: string;
    data: string;
    horario: string;
    usuario_id: string;
    criado_por: string;
    assunto: string;
    informacoes_adicionais: string;
    competencia: string;
    usuario_nome?: string;
    status: "em_aberto" | "concluido" | "pendente";
    arquivado: boolean;
}

const AgendamentosPage: React.FC = () => {
    const { user, userData } = useAuth();
    const navigate = useNavigate();
    const [agendamentos, setAgendamentos] = useState<Agendamento[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
    const [activeTab, setActiveTab] = useState<"geral" | "meus">("geral");
    const [activeSubTab, setActiveSubTab] = useState<"em_aberto" | "concluido" | "pendente" | "arquivados">("em_aberto");
    const [viewMode, setViewMode] = useState<"list" | "kanban">("kanban");

    const loadData = async () => {
        setLoading(true);
        try {
            // Carregar usuários para mapear nomes
            const { data: usersData } = await (supabase.from("profiles").select("id, full_name, user_id") as any);
            const mappedUsers = (usersData || []).map((u: any) => ({
                id: u.user_id || u.id,
                nome: u.full_name || "Sem Nome"
            }));

            // Carregar agendamentos
            const { data: agendaData } = await (supabase
                .from("agendamentos" as any)
                .select("*")
                .eq("competencia", competencia)
                .order("horario", { ascending: true }) as any);

            const now = new Date();

            const enrichedData = (agendaData || []).map((a: any) => {
                let currentStatus = a.status || "em_aberto";
                let isOverdue = false;

                if (currentStatus === "em_aberto" && a.data && a.horario) {
                    const scheduledDateTime = new Date(`${a.data}T${a.horario}`);
                    if (scheduledDateTime < now) {
                        currentStatus = "pendente";
                        isOverdue = true;
                    }
                }

                return {
                    ...a,
                    status: currentStatus,
                    arquivado: !!a.arquivado,
                    usuario_nome: mappedUsers.find(u => u.id === a.usuario_id)?.nome || "Não encontrado",
                    _isOverdueDbUpdateNeeded: isOverdue // Flag to update DB later
                };
            });

            // Fire and forget DB updates for newly identified overdue appointments
            const overdueItems = enrichedData.filter(item => item._isOverdueDbUpdateNeeded);
            if (overdueItems.length > 0) {
                Promise.all(overdueItems.map(item =>
                    supabase.from("agendamentos" as any).update({ status: "pendente" } as any).eq("id", item.id) as any
                )).catch(e => console.error("Failed to auto-update overdue appointments", e));
            }

            setAgendamentos(enrichedData);
        } catch (err: any) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, [competencia]);

    // Background job to check for overdue items every minute
    useEffect(() => {
        const interval = setInterval(() => {
            const now = new Date();
            let hasChanges = false;

            setAgendamentos(prev => {
                const updated = prev.map(a => {
                    if (a.status === "em_aberto" && a.data && a.horario) {
                        const scheduledDateTime = new Date(`${a.data}T${a.horario}`);
                        if (scheduledDateTime < now) {
                            hasChanges = true;
                            // Optionally push the update to Supabase
                            supabase.from("agendamentos" as any).update({ status: "pendente" } as any).eq("id", a.id).then();
                            return { ...a, status: "pendente" as const };
                        }
                    }
                    return a;
                });
                return hasChanges ? updated : prev;
            });
        }, 60000); // Check every minute

        return () => clearInterval(interval);
    }, []);

    const handleUpdateStatus = async (id: string, newStatus: string) => {
        try {
            const { error } = await (supabase
                .from("agendamentos" as any)
                .update({ status: newStatus } as any)
                .eq("id", id) as any);

            if (error) throw error;
            toast.success("Status atualizado!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao atualizar: " + error.message);
        }
    };

    const handleUpdateArquivado = async (id: string, arquivado: boolean) => {
        try {
            const { error } = await (supabase
                .from("agendamentos" as any)
                .update({ arquivado } as any)
                .eq("id", id) as any);

            if (error) throw error;
            toast.success(arquivado ? "Agendamento arquivado!" : "Agendamento desarquivado!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao atualizar: " + error.message);
        }
    };

    const handleDeleteAgendamento = async (id: string) => {
        if (!window.confirm("Tem certeza que deseja excluir este agendamento? Esta ação não pode ser desfeita.")) {
            return;
        }

        try {
            const { error } = await (supabase
                .from("agendamentos" as any)
                .delete()
                .eq("id", id) as any);

            if (error) throw error;
            toast.success("Agendamento excluído com sucesso!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao excluir: " + error.message);
        }
    };

    const filtered = agendamentos.filter(a => {
        const matchSearch = a.assunto.toLowerCase().includes(search.toLowerCase()) ||
            a.usuario_nome?.toLowerCase().includes(search.toLowerCase());

        // Filtragem por Arquivados
        if (activeSubTab === "arquivados") {
            if (!a.arquivado) return false;
        } else {
            if (a.arquivado) return false;
        }

        const isMine = a.usuario_id === user?.id;

        if (activeTab === "geral") {
            // No modo Geral, se estiver na sub-aba arquivados, mostra todos os arquivados
            if (activeSubTab === "arquivados") return matchSearch;
            // Caso contrário, mostra tudo que não está arquivado (filtro padrão do Geral)
            return matchSearch;
        } else {
            // "meus" agendamentos
            const matchUser = isMine;
            if (activeSubTab === "arquivados") {
                return matchSearch && matchUser;
            }
            return matchSearch && matchUser && a.status === activeSubTab;
        }
    });

    if (loading && agendamentos.length === 0) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    const getStatusBadge = (status: string) => {
        switch (status) {
            case "concluido":
                return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-green-500/10 text-green-500 border border-green-500/20 uppercase">Concluído</span>;
            case "pendente":
                return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-amber-500/10 text-amber-500 border border-amber-500/20 uppercase">Pendente</span>;
            default:
                return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-blue-500/10 text-blue-500 border border-blue-500/20 uppercase">Em Aberto</span>;
        }
    };

    const kanbanColumns: KanbanColumn[] = [
        { id: 'em_aberto', title: 'A Fazer', colorClass: 'bg-blue-500/10 text-blue-500 border-blue-500/20' },
        { id: 'pendente', title: 'Pendente', colorClass: 'bg-amber-500/10 text-amber-500 border-amber-500/20' },
        { id: 'concluido', title: 'Concluído', colorClass: 'bg-green-500/10 text-green-500 border-green-500/20' }
    ];

    const kanbanItems: KanbanItem[] = filtered.map(a => ({
        id: a.id,
        status: a.status,
        renderContent: () => (
            <div className={`
                p-4 space-y-3 transition-all h-full bg-card group relative
                border-l-4 ${a.status === 'concluido' ? 'border-l-green-500 opacity-90' : a.status === 'pendente' ? 'border-l-amber-500' : 'border-l-primary'}
            `}>
                <div className="flex items-start justify-between">
                    <div className="space-y-1 w-full">
                        <div className="flex items-start justify-between gap-2">
                            <h3 className="font-bold text-card-foreground leading-tight text-sm flex-1">{a.assunto}</h3>
                            <button
                                onClick={() => handleDeleteAgendamento(a.id)}
                                className="opacity-0 group-hover:opacity-100 p-1.5 rounded-md text-destructive/70 hover:bg-destructive/10 hover:text-destructive transition-all shrink-0"
                                title="Excluir"
                            >
                                <Trash2 size={14} />
                            </button>
                        </div>
                        <p className="text-xs text-muted-foreground flex items-center gap-1.5 pt-1">
                            <User size={12} className="text-primary/70" /> Para: <span className="text-foreground font-medium">{a.usuario_nome}</span>
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3 pt-2">
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Calendar size={14} className="text-primary" />
                        {format(new Date(a.data + 'T00:00:00'), "dd 'de' MMM", { locale: ptBR })}
                    </div>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Clock size={14} className="text-primary" />
                        {a.horario.slice(0, 5)}
                    </div>
                </div>

                {a.informacoes_adicionais && (
                    <div className="bg-muted/40 p-2.5 rounded-lg text-xs tracking-tight text-foreground/80 border border-border italic line-clamp-3">
                        {a.informacoes_adicionais}
                    </div>
                )}

                {(a.usuario_id === user?.id || userData?.isAdmin) && (
                    <div className="flex flex-wrap items-center gap-1.5 pt-2 border-t border-border mt-auto">
                        {!a.arquivado && (
                            <>
                                {a.status !== 'concluido' ? (
                                    <button
                                        onClick={() => handleUpdateStatus(a.id, 'concluido')}
                                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-green-500/10 text-green-500 text-xs font-bold hover:bg-green-500 hover:text-white transition-all"
                                    >
                                        <CheckCircle size={14} /> Concluir
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleUpdateStatus(a.id, 'em_aberto')}
                                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-muted text-muted-foreground text-xs font-bold hover:bg-muted-foreground hover:text-white transition-all"
                                    >
                                        <Circle size={14} /> Reabrir
                                    </button>
                                )}
                            </>
                        )}

                        {!a.arquivado ? (
                            <button
                                onClick={() => handleUpdateArquivado(a.id, true)}
                                className="flex-1 px-3 py-1.5 rounded-md bg-muted/50 text-muted-foreground text-[11px] font-bold hover:bg-destructive hover:text-white transition-all flex items-center justify-center gap-1.5"
                                title="Arquivar"
                            >
                                <X size={13} /> Arquivar
                            </button>
                        ) : (
                            <button
                                onClick={() => handleUpdateArquivado(a.id, false)}
                                className="w-full flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-primary/10 text-primary text-[11px] font-bold hover:bg-primary hover:text-white transition-all"
                            >
                                <RefreshCw size={13} /> Desarquivar
                            </button>
                        )}

                        <button
                            onClick={() => handleDeleteAgendamento(a.id)}
                            className="px-3 py-1.5 rounded-md bg-destructive/10 text-destructive text-[11px] font-bold hover:bg-destructive hover:text-white transition-all flex items-center gap-1.5"
                            title="Excluir"
                        >
                            <Trash2 size={13} /> Excluir
                        </button>
                    </div>
                )}
            </div>
        )
    }));

    return (
        <div className="space-y-6 animate-fade-in flex flex-col min-h-[calc(100vh-100px)]">
            <div className="flex items-center gap-3 justify-end shrink-0">
                <input
                    type="month"
                    value={competencia}
                    onChange={e => setCompetencia(e.target.value)}
                    className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold"
                />
                <button
                    onClick={() => navigate("/agendamentos/novo")}
                    className="button-premium shadow-md"
                >
                    <Plus size={18} /> Novo Agendamento
                </button>
            </div>

            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 shrink-0">
                <div className="flex border-b border-border w-full sm:w-auto overflow-x-auto no-scrollbar">
                    <button
                        className={`px-5 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === "geral" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                        onClick={() => {
                            setActiveTab("geral");
                            if (activeSubTab !== "arquivados") setActiveSubTab("em_aberto");
                        }}
                    >
                        Geral
                    </button>
                    <button
                        className={`px-5 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === "meus" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                        onClick={() => {
                            setActiveTab("meus");
                            if (activeSubTab !== "arquivados") setActiveSubTab("em_aberto");
                        }}
                    >
                        Meus Agendamentos
                    </button>
                </div>

                <div className="flex gap-2 p-1 bg-muted/30 rounded-lg w-fit">
                    {[
                        { id: "em_aberto", label: "Em Aberto", hideOnGeral: true },
                        { id: "concluido", label: "Concluído", hideOnGeral: true },
                        { id: "pendente", label: "Pendente", hideOnGeral: true },
                        { id: "arquivados", label: "Arquivados", hideOnGeral: false }
                    ].map(sub => {
                        if (activeTab === "geral" && sub.hideOnGeral && sub.id !== "em_aberto") return null;

                        const label = activeTab === "geral" && sub.id === "em_aberto" ? "Ativos" : sub.label;

                        return (
                            <button
                                key={sub.id}
                                onClick={() => setActiveSubTab(sub.id as any)}
                                className={`px-4 py-1.5 rounded-md text-xs font-semibold transition-all ${activeSubTab === sub.id ? "bg-card text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                            >
                                {label}
                            </button>
                        );
                    })}
                </div>

                <div className="flex bg-muted p-1 rounded-lg shrink-0">
                    <button
                        onClick={() => setViewMode("list")}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${viewMode === "list" ? "bg-background text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                        title="Ver como Lista"
                    >
                        <List size={16} /> <span className="hidden sm:inline">Lista</span>
                    </button>
                    <button
                        onClick={() => setViewMode("kanban")}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${viewMode === "kanban" ? "bg-background text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                        title="Ver como Quadro (Kanban)"
                    >
                        <LayoutDashboard size={16} /> <span className="hidden sm:inline">Quadro</span>
                    </button>
                </div>
            </div>

            <div className="relative max-w-sm shrink-0">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <input
                    type="text"
                    placeholder="Buscar agendamento ou usuário..."
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                />
            </div>

            {/* View Mode Switching */}
            {viewMode === 'kanban' && activeSubTab !== 'arquivados' ? (
                <div className="flex-1 overflow-hidden min-h-[500px]">
                    <KanbanBoard
                        columns={kanbanColumns}
                        items={kanbanItems}
                        onDragEnd={handleUpdateStatus}
                    />
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pb-10">
                    {filtered.length === 0 ? (
                        <div className="col-span-full py-12 text-center text-muted-foreground bg-muted/20 rounded-xl border border-dashed border-border">
                            Nenhum agendamento encontrado para este período.
                        </div>
                    ) : (
                        filtered.map(a => <React.Fragment key={a.id}>{kanbanItems.find(i => i.id === a.id)?.renderContent()}</React.Fragment>)
                    )}
                </div>
            )}
        </div>
    );
};

export default AgendamentosPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Search, Filter, Eye, Database, List as ListIcon, X } from "lucide-react";
import { PageHeaderSkeleton, TableSkeleton } from "@/components/PageSkeleton";

interface AuditLog {
    id: string;
    created_at: string;
    user_id: string | null;
    action: string;
    table_name: string;
    record_id: string;
    old_data: any;
    new_data: any;
    profile?: { nome_completo: string | null; email: string | null };
}

const AuditoriaPage: React.FC = () => {
    const [logs, setLogs] = useState<AuditLog[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [filterTable, setFilterTable] = useState("all");
    const [filterAction, setFilterAction] = useState("all");
    const [selectedLog, setSelectedLog] = useState<AuditLog | null>(null);

    const fetchLogs = async () => {
        setLoading(true);
        // Join with profiles to get the user name
        const { data: logsData, error } = await supabase
            .from("audit_logs")
            .select(`
        *,
        profile:profiles(nome_completo, email)
      `)
            .order("created_at", { ascending: false })
            .limit(500);

        if (!error && logsData) {
            setLogs(logsData as unknown as AuditLog[]);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchLogs();

        // Subscribe to real-time changes
        const channel = supabase
            .channel('audit_log_changes')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'audit_logs'
                },
                (payload) => {
                    console.log('New audit log received:', payload);
                    const newLog = payload.new as unknown as AuditLog;
                    
                    // Fetch profile for the new log to show name
                    supabase
                        .from("profiles")
                        .select("nome_completo, email")
                        .eq("user_id", newLog.user_id)
                        .maybeSingle()
                        .then(({ data: profile }) => {
                            const logWithProfile = { ...newLog, profile: profile as any };
                            setLogs(prev => [logWithProfile, ...prev].slice(0, 500));
                        });
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, []);

    const tables = Array.from(new Set(logs.map(l => l.table_name)));

    const filteredLogs = logs.filter(log => {
        const searchLower = search.toLowerCase();
        const userName = log.profile?.nome_completo?.toLowerCase() || "";
        const email = log.profile?.email?.toLowerCase() || "";
        const matchesSearch = 
            userName.includes(searchLower) || 
            email.includes(searchLower) ||
            log.table_name.toLowerCase().includes(searchLower) || 
            log.action.toLowerCase().includes(searchLower);
        
        const matchesTable = filterTable === "all" || log.table_name === filterTable;
        const matchesAction = filterAction === "all" || log.action === filterAction;

        return matchesSearch && matchesTable && matchesAction;
    });

    const getActionColor = (action: string) => {
        switch (action) {
            case 'INSERT': return 'bg-success/10 text-success border-success/20';
            case 'UPDATE': return 'bg-warning/10 text-warning border-warning/20';
            case 'DELETE': return 'bg-destructive/10 text-destructive border-destructive/20';
            default: return 'bg-muted text-muted-foreground border-border';
        }
    };

    if (loading) {
        return (
            <div className="space-y-6">
                <PageHeaderSkeleton />
                <TableSkeleton rows={10} />
            </div>
        );
    }
    return (
        <div className="space-y-6 animate-fade-in">
            <div className="space-y-2">
            <div className="flex items-center justify-between px-1">
                <div className="flex items-center gap-2">
                    <Database size={20} className="text-primary" />
                    <h1 className="text-2xl font-black text-card-foreground tracking-tight">Registro de Auditoria</h1>
                </div>
                <div className="flex items-center gap-2 bg-success/10 text-success text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full border border-success/20 shadow-sm animate-pulse-slow">
                    <span className="w-2 h-2 rounded-full bg-success animate-pulse" />
                    Live Feed Ativo
                </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between module-card">
                <div className="relative flex-1 w-full max-w-md">
                    <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Buscar por usuário ou tabela..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="w-full pl-9 pr-4 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                    />
                </div>

                <div className="flex gap-2 w-full sm:w-auto">
                    <div className="relative flex-1 sm:flex-none">
                        <Filter size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <select
                            value={filterAction}
                            onChange={e => setFilterAction(e.target.value)}
                            className="w-full pl-8 pr-8 py-2.5 border border-border rounded-lg bg-background text-sm font-medium appearance-none focus:ring-2 focus:ring-primary outline-none cursor-pointer"
                        >
                            <option value="all">Ação: Todas</option>
                            <option value="INSERT">Inserções (INSERT)</option>
                            <option value="UPDATE">Edições (UPDATE)</option>
                            <option value="DELETE">Exclusões (DELETE)</option>
                        </select>
                    </div>

                    <div className="relative flex-1 sm:flex-none">
                        <Database size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <select
                            value={filterTable}
                            onChange={e => setFilterTable(e.target.value)}
                            className="w-full pl-8 pr-8 py-2.5 border border-border rounded-lg bg-background text-sm font-medium appearance-none focus:ring-2 focus:ring-primary outline-none cursor-pointer"
                        >
                            <option value="all">Tabela: Todas</option>
                            {tables.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            <div className="module-card p-0 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Data e Hora</th>
                                <th>Usuário</th>
                                <th>Tabela</th>
                                <th>Ação</th>
                                <th className="text-right">Detalhes</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredLogs.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="text-center py-12 text-muted-foreground">
                                        <ListIcon size={32} className="mx-auto mb-3 opacity-20" />
                                        <p>Nenhum log de auditoria encontrado.</p>
                                    </td>
                                </tr>
                            ) : (
                                filteredLogs.map(log => (
                                    <tr key={log.id} className="hover:bg-muted/50 transition-colors">
                                        <td className="whitespace-nowrap font-mono text-xs text-muted-foreground">
                                            {format(new Date(log.created_at), "dd/MM/yyyy HH:mm:ss", { locale: ptBR })}
                                        </td>
                                        <td>
                                            <div className="font-semibold text-card-foreground">
                                                {log.profile?.nome_completo || "Sistema / Auto"}
                                            </div>
                                            <div className="text-xs text-muted-foreground font-mono truncate max-w-[150px]" title={log.user_id || ""}>
                                                {log.profile?.email || log.user_id || "N/A"}
                                            </div>
                                        </td>
                                        <td>
                                            <span className="font-mono text-xs bg-muted px-2 py-1 rounded border border-border">
                                                {log.table_name}
                                            </span>
                                        </td>
                                        <td>
                                            <span className={`text-[10px] font-bold px-2 py-1 flex items-center justify-center w-20 rounded-md border ${getActionColor(log.action)}`}>
                                                {log.action}
                                            </span>
                                        </td>
                                        <td className="text-right">
                                            <button
                                                onClick={() => setSelectedLog(log)}
                                                className="p-2 rounded-lg bg-primary/10 text-primary hover:bg-primary/20 transition-colors inline-flex"
                                                title="Ver payload JSON"
                                            >
                                                <Eye size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Detail Modal */}
            {selectedLog && (
                <div className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-card w-full max-w-3xl max-h-[90vh] flex flex-col rounded-2xl shadow-xl border border-border animate-in zoom-in-95 duration-200">
                        <div className="flex items-center justify-between p-4 border-b border-border bg-muted/30">
                            <h3 className="font-bold flex items-center gap-2">
                                <Database size={18} className="text-primary" />
                                Detalhes do Log
                                <span className={`ml-2 text-[10px] uppercase font-bold px-2 py-0.5 rounded border ${getActionColor(selectedLog.action)}`}>
                                    {selectedLog.action}
                                </span>
                            </h3>
                            <button onClick={() => setSelectedLog(null)} className="p-1 rounded-md hover:bg-muted">
                                <X size={20} />
                            </button>
                        </div>

                        <div className="p-6 overflow-y-auto space-y-6 flex-1">
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                <div className="space-y-1">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase">Data Registrada</p>
                                    <p className="text-sm font-mono">{format(new Date(selectedLog.created_at), "dd/MM/yyyy HH:mm:ss")}</p>
                                </div>
                                <div className="space-y-1">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase">Tabela Alvo</p>
                                    <p className="text-sm font-mono">{selectedLog.table_name}</p>
                                </div>
                                <div className="space-y-1 md:col-span-2">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase">ID do Registro</p>
                                    <p className="text-sm font-mono truncate">{selectedLog.record_id}</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {selectedLog.old_data && (
                                    <div className="space-y-2">
                                        <p className="text-sm font-bold text-destructive flex items-center gap-2">
                                            <span className="w-2 h-2 rounded-full bg-destructive" /> Dados Anteriores (OLD)
                                        </p>
                                        <pre className="bg-[#1e1e1e] text-[#d4d4d4] p-4 rounded-xl text-xs font-mono overflow-auto max-h-[400px]">
                                            {JSON.stringify(selectedLog.old_data, null, 2)}
                                        </pre>
                                    </div>
                                )}
                                {selectedLog.new_data && (
                                    <div className="space-y-2">
                                        <p className="text-sm font-bold text-success flex items-center gap-2">
                                            <span className="w-2 h-2 rounded-full bg-success" /> Dados Novos (NEW)
                                        </p>
                                        <pre className="bg-[#1e1e1e] text-[#d4d4d4] p-4 rounded-xl text-xs font-mono overflow-auto max-h-[400px]">
                                            {JSON.stringify(selectedLog.new_data, null, 2)}
                                        </pre>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    </div>
);
};

export default AuditoriaPage;

import React, { useEffect, useState, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { formatDateBR } from "@/lib/utils";
import { Search, Plus, Trash2, ChevronDown, ChevronUp, Building2, FileText, Upload, Download, Eye } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";
import { CertidaoRecord } from "@/types/administrative";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const tiposCertidao = ["CND Federal", "CND Estadual", "CND Municipal", "CND FGTS", "CND Trabalhista", "CNDT", "Certidão INSS", "Certidão Tributos Federais", "Outra"];
const calcDias = (data?: string | null) => { if (!data) return 999; return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000); };

const CertidoesPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("certidoes");
  const [certidoes, setCertidoes] = useState<CertidaoRecord[]>([]);
  const [search, setSearch] = useState("");
  const [expanded, setExpanded] = useState<string | null>(null);
  const [newCert, setNewCert] = useState({ tipo_certidao: "CND Federal", vencimento: "", observacao: "" });
  const [newFile, setNewFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState<string | null>(null);
  const [consulting, setConsulting] = useState<string | null>(null);
  const [cndTipoPessoa, setCndTipoPessoa] = useState<"PJ" | "PF">("PJ");
  const fileInputRef = useRef<HTMLInputElement>(null);
  const newFileInputRef = useRef<HTMLInputElement>(null);

  const load = async () => {
    const { data: certs } = await supabase.from("certidoes").select("*");
    setCertidoes(certs || []);
  };

  useEffect(() => { load(); }, []);

  const filtered = empresas.filter(e => e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search));

  const uploadFile = async (certId: string, file: File) => {
    const ext = file.name.split(".").pop();
    const path = `${certId}.${ext}`;
    setUploading(certId);
    const { error: uploadError } = await supabase.storage.from("certidoes").upload(path, file, { upsert: true });
    if (uploadError) { toast.error("Erro ao enviar arquivo: " + uploadError.message); setUploading(null); return; }
    const { data: urlData } = supabase.storage.from("certidoes").getPublicUrl(path);
    await supabase.from("certidoes").update({ arquivo_url: urlData.publicUrl }).eq("id", certId);
    toast.success("Arquivo anexado!");
    setUploading(null);
    load();
  };

  const handleFileUpload = (certId: string) => {
    const input = fileInputRef.current;
    if (!input) return;
    input.onchange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) uploadFile(certId, file);
      input.value = "";
    };
    input.click();
  };

  const addCertidao = async (empresaId: string) => {
    if (!newCert.tipo_certidao) { toast.error("Selecione o tipo"); return; }
    const { data, error } = await supabase.from("certidoes").insert({ empresa_id: empresaId, tipo_certidao: newCert.tipo_certidao, vencimento: newCert.vencimento || null, observacao: newCert.observacao || null }).select().single();
    if (error) { toast.error(error.message); return; }
    if (newFile && data) {
      await uploadFile(data.id, newFile);
      setNewFile(null);
      if (newFileInputRef.current) newFileInputRef.current.value = "";
    } else {
      toast.success("Certidão adicionada!");
    }
    setNewCert({ tipo_certidao: "CND Federal", vencimento: "", observacao: "" });
    load();
  };

  const handleConsultaCND = async (empresaId: string, cnpj: string | undefined) => {
    setConsulting(empresaId);
    const tid = toast.loading(`Consultando CND Federal ${cndTipoPessoa}...`);

    try {
      let identificador = "";
      let tipoContribuinte = 1; // Default 1 (PJ)

      if (cndTipoPessoa === "PJ") {
        if (!cnpj) throw new Error("CNPJ da empresa não disponível.");
        identificador = cnpj.replace(/\D/g, "");
        tipoContribuinte = 1;
      } else {
        // PF - Buscar sócio administrador
        const { data: socios, error: socError } = await supabase.from("socios").select("*").eq("empresa_id", empresaId).eq("administrador", true);
        if (socError) throw socError;
        if (!socios || socios.length === 0) throw new Error("A empresa não possui um Sócio Administrador cadastrado para consulta PF.");
        
        const admin = socios[0];
        if (!admin.cpf) throw new Error(`O sócio administrador (${admin.nome}) não possui CPF cadastrado.`);
        identificador = admin.cpf.replace(/\D/g, "");
        tipoContribuinte = 2; // Serpro enum: 2 - CPF
      }

      const response = await fetch("https://apigateway.conectagov.estaleiro.serpro.gov.br/api-cnd/v1/ConsultaCnd/certidao", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          TipoContribuinte: tipoContribuinte,
          ContribuinteConsulta: identificador,
          GerarCertidaoPdf: true
        })
      });

      if (!response.ok) throw new Error("Erro na comunicação com a API de Certidões.");

      const data = await response.json();

      if (data.Status !== 1 && data.Status !== 2) {
        throw new Error(data.Mensagem || "Não foi possível obter a certidão.");
      }

      const certData = data.Certidao;
      if (!certData) throw new Error("Dados da certidão não retornados.");

      const { data: newRecord, error: insertError } = await supabase.from("certidoes").insert({
        empresa_id: empresaId,
        tipo_certidao: "CND Federal",
        vencimento: certData.DataValidade ? new Date(certData.DataValidade).toISOString().split('T')[0] : null,
        observacao: `Cód. Controle: ${certData.CodigoControle}${cndTipoPessoa === "PF" ? " (Sócio Admin)" : ""}`
      }).select().single();

      if (insertError) throw insertError;

      if (certData.DocumentoPdf) {
        const binStr = atob(certData.DocumentoPdf);
        const len = binStr.length;
        const arr = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
          arr[i] = binStr.charCodeAt(i);
        }
        const blob = new Blob([arr], { type: "application/pdf" });
        const fileName = `CND_Federal_${cndTipoPessoa}_${identificador}.pdf`;
        const file = new File([blob], fileName, { type: "application/pdf" });
        
        await uploadFile(newRecord.id, file);
      }

      toast.success(`CND Federal (${cndTipoPessoa}) consultada com sucesso!`, { id: tid });
      load();
    } catch (err: any) {
      toast.error(`Falha na consulta (${cndTipoPessoa}): ${err.message}`, { id: tid });
    } finally {
      setConsulting(null);
    }
  };

  const removeCertidao = async (certId: string) => {
    if (!window.confirm("Excluir certidão?")) return;
    // Try to remove file from storage
    const cert = certidoes.find(c => c.id === certId);
    if (cert?.arquivo_url) {
      const fileName = cert.arquivo_url.split("/").pop();
      if (fileName) await supabase.storage.from("certidoes").remove([fileName]);
    }
    await supabase.from("certidoes").delete().eq("id", certId);
    toast.success("Certidão excluída!"); load();
  };

  const viewFile = (url: string) => { window.open(url, "_blank"); };
  const downloadFile = (url: string, name: string) => {
    const a = document.createElement("a");
    a.href = url;
    a.download = name;
    a.target = "_blank";
    a.click();
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full">
        <FavoriteToggleButton moduleId="certidoes" />
        <div>
          <h2 className="text-lg font-bold text-card-foreground">Certidões Federais, Estaduais e Municipais</h2>
          <p className="text-xs text-muted-foreground">Gestão de emissão e controle de CNDs e afins.</p>
        </div>
      </div>
      <input type="file" ref={fileInputRef} accept=".pdf" className="hidden" />
      <div className="relative max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const empCerts = certidoes.filter(c => c.empresa_id === emp.id);
          const vencidas = empCerts.filter(c => calcDias(c.vencimento) < 0).length;
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => setExpanded(isOpen ? null : emp.id)}>
                <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                <div className="flex items-center gap-3"><span className="text-xs text-muted-foreground">{empCerts.length} certidões</span>{vencidas > 0 && <span className="badge-status badge-danger">{vencidas} vencidas</span>}{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-4 bg-muted/10">
                  {empCerts.length > 0 && (
                    <div className="space-y-2">
                      {empCerts.map((c: CertidaoRecord) => {
                        const dias = calcDias(c.vencimento);
                        const statusCls = dias < 0 ? "badge-danger" : dias <= 30 ? "badge-warning" : "badge-success";
                        const statusLabel = dias === 999 ? "—" : dias < 0 ? "Vencida" : dias <= 30 ? "Próxima" : "Válida";
                        const hasFile = !!c.arquivo_url;
                        return (
                          <div key={c.id} className="flex items-center justify-between p-3 rounded-lg border border-border bg-card">
                            <div className="flex items-center gap-3">
                              <FileText size={16} className="text-primary" />
                              <div>
                                <p className="text-sm font-medium text-card-foreground">{c.tipo_certidao}</p>
                                <p className="text-xs text-muted-foreground">
                                  {c.vencimento ? `Venc: ${formatDateBR(c.vencimento)}` : "Sem vencimento"}
                                  {dias !== 999 && ` (${dias}d)`}
                                </p>
                              </div>
                            </div>
                            <div className="flex items-center gap-2">
                              <span className={`badge-status ${statusCls}`}>{statusLabel}</span>
                              {hasFile ? (
                                <>
                                  <button onClick={() => viewFile(c.arquivo_url)} title="Visualizar" className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors"><Eye size={14} /></button>
                                  <button onClick={() => downloadFile(c.arquivo_url, `${c.tipo_certidao}.pdf`)} title="Baixar" className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors"><Download size={14} /></button>
                                </>
                              ) : (
                                <button
                                  onClick={() => handleFileUpload(c.id)}
                                  disabled={uploading === c.id}
                                  title="Anexar PDF"
                                  className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors disabled:opacity-50"
                                >
                                  <Upload size={14} />
                                </button>
                              )}
                              {hasFile && (
                                <button
                                  onClick={() => handleFileUpload(c.id)}
                                  disabled={uploading === c.id}
                                  title="Substituir arquivo"
                                  className="p-1.5 rounded-lg hover:bg-warning/10 text-muted-foreground hover:text-warning transition-colors disabled:opacity-50"
                                >
                                  <Upload size={14} />
                                </button>
                              )}
                              <button onClick={() => removeCertidao(c.id)} className="p-1.5 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"><Trash2 size={14} /></button>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                  <div className="p-4 bg-muted/30 rounded-xl border border-border space-y-3">
                    <p className="text-sm font-medium text-card-foreground">Adicionar Certidão</p>
                    <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
                      <div>
                        <label className={labelCls}>Tipo</label>
                        <select value={newCert.tipo_certidao} onChange={e => setNewCert({ ...newCert, tipo_certidao: e.target.value })} className={inputCls}>{tiposCertidao.map(t => <option key={t} value={t}>{t}</option>)}</select>
                      </div>
                      {newCert.tipo_certidao === "CND Federal" && (
                        <div>
                          <label className={labelCls}>Consultar como</label>
                          <div className="flex gap-2">
                            <select 
                              value={cndTipoPessoa} 
                              onChange={e => setCndTipoPessoa(e.target.value as "PJ" | "PF")} 
                              className={inputCls}
                            >
                              <option value="PJ">Empresa (PJ)</option>
                              <option value="PF">Sócio Titular (PF)</option>
                            </select>
                            <button 
                              onClick={() => handleConsultaCND(emp.id, emp.cnpj)}
                              disabled={consulting === emp.id}
                              className="px-3 py-2 bg-info/10 text-info rounded-lg text-xs font-semibold hover:bg-info/20 whitespace-nowrap transition-all flex items-center gap-2"
                            >
                              {consulting === emp.id ? "Consultando..." : <><Search size={14} /> Consultar CND</>}
                            </button>
                          </div>
                        </div>
                      )}
                      <div><label className={labelCls}>Data de Validade</label><input type="date" value={newCert.vencimento} onChange={e => setNewCert({ ...newCert, vencimento: e.target.value })} className={inputCls} /></div>
                      <div><label className={labelCls}>Observação</label><input value={newCert.observacao} onChange={e => setNewCert({ ...newCert, observacao: e.target.value })} className={inputCls} /></div>
                      <div>
                        <label className={labelCls}>Arquivo PDF</label>
                        <input type="file" ref={newFileInputRef} accept=".pdf" onChange={e => setNewFile(e.target.files?.[0] || null)} className="w-full text-sm text-muted-foreground file:mr-2 file:py-1.5 file:px-3 file:rounded-lg file:border-0 file:text-sm file:font-medium file:bg-primary/10 file:text-primary hover:file:bg-primary/20 cursor-pointer" />
                      </div>
                      <div className="flex items-end"><button onClick={() => addCertidao(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Plus size={14} /> Adicionar</button></div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default CertidoesPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, AlertTriangle, CheckCircle, Clock, ChevronDown, ChevronUp, Save, User } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";
import { useAlertasInteligentes } from "@/contexts/AlertasInteligentesProvider";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const tipoLabels: Record<string, string> = { a1: "A1 (Arquivo)", a3: "A3 (Token)", "e-cpf": "e-CPF", "e-cnpj": "e-CNPJ", nfe: "NF-e" };
const calcDias = (data?: string | null) => { if (!data) return 999; return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000); };

const CertificadosPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("certificados");
  const { checkAlerts } = useAlertasInteligentes();
  const [certData, setCertData] = useState<Record<string, any>>({});
  const [sociosMap, setSociosMap] = useState<Record<string, any>>({});
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("todos");
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");

  useEffect(() => {
    const load = async () => {
      const { data: certs } = await supabase.from("certificados_digitais").select("*");
      const map: Record<string, any> = {};
      certs?.forEach(c => { map[c.empresa_id] = c; });
      setCertData(map);
      // Get all admin socios
      const { data: allSocios } = await supabase.from("socios").select("*").eq("administrador", true);
      const sMap: Record<string, any> = {};
      allSocios?.forEach(s => { sMap[s.empresa_id] = s; });
      setSociosMap(sMap);
    };
    load();
  }, []);

  const empresasWithCert = empresas.map(emp => {
    const cert = certData[emp.id] || {};
    const dias = calcDias(cert.data_vencimento);
    const status = dias === 999 ? "sem_dados" : dias < 0 ? "vencido" : dias <= 30 ? "proximo" : "ativo";
    const admin = sociosMap[emp.id];
    return { ...emp, cert, dias, status, adminNome: admin?.nome || "—", adminCpf: admin?.cpf || "" };
  });

  const filtered = empresasWithCert.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const matchStatus = filterStatus === "todos" || e.status === filterStatus;

    let matchTab = false;
    if (activeTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    } else if (activeTab === "entregue") {
      matchTab = e.situacao === "entregue";
    }

    return matchSearch && matchStatus && matchTab;
  });

  const counts = {
    ativos: filtered.filter(e => e.status === "ativo").length,
    proximos: filtered.filter(e => e.status === "proximo").length,
    vencidos: filtered.filter(e => e.status === "vencido").length,
    semDados: filtered.filter(e => e.status === "sem_dados").length
  };

  const toggleExpand = (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const emp = empresasWithCert.find(e => e.id === id);
    if (emp) setEditForm(prev => ({ ...prev, [id]: { data_vencimento: emp.cert.data_vencimento || "", tipo_emissao: emp.cert.tipo_emissao || "presencial", observacao: emp.cert.observacao || "" } }));
  };

  const handleSave = async (empresaId: string) => {
    const form = editForm[empresaId];
    const existing = certData[empresaId];
    const admin = sociosMap[empresaId];
    try {
      if (existing?.id) {
        const { error } = await supabase.from("certificados_digitais").update({
          data_vencimento: form.data_vencimento || null,
          tipo_emissao: form.tipo_emissao || null,
          observacao: form.observacao || null,
          socio_responsavel_id: admin?.id || null
        }).eq("id", existing.id);

        if (error) throw error;
      } else {
        const { error } = await supabase.from("certificados_digitais").insert({
          empresa_id: empresaId,
          data_vencimento: form.data_vencimento || null,
          tipo_emissao: form.tipo_emissao || null,
          observacao: form.observacao || null,
          socio_responsavel_id: admin?.id || null
        });

        if (error) throw error;
      }
      toast.success("Certificado atualizado!");

      // Trigger instant check for alerts
      checkAlerts();

      const { data: certs } = await supabase.from("certificados_digitais").select("*");
      const map: Record<string, any> = {};
      certs?.forEach(c => { map[c.empresa_id] = c; });
      setCertData(map);
    } catch (err: any) { toast.error(err.message); }
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full">
        <FavoriteToggleButton moduleId="certificados" />
        <div>
          <h2 className="text-lg font-bold text-card-foreground">Certificados Digitais</h2>
          <p className="text-xs text-muted-foreground">Gestão e alertas de vencimentos estruturados.</p>
        </div>
      </div>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[{ label: "Ativos", count: counts.ativos, cls: "text-success", bg: "bg-success/10", icon: <CheckCircle size={20} /> }, { label: "Próximos", count: counts.proximos, cls: "text-warning", bg: "bg-warning/10", icon: <Clock size={20} /> }, { label: "Vencidos", count: counts.vencidos, cls: "text-destructive", bg: "bg-destructive/10", icon: <AlertTriangle size={20} /> }, { label: "Sem Dados", count: counts.semDados, cls: "text-muted-foreground", bg: "bg-muted", icon: <AlertTriangle size={20} /> }].map(s => (
          <div key={s.label} className="stat-card flex items-center justify-between"><div><p className="text-xs text-muted-foreground uppercase tracking-wide">{s.label}</p><p className={`text-2xl font-bold mt-1 ${s.cls}`}>{s.count}</p></div><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${s.bg} ${s.cls}`}>{s.icon}</div></div>
        ))}
      </div>
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
        <div className="flex gap-2">{[{ key: "todos", label: "Todos" }, { key: "ativo", label: "Ativos" }, { key: "proximo", label: "Próximos" }, { key: "vencido", label: "Vencidos" }, { key: "sem_dados", label: "Sem Dados" }].map(f => (<button key={f.key} onClick={() => setFilterStatus(f.key)} className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${filterStatus === f.key ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:text-foreground"}`}>{f.label}</button>))}</div>
      </div>
      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "entregue"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("entregue")}
        >
          Empresas Entregues
        </button>
      </div>
      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const statusCls = emp.status === "vencido" ? "badge-danger" : emp.status === "proximo" ? "badge-warning" : emp.status === "ativo" ? "badge-success" : "badge-gray";
          const statusLabel = emp.status === "vencido" ? "Vencido" : emp.status === "proximo" ? "Próximo" : emp.status === "ativo" ? "Ativo" : "Sem dados";
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0"><User size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"} • Responsável: {emp.adminNome}</p></div></div>
                <div className="flex items-center gap-3"><span className={`badge-status ${statusCls}`}>{statusLabel}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-4 bg-muted/10">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div><label className={labelCls}>Data de Validade</label><input type="date" value={form.data_vencimento || ""} onChange={e => setEditForm(prev => ({ ...prev, [emp.id]: { ...prev[emp.id], data_vencimento: e.target.value } }))} className={inputCls} /></div>
                    <div><label className={labelCls}>Modalidade</label><select value={form.tipo_emissao || "presencial"} onChange={e => setEditForm(prev => ({ ...prev, [emp.id]: { ...prev[emp.id], tipo_emissao: e.target.value } }))} className={inputCls}><option value="presencial">Presencial</option><option value="videoconferencia">Videoconferência</option></select></div>
                    <div><label className={labelCls}>Responsável (Auto)</label><input value={emp.adminNome} className={inputCls} readOnly /></div>
                  </div>
                  <div className="flex justify-end"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={14} /> Salvar</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default CertificadosPage;

import React, { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { Building2, Lock, ArrowRight, ShieldCheck } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from "@/components/ui/card";
import { useFormHelpers } from "@/hooks/useFormHelpers";
import { toast } from "sonner";

const ClientLoginPage: React.FC = () => {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const { loginAsClient } = useAuth();
    const navigate = useNavigate();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await loginAsClient(email, password);
            toast.success("Login realizado com sucesso!");
            navigate("/portal");
        } catch (error: any) {
            toast.error(error.message || "Erro ao realizar login.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen w-full flex items-center justify-center bg-background p-4 relative overflow-hidden">
            {/* Background Orbs */}
            <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-primary/5 rounded-full blur-3xl animate-pulse" />
            <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-primary/10 rounded-full blur-3xl animate-pulse" />

            <Card className="w-full max-w-md border-none shadow-2xl relative z-10 bg-card/50 backdrop-blur-xl">
                <CardHeader className="space-y-4 text-center">
                    <div className="flex justify-center">
                        <div className="w-16 h-16 rounded-2xl bg-primary flex items-center justify-center text-primary-foreground shadow-xl shadow-primary/20 rotate-3 hover:rotate-0 transition-transform duration-300">
                            <Building2 size={32} />
                        </div>
                    </div>
                    <div className="space-y-2">
                        <CardTitle className="text-3xl font-bold tracking-tight">Portal do Cliente</CardTitle>
                        <p className="text-muted-foreground text-sm">
                            Audipreve Contabilidade - Acesso Restrito
                        </p>
                    </div>
                </CardHeader>

                <CardContent>
                    <form id="client-login-form" onSubmit={handleLogin} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-muted-foreground uppercase tracking-widest flex items-center gap-2">
                                <Building2 size={14} /> E-mail (Cadastrado na RFB)
                            </label>
                            <Input
                                type="email"
                                placeholder="Seu E-mail"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="h-12 bg-background/50 border-border/50 focus:border-primary transition-all text-lg font-medium"
                                required
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-bold text-muted-foreground uppercase tracking-widest flex items-center gap-2">
                                <Lock size={14} /> Senha de Acesso
                            </label>
                            <Input
                                type="password"
                                placeholder="••••••••"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="h-12 bg-background/50 border-border/50 focus:border-primary transition-all"
                                required
                            />
                        </div>
                    </form>
                </CardContent>

                <CardFooter className="flex flex-col gap-4">
                    <Button
                        form="client-login-form"
                        type="submit"
                        className="w-full h-12 text-lg font-bold rounded-xl shadow-lg shadow-primary/20 transition-all hover:scale-[1.02] active:scale-[0.98]"
                        disabled={loading}
                    >
                        {loading ? (
                            <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ) : (
                            <>Entrar no Portal <ArrowRight className="ml-2" size={20} /></>
                        )}
                    </Button>

                    <div className="flex items-center justify-center gap-2 text-xs text-muted-foreground border-t border-border/50 pt-4 w-full">
                        <ShieldCheck size={14} className="text-green-500" />
                        Ambiente Seguro e Criptografado
                    </div>
                </CardFooter>
            </Card>

            {/* Footer Branding */}
            <div className="absolute bottom-8 text-center w-full">
                <p className="text-xs text-muted-foreground font-medium opacity-50 uppercase tracking-widest">
                    Desenvolvido por Audipreve Tecnologia
                </p>
            </div>
        </div>
    );
};

