import React, { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";
import logoAudipreve from "@/assets/logo-audipreve.png";
import { maskCPF } from "@/lib/utils";


interface Endereco {
  cep: string;
  logradouro: string;
  numero: string;
  complemento: string;
  bairro: string;
  cidade: string;
  estado: string;
}

const CompletarPerfilPage: React.FC = () => {
  const { user, userData, logout, refreshUserData } = useAuth();
  const navigate = useNavigate();
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({
    nome_completo: "",
    cpf: "",
    telefone: "",
    data_nascimento: "",
    endereco: { cep: "", logradouro: "", numero: "", complemento: "", bairro: "", cidade: "", estado: "" } as Endereco,
  });



  const formatCEP = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 8);
    return digits.replace(/(\d{5})(\d)/, "$1-$2");
  };

  const formatTelefone = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 11);
    if (digits.length <= 10) return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{4})(\d)/, "$1-$2");
    return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{5})(\d)/, "$1-$2");
  };

  const handleCepBlur = async (cep: string) => {
    const cleanCep = cep.replace(/\D/g, "");
    if (cleanCep.length === 8) {
      try {
        const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cleanCep}`);
        if (!response.ok) throw new Error("CEP não encontrado");
        const data = await response.json();
        
        setForm(prev => ({
          ...prev,
          endereco: {
            ...prev.endereco,
            logradouro: data.street || prev.endereco.logradouro,
            bairro: data.neighborhood || prev.endereco.bairro,
            cidade: data.city || prev.endereco.cidade,
            estado: data.state || prev.endereco.estado,
          }
        }));
        toast.info("Endereço preenchido automaticamente");
      } catch (err: any) {
        console.error("Erro ao buscar CEP:", err);
        // Opcional: toast.error("CEP não encontrado");
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.nome_completo.trim() || !form.cpf.trim() || !form.data_nascimento || !form.endereco.cep.trim() || !form.endereco.logradouro.trim() || !form.endereco.cidade.trim() || !form.endereco.estado.trim()) {
      toast.error("Preencha todos os campos obrigatórios");
      return;
    }
    setSaving(true);
    try {
      const { error } = await supabase.from("profiles").update({
        nome_completo: form.nome_completo,
        cpf: form.cpf,
        telefone: form.telefone,
        data_nascimento: form.data_nascimento,
        endereco: form.endereco as any,
        profile_completed: true,
      }).eq("user_id", user!.id);

      if (error) throw error;
      await refreshUserData();
      toast.success("Perfil completado com sucesso!");
      navigate("/termos", { replace: true });
    } catch (err: any) {
      toast.error("Erro ao salvar: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const updateEndereco = (key: keyof Endereco, value: string) => {
    setForm(prev => ({ ...prev, endereco: { ...prev.endereco, [key]: value } }));
  };

  const estados = ["AC", "AL", "AM", "AP", "BA", "CE", "DF", "ES", "GO", "MA", "MG", "MS", "MT", "PA", "PB", "PE", "PI", "PR", "RJ", "RN", "RO", "RR", "RS", "SC", "SE", "SP", "TO"];

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4" style={{ background: "var(--gradient-bg)" }}>
      <div className="w-full max-w-2xl bg-card rounded-2xl shadow-xl border border-border p-8">
        <div className="flex flex-col items-center mb-8 relative">
          <button 
            onClick={logout}
            className="absolute top-0 right-0 p-2 text-muted-foreground hover:text-destructive transition-colors text-xs font-bold flex items-center gap-1"
          >
            Sair
          </button>
          <img src={logoAudipreve} alt="Audipreve" className="w-16 h-16 object-contain mb-4" />
          <h1 className="text-2xl font-bold text-card-foreground">Complete seu Cadastro</h1>
          <p className="text-sm text-muted-foreground mt-1 text-center">Preencha suas informações pessoais para acessar o sistema</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-card-foreground mb-1">Nome Completo *</label>
              <input value={form.nome_completo} onChange={e => setForm({ ...form, nome_completo: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" placeholder="Seu nome completo" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">CPF *</label>
              <input value={form.cpf} onChange={e => setForm({ ...form, cpf: maskCPF(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" placeholder="000.000.000-00" />

            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Telefone</label>
              <input value={form.telefone} onChange={e => setForm({ ...form, telefone: formatTelefone(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" placeholder="(00) 00000-0000" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Data de Nascimento *</label>
              <input type="date" value={form.data_nascimento} onChange={e => setForm({ ...form, data_nascimento: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
          </div>

          <div className="border-t border-border pt-6">
            <h2 className="text-lg font-semibold text-card-foreground mb-4">Endereço *</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">CEP</label>
                <input 
                  value={form.endereco.cep} 
                  onChange={e => updateEndereco("cep", formatCEP(e.target.value))} 
                  onBlur={e => handleCepBlur(e.target.value)}
                  className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" 
                  placeholder="00000-000" 
                />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-card-foreground mb-1">Logradouro</label>
                <input value={form.endereco.logradouro} onChange={e => updateEndereco("logradouro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" placeholder="Rua, Av., etc." />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Número</label>
                <input value={form.endereco.numero} onChange={e => updateEndereco("numero", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Complemento</label>
                <input value={form.endereco.complemento} onChange={e => updateEndereco("complemento", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Bairro</label>
                <input value={form.endereco.bairro} onChange={e => updateEndereco("bairro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Cidade</label>
                <input value={form.endereco.cidade} onChange={e => updateEndereco("cidade", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Estado</label>
                <select value={form.endereco.estado} onChange={e => updateEndereco("estado", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none">
                  <option value="">Selecione</option>
                  {estados.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                </select>
              </div>
            </div>
          </div>

          <button type="submit" disabled={saving} className="w-full py-3 rounded-lg text-sm font-semibold text-primary-foreground shadow-md disabled:opacity-50 transition-all" style={{ background: "var(--gradient-primary)" }}>
            {saving ? "Salvando..." : "Continuar"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CompletarPerfilPage;

import React, { useEffect, useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { Plus, Trash2, X, Shield, ShieldOff, Users, Building } from "lucide-react";
import { toast } from "sonner";
import { Navigate, useNavigate } from "react-router-dom";
import AuditoriaPage from "./AuditoriaPage";

interface Usuario {
  id: string;
  nome: string;
  email: string;
  email_alertas?: string;
  isAdmin: boolean;
  isClient: boolean;
  departamento?: string;
  modules: Record<string, boolean>;
}

const moduleLabels: Record<string, string> = {
  societario: "Societário",
  fiscal: "Fiscal",
  pessoal: "Pessoal",
  certificados: "Certificados",
  certidoes: "Certidões",
  licencas: "Licenças",
  procuracoes: "Procurações",
  vencimentos: "Vencimentos",
  parcelamentos: "Parcelamentos",
  recalculos: "Recálculos",
  honorarios: "Honorários",
  agendamentos: "Agendamentos",
  declaracoes_anuais: "Declarações Anuais",
  declaracoes_mensais: "Declarações Mensais",
};

const ConfiguracoesPage: React.FC = () => {
  const { userData } = useAuth();
  const navigate = useNavigate();
  const [usuarios, setUsuarios] = useState<Usuario[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(true);
  const [activeTab, setActiveTab] = useState<'interna' | 'cliente' | 'auditoria'>('interna');
  const [editingEmailId, setEditingEmailId] = useState<string | null>(null);
  const [emailAlertasInput, setEmailAlertasInput] = useState<string>("");

  const loadUsers = async () => {
    try {
      setLoadingUsers(true);
      console.log("[ConfiguracoesPage] Iniciando carregamento de usuários...");
      const { data: profiles, error: profilesError } = await supabase.from("profiles").select("*");
      console.log("[ConfiguracoesPage] Profiles retornados:", profiles?.length, "Erro:", profilesError);
      if (profilesError) {
        console.error("Erro ao carregar perfis:", profilesError);
        return;
      }
      if (!profiles || profiles.length === 0) {
        console.warn("[ConfiguracoesPage] Nenhum perfil encontrado na tabela profiles");
        return;
      }

      const userIds = profiles.map(p => p.user_id);

      const { data: roles } = await supabase.from("user_roles").select("user_id, role").in("user_id", userIds);
      const { data: perms } = await supabase.from("user_module_permissions").select("user_id, module_name").in("user_id", userIds);
      const { data: access } = await supabase.from("empresa_acessos").select("user_id, empresa_id").in("user_id", userIds);

      const rolesByUserId = roles?.reduce((acc: any, curr: any) => {
        if (!acc[curr.user_id]) acc[curr.user_id] = [];
        acc[curr.user_id].push(curr.role);
        return acc;
      }, {}) || {};

      const permsByUserId = perms?.reduce((acc: any, curr: any) => {
        if (!acc[curr.user_id]) acc[curr.user_id] = [];
        acc[curr.user_id].push(curr.module_name);
        return acc;
      }, {}) || {};

      const accessByUserId = access?.reduce((acc: any, curr: any) => {
        acc[curr.user_id] = true;
        return acc;
      }, {}) || {};

      const users: Usuario[] = [];
      for (const p of profiles) {
        const userRoles = rolesByUserId[p.user_id] || [];
        const userPerms = permsByUserId[p.user_id] || [];

        const modules: Record<string, boolean> = {};
        userPerms.forEach((m: string) => { modules[m] = true; });

        // A user is a client if they have the 'client' role. 
        // Presence in enterprise access for a 'user' role means restriction, not client status.
        const isClient = userRoles.includes('client');
        const isAdmin = userRoles.includes('admin');

        users.push({
          id: p.user_id,
          nome: p.nome_completo || "Sem nome",
          email: "",
          email_alertas: p.email_alertas || "",
          isAdmin,
          isClient,
          departamento: "",
          modules,
        });
      }
      console.log("[ConfiguracoesPage] Usuários carregados:", users.length, users.map(u => u.nome));
      setUsuarios(users);
    } catch (err) {
      console.error("Erro ao carregar usuários:", err);
    } finally {
      setLoadingUsers(false);
    }
  };

  useEffect(() => { loadUsers(); }, []);

  // Aguardar userData carregar antes de decidir redirect
  if (!userData) return null;
  if (!userData.isAdmin) return <Navigate to="/dashboard" replace />;

  const toggleModule = async (userId: string, module: string, current: boolean) => {
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "toggleModule", target_user_id: userId, module, enable: !current }
      });
      if (res.error) throw res.error;
      toast.success(`${moduleLabels[module]} ${!current ? "habilitado" : "desabilitado"}`);
      loadUsers();
    } catch (err: any) {
      console.error("Erro no toggleModule:", err);
      toast.error("Erro ao alterar módulo: " + (err.message || "Falha na requisição"));
    }
  };

  const toggleAdmin = async (userId: string, current: boolean) => {
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "toggleAdmin", target_user_id: userId, enable: !current }
      });
      if (res.error) throw res.error;
      toast.success(!current ? "Promovido a admin" : "Removido de admin");
      loadUsers();
    } catch (err: any) {
      console.error("Erro no toggleAdmin:", err);
      toast.error("Erro ao alterar permissão de admin: " + (err.message || "Falha na requisição"));
    }
  };

  const handleDelete = async (userId: string) => {
    if (!window.confirm("Excluir este usuário do sistema?")) return;
    try {
      const res = await supabase.functions.invoke("manage-user", {
        body: { action: "deleteUser", target_user_id: userId }
      });
      if (res.error) throw res.error;
      if (res.data?.error) throw new Error(res.data.error);
      toast.success("Usuário removido!");
      loadUsers();
    } catch (err: any) {
      console.error("Erro no handleDelete:", err);
      toast.error("Erro ao excluir usuário: " + (err.message || "Falha na requisição"));
    }
  };

  const handleUpdateEmailAlertas = async (userId: string) => {
    try {
      const { error } = await supabase
        .from("profiles")
        .update({ email_alertas: emailAlertasInput })
        .eq("user_id", userId);

      if (error) throw error;
      
      toast.success("E-mail de alertas atualizado com sucesso!");
      setEditingEmailId(null);
      loadUsers();
    } catch (err: any) {
      console.error("Erro:", err);
      toast.error("Erro ao atualizar e-mail: " + err.message);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
        <div>
          <h1 className="header-title text-3xl font-black tracking-tight text-foreground">
            Gerenciamento de Usuários
          </h1>
          <p className="text-muted-foreground mt-1">
            Controle de acessos, permissões e configurações do sistema.
          </p>
        </div>
        <button onClick={() => navigate("/configuracoes/usuarios/novo")} className="button-premium">
          <Plus size={18} /> Novo Usuário
        </button>
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar pt-2">
        <button
          onClick={() => setActiveTab('interna')}
          className={`px-6 py-3 text-xs font-black uppercase tracking-wider border-b-2 transition-all whitespace-nowrap ${activeTab === 'interna' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}
        >
          <div className="flex items-center gap-2">
            <Users size={16} /> Equipe Interna
          </div>
        </button>
        <button
          onClick={() => setActiveTab('cliente')}
          className={`px-6 py-3 text-xs font-black uppercase tracking-wider border-b-2 transition-all whitespace-nowrap ${activeTab === 'cliente' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}
        >
          <div className="flex items-center gap-2">
            <Building size={16} /> Portal Cliente
          </div>
        </button>
        <button
          onClick={() => setActiveTab('auditoria')}
          className={`px-6 py-3 text-xs font-black uppercase tracking-wider border-b-2 transition-all whitespace-nowrap ${activeTab === 'auditoria' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}
        >
          <div className="flex items-center gap-2">
            <Shield size={16} /> Auditoria do Sistema
          </div>
        </button>
      </div>

      {activeTab === 'auditoria' ? (
        <AuditoriaPage />
      ) : (
        <>
          <div className="space-y-4">
            {usuarios.filter(u => activeTab === 'interna' ? !u.isClient : u.isClient).map(u => (
              <div key={u.id} className="card-premium">
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center border border-primary/20 shadow-inner">
                      <span className="text-primary text-lg font-black">{(u.nome || "U").slice(0, 2).toUpperCase()}</span>
                    </div>
                    <div>
                      <p className="font-black text-card-foreground text-lg">{u.nome || "Sem nome"} {u.isAdmin && <span className="ml-2 badge-status badge-success text-[10px] uppercase align-middle">Admin</span>}</p>
                      <p className="text-sm font-medium text-muted-foreground mt-0.5">{u.email} {u.departamento ? <span className="text-primary ml-2">• {u.departamento}</span> : ""}</p>
                      
                      {/* Interface de E-mail de Alertas para Clientes */}
                      {u.isClient && (
                         <div className="mt-2">
                           {editingEmailId === u.id ? (
                             <div className="flex items-center gap-2">
                               <input 
                                 type="email"
                                 autoFocus
                                 className="px-3 py-1 text-sm border border-border rounded-lg bg-background w-64 focus:ring-1 focus:ring-primary outline-none"
                                 placeholder="alerta@empresa.com"
                                 value={emailAlertasInput}
                                 onChange={(e) => setEmailAlertasInput(e.target.value)}
                                 onKeyDown={(e) => e.key === 'Enter' && handleUpdateEmailAlertas(u.id)}
                               />
                               <button onClick={() => handleUpdateEmailAlertas(u.id)} className="text-xs bg-primary text-primary-foreground px-3 py-1.5 rounded-lg font-bold hover:opacity-90 transition-opacity">
                                 Salvar
                               </button>
                               <button onClick={() => setEditingEmailId(null)} className="text-muted-foreground hover:text-foreground p-1 transition-colors">
                                 <X size={16} />
                               </button>
                             </div>
                           ) : (
                             <div className="flex items-center gap-2">
                               <span className="text-xs font-semibold text-muted-foreground">E-mail para Alertas Automáticos:</span>
                               <span className={u.email_alertas ? "text-xs font-bold text-foreground" : "text-xs italic text-muted-foreground opacity-70"}>
                                 {u.email_alertas || "Não configurado"}
                               </span>
                               <button onClick={() => { setEditingEmailId(u.id); setEmailAlertasInput(u.email_alertas || ""); }} className="text-[10px] uppercase tracking-wider font-bold text-primary hover:underline ml-1">
                                 Alterar
                               </button>
                             </div>
                           )}
                         </div>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-2 w-full md:w-auto justify-end border-t md:border-t-0 pt-4 md:pt-0 border-border/50">
                    <button 
                      onClick={() => toggleAdmin(u.id, u.isAdmin)} 
                      className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all border ${u.isAdmin ? "bg-primary/10 border-primary/30 text-primary hover:bg-primary/20" : "bg-muted border-transparent text-muted-foreground hover:bg-muted/80 hover:text-foreground"}`} 
                      title={u.isAdmin ? "Remover admin" : "Tornar admin"}
                    >
                      {u.isAdmin ? <Shield size={16} /> : <ShieldOff size={16} />}
                      {u.isAdmin ? 'Administrador' : 'Tornar Admin'}
                    </button>
                    <button 
                      onClick={() => handleDelete(u.id)} 
                      className="p-2.5 rounded-xl hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors border border-transparent hover:border-destructive/20"
                      title="Excluir Usuário"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>

                {activeTab === 'interna' && (
                  <div className="mt-6 pt-6 border-t border-border/50">
                    <p className="text-xs font-black text-muted-foreground uppercase tracking-[0.15em] mb-4">Permissões de Módulos</p>
                    <div className="grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-3">
                      {Object.entries(moduleLabels).map(([key, label]) => {
                        const hasAccess = u.isAdmin || u.modules?.[key];
                        return (
                          <button
                            key={key}
                            disabled={u.isAdmin}
                            onClick={() => toggleModule(u.id, key, u.modules?.[key] || false)}
                            className={`flex items-center justify-between px-3 py-2.5 rounded-xl text-sm font-bold transition-all border ${hasAccess
                              ? "border-primary/40 bg-primary/10 text-primary shadow-sm"
                              : "border-border/50 bg-muted/30 text-muted-foreground hover:border-primary/30"
                              } ${u.isAdmin ? "opacity-70 cursor-not-allowed" : ""}`}
                          >
                            <span className="truncate pr-2">{label}</span>
                            {hasAccess && <div className="w-2 h-2 rounded-full bg-primary shrink-0" />}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            ))}

            {loadingUsers ? (
              <div className="card-premium text-center py-12">
                <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin mx-auto opacity-50 mb-3" />
                <p className="text-muted-foreground font-bold">Carregando equipe...</p>
              </div>
            ) : usuarios.filter(u => activeTab === 'interna' ? !u.isClient : u.isClient).length === 0 ? (
              <div className="card-premium text-center py-16">
                <div className="p-4 rounded-full bg-muted/10 w-fit mx-auto mb-4">
                  <Users size={32} className="text-muted-foreground opacity-50" />
                </div>
                <p className="text-lg font-black text-card-foreground">Nenhum usuário encontrado</p>
                <p className="text-sm text-muted-foreground mt-1">Você pode adicionar novos usuários clicando no botão acima.</p>
              </div>
            ) : null}
          </div>

          <div className="pt-8">
            <h3 className="header-title text-2xl font-black mb-6 flex items-center gap-3">
              <div className="w-1 h-6 bg-primary rounded-full" />
              Configurações de Notificações
            </h3>
            <NotificationConfig />
          </div>
        </>
      )}
    </div>
  );
};

const NotificationConfig: React.FC = () => {
  const [types, setTypes] = useState<any[]>([]);

  const loadData = async () => {
    const { data: nTypes } = await (supabase as any).from("notification_types").select("*");
    setTypes(nTypes || []);
  };

  useEffect(() => { loadData(); }, []);

  const toggleType = async (id: string, current: boolean) => {
    await (supabase as any).from("notification_types").update({ is_enabled: !current }).eq("id", id);
    toast.success("Configuração atualizada");
    loadData();
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {types.map((t) => (
        <div key={t.id} className="card-premium flex items-center justify-between gap-4 p-5 hover:border-primary/30 transition-colors">
          <div className="flex-1">
            <p className="text-base font-black text-foreground">{t.label}</p>
            <p className="text-xs font-medium text-muted-foreground mt-1 leading-relaxed">
              {t.description}
            </p>
          </div>
          <button
            onClick={() => toggleType(t.id, t.is_enabled)}
            className={`w-14 h-7 rounded-full transition-colors relative shrink-0 ${
              t.is_enabled ? "bg-primary shadow-sm shadow-primary/20" : "bg-muted-foreground/30"
            }`}
          >
            <div
              className={`absolute top-1 w-5 h-5 rounded-full bg-white transition-all shadow-sm ${
                t.is_enabled ? "left-8" : "left-1"
              }`}
            />
          </button>
        </div>
      ))}
    </div>
  );
};

export default ConfiguracoesPage;

import React, { useEffect, useState, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
    ClipboardList, Search, CheckCircle,
    Circle, Save, Building2,
    Users, Info
} from "lucide-react";
import { toast } from "sonner";
import { Database } from "@/integrations/supabase/types";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

type DeclaracaoAnualRow = Database['public']['Tables']['declaracoes_anuais']['Row'];
type DeclaracaoIRPFRow = Database['public']['Tables']['declaracoes_irpf']['Row'];

interface Empresa {
    id: string;
    nome_empresa: string;
    cnpj: string | null;
    regime_tributario: string | null;
    porte_empresa: string | null;
    situacao: string | null;
}

interface Socio {
    id: string;
    nome: string;
    cpf: string | null;
    empresa_id: string;
    empresa_nome?: string;
}

interface DeclaracaoAnual extends Partial<DeclaracaoAnualRow> {
    empresa_id: string;
    ano: number;
    tipo_declaracao: string;
    obrigatorio: boolean;
    enviada: boolean;
    data_envio?: string | null;
}

interface DeclaracaoIRPF extends Partial<DeclaracaoIRPFRow> {
    socio_id: string;
    ano: number;
    faz_pelo_escritorio: boolean;
    transmitida: boolean;
    data_transmissao?: string | null;
    quem_transmitiu?: string | null;
}

const DeclaracoesAnuaisPage: React.FC = () => {
    const [empresas, setEmpresas] = useState<Empresa[]>([]);
    const [socios, setSocios] = useState<Socio[]>([]);
    const [declaracoes, setDeclaracoes] = useState<Record<string, DeclaracaoAnual>>({});
    const [declaracoesIRPF, setDeclaracoesIRPF] = useState<Record<string, DeclaracaoIRPF>>({});
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [search, setSearch] = useState("");
    const [ano, setAno] = useState(new Date().getFullYear());
    const [activeTab, setActiveTab] = useState<"defis" | "ecd_ecf" | "dasn_simei" | "dirf" | "irpf">("defis");

    const prazos: Record<string, string> = {
        defis: "31/03",
        ecd_ecf: "31/07",
        dasn_simei: "31/05",
        dirf: "27/02",
        irpf: "31/05"
    };

    const loadData = useCallback(async () => {
        setLoading(true);
        try {
            const { data: emps } = await supabase.from("empresas").select("*").order("nome_empresa");
            setEmpresas((emps as Empresa[]) || []);

            const { data: socs } = await supabase.from("socios").select("*, empresas(nome_empresa)");
            setSocios(((socs || []) as unknown as (Socio & { empresas: { nome_empresa: string } | null })[]).map((s) => ({
                ...s,
                empresa_nome: s.empresas?.nome_empresa
            })));

            const { data: decls } = await supabase.from("declaracoes_anuais").select("*").eq("ano", ano);
            const declMap: Record<string, DeclaracaoAnual> = {};
            (decls as DeclaracaoAnualRow[])?.forEach(d => {
                declMap[`${d.empresa_id}_${d.tipo_declaracao}`] = d as DeclaracaoAnual;
            });
            setDeclaracoes(declMap);

            const { data: irpfs } = await supabase.from("declaracoes_irpf").select("*").eq("ano", ano);
            const irpfMap: Record<string, DeclaracaoIRPF> = {};
            (irpfs as DeclaracaoIRPFRow[])?.forEach(i => {
                irpfMap[i.socio_id] = i as DeclaracaoIRPF;
            });
            setDeclaracoesIRPF(irpfMap);
        } catch (err: any) {
            toast.error("Erro ao carregar dados: " + err.message);
        } finally {
            setLoading(false);
        }
    }, [ano]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleToggleObrigatorio = (empresaId: string, tipo: string) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: false,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: { ...current, obrigatorio: !current.obrigatorio }
        }));
    };

    const handleToggleEnviada = (empresaId: string, tipo: string) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: true,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: {
                ...current,
                enviada: !current.enviada,
                data_envio: !current.enviada ? new Date().toISOString().split('T')[0] : null
            }
        }));
    };

    const updateDeclaracao = (empresaId: string, tipo: string, field: keyof DeclaracaoAnual, value: string | boolean | number | null) => {
        const key = `${empresaId}_${tipo}`;
        const current = declaracoes[key] || {
            empresa_id: empresaId,
            ano,
            tipo_declaracao: tipo,
            obrigatorio: true,
            enviada: false,
            data_envio: null
        };

        setDeclaracoes(prev => ({
            ...prev,
            [key]: { ...current, [field]: value }
        }));
    };

    const saveDeclaracao = async (empresaId: string, tipo: string) => {
        setSaving(true);
        const key = `${empresaId}_${tipo}`;
        const data = declaracoes[key];
        if (!data) return;

        try {
            // Filter only fields that exist in the database Row
            // Note: 'obrigatorio' and 'data_envio' are not in the current DB schema for declaracoes_anuais
            const dbData = {
                empresa_id: data.empresa_id,
                ano: data.ano,
                tipo_declaracao: data.tipo_declaracao,
                enviada: data.enviada
            };

            if (data.id) {
                await supabase.from("declaracoes_anuais").update(dbData).eq("id", data.id);
            } else {
                const { data: inserted } = await supabase.from("declaracoes_anuais").insert(dbData).select().single();
                if (inserted) {
                    setDeclaracoes(prev => ({ ...prev, [key]: inserted as unknown as DeclaracaoAnual }));
                }
            }
            toast.success("Declaração salva!");
        } catch (err: any) {
            toast.error("Erro ao salvar: " + err.message);
        } finally {
            setSaving(false);
        }
    };

    // IRPF handlers
    const updateIRPF = (socioId: string, field: keyof DeclaracaoIRPF, value: string | boolean | number | null) => {
        const current = declaracoesIRPF[socioId] || {
            socio_id: socioId,
            ano,
            faz_pelo_escritorio: false,
            transmitida: false,
            data_transmissao: null,
            quem_transmitiu: null
        };

        setDeclaracoesIRPF(prev => ({
            ...prev,
            [socioId]: { ...current, [field]: value }
        }));
    };

    const saveIRPF = async (socioId: string) => {
        setSaving(true);
        const data = declaracoesIRPF[socioId];
        if (!data) return;

        try {
            // Filter only fields that exist in the database Row
            // Note: 'faz_pelo_escritorio', 'data_transmissao', 'quem_transmitiu' are not in the current DB schema for declaracoes_irpf
            const dbData = {
                socio_id: data.socio_id,
                ano: data.ano,
                transmitida: data.transmitida
            };

            if (data.id) {
                await supabase.from("declaracoes_irpf").update(dbData).eq("id", data.id);
            } else {
                const { data: inserted } = await supabase.from("declaracoes_irpf").insert(dbData).select().single();
                if (inserted) {
                    setDeclaracoesIRPF(prev => ({ ...prev, [socioId]: inserted as unknown as DeclaracaoIRPF }));
                }
            }
            toast.success("IRPF salvo!");
        } catch (err: any) {
            toast.error("Erro ao salvar IRPF: " + err.message);
        } finally {
            setSaving(false);
        }
    };

    const filterCompanies = () => {
        return empresas.filter(e => {
            const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

            let matchTab = false;
            if (activeTab === "defis") {
                matchTab = e.regime_tributario === "simples";
            } else if (activeTab === "ecd_ecf") {
                matchTab = e.regime_tributario === "lucro_presumido" || e.regime_tributario === "lucro_real";
            } else if (activeTab === "dasn_simei") {
                matchTab = e.porte_empresa === "mei";
            } else if (activeTab === "dirf") {
                matchTab = e.porte_empresa !== "mei";
            } else {
                matchTab = true; // For IRPF we list socios
            }

            // Check for manual override (obrigatorio)
            const key = `${e.id}_${activeTab}`;
            const decl = declaracoes[key];
            if (decl?.obrigatorio) matchTab = true;

            return matchSearch && matchTab;
        });
    };

    const filterSocios = () => {
        return socios.filter(s =>
            s.nome.toLowerCase().includes(search.toLowerCase()) ||
            (s.cpf && s.cpf.includes(search)) ||
            (s.empresa_nome && s.empresa_nome.toLowerCase().includes(search.toLowerCase()))
        );
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    const filteredItems = activeTab === "irpf" ? filterSocios() : filterCompanies();

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full sm:w-auto">
                    <FavoriteToggleButton moduleId="declaracoes-anuais" />
                    <div>
                        <h2 className="text-lg font-bold text-card-foreground">Declarações Anuais</h2>
                        <p className="text-xs text-muted-foreground">Controle de DEFIS, ECD/ECF, DASN, DIRF e IRPF.</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <span className="text-sm font-medium text-muted-foreground uppercase">Ano Base:</span>
                    <select
                        value={ano}
                        onChange={e => setAno(parseInt(e.target.value))}
                        className="px-4 py-2 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-bold shadow-sm"
                    >
                        {[...Array(10)].map((_, i) => {
                            const year = new Date().getFullYear() - 5 + i;
                            return <option key={year} value={year}>{year}</option>;
                        })}
                    </select>
                </div>
            </div>

            <div className="module-card">
                <div className="flex flex-col sm:flex-row gap-4 items-center mb-6">
                    <div className="relative flex-1 w-full">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder={activeTab === "irpf" ? "Buscar por nome, CPF ou empresa..." : "Buscar por nome ou CNPJ..."}
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                        />
                    </div>
                    <div className="flex items-center gap-2 bg-muted/30 p-1 rounded-xl border border-border w-full sm:w-auto overflow-x-auto no-scrollbar">
                        {[
                            { id: "defis", label: "DEFIS" },
                            { id: "ecd_ecf", label: "ECD/ECF" },
                            { id: "dasn_simei", label: "DASN-SIMEI" },
                            { id: "dirf", label: "DIRF" },
                            { id: "irpf", label: "IRPF" }
                        ].map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id as any)}
                                className={`px-4 py-2 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${activeTab === tab.id ? "bg-card text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                            >
                                {tab.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="bg-info/10 border border-info/20 rounded-xl p-4 mb-6 flex gap-3 items-start">
                    <Info size={18} className="text-info mt-0.5 flex-shrink-0" />
                    <div className="text-sm text-info">
                        <p className="font-semibold">Obrigação para {prazos[activeTab]}</p>
                    </div>
                </div>

                <div className="space-y-3">
                    {activeTab !== "irpf" ? (
                        // Empresas List
                        (filteredItems as Empresa[]).map(emp => {
                            const key = `${emp.id}_${activeTab}`;
                            // Lógica de obrigatoriedade automática
                            const isAutoObligatory =
                                (activeTab === "defis" && emp.regime_tributario === "simples") ||
                                (activeTab === "ecd_ecf" && (emp.regime_tributario === "lucro_presumido" || emp.regime_tributario === "lucro_real")) ||
                                (activeTab === "dasn_simei" && emp.porte_empresa === "mei") ||
                                (activeTab === "dirf" && emp.porte_empresa !== "mei");

                            const decl = declaracoes[key] || {
                                empresa_id: emp.id,
                                ano,
                                tipo_declaracao: activeTab,
                                obrigatorio: isAutoObligatory,
                                enviada: false,
                                data_envio: null
                            };

                            return (
                                <div key={emp.id} className="p-4 bg-card border border-border rounded-xl hover:shadow-md transition-shadow">
                                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${decl.obrigatorio ? "bg-primary/10 text-primary" : "bg-muted text-muted-foreground"}`}>
                                                <Building2 size={20} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-card-foreground">{emp.nome_empresa}</p>
                                                <p className="text-xs text-muted-foreground flex items-center gap-2">
                                                    {emp.cnpj || "—"} •
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${decl.obrigatorio ? "bg-info/20 text-info" : "bg-muted text-muted-foreground"}`}>
                                                        {decl.obrigatorio ? "Obrigatória" : "Não Obrigatória"}
                                                    </span>
                                                </p>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-1 sm:grid-cols-4 items-center gap-4">
                                            {/* Obrigação Manual */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.obrigatorio}
                                                    onChange={() => handleToggleObrigatorio(emp.id, activeTab)}
                                                    className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                                                />
                                                <span className="text-sm font-medium">Obrigatória</span>
                                            </label>

                                            {/* Enviada */}
                                            <label className={`flex items-center gap-2 cursor-pointer ${!decl.obrigatorio ? "opacity-30 pointer-events-none" : ""}`}>
                                                <input
                                                    type="checkbox"
                                                    disabled={!decl.obrigatorio}
                                                    checked={decl.enviada}
                                                    onChange={() => handleToggleEnviada(emp.id, activeTab)}
                                                    className="w-4 h-4 rounded border-border text-success focus:ring-success"
                                                />
                                                <span className="text-sm font-medium">Enviada</span>
                                            </label>

                                            {/* Data de Envio */}
                                            <div className={!decl.obrigatorio ? "opacity-30 pointer-events-none" : ""}>
                                                <input
                                                    type="date"
                                                    disabled={!decl.obrigatorio}
                                                    value={decl.data_envio || ""}
                                                    onChange={e => updateDeclaracao(emp.id, activeTab, "data_envio", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Botão Salvar */}
                                            <button
                                                onClick={() => saveDeclaracao(emp.id, activeTab)}
                                                disabled={saving}
                                                className="flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-bold hover:bg-primary/90 transition-colors disabled:opacity-50"
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    ) : (
                        // IRPF List
                        (filteredItems as Socio[]).map(socio => {
                            const decl = declaracoesIRPF[socio.id] || {
                                socio_id: socio.id,
                                ano,
                                faz_pelo_escritorio: false,
                                transmitida: false,
                                data_transmissao: null,
                                quem_transmitiu: null
                            };

                            return (
                                <div key={socio.id} className="p-4 bg-card border border-border rounded-xl hover:shadow-md transition-shadow">
                                    <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-warning/10 text-warning flex items-center justify-center">
                                                <Users size={20} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-card-foreground">{socio.nome}</p>
                                                <p className="text-xs text-muted-foreground">
                                                    CPF: {socio.cpf || "—"} • Empresa: {socio.empresa_nome || "—"}
                                                </p>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 items-center gap-3">
                                            {/* Pelo Escritório */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.faz_pelo_escritorio}
                                                    onChange={e => updateIRPF(socio.id, "faz_pelo_escritorio", e.target.checked)}
                                                    className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                                                />
                                                <span className="text-xs font-medium">Pelo Escritório?</span>
                                            </label>

                                            {/* Transmitida */}
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={decl.transmitida}
                                                    onChange={e => updateIRPF(socio.id, "transmitida", e.target.checked)}
                                                    className="w-4 h-4 rounded border-border text-success focus:ring-success"
                                                />
                                                <span className="text-xs font-medium">Transmitida?</span>
                                            </label>

                                            {/* Data Transmissão */}
                                            <div>
                                                <input
                                                    type="date"
                                                    value={decl.data_transmissao || ""}
                                                    onChange={e => updateIRPF(socio.id, "data_transmissao", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Quem Transmitiu */}
                                            <div>
                                                <input
                                                    type="text"
                                                    placeholder="Quem transmitiu?"
                                                    value={decl.quem_transmitiu || ""}
                                                    onChange={e => updateIRPF(socio.id, "quem_transmitiu", e.target.value)}
                                                    className="w-full px-2 py-1.5 border border-border rounded-lg bg-background text-xs"
                                                />
                                            </div>

                                            {/* Botão Salvar */}
                                            <button
                                                onClick={() => saveIRPF(socio.id)}
                                                disabled={saving}
                                                className="flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-bold hover:bg-primary/90 transition-colors disabled:opacity-50"
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    )}

                    {filteredItems.length === 0 && (
                        <div className="text-center py-12 bg-muted/20 rounded-xl border border-dashed border-border">
                            <ClipboardList size={40} className="mx-auto text-muted-foreground/30 mb-3" />
                            <p className="text-muted-foreground font-medium">Nenhum registro encontrado para esta categoria.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default DeclaracoesAnuaisPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, Save, CheckCircle, Circle, ChevronLeft, ChevronRight } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/contexts/AuthContext";
import { useSocietario } from "@/hooks/useSocietario";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const DeclaracoesMensaisPage: React.FC = () => {
    const { user } = useAuth();
    const { getPaginatedEmpresas } = useSocietario();
    const [search, setSearch] = useState("");
    const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
    
    const [pagination, setPagination] = useState({ pageIndex: 0, pageSize: 12 });
    const [paginatedData, setPaginatedData] = useState<any[]>([]);
    const [totalCount, setTotalCount] = useState(0);
    const [loadingPaginated, setLoadingPaginated] = useState(false);

    const [pessoalData, setPessoalData] = useState<Record<string, any>>({});
    const [editForm, setEditForm] = useState<Record<string, any>>({});
    const [isSaving, setIsSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");

    useEffect(() => {
        setPagination(prev => ({ ...prev, pageIndex: 0 }));
    }, [search, activeTab]);

    useEffect(() => {
        const fetch = async () => {
            setLoadingPaginated(true);
            try {
                const { data, count } = await getPaginatedEmpresas(
                    pagination.pageIndex,
                    pagination.pageSize,
                    search,
                    activeTab,
                    "todos",
                    "declaracoes_mensais",
                    user?.id
                );
                setPaginatedData(data);
                setTotalCount(count);
            } catch (err) {
                console.error("Erro ao carregar empresas paginadas:", err);
            } finally {
                setLoadingPaginated(false);
            }
        };
        fetch();
    }, [pagination, search, activeTab, user]);

    useEffect(() => {
        const load = async () => {
            if (paginatedData.length === 0) {
                setPessoalData({});
                setEditForm({});
                return;
            }
            const empresaIds = paginatedData.map(e => e.id);
            const { data } = await supabase.from("pessoal").select("*")
                .eq("competencia", competencia)
                .in("empresa_id", empresaIds);
            const map: Record<string, any> = {};
            const formMap: Record<string, any> = {};

            data?.forEach(p => {
                map[p.empresa_id] = p;
                formMap[p.empresa_id] = {
                    dctf_web_gerada: p.dctf_web_gerada || false,
                    dctf_web_data_envio: (p as any).dctf_web_data_envio || ""
                };
            });

            // For businesses not in "pessoal" yet
            empresaIds.forEach(id => {
                if (!formMap[id]) {
                    formMap[id] = { dctf_web_gerada: false, dctf_web_data_envio: "" };
                }
            });

            setPessoalData(map);
            setEditForm(formMap);
        };
        load();
    }, [competencia, paginatedData]);

    const updateForm = (empresaId: string, field: string, value: any) => {
        setEditForm(prev => ({
            ...prev,
            [empresaId]: {
                ...prev[empresaId],
                [field]: value
            }
        }));
    };

    const handleSave = async (empresaId: string) => {
        const form = editForm[empresaId] || {};
        const existing = pessoalData[empresaId];
        setIsSaving(true);

        try {
            const payload = {
                empresa_id: empresaId,
                competencia,
                dctf_web_gerada: form.dctf_web_gerada || false,
                dctf_web_data_envio: form.dctf_web_data_envio || null
            };

            if (existing?.id) {
                await supabase.from("pessoal").update({
                    dctf_web_gerada: payload.dctf_web_gerada,
                    dctf_web_data_envio: payload.dctf_web_data_envio
                }).eq("id", existing.id);
            } else {
                await supabase.from("pessoal").insert(payload);
            }

            toast.success("Dados salvos com sucesso!");

            const { data } = await supabase.from("pessoal").select("*").eq("empresa_id", empresaId).eq("competencia", competencia).maybeSingle();
            if (data) {
                setPessoalData(prev => ({ ...prev, [empresaId]: data }));
            }
        } catch (err: any) {
            toast.error(err.message || "Erro ao salvar");
        } finally {
            setIsSaving(false);
        }
    };

    const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
    const completedCountInPage = paginatedData.filter(e => editForm[e.id]?.dctf_web_gerada).length;

    if (loadingPaginated && paginatedData.length === 0) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full sm:w-auto">
                    <FavoriteToggleButton moduleId="declaracoes-mensais" />
                    <div>
                        <h1 className="text-2xl font-bold text-card-foreground">Declarações Mensais</h1>
                        <p className="text-sm text-muted-foreground mt-1">Controle de declarações sincronizado.</p>
                    </div>
                </div>
                <input
                    type="month"
                    value={competencia}
                    onChange={e => setCompetencia(e.target.value)}
                    className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase font-bold">Empresas na Categoria</p>
                    <p className="text-2xl font-black text-primary mt-1">{totalCount}</p>
                </div>
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase font-bold">Nesta Página</p>
                    <p className="text-2xl font-black text-card-foreground mt-1">{paginatedData.length}</p>
                </div>
                <div className="stat-card">
                    <p className="text-xs text-muted-foreground uppercase font-bold">Concluídas (Página)</p>
                    <p className="text-2xl font-black text-success mt-1">{completedCountInPage}</p>
                </div>
            </div>

            <div className="relative max-w-sm">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <input
                    type="text"
                    placeholder="Buscar empresa por nome ou CNPJ..."
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                />
            </div>

            <div className="flex border-b border-border overflow-x-auto no-scrollbar">
                {["ativas", "mei", "paralisadas", "baixadas", "entregue"].map(t => (
                    <button
                        key={t}
                        className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === t ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                        onClick={() => setActiveTab(t as any)}
                    >
                        {t === "ativas" ? "Empresas Ativas" : t === "mei" ? "Empresas MEI" : t === "paralisadas" ? "Empresas Paralisadas" : t === "entregue" ? "Empresas Entregues" : "Empresas Baixadas"}
                    </button>
                ))}
            </div>

            <div className="bg-card border border-border rounded-xl overflow-hidden shadow-sm relative">
                {loadingPaginated && (
                   <div className="absolute inset-0 bg-background/50 backdrop-blur-[1px] z-10 flex items-center justify-center">
                       <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
                   </div>
                )}
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="text-xs text-muted-foreground uppercase bg-muted/50 border-b border-border">
                            <tr>
                                <th className="px-4 py-4 font-black">Situação</th>
                                <th className="px-4 py-4 font-black">Empresa</th>
                                <th className="px-4 py-4 font-black">CNPJ</th>
                                <th className="px-4 py-4 font-black">DCTF WEB</th>
                                <th className="px-4 py-4 font-black text-center">Data de Envio</th>
                                <th className="px-4 py-4 font-black text-right">Ação</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {paginatedData.map((emp) => {
                                const form = editForm[emp.id] || { dctf_web_gerada: false, dctf_web_data_envio: "" };
                                const isGenerated = form.dctf_web_gerada;

                                return (
                                    <tr key={emp.id} className="hover:bg-muted/20 transition-colors">
                                        <td className="px-4 py-3">
                                            {isGenerated ? (
                                                <span className="flex items-center gap-1.5 text-success font-bold text-xs uppercase">
                                                    <CheckCircle size={14} /> Gerada
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-muted-foreground font-bold text-xs uppercase">
                                                    <Circle size={14} /> Pendente
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 font-semibold text-card-foreground">
                                            {emp.nome_empresa}
                                        </td>
                                        <td className="px-4 py-3 text-muted-foreground whitespace-nowrap text-xs">
                                            {emp.cnpj || "—"}
                                        </td>
                                        <td className="px-4 py-3 w-48">
                                            <select
                                                value={isGenerated ? "sim" : "nao"}
                                                onChange={e => {
                                                    const val = e.target.value === "sim";
                                                    updateForm(emp.id, "dctf_web_gerada", val);
                                                    if (!val) updateForm(emp.id, "dctf_web_data_envio", "");
                                                }}
                                                className={inputCls}
                                            >
                                                <option value="nao">Não Gerada</option>
                                                <option value="sim">Gerada</option>
                                            </select>
                                        </td>
                                        <td className="px-4 py-3 w-48 text-center">
                                            {isGenerated ? (
                                                <input
                                                    type="date"
                                                    value={form.dctf_web_data_envio || ""}
                                                    onChange={e => updateForm(emp.id, "dctf_web_data_envio", e.target.value)}
                                                    className={inputCls}
                                                />
                                            ) : (
                                                <span className="text-xs text-muted-foreground italic px-2">N/A</span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <button
                                                onClick={() => handleSave(emp.id)}
                                                disabled={isSaving}
                                                className="inline-flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-xs font-black text-white shadow-lg hover:scale-105 transition-all disabled:opacity-50 uppercase tracking-widest bg-primary"
                                            >
                                                <Save size={14} /> Salvar
                                            </button>
                                        </td>
                                    </tr>
                                );
                            })}

                            {paginatedData.length === 0 && !loadingPaginated && (
                                <tr>
                                    <td colSpan={6} className="px-4 py-12 text-center text-muted-foreground font-medium">
                                        Nenhuma empresa encontrada com os filtros atuais.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {totalCount > pagination.pageSize && (
                <div className="flex items-center justify-between mt-4 px-2">
                    <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">
                        Página {pagination.pageIndex + 1} de {Math.ceil(totalCount / pagination.pageSize)}
                    </p>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => setPagination(prev => ({ ...prev, pageIndex: Math.max(0, prev.pageIndex - 1) }))}
                            disabled={pagination.pageIndex === 0 || loadingPaginated}
                            className="p-2 rounded-lg border border-border bg-card hover:bg-muted disabled:opacity-50 transition-colors shadow-sm"
                        >
                            <ChevronLeft size={18} />
                        </button>
                        <button
                            onClick={() => setPagination(prev => ({ ...prev, pageIndex: prev.pageIndex + 1 }))}
                            disabled={(pagination.pageIndex + 1) * pagination.pageSize >= totalCount || loadingPaginated}
                            className="p-2 rounded-lg border border-border bg-card hover:bg-muted disabled:opacity-50 transition-colors shadow-sm"
                        >
                            <ChevronRight size={18} />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default DeclaracoesMensaisPage;

import React, { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate, Link } from "react-router-dom";
import { Loader2, Fingerprint, Mail, ArrowLeft, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import logoAudipreve from "@/assets/logo-audipreve.png";
import { maskCPF } from "@/lib/utils";


const EsqueciSenhaPage: React.FC = () => {
    const navigate = useNavigate();
    const [email, setEmail] = useState("");
    const [cpf, setCpf] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState(false);



    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setLoading(true);

        try {
            // 1. Verificar usando a função RPC segura que ignora RLS (lê perfis e auth anonimamente de forma controlada)
            const { data: isMatch, error: matchError } = await supabase.rpc('check_cpf_email_match', {
                p_cpf: cpf,
                p_email: email
            });

            if (matchError || !isMatch) {
                throw new Error("CPF não encontrado ou e-mail divergente do cadastro.");
            }

            const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
                redirectTo: window.location.origin + "/reset-password",
            });

            if (resetError) throw resetError;

            setSuccess(true);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <div className="min-h-screen flex items-center justify-center p-4">
                <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md p-8 text-center space-y-6">
                    <div className="w-16 h-16 bg-success/10 text-success rounded-full flex items-center justify-center mx-auto">
                        <Mail size={32} />
                    </div>
                    <h2 className="text-2xl font-bold">Verifique seu E-mail</h2>
                    <p className="text-muted-foreground">
                        Enviamos um link de recuperação para <strong>{email}</strong>. Por favor, verifique sua caixa de entrada e spam.
                    </p>
                    <Link to="/login" className="block w-full py-3 rounded-xl font-bold bg-muted hover:bg-muted/80 transition-all">
                        Voltar para o Login
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className="bg-card border border-border rounded-2xl shadow-xl w-full max-w-md overflow-hidden p-8 space-y-8 animate-fade-in">
                <div className="text-center">
                    <img src={logoAudipreve} alt="Audipreve" className="w-20 h-20 object-contain mx-auto mb-6" />
                    <h2 className="text-2xl font-bold text-card-foreground">Recuperar Senha</h2>
                    <p className="text-muted-foreground mt-2 text-sm">Informe seu CPF e e-mail cadastrados.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">CPF</label>
                            <div className="relative">
                                <Fingerprint size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="text"
                                    placeholder="000.000.000-00"
                                    value={cpf}
                                    onChange={e => setCpf(maskCPF(e.target.value))}

                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-semibold text-muted-foreground mb-1.5 ml-1">E-mail Cadastrado</label>
                            <div className="relative">
                                <Mail size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    type="email"
                                    placeholder="seu@email.com"
                                    value={email}
                                    onChange={e => setEmail(e.target.value)}
                                    required
                                    className="w-full pl-11 pr-4 py-3 border border-border rounded-xl bg-background focus:ring-2 focus:ring-primary outline-none transition-all"
                                />
                            </div>
                        </div>
                    </div>

                    {error && (
                        <div className="flex gap-3 p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive">
                            <AlertCircle size={18} className="shrink-0 mt-0.5" />
                            <p className="text-sm font-medium">{error}</p>
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full py-4 rounded-xl font-bold text-primary-foreground shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        style={{ background: "var(--gradient-primary)" }}
                    >
                        {loading ? <Loader2 className="animate-spin mx-auto" size={20} /> : "Enviar Link de Recuperação"}
                    </button>
                </form>

                <div className="text-center">
                    <Link to="/login" className="inline-flex items-center gap-2 text-sm font-medium text-muted-foreground hover:text-primary transition-colors">
                        <ArrowLeft size={16} /> Voltar para o Login
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default EsqueciSenhaPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, ChevronDown, ChevronUp, Save, CheckCircle, Circle } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";
import { useFiscal } from "@/hooks/useFiscal";
import { FiscalRecord, GuiaStatus } from "@/types/fiscal";
import { PageHeaderSkeleton, TableSkeleton } from "@/components/PageSkeleton";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const regimeLabels: Record<string, string> = { simples: "Simples Nacional", lucro_presumido: "Lucro Presumido", lucro_real: "Lucro Real", mei: "MEI" };

const FiscalPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("fiscal");
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");
  const [filterStatus, setFilterStatus] = useState<"todos" | "pendente" | "concluido">("todos");
  
  const { fiscalData, loading: fiscalLoading, saveFiscalRecord } = useFiscal(competencia);

  const filtered = React.useMemo(() => {
    return empresas.filter(e => {
      const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

      let matchTab = false;
      if (activeTab === "ativas") {
        matchTab = (e.situacao === "ativa" || !e.situacao) && e.porte_empresa !== "mei";
      } else if (activeTab === "mei") {
        matchTab = e.situacao === "mei" || ((e.situacao === "ativa" || !e.situacao) && e.porte_empresa === "mei");
      } else if (activeTab === "paralisadas") {
        matchTab = e.situacao === "paralisada";
      } else if (activeTab === "baixadas") {
        matchTab = e.situacao === "baixada";
      } else if (activeTab === "entregue") {
        matchTab = e.situacao === "entregue";
      }

      let matchStatus = true;
      if (filterStatus !== "todos") {
        const record = fiscalData[e.id];
        const items = e.regime_tributario === 'simples' ? ['status_guia'] : 
                      e.regime_tributario === 'lucro_presumido' || e.regime_tributario === 'lucro_real' ? 
                      ['irpj_csll_status', 'pis_cofins_status', 'icms_status', 'iss_status'] : [];
        
        if (items.length > 0) {
          const statuses = items.map(field => record?.[field as keyof FiscalRecord] || 'pendente');
          const isAllConcluido = statuses.every(s => s === 'enviada' || s === 'gerada' || s === 'isento');
          matchStatus = filterStatus === 'concluido' ? isAllConcluido : !isAllConcluido;
        } else {
          matchStatus = filterStatus === 'pendente';
        }
      }

      return matchSearch && matchTab && matchStatus;
    });
  }, [empresas, fiscalData, search, activeTab, filterStatus]);

  const toggleExpand = async (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const existing = (fiscalData[id] || {}) as Partial<FiscalRecord>;
    let fixedFields = {
      tipo_nota: "", recebimento_arquivos: "", aliquota: "", ramo_empresarial: "",
      aliquota_irpj: "", aliquota_csll: "", aliquota_pis: "", aliquota_cofins: "",
      aliquota_icms: "", aliquota_iss: "", aliquota_cbs: "", aliquota_ibs: ""
    };

    if (!existing.id) {
      const { data: prev } = await supabase.from("fiscal").select("*").eq("empresa_id", id).order("competencia", { ascending: false }).limit(1);
      if (prev?.[0]) {
        fixedFields = {
          tipo_nota: prev[0].tipo_nota || "", recebimento_arquivos: prev[0].recebimento_arquivos || "", aliquota: prev[0].aliquota?.toString() || "", ramo_empresarial: prev[0].ramo_empresarial || "",
          aliquota_irpj: prev[0].aliquota_irpj?.toString() || "", aliquota_csll: prev[0].aliquota_csll?.toString() || "",
          aliquota_pis: prev[0].aliquota_pis?.toString() || "", aliquota_cofins: prev[0].aliquota_cofins?.toString() || "",
          aliquota_icms: prev[0].aliquota_icms?.toString() || "", aliquota_iss: prev[0].aliquota_iss?.toString() || "",
          aliquota_cbs: prev[0].aliquota_cbs?.toString() || "", aliquota_ibs: prev[0].aliquota_ibs?.toString() || ""
        };
      }
    } else {
      fixedFields = {
        tipo_nota: existing.tipo_nota || "", recebimento_arquivos: existing.recebimento_arquivos || "", aliquota: existing.aliquota?.toString() || "", ramo_empresarial: existing.ramo_empresarial || "",
        aliquota_irpj: existing.aliquota_irpj?.toString() || "", aliquota_csll: existing.aliquota_csll?.toString() || "",
        aliquota_pis: existing.aliquota_pis?.toString() || "", aliquota_cofins: existing.aliquota_cofins?.toString() || "",
        aliquota_icms: existing.aliquota_icms?.toString() || "", aliquota_iss: existing.aliquota_iss?.toString() || "",
        aliquota_cbs: existing.aliquota_cbs?.toString() || "", aliquota_ibs: existing.aliquota_ibs?.toString() || ""
      };
    }

    setEditForm(prev => ({
      ...prev, [id]: {
        ...fixedFields, forma_envio: existing.forma_envio || "",
        status_guia: existing.status_guia || "pendente", data_envio: existing.data_envio || "",
        irpj_csll_status: existing.irpj_csll_status || "pendente", irpj_csll_data_envio: existing.irpj_csll_data_envio || "",
        pis_cofins_status: existing.pis_cofins_status || "pendente", pis_cofins_data_envio: existing.pis_cofins_data_envio || "",
        icms_status: existing.icms_status || "pendente", icms_data_envio: existing.icms_data_envio || "",
        iss_status: existing.iss_status || "pendente", iss_data_envio: existing.iss_data_envio || "",
        cbs_status: existing.cbs_status || "pendente", cbs_data_envio: existing.cbs_data_envio || "",
        ibs_status: existing.ibs_status || "pendente", ibs_data_envio: existing.ibs_data_envio || "",
        observacoes: existing.observacoes || {},
      }
    }));
  };

  const handleSave = async (empresaId: string) => {
    const form = (editForm[empresaId] || {}) as Partial<FiscalRecord> & Record<string, any>;
    const existing = (fiscalData[empresaId] || {}) as Partial<FiscalRecord>;
    try {
      const payload = {
        empresa_id: empresaId, competencia, tipo_nota: form.tipo_nota || null,
        recebimento_arquivos: form.recebimento_arquivos || null, forma_envio: form.forma_envio || null,
        aliquota: form.aliquota ? parseFloat(String(form.aliquota)) : null,
        status_guia: form.status_guia || "pendente", data_envio: form.data_envio || null,
        observacoes: form.observacoes || {}, ramo_empresarial: form.ramo_empresarial || null,

        aliquota_irpj: form.aliquota_irpj ? parseFloat(String(form.aliquota_irpj)) : null,
        aliquota_csll: form.aliquota_csll ? parseFloat(String(form.aliquota_csll)) : null,
        irpj_csll_status: form.irpj_csll_status || "pendente",
        irpj_csll_data_envio: form.irpj_csll_data_envio || null,

        aliquota_pis: form.aliquota_pis ? parseFloat(String(form.aliquota_pis)) : null,
        aliquota_cofins: form.aliquota_cofins ? parseFloat(String(form.aliquota_cofins)) : null,
        pis_cofins_status: form.pis_cofins_status || "pendente",
        pis_cofins_data_envio: form.pis_cofins_data_envio || null,

        aliquota_icms: form.aliquota_icms ? parseFloat(String(form.aliquota_icms)) : null,
        icms_status: form.icms_status || "pendente",
        icms_data_envio: form.icms_data_envio || null,

        aliquota_iss: form.aliquota_iss ? parseFloat(String(form.aliquota_iss)) : null,
        iss_status: form.iss_status || "pendente",
        iss_data_envio: form.iss_data_envio || null,

        aliquota_cbs: form.aliquota_cbs ? parseFloat(String(form.aliquota_cbs)) : null,
        cbs_status: form.cbs_status || "pendente",
        cbs_data_envio: form.cbs_data_envio || null,

        aliquota_ibs: form.aliquota_ibs ? parseFloat(String(form.aliquota_ibs)) : null,
        ibs_status: form.ibs_status || "pendente",
        ibs_data_envio: form.ibs_data_envio || null,
      };
      const success = await saveFiscalRecord(payload);
      if (success) {
        toast.success("Dados salvos com sucesso!");
        setExpanded(null);
      }
    } catch (err: any) { toast.error(err.message); }
  };

  const updateForm = (empresaId: string, field: string, value: string | number | boolean | null | Record<string, any>) => {
    setEditForm(prev => ({ ...prev, [empresaId]: { ...prev[empresaId], [field]: value } }));
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  const completedCount = filtered.filter(e => {
    const record = fiscalData[e.id];
    if (!record) return false;
    if (e.regime_tributario === "lucro_real") {
      return (record.irpj_csll_status === "enviada" || record.irpj_csll_status === "gerada");
    }
    return (record.status_guia === "enviada" || record.status_guia === "gerada");
  }).length;

  if (loading || fiscalLoading) {
    return (
      <div className="space-y-6 animate-fade-in">
        <PageHeaderSkeleton />
        <TableSkeleton rows={8} />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex bg-card border border-border/60 rounded-xl shadow-sm overflow-hidden h-12">
          <div className="px-4 flex items-center gap-2 border-r border-border/60">
            <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Empresas</span>
            <span className="text-lg font-black text-primary">{filtered.length}</span>
          </div>
          <div className="px-4 flex items-center gap-2 border-r border-border/60">
            <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Concluídas</span>
            <span className="text-lg font-black text-emerald-500">{completedCount}</span>
          </div>
          <div className="px-4 flex items-center gap-2 bg-warning/5">
            <span className="text-[10px] text-warning font-bold uppercase tracking-wider">Pendentes</span>
            <span className="text-lg font-black text-warning">{filtered.length - completedCount}</span>
          </div>
        </div>
        <div className="flex flex-col sm:flex-row gap-3 w-full sm:w-auto items-center">
          <FavoriteToggleButton moduleId="fiscal" />
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
            <input
              type="text"
              placeholder="Buscar empresa..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9 pr-4 h-10 bg-card border border-border/60 rounded-xl focus:ring-2 focus:ring-primary outline-none text-[13px] w-full sm:w-56"
            />
          </div>
          <input
            type="month"
            value={competencia}
            onChange={(e) => setCompetencia(e.target.value)}
            className="px-4 h-10 bg-card border border-border/60 rounded-xl focus:ring-2 focus:ring-primary outline-none text-[13px] font-medium"
          />
        </div>

        <div className="flex bg-muted/50 p-1 rounded-lg self-end">
          <button 
            onClick={() => setFilterStatus("todos")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "todos" ? "bg-card text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Todos
          </button>
          <button 
            onClick={() => setFilterStatus("pendente")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "pendente" ? "bg-card text-orange-500 shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Pendentes
          </button>
          <button 
            onClick={() => setFilterStatus("concluido")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "concluido" ? "bg-card text-green-500 shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Concluídos
          </button>
        </div>
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "entregue"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("entregue")}
        >
          Empresas Entregues
        </button>
      </div>

      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const done = emp.regime_tributario === "lucro_real"
            ? (fiscalData[emp.id]?.irpj_csll_status === "enviada" || fiscalData[emp.id]?.irpj_csll_status === "gerada")
            : (fiscalData[emp.id]?.status_guia === "enviada" || fiscalData[emp.id]?.status_guia === "gerada");
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3">{done ? <CheckCircle size={18} className="text-success" /> : <Circle size={18} className="text-muted-foreground" />}<div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"} • {regimeLabels[emp.regime_tributario] || "—"}</p></div></div>
                <div className="flex items-center gap-2"><span className={`badge-status ${done ? "badge-success" : "badge-warning"}`}>{done ? "Concluído" : "Pendente"}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-5 bg-muted/10">
                  {/* Informações Iniciais Comuns */}
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div><label className={labelCls}>Tipo de Nota</label><input value={form.tipo_nota || ""} onChange={e => updateForm(emp.id, "tipo_nota", e.target.value)} className={inputCls} placeholder="NFE, NFCE, NFSE" /></div>
                    <div><label className={labelCls}>Recebimento de Arquivos</label><input value={form.recebimento_arquivos || ""} onChange={e => updateForm(emp.id, "recebimento_arquivos", e.target.value)} className={inputCls} placeholder="Ex: Email, WhatsApp..." /></div>
                    <div><label className={labelCls}>Forma de Envio</label><input value={form.forma_envio || ""} onChange={e => updateForm(emp.id, "forma_envio", e.target.value)} className={inputCls} placeholder="Ex: Email, WhatsApp..." /></div>
                    <div><label className={labelCls}>Ramo Empresarial</label><input value={form.ramo_empresarial || ""} onChange={e => updateForm(emp.id, "ramo_empresarial", e.target.value)} className={inputCls} placeholder="Ex: Comércio, Serviços..." /></div>
                  </div>

                  {emp.regime_tributario === "lucro_real" ? (
                    <div className="space-y-6">
                      {/* Impostos Federais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Federais</h4>

                        <div className="space-y-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">IRPJ / CSLL</p>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div><label className={labelCls}>Alíquota IRPJ (%)</label><input value={form.aliquota_irpj || ""} onChange={e => updateForm(emp.id, "aliquota_irpj", e.target.value)} className={inputCls} placeholder="Ex: 15" /></div>
                            <div><label className={labelCls}>Alíquota CSLL (%)</label><input value={form.aliquota_csll || ""} onChange={e => updateForm(emp.id, "aliquota_csll", e.target.value)} className={inputCls} placeholder="Ex: 9" /></div>
                            <div><label className={labelCls}>Status (IRPJ/CSLL)</label><select value={form.irpj_csll_status || "pendente"} onChange={e => updateForm(emp.id, "irpj_csll_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.irpj_csll_data_envio || ""} onChange={e => updateForm(emp.id, "irpj_csll_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>

                        <div className="space-y-2 pt-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">PIS / COFINS</p>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div><label className={labelCls}>Alíquota PIS (%)</label><input value={form.aliquota_pis || ""} onChange={e => updateForm(emp.id, "aliquota_pis", e.target.value)} className={inputCls} placeholder="Ex: 1.65" /></div>
                            <div><label className={labelCls}>Alíquota COFINS (%)</label><input value={form.aliquota_cofins || ""} onChange={e => updateForm(emp.id, "aliquota_cofins", e.target.value)} className={inputCls} placeholder="Ex: 7.6" /></div>
                            <div><label className={labelCls}>Status (PIS/COFINS)</label><select value={form.pis_cofins_status || "pendente"} onChange={e => updateForm(emp.id, "pis_cofins_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.pis_cofins_data_envio || ""} onChange={e => updateForm(emp.id, "pis_cofins_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                      </div>

                      {/* Impostos Estaduais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Estaduais (ICMS)</h4>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div><label className={labelCls}>Alíquota ICMS (%)</label><input value={form.aliquota_icms || ""} onChange={e => updateForm(emp.id, "aliquota_icms", e.target.value)} className={inputCls} placeholder="Ex: 18" /></div>
                          <div><label className={labelCls}>Status da Guia</label><select value={form.icms_status || "pendente"} onChange={e => updateForm(emp.id, "icms_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                          <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.icms_data_envio || ""} onChange={e => updateForm(emp.id, "icms_data_envio", e.target.value)} className={inputCls} /></div>
                        </div>
                      </div>

                      {/* Impostos Municipais */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Impostos Municipais (ISS)</h4>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div><label className={labelCls}>Alíquota ISS (%)</label><input value={form.aliquota_iss || ""} onChange={e => updateForm(emp.id, "aliquota_iss", e.target.value)} className={inputCls} placeholder="Ex: 5" /></div>
                          <div><label className={labelCls}>Status da Guia</label><select value={form.iss_status || "pendente"} onChange={e => updateForm(emp.id, "iss_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                          <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.iss_data_envio || ""} onChange={e => updateForm(emp.id, "iss_data_envio", e.target.value)} className={inputCls} /></div>
                        </div>
                      </div>

                      {/* Reforma Tributária */}
                      <div className="bg-card p-4 rounded-xl border border-border shadow-sm space-y-4">
                        <h4 className="text-sm font-bold text-foreground border-b border-border pb-2">Reforma Tributária</h4>
                        <div className="space-y-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">Federal (CBS)</p>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div><label className={labelCls}>Alíquota CBS (%)</label><input value={form.aliquota_cbs || ""} onChange={e => updateForm(emp.id, "aliquota_cbs", e.target.value)} className={inputCls} placeholder="Ex: 8.8" /></div>
                            <div><label className={labelCls}>Status da Guia</label><select value={form.cbs_status || "pendente"} onChange={e => updateForm(emp.id, "cbs_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.cbs_data_envio || ""} onChange={e => updateForm(emp.id, "cbs_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                        <div className="space-y-2 pt-2">
                          <p className="text-xs font-semibold text-muted-foreground uppercase">Estadual/Municipal (IBS)</p>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div><label className={labelCls}>Alíquota IBS (%)</label><input value={form.aliquota_ibs || ""} onChange={e => updateForm(emp.id, "aliquota_ibs", e.target.value)} className={inputCls} placeholder="Ex: 17.7" /></div>
                            <div><label className={labelCls}>Status da Guia</label><select value={form.ibs_status || "pendente"} onChange={e => updateForm(emp.id, "ibs_status", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                            <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.ibs_data_envio || ""} onChange={e => updateForm(emp.id, "ibs_data_envio", e.target.value)} className={inputCls} /></div>
                          </div>
                        </div>
                      </div>

                    </div>
                  ) : (
                    <div className="bg-card p-4 rounded-xl border border-border shadow-sm">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div><label className={labelCls}>Alíquota Geral Única (%)</label><input value={form.aliquota || ""} onChange={e => updateForm(emp.id, "aliquota", e.target.value)} className={inputCls} placeholder="Ex: 6" /></div>
                        <div><label className={labelCls}>Status da Guia Única</label><select value={form.status_guia || "pendente"} onChange={e => updateForm(emp.id, "status_guia", e.target.value)} className={inputCls}><option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option></select></div>
                        <div><label className={labelCls}>Data de Envio</label><input type="date" value={form.data_envio || ""} onChange={e => updateForm(emp.id, "data_envio", e.target.value)} className={inputCls} /></div>
                      </div>
                    </div>
                  )}

                  <div className="flex justify-end pt-2"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md hover:brightness-110 transition-all" style={{ background: "var(--gradient-primary)" }}><Save size={16} /> Salvar Alterações</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default FiscalPage;

import React, { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Bell, Mail, Clock, Shield, Plus, ArrowRight, Trash2, CalendarDays, X } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";


interface AlertType {
  id: string;
  label: string;
  description: string;
  is_enabled: boolean;
}

interface NotificationRule {
  id: string;
  module_id: string;
  trigger_name: string;
  days_before: number;
  is_active: boolean;
}

const moduleLabels: Record<string, string> = {
  licencas: "Licenças",
  certificados: "Certificados Digitais",
  procuracoes: "Procurações",
  certidoes: "Certidões",
  vencimentos: "Vencimentos",
};

const GestorAlertasPage: React.FC = () => {
  const [alertTypes, setAlertTypes] = useState<AlertType[]>([]);
  const [rules, setRules] = useState<NotificationRule[]>([]);
  const [loading, setLoading] = useState(true);
  const [triggerLoading, setTriggerLoading] = useState(false);
  const [testMode, setTestMode] = useState(false);
  const [showAddRule, setShowAddRule] = useState(false);
  const [newRule, setNewRule] = useState({ module_id: "licencas", trigger_name: "", days_before: 7 });


  const fetchAlertTypes = async () => {
    try {
      const { data, error } = await supabase.from("notification_types").select("*");
      if (error) throw error;
      setAlertTypes((data as AlertType[]) || []);
    } catch (err: any) {
      console.error(err);
    }
  };

  const fetchRules = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from("notification_rules" as any)
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw error;
      setRules((data as unknown as NotificationRule[]) || []);
    } catch (err: any) {
      toast.error("Erro ao carregar regras de alertas.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAlertTypes();
    fetchRules();
  }, []);

  const toggleAlertType = async (id: string, current: boolean) => {
    try {
      await supabase.from("notification_types").update({ is_enabled: !current }).eq("id", id);
      toast.success("Status atualizado!");
      fetchAlertTypes();
    } catch (err) {
      toast.error("Erro ao atualizar status");
    }
  };

  const toggleRuleStatus = async (id: string, current: boolean) => {
    try {
      await supabase.from("notification_rules" as any).update({ is_active: !current }).eq("id", id);
      toast.success("Regra atualizada!");
      fetchRules();
    } catch (err) {
      toast.error("Erro ao atualizar regra");
    }
  };

  const deleteRule = async (id: string) => {
    if (!window.confirm("Deseja excluir esta regra de disparo?")) return;
    try {
      await supabase.from("notification_rules" as any).delete().eq("id", id);
      toast.success("Regra excluída!");
      fetchRules();
    } catch (err) {
      toast.error("Erro ao excluir regra");
    }
  };

  const handleAddRule = async () => {
    if (!newRule.trigger_name) {
      toast.error("Digite o nome do gatilho");
      return;
    }
    try {
      const { error } = await supabase.from("notification_rules" as any).insert([newRule]);
      if (error) throw error;
      toast.success("Nova regra adicionada!");
      setShowAddRule(false);
      setNewRule({ module_id: "licencas", trigger_name: "", days_before: 7 });
      fetchRules();
    } catch (err) {
      toast.error("Erro ao adicionar regra");
    }
  };


  const handleManualTrigger = async () => {
    try {
      setTriggerLoading(true);
      const { data, error } = await supabase.functions.invoke('send-alert-email', {
        body: { test: testMode }
      });

      if (error) throw error;

      console.log('Edge Function Response:', data);

      let debugInfo = data.debug
        ? `\n(Docs: ${data.debug.expirationsFound}, Acessos: ${data.debug.accessRowsFound})`
        : '';

      if (data.failCount > 0 && data.debug?.errors?.length > 0) {
        const firstErrorDetails = data.debug.errors[0].error;
        const errorMsg = firstErrorDetails?.message || firstErrorDetails?.name || JSON.stringify(firstErrorDetails);
        debugInfo += `\nFalhas: ${data.failCount}. Motivo: ${errorMsg}`;
      }

      const toastFn = data.successCount > 0 ? toast.success : (data.failCount > 0 ? toast.error : toast.success);

      toastFn(
        `Disparo concluído! ${data.companiesNotified || 0} empresas e ${data.usersNotified || 0} usuários notificados.${debugInfo}`,
        { duration: 10000 }
      );
    } catch (err: any) {
      toast.error(`Erro ao disparar alertas: ${err.message || 'Erro desconhecido'}`);
      console.error(err);
    } finally {
      setTriggerLoading(false);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
        <div>
          <h1 className="header-title text-3xl font-black tracking-tight text-foreground flex items-center gap-3">
            <Bell className="text-primary" size={28} /> Gestor de Alertas
          </h1>
          <p className="text-muted-foreground mt-1">
            Configure disparos automáticos de e-mails para os clientes do portal.
          </p>
        </div>
        <button
          className="button-premium"
          onClick={() => setShowAddRule(!showAddRule)}
        >
          {showAddRule ? <X size={18} /> : <Plus size={18} />}
          {showAddRule ? "Cancelar" : "Nova Regra de Disparo"}
        </button>
      </div>


      {showAddRule && (
        <div className="card-premium p-6 animate-scale-in border-primary/30">
          <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
            <Plus className="text-primary" size={20} /> Adicionar Nova Regra
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-muted-foreground uppercase">Módulo</label>
              <select
                className="w-full px-3 py-2 rounded-xl bg-background border border-border focus:ring-2 focus:ring-primary outline-none text-sm"
                value={newRule.module_id}
                onChange={(e) => setNewRule({ ...newRule, module_id: e.target.value })}
              >
                {Object.entries(moduleLabels).map(([id, label]) => (
                  <option key={id} value={id}>{label}</option>
                ))}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-muted-foreground uppercase">Gatilho (Nome do Documento/Evento)</label>
              <input
                type="text"
                placeholder="Ex: Alvará, e-CNPJ..."
                className="w-full px-3 py-2 rounded-xl bg-background border border-border focus:ring-2 focus:ring-primary outline-none text-sm"
                value={newRule.trigger_name}
                onChange={(e) => setNewRule({ ...newRule, trigger_name: e.target.value })}
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-muted-foreground uppercase">Disparar antes (Dias)</label>
              <input
                type="number"
                className="w-full px-3 py-2 rounded-xl bg-background border border-border focus:ring-2 focus:ring-primary outline-none text-sm"
                value={newRule.days_before}
                onChange={(e) => setNewRule({ ...newRule, days_before: parseInt(e.target.value) })}
              />
            </div>
          </div>
          <div className="mt-6 flex justify-end">
            <button className="button-premium" onClick={handleAddRule}>
              Confirmar Regra
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Painel Principal */}
        <div className="lg:col-span-2 space-y-6">
          <div className="card-premium p-6">
            <h2 className="text-lg font-bold flex items-center gap-2 mb-6">
              <CalendarDays className="text-primary" size={20} /> Regras de Disparo Ativas
            </h2>

            <div className="space-y-4">
              {loading ? (
                <div className="flex items-center justify-center p-12">
                  <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
                </div>
              ) : rules.length === 0 ? (
                <div className="text-center py-12 bg-muted/10 rounded-2xl border border-dashed border-border">
                  <p className="text-muted-foreground">Nenhuma regra configurada ainda.</p>
                </div>
              ) : rules.map((rule) => (
                <div key={rule.id} className={`flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 rounded-xl border transition-colors ${rule.is_active ? "border-border/50 bg-muted/20 hover:bg-muted/40" : "border-border/30 bg-muted/5 opacity-60"}`}>
                  <div className="flex items-start gap-4">
                    <div
                      className={`p-2.5 rounded-lg border flex items-center justify-center shrink-0 cursor-pointer transition-colors ${rule.is_active ? "bg-background border-border text-primary" : "bg-muted border-transparent text-muted-foreground"}`}
                      onClick={() => toggleRuleStatus(rule.id, rule.is_active)}
                    >
                      <Clock size={20} />
                    </div>
                    <div>
                      <p className="font-bold text-foreground text-sm uppercase tracking-tight">{rule.trigger_name}</p>
                      <p className="text-xs text-muted-foreground mt-0.5">Módulo: {moduleLabels[rule.module_id] || rule.module_id}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-6 justify-between sm:justify-end border-t sm:border-0 pt-3 sm:pt-0 mt-3 sm:mt-0 border-border/50">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Disparo:</span>
                      <span className="text-sm font-black text-primary bg-primary/10 px-2 py-0.5 rounded-md">
                        {rule.days_before} dias antes
                      </span>
                    </div>

                    <div className="flex items-center gap-3">
                      <div className="w-px h-6 bg-border/50 hidden sm:block" />
                      <button
                        className="p-2 text-muted-foreground hover:text-destructive transition-colors"
                        onClick={() => deleteRule(rule.id)}
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

          </div>
        </div>

        {/* Sidebar Direita: Categorias Nativas */}
        <div className="space-y-6">
          <div className="card-premium p-6">
            <h2 className="text-lg font-bold flex items-center gap-2 mb-4">
              <Shield className="text-primary" size={20} /> Módulos Habilitados
            </h2>
            <p className="text-xs text-muted-foreground mb-6">
              Estes são os módulos internos do sistema que atualmente suportam o rastreio de notificações visuais.
            </p>

            <div className="space-y-3">
              {loading ? (
                <div className="flex items-center justify-center p-6">
                  <div className="w-6 h-6 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                </div>
              ) : alertTypes.map((type) => (
                <div key={type.id} className="flex items-center justify-between p-3 rounded-xl border border-border/50 bg-background">
                  <div>
                    <p className="text-sm font-bold text-foreground">{type.label}</p>
                  </div>
                  <button
                    onClick={() => toggleAlertType(type.id, type.is_enabled)}
                    className={`w-10 h-6 rounded-full transition-colors relative shrink-0 ${type.is_enabled ? "bg-primary" : "bg-muted-foreground/30"
                      }`}
                  >
                    <div
                      className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${type.is_enabled ? "left-5" : "left-1"
                        }`}
                    />
                  </button>
                </div>
              ))}
            </div>
          </div>

          <div className="card-premium p-6 bg-gradient-to-br from-background to-muted/30 border-primary/20">
            <div className="flex items-center justify-between p-3 mb-4 rounded-xl border border-primary/20 bg-primary/5">
              <div className="flex flex-col">
                <span className="text-xs font-bold text-primary">Modo de Teste (Forçar Todos)</span>
                <span className="text-[10px] text-muted-foreground italic">Ignora filtros de datas (envia tudo dos próximos 30 dias)</span>
              </div>
              <button
                onClick={() => setTestMode(!testMode)}
                className={`w-10 h-6 rounded-full transition-colors relative shrink-0 ${testMode ? "bg-primary" : "bg-muted-foreground/30"
                  }`}
              >
                <div
                  className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${testMode ? "left-5" : "left-1"
                    }`}
                />
              </button>
            </div>

            <button
              onClick={handleManualTrigger}
              disabled={triggerLoading}
              className={`w-full py-2.5 text-xs font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${triggerLoading
                  ? "bg-muted text-muted-foreground cursor-not-allowed"
                  : "bg-primary text-white hover:scale-[1.02] shadow-lg shadow-primary/20"
                }`}
            >
              {triggerLoading ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <Mail size={14} />
              )}
              {triggerLoading ? "Processando..." : (testMode ? "Disparar TESTE Agora" : "Disparar Alertas Agora")}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GestorAlertasPage;

import React, { useEffect, useState, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search } from "lucide-react";
import { toast } from "sonner";
import { useHonorarios } from "@/hooks/useHonorarios";
import { useSocietario } from "@/hooks/useSocietario";
import { useAuth } from "@/contexts/AuthContext";
import { HonorariosGeralView } from "@/components/honorarios/HonorariosGeralView";
import { HonorariosEmpresasView } from "@/components/honorarios/HonorariosEmpresasView";
import { HonorarioConfig, HonorarioMensal, ServicoEsporadico } from "@/types/honorarios";
import { Empresa } from "@/types/societario";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const HonorariosPage: React.FC = () => {
  const { user } = useAuth();
  const { getPaginatedEmpresas } = useSocietario();
  const [search, setSearch] = useState("");
  const [mainTab, setMainTab] = useState<"empresas" | "geral">("empresas");
  const [globalCompetencia, setGlobalCompetencia] = useState(new Date().toISOString().slice(0, 7));
  
  const { 
    listGeral, listEsporadicos, revenueTrend, loading: loadingHonorarios,
    saveConfig, saveMensal, saveEsporadico, deleteEsporadico 
  } = useHonorarios(globalCompetencia);

  const [expanded, setExpanded] = useState<string | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<string, "mensal" | "configuracao">>({});
  const [activeStatusTab, setActiveStatusTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");

  const [pagination, setPagination] = useState({ pageIndex: 0, pageSize: 12 });
  const [paginatedData, setPaginatedData] = useState<Empresa[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loadingPaginated, setLoadingPaginated] = useState(false);

  const [configs, setConfigs] = useState<Record<string, Partial<HonorarioConfig>>>({});
  const [mensalData, setMensalData] = useState<Record<string, HonorarioMensal[]>>({});
  const [configForms, setConfigForms] = useState<Record<string, Partial<HonorarioConfig>>>({});
  const [mensalForms, setMensalForms] = useState<Record<string, Partial<HonorarioMensal>>>({});
  const [competenciaSelecionada, setCompetenciaSelecionada] = useState<Record<string, string>>({});
  const [todasEmpresas, setTodasEmpresas] = useState<Empresa[]>([]);

  useEffect(() => {
    if (mainTab === 'geral' && todasEmpresas.length === 0) {
      const fetchAll = async () => {
        const { data } = await supabase.from("empresas").select("*").order("nome_empresa");
        setTodasEmpresas((data as Empresa[]) || []);
      };
      fetchAll();
    }
  }, [mainTab, todasEmpresas.length]);

  const loadPaginatedData = useCallback(async () => {
    setLoadingPaginated(true);
    try {
      const { data, count } = await getPaginatedEmpresas(
        pagination.pageIndex,
        pagination.pageSize,
        search,
        activeStatusTab,
        "todos",
        "honorarios",
        user?.id
      );
      setPaginatedData(data);
      setTotalCount(count);
    } catch (err) {
      console.error("Erro ao carregar empresas paginadas:", err);
    } finally {
      setLoadingPaginated(false);
    }
  }, [pagination.pageIndex, pagination.pageSize, search, activeStatusTab, user?.id, getPaginatedEmpresas]);

  useEffect(() => {
    loadPaginatedData();
  }, [loadPaginatedData]);

  useEffect(() => {
    setPagination(prev => ({ ...prev, pageIndex: 0 }));
  }, [search, activeStatusTab]);

  const toggleExpand = async (empresaId: string) => {
    if (expanded === empresaId) {
      setExpanded(null);
      return;
    }
    setExpanded(empresaId);
    if (!activeTabs[empresaId]) setActiveTabs(prev => ({ ...prev, [empresaId]: "mensal" }));
    if (!competenciaSelecionada[empresaId]) setCompetenciaSelecionada(prev => ({ ...prev, [empresaId]: new Date().toISOString().slice(0, 7) }));
    
    // Load local data for the company
    const { data: config } = await supabase.from("honorarios_config").select("*").eq("empresa_id", empresaId).maybeSingle();
    const finalConfig: Partial<HonorarioConfig> = (config as unknown as Partial<HonorarioConfig>) || { empresa_id: empresaId, valor_honorario: 0, valor_por_funcionario: 0, valor_por_recalculo: 0, valor_trabalhista: 0, outros_servicos: [] };
    setConfigs(prev => ({ ...prev, [empresaId]: finalConfig }));
    setConfigForms(prev => ({ ...prev, [empresaId]: { ...finalConfig } }));

    const { data: mensal } = await supabase.from("honorarios_mensal").select("*").eq("empresa_id", empresaId).order('competencia', { ascending: false });
    setMensalData(prev => ({ ...prev, [empresaId]: (mensal as unknown as HonorarioMensal[]) || [] }));
  };

  const parseCurrency = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    const str = String(val);
    if (str.includes(',')) return parseFloat(str.replace(/\./g, "").replace(",", ".")) || 0;
    return parseFloat(str) || 0;
  };

  const calculateTotal = (config: Partial<HonorarioConfig>, qtdFunc: number, qtdRecalculos: number, teveTrabalhista: boolean, qtdRecibos: number) => {
    const honorario = Number(config?.valor_honorario || 0);
    const funcVlr = Number(config?.valor_por_funcionario || 0) * qtdFunc;
    const recVlr = Number(config?.valor_por_recalculo || 0) * qtdRecalculos;
    const trabVlr = teveTrabalhista ? Number(config?.valor_trabalhista || 0) : 0;
    const reciboVlr = Number(config?.valor_por_recibo || 0) * qtdRecibos;
    const outrosVlr = (config?.outros_servicos || []).reduce((sum: number, item: any) => sum + Number(item.valor || 0), 0);

    const detalhes = [
      { rotulo: "Honorário Base", qtd: 1, vlrUnit: honorario, vlrTotal: honorario },
      ...(qtdFunc > 0 ? [{ rotulo: "Funcionários/Pró-labore", qtd: qtdFunc, vlrUnit: Number(config?.valor_por_funcionario || 0), vlrTotal: funcVlr }] : []),
      ...(qtdRecalculos > 0 ? [{ rotulo: "Recálculos", qtd: qtdRecalculos, vlrUnit: Number(config?.valor_por_recalculo || 0), vlrTotal: recVlr }] : []),
      ...(teveTrabalhista ? [{ rotulo: "Encargos Trabalhistas", qtd: 1, vlrUnit: Number(config?.valor_trabalhista || 0), vlrTotal: trabVlr }] : []),
      ...(qtdRecibos > 0 ? [{ rotulo: "Recibos (Pessoal)", qtd: qtdRecibos, vlrUnit: Number(config?.valor_por_recibo || 0), vlrTotal: reciboVlr }] : []),
      ...(config?.outros_servicos || []).map((s: any) => ({ rotulo: s.descricao || "Serviço Adicional", qtd: 1, vlrUnit: Number(s.valor || 0), vlrTotal: Number(s.valor || 0) }))
    ];

    return { total: honorario + funcVlr + recVlr + trabVlr + reciboVlr + outrosVlr, detalhes };
  };

  const handleGenerateMonth = async (empresaId: string, compOverride?: string) => {
    const comp = compOverride || competenciaSelecionada[empresaId];
    if (!comp) return;
    try {
      const config = configs[empresaId];
      if (!config || typeof config.valor_honorario === 'undefined') {
        toast.error("Configure os valores base primeiro na aba Configuração");
        return;
      }
      const { data: pessoalData } = await supabase.from("pessoal").select("*").eq("empresa_id", empresaId).eq("competencia", comp).maybeSingle();
      const qtdFunc = (pessoalData?.qtd_funcionarios || 0) + (pessoalData?.qtd_pro_labore || 0);
      const qtdRecibos = (pessoalData?.qtd_recibos || 0);
      const teveTrabalhista = pessoalData?.possui_vt || pessoalData?.possui_va || pessoalData?.possui_vc;
      const { count: qtdRecalculos } = await supabase.from("recalculos").select("*", { count: 'exact', head: true }).eq("empresa_id", empresaId).eq("competencia", comp);

      const { total: valorTotal, detalhes } = calculateTotal(config, qtdFunc, (qtdRecalculos as number) || 0, teveTrabalhista || false, qtdRecibos);

      setMensalForms(prev => ({
        ...prev, [empresaId]: {
          competencia: comp, qtd_funcionarios: qtdFunc, qtd_recalculos: (qtdRecalculos as number) || 0,
          qtd_recibos: qtdRecibos,
          teve_encargo_trabalhista: teveTrabalhista || false, valor_total: valorTotal,
          detalhes_calculo: detalhes, empresa_id: empresaId,
          data_vencimento: "", data_envio: "", forma_envio: "", status: "pendente", pago: false, observacoes: { texto: "" }
        }
      }));
    } catch (err: any) { toast.error("Erro ao gerar mês: " + err.message); }
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";

  if (loadingPaginated && paginatedData.length === 0) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full sm:w-auto">
          <FavoriteToggleButton moduleId="honorarios" />
          <div>
            <h2 className="text-lg font-bold text-card-foreground">Honorários Extras</h2>
            <p className="text-xs text-muted-foreground">Gestão de honorários e faturamento.</p>
          </div>
        </div>
        <div className="flex bg-muted/30 p-1 rounded-xl w-full sm:w-fit">
        <button
          className={`flex-1 sm:flex-none uppercase tracking-wider text-xs font-bold px-6 py-2.5 rounded-lg transition-all duration-200 ${mainTab === "empresas" ? "bg-background text-primary shadow-sm ring-1 ring-border" : "text-muted-foreground hover:text-foreground"}`}
          onClick={() => setMainTab("empresas")}
        >
          Painel de Empresas
        </button>
        <button
          className={`flex-1 sm:flex-none uppercase tracking-wider text-xs font-bold px-6 py-2.5 rounded-lg transition-all duration-200 ${mainTab === "geral" ? "bg-background text-primary shadow-sm ring-1 ring-border" : "text-muted-foreground hover:text-foreground"}`}
          onClick={() => setMainTab("geral")}
        >
          Controle Geral (Resumo)
        </button>
      </div>
      </div>

      {mainTab === "geral" ? (
        <HonorariosGeralView 
          geralData={listGeral}
          esporadicosData={listEsporadicos}
          revenueTrend={revenueTrend}
          todasEmpresas={todasEmpresas as any}
          globalCompetencia={globalCompetencia}
          setGlobalCompetencia={setGlobalCompetencia}
          onToggleMensalPago={(id, current) => saveMensal.mutate({ id, pago: !current })}
          onToggleMensalStatus={(id, current) => saveMensal.mutate({ id, status: current === "enviada" ? "gerada" : "enviada" })}
          onToggleEsporadicoPago={(id, current) => saveEsporadico.mutate({ id, pago: !current } as ServicoEsporadico)}
          onDeleteEsporadico={(id) => deleteEsporadico.mutate(id)}
          onSaveEsporadico={(data) => saveEsporadico.mutate({ ...data, competencia: globalCompetencia } as ServicoEsporadico)}
          onActionGerar={async (empresaId) => {
            // 1. Identify correct sub-tab for the company
            const empresa = todasEmpresas.find(e => e.id === empresaId);
            if (empresa) {
              if (empresa.situacao === "paralisada") setActiveStatusTab("paralisadas");
              else if (empresa.situacao === "baixada") setActiveStatusTab("baixadas");
              else if (empresa.porte_empresa === "mei") setActiveStatusTab("mei");
              else setActiveStatusTab("ativas");
            }

            // 2. Switch tab and expand
            setMainTab("empresas");
            setExpanded(empresaId);
            setActiveTabs(prev => ({ ...prev, [empresaId]: "mensal" }));
            setCompetenciaSelecionada(prev => ({ ...prev, [empresaId]: globalCompetencia }));
            
            // 3. Load config and generate (mimic toggleExpand + handleGenerateMonth)
            const { data: config } = await supabase.from("honorarios_config").select("*").eq("empresa_id", empresaId).maybeSingle();
            const finalConfig: Partial<HonorarioConfig> = (config as unknown as Partial<HonorarioConfig>) || { empresa_id: empresaId, valor_honorario: 0, valor_por_funcionario: 0, valor_por_recalculo: 0, valor_trabalhista: 0, outros_servicos: [] };
            
            setConfigs(prev => ({ ...prev, [empresaId]: finalConfig }));
            setConfigForms(prev => ({ ...prev, [empresaId]: { ...finalConfig } }));

            const { data: mensal } = await supabase.from("honorarios_mensal").select("*").eq("empresa_id", empresaId).order('competencia', { ascending: false });
            setMensalData(prev => ({ ...prev, [empresaId]: (mensal as unknown as HonorarioMensal[]) || [] }));

            // 4. Trigger generation with the loaded config
            const { data: pessoalData } = await supabase.from("pessoal").select("*").eq("empresa_id", empresaId).eq("competencia", globalCompetencia).maybeSingle();
            const qtdFunc = (pessoalData?.qtd_funcionarios || 0) + (pessoalData?.qtd_pro_labore || 0);
            const qtdRecibos = (pessoalData?.qtd_recibos || 0);
            const teveTrabalhista = pessoalData?.possui_vt || pessoalData?.possui_va || pessoalData?.possui_vc;
            const { count: qtdRecalculos } = await supabase.from("recalculos").select("*", { count: 'exact', head: true }).eq("empresa_id", empresaId).eq("competencia", globalCompetencia);

            const { total: valorTotal, detalhes } = calculateTotal(finalConfig, qtdFunc, (qtdRecalculos as number) || 0, teveTrabalhista || false, qtdRecibos);

            setMensalForms(prev => ({
              ...prev, [empresaId]: {
                competencia: globalCompetencia,
                qtd_funcionarios: qtdFunc,
                qtd_recalculos: (qtdRecalculos as number) || 0,
                qtd_recibos: qtdRecibos,
                teve_encargo_trabalhista: teveTrabalhista || false,
                valor_total: valorTotal,
                detalhes_calculo: detalhes,
                empresa_id: empresaId,
                data_vencimento: "", data_envio: "", forma_envio: "", status: "pendente", pago: false, observacoes: { texto: "" }
              }
            }));

            window.scrollTo({ top: 0, behavior: 'smooth' });
          }}
          onUpdateValor={(id, val) => saveMensal.mutate({ id, valor_total: val })}
        />
      ) : (
        <div className="space-y-4 animate-fade-in">
          <div className="flex border-b border-border overflow-x-auto no-scrollbar">
            {["ativas", "mei", "paralisadas", "baixadas", "entregue"].map(t => (
              <button
                key={t}
                className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === t ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                onClick={() => setActiveStatusTab(t as any)}
              >
                {t === "ativas" ? "Empresas Ativas" : t === "mei" ? "Empresas MEI" : t === "paralisadas" ? "Empresas Paralisadas" : t === "entregue" ? "Empresas Entregues" : "Empresas Baixadas"}
              </button>
            ))}
          </div>

          <div className="relative max-w-sm">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
            <input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className={inputCls + " pl-9"} />
          </div>

          <HonorariosEmpresasView 
            empresas={paginatedData as any}
            expanded={expanded}
            onToggleExpand={toggleExpand}
            activeTabs={activeTabs}
            setActiveTab={(id, tab) => setActiveTabs(prev => ({ ...prev, [id]: tab }))}
            configs={configs}
            configForms={configForms}
            onUpdateConfigField={(id, f, v) => setConfigForms(prev => ({ ...prev, [id]: { ...prev[id], [f]: v } }))}
            onAddOutroServico={(id) => setConfigForms(prev => ({ ...prev, [id]: { ...prev[id], outros_servicos: [...(prev[id]?.outros_servicos || []), { descricao: "", valor: 0 }] } }))}
            onUpdateOutroServico={(id, idx, f, v) => setConfigForms(prev => {
              const outros = [...(prev[id]?.outros_servicos || [])];
              outros[idx] = { ...outros[idx], [f]: v };
              return { ...prev, [id]: { ...prev[id], outros_servicos: outros } };
            })}
            onRemoveOutroServico={(id, idx) => setConfigForms(prev => {
              const outros = [...(prev[id]?.outros_servicos || [])];
              outros.splice(idx, 1);
              return { ...prev, [id]: { ...prev[id], outros_servicos: outros } };
            })}
            onSaveConfig={(id) => {
              const form = configForms[id];
              const finalizedFields = {
                valor_honorario: parseCurrency(form?.valor_honorario),
                valor_por_funcionario: parseCurrency(form?.valor_por_funcionario),
                valor_por_recalculo: parseCurrency(form?.valor_por_recalculo),
                valor_trabalhista: parseCurrency(form?.valor_trabalhista),
                valor_por_recibo: parseCurrency(form?.valor_por_recibo),
                outros_servicos: (form?.outros_servicos || []).map((s: any) => ({ ...s, valor: parseCurrency(s.valor) }))
              };
              const payload = { ...form, ...finalizedFields };
              
              saveConfig.mutate(payload as any, {
                onSuccess: () => {
                  setConfigs(prev => ({ ...prev, [id]: payload }));
                }
              });
            }}
            mensalData={mensalData}
            mensalForms={mensalForms as any}
            onUpdateMensalField={(id, f, v) => setMensalForms(prev => ({ ...prev, [id]: { ...prev[id], [f]: v } }))}
            onSaveMensal={async (id) => {
              const form = mensalForms[id];
              await saveMensal.mutateAsync({
                ...form,
                data_vencimento: form?.data_vencimento || null,
                data_envio: form?.data_envio || null,
                observacoes: form?.observacoes ? { texto: typeof form.observacoes === 'string' ? form.observacoes : form.observacoes.texto } : null
              } as any);
              setMensalForms(prev => { const n = { ...prev }; delete n[id]; return n; });
              const { data: mensal } = await supabase.from("honorarios_mensal").select("*").eq("empresa_id", id).order('competencia', { ascending: false });
              setMensalData(prev => ({ ...prev, [id]: (mensal as unknown as HonorarioMensal[]) || [] }));
            }}
            onGenerateMonth={handleGenerateMonth}
            onStartEditMensal={(id, record) => {
              setCompetenciaSelecionada(prev => ({ ...prev, [id]: record.competencia }));
              setMensalForms(prev => ({ ...prev, [id]: { ...record, observacoes: { texto: record.observacoes?.texto || "" } } }));
            }}
            competenciaSelecionada={competenciaSelecionada}
            setCompetenciaSelecionada={(id, v) => setCompetenciaSelecionada(prev => ({ ...prev, [id]: v }))}
            onCancelMensalForm={(id) => setMensalForms(prev => { const n = { ...prev }; delete n[id]; return n; })}
            pagination={pagination}
            onPageChange={(page) => setPagination(prev => ({ ...prev, pageIndex: page }))}
            totalCount={totalCount}
            loading={loadingPaginated}
            onUpdateMensalValor={async (empId, recId, val) => {
              await saveMensal.mutateAsync({ id: recId, valor_total: val } as any);
              const { data: mensal } = await supabase.from("honorarios_mensal").select("*").eq("empresa_id", empId).order('competencia', { ascending: false });
              setMensalData(prev => ({ ...prev, [empId]: (mensal as unknown as HonorarioMensal[]) || [] }));
            }}
          />
        </div>
      )}
    </div>
  );
};

export default HonorariosPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { formatDateBR } from "@/lib/utils";
import {
  Search, Building2, ChevronDown, ChevronUp,
  Shield, CheckCircle, Clock, AlertTriangle, Save,
  Upload, Eye, FileText
} from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";
import { LicencaRecord, LicencaTaxaRecord, GuiaStatus } from "@/types/administrative";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const licencaLabels: Record<string, string> = {
  alvara: "Alvará de Funcionamento",
  vigilancia_sanitaria: "Vigilância Sanitária",
  corpo_bombeiros: "Corpo de Bombeiros",
  meio_ambiente: "Meio Ambiente"
};

const tipoStatusLabels: Record<string, { label: string; cls: string }> = {
  definitiva: { label: "Definitiva", cls: "badge-success" },
  dispensada: { label: "Dispensada", cls: "badge-gray" },
  com_vencimento: { label: "Com Vencimento", cls: "badge-warning" },
  em_processo: { label: "Em Processo", cls: "badge-info" },
};

const calcDias = (data?: string | null) => {
  if (!data) return 999;
  return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);
};

type TabType = "licencas" | "taxas";

const LicencasPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("licencas");
  const [licencas, setLicencas] = useState<LicencaRecord[]>([]);
  const [taxas, setTaxas] = useState<LicencaTaxaRecord[]>([]);

  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("todos");
  const [expanded, setExpanded] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<TabType>("licencas");
  const [activeStatusTab, setActiveStatusTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [taxasForm, setTaxasForm] = useState<Record<string, Record<string, Partial<LicencaTaxaRecord>>>>({});
  const [isConsultandoGuia, setIsConsultandoGuia] = useState<string | null>(null);

  const loadBaseData = async () => {
    const { data: lics } = await supabase.from("licencas").select("*");
    setLicencas((lics as unknown as LicencaRecord[]) || []);
  };

  const loadTaxas = async () => {
    const { data } = await supabase.from("licencas_taxas").select("*").eq("competencia", competencia);
    setTaxas((data as unknown as LicencaTaxaRecord[]) || []);

    // Auto-populate edit form with fetched data
    const map: Record<string, Record<string, Partial<LicencaTaxaRecord>>> = {};
    (data as unknown as LicencaTaxaRecord[])?.forEach(t => {
      if (!map[t.empresa_id]) map[t.empresa_id] = {};
      map[t.empresa_id][t.tipo_licenca] = {
        id: t.id,
        status: t.status,
        data_envio: t.data_envio,
        forma_envio: t.forma_envio,
        data_vencimento: t.data_vencimento
      };
    });
    setTaxasForm(map);
  };

  useEffect(() => { loadBaseData(); }, []);
  useEffect(() => { if (activeTab === "taxas") loadTaxas(); }, [competencia, activeTab]);

  const licByEmpresa = (empId: string) => licencas.filter(l => l.empresa_id === empId);

  // Filters for Licencas Tab
  const filteredLicencas = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const matchStatus = filterStatus === "todos" || licByEmpresa(e.id).some((l: LicencaRecord) => l.status === filterStatus);

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    } else if (activeStatusTab === "entregue") {
      matchTab = e.situacao === "entregue";
    }

    return matchSearch && matchStatus && matchTab;
  });

  // Filters for Taxas Tab (Shows only companies that have at least one valid license)
  const filteredTaxas = empresas.filter(e => {
    const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);
    const hasAnyLicence = licByEmpresa(e.id).length > 0;

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (!e.situacao || e.situacao === "ativa") && e.porte_empresa === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = e.situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = e.situacao === "baixada";
    }

    return matchSearch && hasAnyLicence && matchTab;
  });

  const counts = {
    definitiva: licencas.filter(l => l.status === "definitiva").length,
    dispensada: licencas.filter(l => l.status === "dispensada").length,
    com_vencimento: licencas.filter(l => l.status === "com_vencimento").length,
    em_processo: licencas.filter(l => l.status === "em_processo").length
  };

  // --- Handlers for Taxas Tab ---
  const handleTaxaChange = (empresaId: string, tipoLicenca: string, field: string, value: string | GuiaStatus | null) => {
    setTaxasForm(prev => {
      const empData = prev[empresaId] || {};
      const licData = empData[tipoLicenca] || { status: 'pendente', data_envio: '', forma_envio: '' };
      return {
        ...prev,
        [empresaId]: {
          ...empData,
          [tipoLicenca]: { ...licData, [field]: value }
        }
      }
    });
  };

  const saveTaxas = async (empresaId: string) => {
    const empTaxas = taxasForm[empresaId];
    if (!empTaxas) return;

    try {
      const promises = Object.keys(licencaLabels).map(async (tipoLicenca) => {
        const data = empTaxas[tipoLicenca];
        if (!data) return; // Only save those modified/existing in form state

        const payload = {
          empresa_id: empresaId,
          tipo_licenca: tipoLicenca,
          competencia,
          status: data.status || 'pendente',
          data_envio: data.data_envio || null,
          forma_envio: data.forma_envio || null,
          data_vencimento: data.data_vencimento || null
        };

        if (data.id) {
          return supabase.from("licencas_taxas").update(payload).eq("id", data.id);
        } else {
          return supabase.from("licencas_taxas").insert(payload);
        }
      });

      await Promise.all(promises);
      toast.success("Taxas atualizadas com sucesso!");
      loadTaxas(); // Reload to get newly inserted IDs
    } catch (err: any) {
      toast.error(err.message || "Erro ao salvar as taxas.");
    }
  };

  const handleConsultarGuiaAlvara = async (cnpj: string | null | undefined) => {
    if (!cnpj) {
      toast.error("CNPJ não encontrado para esta empresa.");
      return;
    }
    
    setIsConsultandoGuia(cnpj);
    const toastId = toast.loading("Consultando guias no portal da prefeitura (Betha)...", { duration: 30000 });
    
    try {
      // Endpoint that will run the headless browser script
      // Note: In Vercel, this serverless function requires puppeteer-core and @sparticuz/chromium
      const res = await fetch('/api/consultar-guia-alvara', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cnpj }),
      });
      
      if (!res.ok) {
        let errMessage = "Ocorreu um erro no servidor.";
        try { const errObj = await res.json(); errMessage = errObj.error || errMessage; } catch (e) {}
        throw new Error(errMessage);
      }
      
      const blob = await res.blob();
      if (blob.size === 0) throw new Error("Documento vazio retornado.");
      
      // Create a link and click it to download the file directly, not saving to DB
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = `Guias_Alvara_${cnpj.replace(/\D/g, '')}.pdf`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      
      toast.success("Guias baixadas com sucesso!", { id: toastId });
    } catch (err: any) {
      toast.error(`Falha na consulta: ${err.message}`, { id: toastId });
    } finally {
      setIsConsultandoGuia(null);
    }
  };

  const inputCls = "w-full px-3 py-1.5 border border-border rounded-md bg-background text-foreground text-xs focus:ring-1 focus:ring-primary outline-none";
  const labelCls = "block text-[11px] font-semibold text-muted-foreground mb-1 uppercase tracking-wider";

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full">
        <FavoriteToggleButton moduleId="licencas" />
        <div>
          <h2 className="text-lg font-bold text-card-foreground">Licenças e Taxas</h2>
          <p className="text-xs text-muted-foreground">Gestão de alvarás e taxas municipais/estaduais.</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-border">
        <button
          onClick={() => { setActiveTab("licencas"); setExpanded(null); }}
          className={`pb-3 px-4 text-sm font-semibold transition-colors border-b-2 ${activeTab === "licencas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
        >
          Status das Licenças
        </button>
        <button
          onClick={() => { setActiveTab("taxas"); setExpanded(null); }}
          className={`pb-3 px-4 text-sm font-semibold transition-colors border-b-2 ${activeTab === "taxas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
        >
          Taxas das Licenças
        </button>
      </div>

      {/* Status Tabs */}
      <div className="flex border-b border-border overflow-x-auto no-scrollbar pt-2">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("baixadas")}
        >
          Empresas Baixadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "entregue"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("entregue")}
        >
          Empresas Entregues
        </button>
      </div>

      {activeTab === "licencas" && (
        <div className="space-y-6 animate-fade-in">
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {[{ label: "Definitivas", count: counts.definitiva, cls: "text-success", bg: "bg-success/10", icon: <CheckCircle size={20} /> }, { label: "Com Vencimento", count: counts.com_vencimento, cls: "text-warning", bg: "bg-warning/10", icon: <Clock size={20} /> }, { label: "Em Processo", count: counts.em_processo, cls: "text-primary", bg: "bg-primary/10", icon: <Shield size={20} /> }, { label: "Dispensadas", count: counts.dispensada, cls: "text-muted-foreground", bg: "bg-muted", icon: <AlertTriangle size={20} /> }].map(s => (
              <div key={s.label} className="stat-card flex items-center justify-between"><div><p className="text-xs text-muted-foreground uppercase tracking-wide">{s.label}</p><p className={`text-2xl font-bold mt-1 ${s.cls}`}>{s.count}</p></div><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${s.bg} ${s.cls}`}>{s.icon}</div></div>
            ))}
          </div>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
            <div className="flex gap-2 flex-wrap">
              {[{ key: "todos", label: "Todos" }, { key: "definitiva", label: "Definitivas" }, { key: "com_vencimento", label: "Com Vencimento" }, { key: "em_processo", label: "Em Processo" }, { key: "dispensada", label: "Dispensadas" }].map(f => (
                <button key={f.key} onClick={() => setFilterStatus(f.key)} className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${filterStatus === f.key ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:text-foreground"}`}>{f.label}</button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            {filteredLicencas.length === 0 ? <div className="module-card text-center py-12 text-muted-foreground">Nenhuma empresa encontrada</div> : filteredLicencas.map(emp => {
              const isOpen = expanded === emp.id;
              const empLicencas = licByEmpresa(emp.id);
              return (
                <div key={emp.id} className="module-card !p-0 overflow-hidden">
                  <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => setExpanded(isOpen ? null : emp.id)}>
                    <div className="flex items-center gap-3"><div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div><div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                    <div className="flex items-center gap-2">{empLicencas.map((l: LicencaRecord, i: number) => { const cfg = tipoStatusLabels[l.status || ""] || { label: "—", cls: "badge-gray" }; return <span key={i} className={`badge-status ${cfg.cls} text-[10px]`}>{cfg.label}</span>; })}{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
                  </div>
                  {isOpen && (
                    <div className="border-t border-border p-5 bg-muted/10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {Object.entries(licencaLabels).map(([key, label]) => {
                          const lic = empLicencas.find((l: LicencaRecord) => l.tipo_licenca === key);
                          const cfg = lic ? tipoStatusLabels[lic.status] || { label: "Não definido", cls: "badge-gray" } : { label: "Não definido", cls: "badge-gray" };
                          const dias = lic?.status === "com_vencimento" ? calcDias(lic.vencimento) : null;
                          return (
                            <div key={key} className="p-4 rounded-xl border border-border bg-card">
                              <div className="flex items-center justify-between mb-2">
                                <h4 className="text-sm font-semibold text-card-foreground">{label}</h4>
                                <div className="flex items-center gap-2">
                                  <span className={`badge-status ${cfg.cls}`}>{cfg.label}</span>
                                  {lic?.file_url ? (
                                    <button
                                      onClick={() => window.open(lic.file_url, "_blank")}
                                      className="p-1.5 rounded-lg bg-primary/10 text-primary hover:bg-primary/20 transition-all"
                                      title="Visualizar anexo"
                                    >
                                      <Eye size={14} />
                                    </button>
                                  ) : (
                                    <div className="relative">
                                      <input
                                        type="file"
                                        accept=".pdf"
                                        className="hidden"
                                        id={`upload-${emp.id}-${key}`}
                                        onChange={async (e) => {
                                          const file = e.target.files?.[0];
                                          if (!file) return;

                                          toast.loading("Enviando...", { id: "up-lic" });
                                          const path = `licencas/${emp.id}/${key}_${Date.now()}.pdf`;

                                          const { error: upErr } = await supabase.storage.from("documentos").upload(path, file);
                                          if (upErr) {
                                            toast.error("Erro: " + upErr.message, { id: "up-lic" });
                                            return;
                                          }

                                          const { data: { publicUrl } } = supabase.storage.from("documentos").getPublicUrl(path);

                                          // Update database
                                          const { error: dbErr } = await supabase.from("licencas")
                                            .update({ file_url: publicUrl })
                                            .eq("empresa_id", emp.id)
                                            .eq("tipo_licenca", key);

                                          if (dbErr) {
                                            toast.error("Erro DB: " + dbErr.message, { id: "up-lic" });
                                          } else {
                                            toast.success("Anexo salvo!", { id: "up-lic" });
                                            loadBaseData();
                                          }
                                        }}
                                      />
                                      <label
                                        htmlFor={`upload-${emp.id}-${key}`}
                                        className="p-1.5 rounded-lg bg-muted hover:bg-muted/80 text-muted-foreground cursor-pointer transition-all flex items-center justify-center"
                                        title="Anexar PDF"
                                      >
                                        <Upload size={14} />
                                      </label>
                                    </div>
                                  )}
                                </div>
                              </div>
                              {lic?.status === "com_vencimento" && lic.vencimento && <div className="text-xs text-muted-foreground">Vencimento: {formatDateBR(lic.vencimento)}{dias !== null && <span className={`ml-2 font-medium ${dias < 0 ? "text-destructive" : dias <= 30 ? "text-warning" : "text-success"}`}>({dias}d)</span>}</div>}
                              {lic?.status === "em_processo" && lic.numero_processo && <div className="text-xs text-muted-foreground">Processo: {lic.numero_processo}</div>}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {activeTab === "taxas" && (
        <div className="space-y-6 animate-fade-in">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
            <div className="relative max-w-sm w-full">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
              <input type="text" placeholder="Buscar empresa..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div className="flex items-center gap-2">
              <span className="text-sm font-semibold text-muted-foreground">Competência:</span>
              <input type="month" value={competencia} onChange={e => setCompetencia(e.target.value)} className="px-4 py-2 border border-border rounded-lg bg-background text-foreground font-semibold text-sm outline-none focus:ring-2 focus:ring-primary" />
            </div>
          </div>

          <div className="space-y-3">
            {filteredTaxas.length === 0 ? <div className="module-card text-center py-12 text-muted-foreground">Nenhuma empresa com licenças encontradas</div> : filteredTaxas.map(emp => {
              const isOpen = expanded === emp.id;
              const empLicencas = licByEmpresa(emp.id);
              return (
                <div key={emp.id} className="module-card !p-0 overflow-hidden">
                  <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => setExpanded(isOpen ? null : emp.id)}>
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center"><Building2 size={16} className="text-primary" /></div>
                      <div>
                        <p className="font-semibold text-card-foreground">{emp.nome_empresa}</p>
                        <p className="text-xs text-muted-foreground">{emp.cnpj || "—"} • {empLicencas.length} Licença(s)</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      {isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}
                    </div>
                  </div>

                  {isOpen && (
                    <div className="border-t border-border p-5 bg-muted/10 space-y-4">
                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                        {Object.entries(licencaLabels).map(([key, label]) => {
                          const lic = empLicencas.find((l: LicencaRecord) => l.tipo_licenca === key);
                          if (!lic) return null; // Only show taxes blocks for licenses they actually have

                          const taxaData = (taxasForm[emp.id] && taxasForm[emp.id][key]) || { status: 'pendente', data_envio: '', forma_envio: '' };

                          return (
                            <div key={key} className="p-4 rounded-xl border border-border bg-card flex flex-col gap-3">
                              <h4 className="text-sm font-bold text-primary flex items-center justify-between gap-2 w-full">
                                <span className="flex items-center gap-2">
                                  <Shield size={14} /> {label}
                                </span>
                                {key === 'alvara' && (
                                  <button
                                    onClick={() => handleConsultarGuiaAlvara(emp.cnpj)}
                                    disabled={isConsultandoGuia === emp.cnpj}
                                    className="px-3 py-1 bg-primary/10 text-primary hover:bg-primary/20 transition-colors text-xs rounded-md flex items-center gap-1 font-semibold disabled:opacity-50 disabled:cursor-not-allowed"
                                  >
                                    {isConsultandoGuia === emp.cnpj ? (
                                      <div className="w-3 h-3 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                                    ) : (
                                      <Search size={12} />
                                    )} 
                                    {isConsultandoGuia === emp.cnpj ? 'Consultando...' : 'Consultar Guia'}
                                  </button>
                                )}
                              </h4>

                              <div className="grid grid-cols-2 lg:grid-cols-4 gap-2">
                                <div>
                                  <label className={labelCls}>Status Atual</label>
                                  <select
                                    className={inputCls}
                                    value={taxaData.status}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'status', e.target.value)}
                                  >
                                    <option value="pendente">Pendente</option>
                                    <option value="gerada">Gerada</option>
                                    <option value="enviada">Enviada</option>
                                  </select>
                                </div>
                                <div>
                                  <label className={labelCls}>Vencimento</label>
                                  <input
                                    type="date"
                                    className={inputCls}
                                    value={taxaData.data_vencimento || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'data_vencimento', e.target.value)}
                                  />
                                </div>
                                <div>
                                  <label className={labelCls}>Data do Envio</label>
                                  <input
                                    type="date"
                                    className={inputCls}
                                    value={taxaData.data_envio || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'data_envio', e.target.value)}
                                  />
                                </div>
                                <div>
                                  <label className={labelCls}>Envio</label>
                                  <input
                                    type="text"
                                    placeholder="Ex: WhatsApp"
                                    className={inputCls}
                                    value={taxaData.forma_envio || ''}
                                    onChange={(e) => handleTaxaChange(emp.id, key, 'forma_envio', e.target.value)}
                                  />
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>

                      <div className="flex justify-end pt-2 border-t border-border/50">
                        <button
                          onClick={() => saveTaxas(emp.id)}
                          className="flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
                          style={{ background: "var(--gradient-primary)" }}
                        >
                          <Save size={16} /> Salvar Taxas deste Mês
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

