    nome_empresa: string;
    cnpj: string | null;
    socios?: any[];
}

interface Ocorrencia {
    id: string;
    empresa_id: string;
    departamento: string;
    descricao: string;
    cidade: string;
    estado: string;
    data_ocorrencia: string;
    created_at: string;
