        nome_empresa: string;
        cnpj: string | null;
    };
}

const DEPARTAMENTOS = [
    "Societário",
    "Fiscal",
    "Pessoal",
    "Contábil",
    "Financeiro",
    "Administrativo"
];

const OcorrenciasPage: React.FC = () => {
    const { userData } = useAuth();
    const [empresas, setEmpresas] = useState<Empresa[]>([]);
    const [ocorrencias, setOcorrencias] = useState<Ocorrencia[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<"geral" | "config">("geral");
    const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
    const [savingConfig, setSavingConfig] = useState(false);
    const [uploadingLogo, setUploadingLogo] = useState(false);

    // Form state
    const [selectedEmpresaId, setSelectedEmpresaId] = useState("");
    const [selectedDepto, setSelectedDepto] = useState("");
    const [descricao, setDescricao] = useState("");
    const [cidade, setCidade] = useState("Fazenda Rio Grande");
    const [estado, setEstado] = useState("PR");
    const [dataOcorrencia, setDataOcorrencia] = useState(new Date().toISOString().split('T')[0]);

    const fetchInitialData = async () => {
        try {
            const { data: empData } = await supabase.from("empresas").select("id, nome_empresa, cnpj").order("nome_empresa");
            const { data: ocData } = await (supabase.from("ocorrencias") as any).select("*, empresas(nome_empresa, cnpj)").order("created_at", { ascending: false });
            const { data: configData } = await supabase.from("app_config").select("value").eq("key", "pdf_header_config").maybeSingle();

            if (empData) setEmpresas(empData);
            if (ocData) setOcorrencias(ocData as any);
            if (configData?.value) {
                try {
                    setHeaderConfig(JSON.parse(configData.value));
                } catch (e) {
                    console.error("Erro ao parsear config:", e);
                }
            }
        } catch (error) {
            console.error("Erro ao carregar dados:", error);
            toast.error("Erro ao carregar dados");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchInitialData();
    }, []);

    const handleSave = async (generatePdf = false) => {
        if (!selectedEmpresaId || !selectedDepto || !descricao) {
            toast.error("Preencha todos os campos obrigatórios");
            return;
        }

        setSaving(true);
        try {
            const { data, error } = await (supabase.from("ocorrencias") as any).insert([
                {
                    empresa_id: selectedEmpresaId,
                    departamento: selectedDepto,
                    descricao,
                    cidade,
                    estado,
                    data_ocorrencia: dataOcorrencia,
                    usuario_id: userData?.userId
                }
            ]).select("*, empresas(nome_empresa, cnpj)").single();

            if (error) throw error;

            toast.success("Ocorrência registrada com sucesso!");
            setOcorrencias([data as any, ...ocorrencias]);

            if (generatePdf) {
                handleGeneratePdf(data as any);
            }

            // Reset form
            setSelectedEmpresaId("");
            setSelectedDepto("");
            setDescricao("");
        } catch (error: any) {
            toast.error("Erro ao salvar ocorrência: " + error.message);
        } finally {
            setSaving(false);
        }
    };

    const handleGeneratePdf = async (oc: Ocorrencia) => {
        const doc = new jsPDF();

        doc.addFileToVFS("Ubuntu-Regular.ttf", UbuntuRegular);
        doc.addFont("Ubuntu-Regular.ttf", "Ubuntu", "normal");
        doc.addFileToVFS("Ubuntu-Bold.ttf", UbuntuBold);
        doc.addFont("Ubuntu-Bold.ttf", "Ubuntu", "bold");

        const pageWidth = doc.internal.pageSize.getWidth();

        // Fetch Socio Administrador
        const { data: manager } = await supabase
            .from("socios")
            .select("nome, cpf")
            .eq("empresa_id", oc.empresa_id)
            .eq("administrador", true)
            .maybeSingle();

        // Fetch User Profile to get latest Name/CPF (avoiding stale context)
        const { data: profile } = await supabase
            .from("profiles")
            .select("nome_completo, cpf")
            .eq("user_id", userData?.userId)
            .maybeSingle();

        const usuarioNome = profile?.nome_completo || userData?.nome || "";
        const usuarioCPF = profile?.cpf || userData?.cpf || "";

        // Header - Logo and Text
        try {
            const logoToUse = headerConfig.logoUrl || logoCaduceu;

            // Safe image loading via DOM Image
            const imgData = await new Promise<HTMLImageElement | string>((resolve, reject) => {
                if (logoToUse.startsWith('data:')) {
                    resolve(logoToUse);
                } else {
                    const img = new Image();
                    if (logoToUse.startsWith('http')) {
                        img.crossOrigin = 'Anonymous';
                    }
                    img.onload = () => resolve(img);
                    img.onerror = () => reject(new Error("Image failed to load (CORS or Invalid URL)"));
                    img.src = logoToUse;
                }
            });

            let format = 'PNG';
            if (typeof imgData === 'string') {
                if (imgData.startsWith('data:image/jpeg') || imgData.startsWith('data:image/jpg')) format = 'JPEG';
                else if (imgData.startsWith('data:image/webp')) format = 'WEBP';
            }

            doc.addImage(imgData, format, headerConfig.logoX, headerConfig.logoY, headerConfig.logoWidth, headerConfig.logoHeight);
        } catch (e) {
            console.warn("Logo blocked by CORS or invalid. Generating PDF without custom logo.", e);
            if (headerConfig.logoUrl && headerConfig.logoUrl.startsWith('http')) {
                toast.error("O link da logo foi bloqueado por segurança (CORS). Por favor, baixe a imagem para o seu computador e faça o upload dela nas configurações.");
            }
            // Fallback to default if custom url failed
            try {
                if (headerConfig.logoUrl) {
                    doc.addImage(logoCaduceu, 'PNG', headerConfig.logoX, headerConfig.logoY, headerConfig.logoWidth, headerConfig.logoHeight);
                }
            } catch (fallbackError) {
                console.warn("Fallback logo failed", fallbackError);
            }
        }

        doc.setFont("Ubuntu", "bold");
        doc.setFontSize(headerConfig.titleFontSize);
        doc.text(headerConfig.title, pageWidth / 2 + 10, 20, { align: "center" });

        doc.setFontSize(headerConfig.subtitleFontSize);
        doc.setFont("Ubuntu", "normal");
        doc.text(headerConfig.subtitle, pageWidth / 2 + 10, 26, { align: "center" });

        doc.setFontSize(headerConfig.infoFontSize);
        doc.text(headerConfig.address, pageWidth / 2, 34, { align: "center" });
        doc.text(headerConfig.contact, pageWidth / 2, 38, { align: "center" });

        // Separator line
        doc.setDrawColor(0);
        doc.setLineWidth(0.5);
        doc.line(10, 42, pageWidth - 10, 42);

        // Title
        doc.setFontSize(14);
        doc.setFont("Ubuntu", "bold");
        doc.text("OCORRÊNCIA", pageWidth / 2, 55, { align: "center" });

        // Company Info
        doc.setFontSize(11);
        doc.text(`Empresa: ${oc.empresas.nome_empresa}`, 20, 70);
        doc.text(`CNPJ: ${oc.empresas.cnpj || "—"}`, 20, 76);

        // Occurrence text
        doc.setFont("Ubuntu", "normal"); // Utilizing custom Ubuntu font
        const splitDesc = doc.splitTextToSize(oc.descricao, pageWidth - 40);
        doc.text(splitDesc, 20, 90);

        const descHeight = splitDesc.length * 7;
        const lineY = 90 + descHeight + 10;


        // Date/Place
        const formattedDate = new Date(oc.data_ocorrencia).toLocaleDateString("pt-BR", { day: '2-digit', month: 'long', year: 'numeric' });
        doc.text(`${oc.cidade}/${oc.estado}, ${formattedDate}`, pageWidth - 20, lineY + 20, { align: "right" });

        // Signatures
        const sigY = lineY + 60;

        // Left side: Company/Admin
        doc.line(20, sigY, 100, sigY);
        doc.setFont("Ubuntu", "bold");
        doc.setFontSize(9);
        doc.text(oc.empresas.nome_empresa, 20, sigY + 5);
        doc.text(`CNPJ: ${oc.empresas.cnpj || ""}`, 20, sigY + 10);

        doc.text("Socio(a) Administrador(a)", 20, sigY + 18);
        doc.setFont("Ubuntu", "normal");
        doc.text(manager?.nome || "____________________________", 20, sigY + 23);
        const managerCPF = manager?.cpf ? `CPF: ${manager.cpf}` : "CPF: ________________________";
        doc.text(managerCPF, 20, sigY + 28);

        // Right side: User/Dept
        doc.line(pageWidth - 100, sigY, pageWidth - 20, sigY);
        doc.setFont("Ubuntu", "bold");
        doc.text(usuarioNome.toUpperCase(), pageWidth - 100, sigY + 5);
        doc.text(`CPF: ${usuarioCPF}`, pageWidth - 100, sigY + 10);
        doc.text(`Departamento: ${oc.departamento}`, pageWidth - 100, sigY + 15);

        doc.save(`Ocorrencia_${oc.empresas.nome_empresa.replace(/\s+/g, '_')}.pdf`);
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm("Tem certeza que deseja excluir esta ocorrência?")) return;
        try {
            const { error } = await (supabase.from("ocorrencias") as any).delete().eq("id", id);
            if (error) throw error;
            setOcorrencias(ocorrencias.filter(o => o.id !== id));
            toast.success("Ocorrência excluída");
        } catch (error) {
            toast.error("Erro ao excluir");
        }
    };

    const handleUpdateStatus = async (id: string, newStatus: string) => {
        try {
            // Optimistic update
            setOcorrencias(ocorrencias.map(o => o.id === id ? { ...o, status: newStatus } : o));
            
            const { error } = await (supabase.from("ocorrencias") as any).update({ status: newStatus }).eq("id", id);
            if (error) throw error;
        } catch (error: any) {
            toast.error("Erro ao atualizar status do card: " + error.message);
            // Revert state
            fetchInitialData();
        }
    };

    const saveHeaderConfig = async () => {
        setSavingConfig(true);
        try {
            const { error } = await supabase.from("app_config").upsert({
                key: "pdf_header_config",
                value: JSON.stringify(headerConfig)
            }, { onConflict: "key" });

            if (error) throw error;
            toast.success("Configuração de cabeçalho salva!");
        } catch (error: any) {
            toast.error("Erro ao salvar config: " + error.message);
        } finally {
            setSavingConfig(false);
        }
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            toast.error("A logo deve ter no máximo 2MB");
            return;
        }

        setUploadingLogo(true);
        const reader = new FileReader();
        reader.onloadend = () => {
            setHeaderConfig({ ...headerConfig, logoUrl: reader.result as string });
            setUploadingLogo(false);
            toast.success("Logo carregada localmente! Salve as configurações.");
        };
        reader.onerror = () => {
            setUploadingLogo(false);
            toast.error("Erro ao carregar a imagem selecionada.");
        };
        reader.readAsDataURL(file);
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-card-foreground">Ocorrências</h1>
                    <p className="text-muted-foreground">Gerenciamento e geração de documentos de ocorrência</p>
                </div>
                <div className="flex gap-2 bg-muted p-1 rounded-lg self-start">
                    <button
                        onClick={() => setActiveTab("geral")}
                        className={`px-4 py-1.5 rounded-md text-sm font-bold transition-all ${activeTab === "geral" ? "bg-background text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                    >
                        Geral
                    </button>
                    <button
                        onClick={() => setActiveTab("config")}
                        className={`px-4 py-1.5 rounded-md text-sm font-bold transition-all flex items-center gap-2 ${activeTab === "config" ? "bg-background text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                    >
                        <Settings2 size={16} /> Configurações
                    </button>
                </div>
            </div>

            {activeTab === "config" ? (
                <div className="module-card max-w-4xl mx-auto space-y-6">
                    <h2 className="text-xl font-bold text-primary flex items-center gap-2">
                        <Settings2 size={24} /> Personalização do Cabeçalho PDF
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-muted-foreground uppercase">Conteúdo</h3>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Título Principal</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.title}
                                    onChange={e => setHeaderConfig({ ...headerConfig, title: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Subtítulo (CRC, etc)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.subtitle}
                                    onChange={e => setHeaderConfig({ ...headerConfig, subtitle: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Endereço (Linha 1)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.address}
                                    onChange={e => setHeaderConfig({ ...headerConfig, address: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Contato/Email (Linha 2)</label>
                                <input
                                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                    value={headerConfig.contact}
                                    onChange={e => setHeaderConfig({ ...headerConfig, contact: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold mb-1 block">Logo do Cabeçalho</label>
                                <div className="flex items-center gap-4 p-4 border border-dashed border-border rounded-xl bg-muted/20">
                                    <div className="w-20 h-20 rounded-lg bg-background border border-border flex items-center justify-center overflow-hidden">
                                        {headerConfig.logoUrl ? (
                                            <img src={headerConfig.logoUrl} alt="Logo" className="max-w-full max-h-full object-contain" />
                                        ) : (
                                            <ImageIcon size={30} className="text-muted-foreground/30" />
                                        )}
                                    </div>
                                    <div className="flex-1 space-y-2">
                                        <p className="text-[10px] text-muted-foreground">Upload da logo em PNG ou JPG. <br />Tamanho recomendado: 200x200px</p>
                                        <div className="flex flex-wrap gap-2">
                                            <label className="inline-flex items-center gap-2 px-3 py-1.5 bg-primary/10 text-primary text-xs font-bold rounded-lg cursor-pointer hover:bg-primary/20 transition-all">
                                                <Upload size={14} />
                                                {uploadingLogo ? "Carregando..." : "Selecionar Logo"}
                                                <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} disabled={uploadingLogo} />
                                            </label>

                                            {headerConfig.logoUrl && (
                                                <button
                                                    onClick={() => setHeaderConfig({ ...headerConfig, logoUrl: "" })}
                                                    className="inline-flex items-center gap-2 px-3 py-1.5 bg-destructive/10 text-destructive text-xs font-bold rounded-lg cursor-pointer hover:bg-destructive/20 transition-all"
                                                    title="Remover Logo Customizada"
                                                >
                                                    <Trash2 size={14} />
                                                    Remover
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-muted-foreground uppercase">Tamanhos e Posições</h3>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Título</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.titleFontSize} onChange={e => setHeaderConfig({ ...headerConfig, titleFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Subtítulo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.subtitleFontSize} onChange={e => setHeaderConfig({ ...headerConfig, subtitleFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Fonte Info</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.infoFontSize} onChange={e => setHeaderConfig({ ...headerConfig, infoFontSize: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Largura Logo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoWidth} onChange={e => setHeaderConfig({ ...headerConfig, logoWidth: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Altura Logo</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoHeight} onChange={e => setHeaderConfig({ ...headerConfig, logoHeight: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Posição Logo X</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoX} onChange={e => setHeaderConfig({ ...headerConfig, logoX: parseInt(e.target.value) })} />
                                </div>
                                <div>
                                    <label className="text-xs font-bold mb-1 block">Posição Logo Y</label>
                                    <input type="number" className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm" value={headerConfig.logoY} onChange={e => setHeaderConfig({ ...headerConfig, logoY: parseInt(e.target.value) })} />
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="pt-6 border-t border-border flex justify-end">
                        <button
                            onClick={saveHeaderConfig}
                            disabled={savingConfig}
                            className="px-8 py-3 bg-primary text-primary-foreground font-bold rounded-xl shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        >
                            {savingConfig ? "Salvando..." : "Salvar Configurações"}
                        </button>
                    </div>
                </div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Registration Form */}
                    <div className="lg:col-span-1 space-y-6">
                        <div className="module-card">
                            <h3 className="text-lg font-bold text-primary flex items-center gap-2 mb-4">
                                <Plus size={20} /> Nova Ocorrência
                            </h3>

                            <div className="space-y-4">
                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Empresa</label>
                                    <select
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={selectedEmpresaId}
                                        onChange={(e) => setSelectedEmpresaId(e.target.value)}
                                    >
                                        <option value="">Selecione...</option>
                                        {empresas.map(e => <option key={e.id} value={e.id}>{e.nome_empresa}</option>)}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Departamento</label>
                                    <select
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={selectedDepto}
                                        onChange={(e) => setSelectedDepto(e.target.value)}
                                    >
                                        <option value="">Selecione...</option>
                                        {DEPARTAMENTOS.map(d => <option key={d} value={d}>{d}</option>)}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Data</label>
                                    <input
                                        type="date"
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary"
                                        value={dataOcorrencia}
                                        onChange={(e) => setDataOcorrencia(e.target.value)}
                                    />
                                </div>

                                <div>
                                    <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Ocorrência/Descrição</label>
                                    <textarea
                                        className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm outline-none focus:ring-2 focus:ring-primary min-h-[120px]"
                                        placeholder="Descreva a ocorrência..."
                                        value={descricao}
                                        onChange={(e) => setDescricao(e.target.value)}
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-2">
                                    <div>
                                        <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Cidade</label>
                                        <input
                                            className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                            value={cidade}
                                            onChange={(e) => setCidade(e.target.value)}
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-muted-foreground block mb-1 uppercase tracking-tight">Estado</label>
                                        <input
                                            className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm"
                                            value={estado}
                                            onChange={(e) => setEstado(e.target.value)}
                                        />
                                    </div>
                                </div>

                                <div className="flex flex-col gap-2 pt-2">
                                    <button
                                        onClick={() => handleSave(false)}
                                        disabled={saving}
                                        className="w-full py-2.5 bg-muted text-foreground rounded-lg font-bold text-sm hover:bg-muted/80 transition-all flex items-center justify-center gap-2"
                                    >
                                        {saving ? "Salvando..." : "Apenas Salvar"}
                                    </button>
                                    <button
                                        onClick={() => handleSave(true)}
                                        disabled={saving}
                                        className="w-full py-2.5 bg-primary text-primary-foreground rounded-lg font-bold text-sm shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2"
                                    >
                                        {saving ? "Salvando..." : <><Download size={18} /> Salvar e Gerar PDF</>}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* List of Recent Occurrences */}
                    <div className="lg:col-span-2 space-y-4">
                        <div className="flex items-center justify-between mb-2">
                           <h3 className="text-lg font-bold text-card-foreground flex items-center gap-2">
                               <HistoryIcon size={20} className="text-primary" /> Board de Ocorrências
                           </h3>
                        </div>

                        <div className="module-card">
                            <div className="space-y-3">
                                {ocorrencias.length === 0 && !loading && (
                                    <div className="text-center py-12 text-muted-foreground">
                                        <FileText size={40} className="mx-auto mb-3 opacity-20" />
                                        <p>Nenhuma ocorrência registrada</p>
                                    </div>
                                )}

                                {ocorrencias.map(oc => (
                                    <div key={oc.id} className="p-4 border border-border rounded-xl hover:bg-muted/30 transition-all flex items-center justify-between group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary group-hover:scale-110 transition-transform">
                                                <Building2 size={20} />
                                            </div>
                                            <div>
                                                <h4 className="font-bold text-sm text-card-foreground">{oc.empresas.nome_empresa}</h4>
                                                <div className="flex items-center gap-3 mt-1 text-[11px] text-muted-foreground font-medium">
                                                    <span className="flex items-center gap-1"><User size={12} /> {oc.departamento}</span>
                                                    <span className="flex items-center gap-1"><Calendar size={12} /> {new Date(oc.data_ocorrencia).toLocaleDateString()}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-1">
                                            <button
                                                onClick={() => handleGeneratePdf(oc)}
                                                className="p-2 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors"
                                                title="Gerar PDF"
                                            >
                                                <Download size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(oc.id)}
                                                className="p-2 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"
                                                title="Excluir"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default OcorrenciasPage;

import React, { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { ArrowLeft, Save } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";

const tiposParcelamento = [
    "Previdenciário",
    "Simples Nacional",
    "MEI",
    "IRPF",
    "Dívida Ativa",
    "ICMS",
    "Outros",
];

const calcPrevisao = (dataInicio: string, qtd: number) => {
    if (!dataInicio || !qtd) return "";
    const d = new Date(dataInicio);
    d.setMonth(d.getMonth() + qtd);
    return d.toISOString().slice(0, 10);
};

const ParcelamentoFormPage: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [form, setForm] = useState({
        tipo_pessoa: "empresa",
        nome_pessoa_fisica: "",
        cpf_pessoa_fisica: "",
        tipo_parcelamento: "Simples Nacional",
        data_inicio: "",
        qtd_parcelas: "",
        forma_envio: "",
        metodo_login: "procuracao",
        login_gov_br: "",
        senha_gov_br: "",
        codigo_sn: "",
    });

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!form.nome_pessoa_fisica.trim()) {
            toast.error("Nome é obrigatório");
            return;
        }

        setLoading(true);
        const qtd = parseInt(form.qtd_parcelas) || 0;
        const payload = {
            tipo_pessoa: form.tipo_pessoa,
            nome_pessoa_fisica: form.nome_pessoa_fisica,
            cpf_pessoa_fisica: form.cpf_pessoa_fisica || null,
            tipo_parcelamento: form.tipo_parcelamento,
            data_inicio: form.data_inicio || null,
            qtd_parcelas: qtd,
            previsao_termino: calcPrevisao(form.data_inicio, qtd) || null,
            forma_envio: form.forma_envio || null,
            metodo_login: form.metodo_login,
            login_gov_br: form.metodo_login === "gov_br" ? form.login_gov_br : null,
            senha_gov_br: form.metodo_login === "gov_br" ? form.senha_gov_br : null,
            codigo_sn: form.metodo_login === "codigo_sn" ? form.codigo_sn : null,
        };

        try {
            const { error } = await supabase.from("parcelamentos").insert(payload);
            if (error) throw error;
            toast.success("Parcelamento cadastrado com sucesso!");
            navigate("/parcelamentos");
        } catch (err: any) {
            toast.error(err.message || "Erro ao salvar");
        } finally {
            setLoading(false);
        }
    };

    const inputCls =
        "w-full px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none transition-all";
    const labelCls = "block text-sm font-semibold text-card-foreground mb-1.5";

    return (
        <div className="space-y-6 animate-fade-in max-w-3xl mx-auto">
            <div className="flex items-center gap-4">
                <button
                    onClick={() => navigate(-1)}
                    className="p-2.5 rounded-xl border border-border bg-card hover:bg-muted text-card-foreground transition-colors"
                >
                    <ArrowLeft size={18} />
                </button>
            </div>

            <div className="module-card p-6 md:p-8">
                <form onSubmit={handleSave} className="space-y-6">
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold border-b border-border pb-2 text-foreground">
                            Dados Gerais
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className={labelCls}>Tipo de Cadastro</label>
                                <select
                                    value={form.tipo_pessoa}
                                    onChange={(e) =>
                                        setForm({ ...form, tipo_pessoa: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    <option value="empresa">Empresa (PJ)</option>
                                    <option value="pessoa_fisica">Pessoa Física (PF)</option>
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className={labelCls}>Nome ou Razão Social *</label>
                                <input
                                    required
                                    value={form.nome_pessoa_fisica}
                                    onChange={(e) =>
                                        setForm({ ...form, nome_pessoa_fisica: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Nome do cliente"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>
                                    {form.tipo_pessoa === "empresa" ? "CNPJ" : "CPF"}
                                </label>
                                <input
                                    value={form.cpf_pessoa_fisica}
                                    onChange={(e) =>
                                        setForm({ ...form, cpf_pessoa_fisica: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Apenas números"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Tipo de Parcelamento</label>
                                <select
                                    value={form.tipo_parcelamento}
                                    onChange={(e) =>
                                        setForm({ ...form, tipo_parcelamento: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    {tiposParcelamento.map((t) => (
                                        <option key={t} value={t}>
                                            {t}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className={labelCls}>Data de Início</label>
                                <input
                                    type="date"
                                    value={form.data_inicio}
                                    onChange={(e) =>
                                        setForm({ ...form, data_inicio: e.target.value })
                                    }
                                    className={inputCls}
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Quantidade de Parcelas</label>
                                <input
                                    type="number"
                                    min="1"
                                    value={form.qtd_parcelas}
                                    onChange={(e) =>
                                        setForm({ ...form, qtd_parcelas: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Ex: 60"
                                />
                            </div>
                            <div>
                                <label className={labelCls}>Forma de Envio Padrão</label>
                                <input
                                    value={form.forma_envio}
                                    onChange={(e) =>
                                        setForm({ ...form, forma_envio: e.target.value })
                                    }
                                    className={inputCls}
                                    placeholder="Ex: WhatsApp, Email..."
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4 pt-4">
                        <h3 className="text-lg font-bold border-b border-border pb-2 text-foreground">
                            Acesso e Login
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className={labelCls}>Método de Login</label>
                                <select
                                    value={form.metodo_login}
                                    onChange={(e) =>
                                        setForm({ ...form, metodo_login: e.target.value })
                                    }
                                    className={inputCls}
                                >
                                    <option value="procuracao">Por Procuração / Certificado</option>
                                    <option value="gov_br">Acesso Gov.br</option>
                                    <option value="codigo_sn">Código de Acesso Simples Nacional</option>
                                </select>
                            </div>

                            {form.metodo_login === "gov_br" && (
                                <>
                                    <div className="animate-fade-in">
                                        <label className={labelCls}>Login (CPF Gov.br)</label>
                                        <input
                                            required
                                            value={form.login_gov_br}
                                            onChange={(e) =>
                                                setForm({ ...form, login_gov_br: e.target.value })
                                            }
                                            className={inputCls}
                                            placeholder="CPF de acesso"
                                        />
                                    </div>
                                    <div className="animate-fade-in">
                                        <label className={labelCls}>Senha (Gov.br)</label>
                                        <input
                                            required
                                            type="password"
                                            value={form.senha_gov_br}
                                            onChange={(e) =>
                                                setForm({ ...form, senha_gov_br: e.target.value })
                                            }
                                            className={inputCls}
                                            placeholder="Senha do gov.br"
                                        />
                                    </div>
                                </>
                            )}

                            {form.metodo_login === "codigo_sn" && (
                                <div className="md:col-span-2 animate-fade-in">
                                    <label className={labelCls}>Código de Acesso SN</label>
                                    <input
                                        required
                                        value={form.codigo_sn}
                                        onChange={(e) =>
                                            setForm({ ...form, codigo_sn: e.target.value })
                                        }
                                        className={inputCls}
                                        placeholder="Ex: 123456789012"
                                    />
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 pt-6 border-t border-border mt-6">
                        <button
                            type="button"
                            onClick={() => navigate("-1")}
                            className="px-5 py-2.5 text-sm font-semibold text-muted-foreground bg-muted hover:bg-muted/80 rounded-xl transition-colors"
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex items-center gap-2 px-6 py-2.5 text-sm font-semibold text-primary-foreground rounded-xl shadow-md disabled:opacity-50 transition-all hover:opacity-90 active:scale-95"
                            style={{ background: "var(--gradient-primary)" }}
                        >
                            {loading ? (
                                "Salvando..."
                            ) : (
                                <>
                                    <Save size={18} /> Salvar Parcelamento
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ParcelamentoFormPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { formatDateBR } from "@/lib/utils";
import {
  Search,
  ChevronDown,
  ChevronUp,
  Save,
  CheckCircle,
  Circle,
  Plus,
  Trash2,
} from "lucide-react";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";
import { format, isBefore, isSameDay } from "date-fns";
import { ParcelamentoRecord, ParcelamentoMensalRecord, GuiaStatus } from "@/types/administrative";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const ParcelamentosPage: React.FC = () => {
  const navigate = useNavigate();
  const [parcelamentos, setParcelamentos] = useState<ParcelamentoRecord[]>([]);
  const [mensalData, setMensalData] = useState<Record<string, ParcelamentoMensalRecord>>({});
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(
    new Date().toISOString().slice(0, 7)
  );
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, Partial<ParcelamentoMensalRecord>>>({});
  const [activeTab, setActiveTab] = useState<"andamento" | "encerrados">("andamento");
  const [filterStatus, setFilterStatus] = useState<"todos" | "pendente" | "concluido">("todos");

  useEffect(() => {
    const loadParcelamentos = async () => {
      const { data } = await supabase
        .from("parcelamentos")
        .select("*")
        .order("nome_pessoa_fisica");
      setParcelamentos((data as unknown as ParcelamentoRecord[]) || []);
    };
    loadParcelamentos();
  }, []);

  useEffect(() => {
    const loadMensal = async () => {
      const { data } = await (supabase.from("parcelamentos_mensal" as any).select("*").eq("competencia", competencia) as any);
      const map: Record<string, ParcelamentoMensalRecord> = {};
      data?.forEach((f) => {
        map[f.parcelamento_id] = f as unknown as ParcelamentoMensalRecord;
      });
      setMensalData(map);
    };
    loadMensal();
  }, [competencia]);

  const calcIsEncerrado = (p: ParcelamentoRecord) => {
    if (p.encerrado) return true;
    if (p.previsao_termino) {
      const hoje = new Date();
      hoje.setHours(0, 0, 0, 0);
      const previsao = new Date(p.previsao_termino);
      // Extra hour adjustment for timezone if needed, but simple comparison suffices for dates
      previsao.setHours(0, 0, 0, 0);
      if (isBefore(previsao, hoje) || isSameDay(previsao, hoje)) return true;
    }
    return false;
  };

  const filtered = parcelamentos.filter((p) => {
    const isEncerrado = calcIsEncerrado(p);
    const matchesTab = activeTab === "encerrados" ? isEncerrado : !isEncerrado;
    const matchesSearch =
      p.nome_pessoa_fisica?.toLowerCase().includes(search.toLowerCase()) ||
      p.cpf_pessoa_fisica?.includes(search);
    
    let matchesStatus = true;
    if (filterStatus !== "todos") {
      const record = mensalData[p.id];
      const isConcluido = record?.status === "concluido" || record?.status === "isento";
      matchesStatus = filterStatus === "concluido" ? isConcluido : !isConcluido;
    }

    return matchesTab && matchesSearch && matchesStatus;
  });

  const toggleExpand = (id: string) => {
    if (expanded === id) {
      setExpanded(null);
      return;
    }
    setExpanded(id);
    const existing = (mensalData[id] || {}) as Partial<ParcelamentoMensalRecord>;

    setEditForm((prev) => ({
      ...prev,
      [id]: {
        status: existing.status || "pendente",
        data_envio: existing.data_envio || "",
        observacoes: existing.observacoes || "",
      },
    }));
  };

  const handleSaveMensal = async (parcelamentoId: string) => {
    const form = (editForm[parcelamentoId] || {}) as Partial<ParcelamentoMensalRecord>;
    const existing = mensalData[parcelamentoId];
    try {
      const payload = {
        parcelamento_id: parcelamentoId,
        competencia,
        status: form.status || "pendente",
        data_envio: form.data_envio || null,
        observacoes: form.observacoes || null,
      };

        if (existing?.id) {
          await supabase
            .from("parcelamentos_mensal" as any)
            .update(payload)
            .eq("id", existing.id);
        } else {
          await supabase.from("parcelamentos_mensal" as any).insert(payload);
        }
      toast.success("Mês atualizado com sucesso!");

      // Refresh just the month data
      const { data } = await (supabase
        .from("parcelamentos_mensal" as any)
        .select("*")
        .eq("competencia", competencia) as any);
      const map: Record<string, ParcelamentoMensalRecord> = {};
      data?.forEach((f) => {
        map[f.parcelamento_id] = f as unknown as ParcelamentoMensalRecord;
      });
      setMensalData(map);
      setExpanded(null);
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleDeleteParcelamento = async (id: string) => {
    if (!window.confirm("Deseja realmente excluir este parcelamento? Isso removerá o histórico também.")) return;
    try {
      await supabase.from("parcelamentos").delete().eq("id", id);
      toast.success("Parcelamento excluído!");
      setParcelamentos(parcelamentos.filter((p) => p.id !== id));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleToggleEncerrado = async (p: ParcelamentoRecord) => {
    const isAtualmenteEncerrado = calcIsEncerrado(p);
    // Para reabrir, forçamos 'encerrado' para false E removemos a 'previsao_termino'
    // se ela já tiver passado, para não fechar automaticamente de novo.
    // Mas o mais seguro para "reabrir" é apenas setar a flag `encerrado` e
    // deixar a data original. Na lógica, `previsao_termino` ainda forçaria encerrado.
    // Como a instrução era ter um controle manual da aba, vamos usar a flag `encerrado`
    // e para forçar reabrir podemos precisar limpar a data. Para o escopo pedido,
    // o foco é encerrar manualmente.

    // Simplificando o pedido: Mudar a flag `encerrado` inverte a situação?
    // Se "Em Andamento (isEncerrado = false)", marcamos encerrado = true.
    // Se "Encerrado (isEncerrado = true)", marcamos encerrado = false E podemos ter que adiar a previsão 
    // ou apenas dar prioridade a flag false se quisermos um override? 
    // Vamos apenas rodar a flag `encerrado` boolean pra simular ação manual
    try {
      const newVal = !p.encerrado;
      // Se tentou re-abrir mas a data já passou, alertar? Ou limpar a data?
      // Vamos apagar a data de encerramento se ele explicitamente reabrir para não dar conflito 
      const payload: Partial<ParcelamentoRecord> = { encerrado: newVal };

      if (!newVal && p.previsao_termino) {
        const hoje = new Date();
        hoje.setHours(0, 0, 0, 0);
        const prev = new Date(p.previsao_termino);
        prev.setHours(0, 0, 0, 0);
        if (isBefore(prev, hoje) || isSameDay(prev, hoje)) {
          if (window.confirm("A previsão de término deste parcelamento já passou. Para reabri-lo, a previsão será limpa. Deseja continuar?")) {
            payload.previsao_termino = null;
          } else {
            return;
          }
        }
      }

      const { error } = await supabase.from("parcelamentos").update(payload).eq("id", p.id);
      if (error) throw error;

      toast.success(newVal ? "Parcelamento encerrado." : "Parcelamento reaberto.");
      setParcelamentos(parcelamentos.map(item => item.id === p.id ? { ...item, ...payload } : item));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const updateForm = (id: string, field: string, value: string | GuiaStatus | null) => {
    setEditForm((prev) => ({
      ...prev,
      [id]: { ...prev[id], [field]: value },
    }));
  };

  const inputCls =
    "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";

  const completedCount = parcelamentos.filter(
    (p) =>
      mensalData[p.id]?.status === "enviada" ||
      mensalData[p.id]?.status === "gerada"
  ).length;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full sm:w-auto">
          <FavoriteToggleButton moduleId="parcelamentos" />
          <div>
            <h2 className="text-lg font-bold text-card-foreground">Parcelamentos</h2>
            <p className="text-xs text-muted-foreground">Gestão de parcelamentos, acompanhamento e emissão de guias mensais.</p>
          </div>
        </div>
        <div className="flex gap-3">
          <input
            type="month"
            value={competencia}
            onChange={(e) => setCompetencia(e.target.value)}
            className="px-4 py-2 border border-border rounded-xl bg-background text-foreground font-semibold outline-none focus:ring-2 focus:ring-primary"
          />
          <button
            onClick={() => navigate("/parcelamentos/novo")}
            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
            style={{ background: "var(--gradient-primary)" }}
          >
            <Plus size={18} /> Novo Parcelamento
          </button>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Total Cadastrados
          </p>
          <p className="text-2xl font-bold text-primary mt-1">
            {parcelamentos.length}
          </p>
        </div>
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Mês Concluído
          </p>
          <p className="text-2xl font-bold text-success mt-1">
            {completedCount}
          </p>
        </div>
        <div className="stat-card">
          <p className="text-xs text-muted-foreground font-medium uppercase">
            Pendentes
          </p>
          <p className="text-2xl font-bold text-warning mt-1">
            {parcelamentos.length - completedCount}
          </p>
        </div>
      </div>

      <div className="relative max-w-sm">
        <Search
          size={16}
          className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground"
        />
        <input
          type="text"
          placeholder="Buscar por nome ou CPF/CNPJ..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
        />
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "andamento"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("andamento")}
        >
          Em Andamento
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "encerrados"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("encerrados")}
        >
          Parcelamentos Encerrados
        </button>
      </div>

      <div className="space-y-3">
        {filtered.length === 0 ? (
          <div className="text-center py-12 bg-card border border-border rounded-xl text-muted-foreground">
            {search
              ? "Nenhum parcelamento encontrado na busca."
              : "Nenhum parcelamento cadastrado. Clique em Novo Parcelamento para começar."}
          </div>
        ) : (
          filtered.map((p) => {
            const isOpen = expanded === p.id;
            const form = editForm[p.id] || {};
            const done =
              mensalData[p.id]?.status === "enviada" ||
              mensalData[p.id]?.status === "gerada";

            return (
              <div key={p.id} className="module-card !p-0 overflow-hidden">
                <div
                  className="flex flex-col sm:flex-row sm:items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors gap-4"
                  onClick={() => toggleExpand(p.id)}
                >
                  <div className="flex items-center gap-3">
                    {done ? (
                      <CheckCircle size={18} className="text-success" />
                    ) : (
                      <Circle size={18} className="text-muted-foreground" />
                    )}
                    <div>
                      <p className="font-semibold text-card-foreground">
                        {p.nome_pessoa_fisica}
                      </p>
                      <p className="text-xs text-muted-foreground mt-0.5">
                        {p.cpf_pessoa_fisica || "S/N"} • {p.tipo_parcelamento} •{" "}
                        {p.qtd_parcelas} Parcelas
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center justify-between sm:justify-end gap-4 w-full sm:w-auto">
                    <span
                      className={`badge-status ${done ? "badge-success" : "badge-warning"
                        }`}
                    >
                      {mensalData[p.id]?.status === "enviada"
                        ? "Enviada"
                        : mensalData[p.id]?.status === "gerada"
                          ? "Gerada"
                          : "Pendente"}
                    </span>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleToggleEncerrado(p);
                      }}
                      className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${calcIsEncerrado(p) ? 'border-border text-foreground bg-muted/50 hover:bg-muted' : 'border-destructive text-destructive bg-destructive/10 hover:bg-destructive/20'}`}
                    >
                      {calcIsEncerrado(p) ? 'Reabrir' : 'Encerrar'}
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDeleteParcelamento(p.id);
                      }}
                      className="p-1.5 text-muted-foreground hover:text-destructive transition-colors ml-2"
                      title="Excluir este parcelamento de todos os meses"
                    >
                      <Trash2 size={16} />
                    </button>
                    {isOpen ? (
                      <ChevronUp size={16} className="text-muted-foreground" />
                    ) : (
                      <ChevronDown
                        size={16}
                        className="text-muted-foreground"
                      />
                    )}
                  </div>
                </div>

                {isOpen && (
                  <div className="border-t border-border bg-muted/20">
                    <div className="p-5 border-b border-border/50 grid grid-cols-2 md:grid-cols-4 gap-4 bg-muted/10 text-xs">
                      <div>
                        <span className="text-muted-foreground block mb-1">
                          Início
                        </span>
                        <span className="font-medium text-foreground">
                          {p.data_inicio
                            ? formatDateBR(p.data_inicio)
                            : "—"}
                        </span>
                      </div>
                      <div className="space-y-1">
                        <p className="description-label">Término Estimado</p>
                        <p className="description-value">
                          {p.previsao_termino ? formatDateBR(p.previsao_termino) : "—"}
                        </p>
                      </div>
                      <div>
                        <span className="text-muted-foreground block mb-1">
                          Envio Fixo
                        </span>
                        <span className="font-medium text-foreground">
                          {p.forma_envio || "—"}
                        </span>
                      </div>
                      <div className="md:col-span-1">
                        <span className="text-muted-foreground block mb-1">
                          Acesso:{" "}
                          <strong className="text-primary font-medium">
                            {p.metodo_login === "gov_br"
                              ? "Gov.br"
                              : p.metodo_login === "codigo_sn"
                                ? "Cód. AC. Simples Nacional"
                                : "Procuração"}
                          </strong>
                        </span>
                        <span className="font-mono text-foreground tracking-tight">
                          {p.metodo_login === "gov_br" &&
                            `L: ${p.login_gov_br || "-"} | S: ${p.senha_gov_br || "-"
                            }`}
                          {p.metodo_login === "codigo_sn" &&
                            `Cód: ${p.codigo_sn || "-"}`}
                          {p.metodo_login === "procuracao" && "Acesso Padrão"}
                        </span>
                      </div>
                    </div>
                    <div className="p-5 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                          <label className={labelCls}>Status no Mês</label>
                          <select
                            value={form.status || "pendente"}
                            onChange={(e) =>
                              updateForm(p.id, "status", e.target.value)
                            }
                            className={inputCls}
                          >
                            <option value="pendente">Pendente para Envio</option>
                            <option value="gerada">Em Andamento</option>
                            <option value="enviada">Concluída / Enviada</option>
                          </select>
                        </div>
                        <div>
                          <label className={labelCls}>Data do Envio (Opcional)</label>
                          <input
                            type="date"
                            value={form.data_envio || ""}
                            onChange={(e) =>
                              updateForm(p.id, "data_envio", e.target.value)
                            }
                            className={inputCls}
                          />
                        </div>
                        <div>
                          <label className={labelCls}>Anotação Breve</label>
                          <input
                            value={form.observacoes || ""}
                            onChange={(e) =>
                              updateForm(p.id, "observacoes", e.target.value)
                            }
                            className={inputCls}
                            placeholder="Ex: Falta emitir boleto atualizado"
                          />
                        </div>
                      </div>
                      <div className="flex justify-end pt-2">
                        <button
                          onClick={() => handleSaveMensal(p.id)}
                          className="flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md transition-all hover:opacity-90 active:scale-95"
                          style={{ background: "var(--gradient-primary)" }}
                        >
                          <Save size={16} /> Salvar Mês de{" "}
                          {competencia.split("-").reverse().join("/")}
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default ParcelamentosPage;

import React, { useEffect, useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { Save, User, Lock, Upload, Camera, Loader2 } from "lucide-react";
import { maskCPF } from "@/lib/utils";


interface Endereco {
  cep: string;
  logradouro: string;
  numero: string;
  complemento: string;
  bairro: string;
  cidade: string;
  estado: string;
}

const PerfilPage: React.FC = () => {
  const { user } = useAuth();
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [upLoading, setUpLoading] = useState(false);
  const [form, setForm] = useState({
    nome_completo: "",
    cpf: "",
    telefone: "",
    data_nascimento: "",
    foto_url: "",
    endereco: { cep: "", logradouro: "", numero: "", complemento: "", bairro: "", cidade: "", estado: "" } as Endereco,
  });

  useEffect(() => {
    const load = async () => {
      if (!user) return;
      const { data } = await supabase.from("profiles").select("*").eq("user_id", user.id).single();
      if (data) {
        const end = (data.endereco || {}) as any;
        setForm({
          nome_completo: data.nome_completo || "",
          cpf: data.cpf || "",
          telefone: data.telefone || "",
          data_nascimento: data.data_nascimento || "",
          foto_url: data.foto_url || "",
          endereco: {
            cep: end.cep || "", logradouro: end.logradouro || "", numero: end.numero || "",
            complemento: end.complemento || "", bairro: end.bairro || "", cidade: end.cidade || "", estado: end.estado || "",
          },
        });
      }
      setLoading(false);
    };
    load();
  }, [user]);



  const formatCEP = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 8);
    return digits.replace(/(\d{5})(\d)/, "$1-$2");
  };

  const formatTelefone = (value: string) => {
    const digits = value.replace(/\D/g, "").slice(0, 11);
    if (digits.length <= 10) return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{4})(\d)/, "$1-$2");
    return digits.replace(/(\d{2})(\d)/, "($1) $2").replace(/(\d{5})(\d)/, "$1-$2");
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;

    setUpLoading(true);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${user.id}_${Math.random()}.${fileExt}`;
      const filePath = `avatars/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('documentos')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('documentos')
        .getPublicUrl(filePath);

      const { error: updateError } = await supabase
        .from('profiles')
        .update({ foto_url: publicUrl })
        .eq('user_id', user.id);

      if (updateError) throw updateError;

      setForm(prev => ({ ...prev, foto_url: publicUrl }));
      toast.success("Foto atualizada com sucesso!");
    } catch (err: any) {
      toast.error("Erro ao fazer upload: " + err.message);
    } finally {
      setUpLoading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.nome_completo.trim() || !form.cpf.trim()) {
      toast.error("Nome e CPF são obrigatórios");
      return;
    }
    setSaving(true);
    try {
      const { error } = await supabase.from("profiles").update({
        nome_completo: form.nome_completo,
        cpf: form.cpf,
        telefone: form.telefone,
        data_nascimento: form.data_nascimento || null,
        endereco: form.endereco as any,
      }).eq("user_id", user!.id);
      if (error) throw error;
      toast.success("Perfil atualizado com sucesso!");
    } catch (err: any) {
      toast.error("Erro: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const updateEndereco = (key: keyof Endereco, value: string) => {
    setForm(prev => ({ ...prev, endereco: { ...prev.endereco, [key]: value } }));
  };

  const estados = ["AC", "AL", "AM", "AP", "BA", "CE", "DF", "ES", "GO", "MA", "MG", "MS", "MT", "PA", "PB", "PE", "PI", "PR", "RJ", "RN", "RO", "RR", "RS", "SC", "SE", "SP", "TO"];

  if (loading) return <div className="flex items-center justify-center p-8"><p className="text-muted-foreground">Carregando...</p></div>;

  return (
    <div className="space-y-6 animate-fade-in max-w-4xl mx-auto py-8">
      <div className="flex flex-col items-center gap-4 mb-8 text-center">
        <div className="relative group">
          <div className="w-32 h-32 rounded-full border-4 border-background shadow-xl overflow-hidden bg-primary/10 flex items-center justify-center relative">
            {form.foto_url ? (
              <img src={form.foto_url} alt="Profile" className="w-full h-full object-cover" />
            ) : (
              <User size={64} className="text-primary" />
            )}
            {upLoading && (
              <div className="absolute inset-0 bg-background/50 flex items-center justify-center">
                <Loader2 className="animate-spin text-primary" size={32} />
              </div>
            )}
          </div>
          <label htmlFor="foto-upload" className="absolute bottom-1 right-1 p-2.5 rounded-full bg-primary text-primary-foreground shadow-lg cursor-pointer hover:scale-110 active:scale-95 transition-all">
            <Camera size={18} />
            <input 
              id="foto-upload" 
              type="file" 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload}
              disabled={upLoading}
            />
          </label>
        </div>
        <div>
          <h3 className="text-2xl font-bold text-card-foreground">Meu Perfil</h3>
          <p className="text-muted-foreground">Gerencie suas informações pessoais e de acesso</p>
        </div>
      </div>

      <div className="module-card space-y-8">
        <form onSubmit={handleSave} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-card-foreground mb-1">Nome Completo</label>
              <input value={form.nome_completo} onChange={e => setForm({ ...form, nome_completo: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">CPF</label>
              <input value={form.cpf} onChange={e => setForm({ ...form, cpf: maskCPF(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />

            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Telefone</label>
              <input value={form.telefone} onChange={e => setForm({ ...form, telefone: formatTelefone(e.target.value) })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">Data de Nascimento</label>
              <input type="date" value={form.data_nascimento} onChange={e => setForm({ ...form, data_nascimento: e.target.value })} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-card-foreground mb-1">E-mail</label>
              <input value={user?.email || ""} disabled className="w-full px-3 py-2.5 border border-border rounded-lg bg-muted/50 text-muted-foreground text-sm cursor-not-allowed" />
            </div>
          </div>

          <div className="border-t border-border pt-6">
            <h2 className="text-base font-semibold text-card-foreground mb-4">Endereço</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">CEP</label>
                <input value={form.endereco.cep} onChange={e => updateEndereco("cep", formatCEP(e.target.value))} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-card-foreground mb-1">Logradouro</label>
                <input value={form.endereco.logradouro} onChange={e => updateEndereco("logradouro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Número</label>
                <input value={form.endereco.numero} onChange={e => updateEndereco("numero", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Complemento</label>
                <input value={form.endereco.complemento} onChange={e => updateEndereco("complemento", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Bairro</label>
                <input value={form.endereco.bairro} onChange={e => updateEndereco("bairro", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Cidade</label>
                <input value={form.endereco.cidade} onChange={e => updateEndereco("cidade", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-card-foreground mb-1">Estado</label>
                <select value={form.endereco.estado} onChange={e => updateEndereco("estado", e.target.value)} className="w-full px-3 py-2.5 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none">
                  <option value="">Selecione</option>
                  {estados.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                </select>
              </div>
            </div>
          </div>

          <div className="flex justify-end pt-4">
            <button type="submit" disabled={saving} className="flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-semibold text-primary-foreground shadow-md disabled:opacity-50" style={{ background: "var(--gradient-primary)" }}>
              <Save size={16} /> {saving ? "Salvando..." : "Salvar Alterações"}
            </button>
          </div>
        </form>

        {/* Seção Alterar Senha - Agora fora do form principal */}
        <div className="bg-card border border-border rounded-2xl overflow-hidden shadow-sm">
          <div className="p-6 border-b border-border bg-muted/30 flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-orange-500/10 text-orange-500 flex items-center justify-center">
              <Lock size={20} />
            </div>
            <div>
              <h2 className="text-lg font-bold">Alterar Senha</h2>
              <p className="text-sm text-muted-foreground">Mantenha sua conta segura</p>
            </div>
          </div>
          <div className="p-6">
            <form onSubmit={async (e) => {
              e.preventDefault();
              const target = e.currentTarget;
              const newPassword = (target.elements.namedItem("newPassword") as HTMLInputElement).value;
              const confirmPassword = (target.elements.namedItem("confirmPassword") as HTMLInputElement).value;

              if (newPassword.length < 8) {
                toast.error("A nova senha deve ter pelo menos 8 caracteres.");
                return;
              }
              if (newPassword !== confirmPassword) {
                toast.error("As senhas não coincidem.");
                return;
              }

              try {
                const { error } = await supabase.auth.updateUser({ password: newPassword });
                if (error) throw error;
                toast.success("Senha alterada com sucesso!");
                target.reset();
              } catch (err: any) {
                toast.error("Erro ao alterar senha: " + err.message);
              }
            }} className="space-y-4 max-w-md">
              <div className="space-y-2">
                <label className="text-sm font-semibold ml-1">Nova Senha</label>
                <input
                  name="newPassword"
                  type="password"
                  placeholder="No mínimo 8 caracteres"
                  className="w-full px-4 py-3 border border-border rounded-xl bg-background outline-none focus:ring-2 focus:ring-primary transition-all"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold ml-1">Confirmar Nova Senha</label>
                <input
                  name="confirmPassword"
                  type="password"
                  placeholder="Repita a nova senha"
                  className="w-full px-4 py-3 border border-border rounded-xl bg-background outline-none focus:ring-2 focus:ring-primary transition-all"
                  required
                />
              </div>
              <button
                type="submit"
                className="px-8 py-3 bg-primary text-primary-foreground font-bold rounded-xl shadow-lg transition-all hover:scale-[1.02] active:scale-[0.98]"
              >
                Atualizar Senha
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PerfilPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Search, ChevronDown, ChevronUp, Save, CheckCircle, Circle } from "lucide-react";
import { toast } from "sonner";
import { useEmpresas } from "@/hooks/useEmpresas";
import { usePessoal } from "@/hooks/usePessoal";
import { PessoalRecord, GuiaStatus } from "@/types/pessoal";
import { PageHeaderSkeleton, TableSkeleton } from "@/components/PageSkeleton";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

const PessoalPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("pessoal");
  const [search, setSearch] = useState("");
  const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
  const [expanded, setExpanded] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Record<string, any>>({});
  const [activeTab, setActiveTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");
  const [filterStatus, setFilterStatus] = useState<"todos" | "pendente" | "concluido">("todos");

  const { pessoalData, loading: pessoalLoading, savePessoalRecord } = usePessoal(competencia);

  const filtered = React.useMemo(() => {
    return empresas.filter(e => {
      const matchSearch = e.nome_empresa?.toLowerCase().includes(search.toLowerCase()) || e.cnpj?.includes(search);

      let matchTab = false;
      if (activeTab === "ativas") {
        matchTab = (e.situacao === "ativa" || !e.situacao) && e.porte_empresa !== "mei";
      } else if (activeTab === "mei") {
        matchTab = e.situacao === "mei" || ((e.situacao === "ativa" || !e.situacao) && e.porte_empresa === "mei");
      } else if (activeTab === "paralisadas") {
        matchTab = e.situacao === "paralisada";
      } else if (activeTab === "baixadas") {
        matchTab = e.situacao === "baixada";
      } else if (activeTab === "entregue") {
        matchTab = e.situacao === "entregue";
      }

      let matchStatus = true;
      if (filterStatus !== "todos") {
        const record = pessoalData[e.id];
        if (!record) {
          matchStatus = filterStatus === 'pendente';
        } else {
          const checks = [];
          if (record.possui_vt) checks.push(record.vt_status);
          if (record.possui_va) checks.push(record.va_status);
          if (record.possui_vc) checks.push(record.vc_status);
          checks.push(record.inss_status);
          checks.push(record.fgts_status);
          
          const isAllConcluido = checks.every(s => s === 'enviada' || s === 'gerada' || s === 'isento') && record.dctf_web_gerada;
          matchStatus = filterStatus === 'concluido' ? isAllConcluido : !isAllConcluido;
        }
      }

      return matchSearch && matchTab && matchStatus;
    });
  }, [empresas, pessoalData, search, activeTab, filterStatus]);

  const toggleExpand = async (id: string) => {
    if (expanded === id) { setExpanded(null); return; }
    setExpanded(id);
    const existing = (pessoalData[id] || {}) as Partial<PessoalRecord> & Record<string, any>;
    
    let infoGerais = {
      forma_envio: "", qtd_funcionarios: 0, qtd_pro_labore: 0,
      possui_vt: false, possui_va: false, possui_vc: false,
      possui_recibos: false, qtd_recibos: 0
    };

    if (!existing.id) {
      const { data: prev } = await supabase.from("pessoal").select("*").eq("empresa_id", id).order("competencia", { ascending: false }).limit(1);
      if (prev?.[0]) {
        infoGerais = {
          forma_envio: prev[0].forma_envio || "",
          qtd_funcionarios: prev[0].qtd_funcionarios || 0,
          qtd_pro_labore: prev[0].qtd_pro_labore || 0,
          possui_vt: prev[0].possui_vt || false,
          possui_va: prev[0].possui_va || false,
          possui_vc: prev[0].possui_vc || false,
          possui_recibos: prev[0].possui_recibos || false,
          qtd_recibos: prev[0].qtd_recibos || 0
        };
      }
    } else {
      infoGerais = {
        forma_envio: existing.forma_envio || "",
        qtd_funcionarios: existing.qtd_funcionarios || 0,
        qtd_pro_labore: existing.qtd_pro_labore || 0,
        possui_vt: existing.possui_vt || false,
        possui_va: existing.possui_va || false,
        possui_vc: existing.possui_vc || false,
        possui_recibos: existing.possui_recibos || false,
        qtd_recibos: existing.qtd_recibos || 0
      };
    }

    setEditForm(prev => ({
      ...prev, [id]: {
        ...infoGerais,
        vt_status: existing.vt_status || "pendente", vt_data_envio: existing.vt_data_envio || "",
        va_status: existing.va_status || "pendente", va_data_envio: existing.va_data_envio || "",
        vc_status: existing.vc_status || "pendente", vc_data_envio: existing.vc_data_envio || "",
        inss_status: existing.inss_status || "pendente", inss_data_envio: existing.inss_data_envio || "",
        fgts_status: existing.fgts_status || "pendente", fgts_data_envio: existing.fgts_data_envio || "",
        dctf_web_gerada: existing.dctf_web_gerada || false, dctf_web_data_envio: existing.dctf_web_data_envio || "",
      }
    }));
  };

  const handleSave = async (empresaId: string) => {
    const form = editForm[empresaId];
    const existing = pessoalData[empresaId];
    try {
      const payload = {
        empresa_id: empresaId, competencia, forma_envio: form.forma_envio || null,
        qtd_funcionarios: parseInt(String(form.qtd_funcionarios || 0)) || 0, 
        qtd_pro_labore: parseInt(String(form.qtd_pro_labore || 0)) || 0,
        possui_vt: !!form.possui_vt, possui_va: !!form.possui_va,
        possui_vc: !!form.possui_vc, possui_recibos: !!form.possui_recibos,
        qtd_recibos: parseInt(String(form.qtd_recibos || 0)) || 0,
        vt_status: form.vt_status as GuiaStatus, vt_data_envio: form.vt_data_envio || null,
        va_status: form.va_status as GuiaStatus, va_data_envio: form.va_data_envio || null,
        vc_status: form.vc_status as GuiaStatus, vc_data_envio: form.vc_data_envio || null,
        inss_status: form.inss_status as GuiaStatus, inss_data_envio: form.inss_data_envio || null,
        fgts_status: form.fgts_status as GuiaStatus, fgts_data_envio: form.fgts_data_envio || null,
        dctf_web_gerada: !!form.dctf_web_gerada, dctf_web_data_envio: form.dctf_web_data_envio || null,
      };
      const success = await savePessoalRecord(payload);
      if (success) {
        toast.success("Dados salvos com sucesso!");
        setExpanded(null);
      }
    } catch (err: any) { toast.error(err.message); }
  };

  const updateForm = (empresaId: string, field: string, value: string | number | boolean | null) => {
    setEditForm(prev => ({ ...prev, [empresaId]: { ...prev[empresaId], [field]: value } }));
  };

  const inputCls = "w-full px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none";
  const labelCls = "block text-xs font-medium text-muted-foreground mb-1";
  const completedCount = filtered.filter(e => pessoalData[e.id]?.dctf_web_gerada).length;

  if (loading || pessoalLoading) {
    return (
      <div className="space-y-6 animate-fade-in">
        <PageHeaderSkeleton />
        <TableSkeleton rows={8} />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex bg-card border border-border/60 rounded-xl shadow-sm overflow-hidden h-12">
          <div className="px-4 flex items-center gap-2 border-r border-border/60">
            <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Empresas</span>
            <span className="text-lg font-black text-primary">{filtered.length}</span>
          </div>
          <div className="px-4 flex items-center gap-2 border-r border-border/60">
            <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Concluídas</span>
            <span className="text-lg font-black text-emerald-500">{completedCount}</span>
          </div>
          <div className="px-4 flex items-center gap-2 bg-warning/5">
            <span className="text-[10px] text-warning font-bold uppercase tracking-wider">Pendentes</span>
            <span className="text-lg font-black text-warning">{filtered.length - completedCount}</span>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 w-full sm:w-auto items-center">
          <FavoriteToggleButton moduleId="pessoal" />
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
            <input
              type="text"
              placeholder="Buscar empresa..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9 pr-4 h-10 bg-card border border-border/60 rounded-xl focus:ring-2 focus:ring-primary outline-none text-[13px] w-full sm:w-56"
            />
          </div>
          <input
            type="month"
            value={competencia}
            onChange={(e) => setCompetencia(e.target.value)}
            className="px-4 h-10 bg-card border border-border/60 rounded-xl focus:ring-2 focus:ring-primary outline-none text-[13px] font-medium"
          />
        </div>

        <div className="flex bg-muted/50 p-1 rounded-lg self-end">
          <button 
            onClick={() => setFilterStatus("todos")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "todos" ? "bg-card text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Todos
          </button>
          <button 
            onClick={() => setFilterStatus("pendente")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "pendente" ? "bg-card text-orange-500 shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Pendentes
          </button>
          <button 
            onClick={() => setFilterStatus("concluido")}
            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${filterStatus === "concluido" ? "bg-card text-green-500 shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
          >
            Concluídos
          </button>
        </div>
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("baixadas")}
        >
          Empresas Baixadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === "entregue"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveTab("entregue")}
        >
          Empresas Entregues
        </button>
      </div>

      <div className="space-y-3">
        {filtered.map(emp => {
          const isOpen = expanded === emp.id;
          const form = editForm[emp.id] || {};
          const done = pessoalData[emp.id]?.dctf_web_gerada;
          return (
            <div key={emp.id} className="module-card !p-0 overflow-hidden">
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/30 transition-colors" onClick={() => toggleExpand(emp.id)}>
                <div className="flex items-center gap-3">{done ? <CheckCircle size={18} className="text-success" /> : <Circle size={18} className="text-muted-foreground" />}<div><p className="font-medium text-card-foreground">{emp.nome_empresa}</p><p className="text-xs text-muted-foreground">{emp.cnpj || "—"}</p></div></div>
                <div className="flex items-center gap-2"><span className={`badge-status ${done ? "badge-success" : "badge-warning"}`}>{done ? "Concluído" : "Pendente"}</span>{isOpen ? <ChevronUp size={16} className="text-muted-foreground" /> : <ChevronDown size={16} className="text-muted-foreground" />}</div>
              </div>
              {isOpen && (
                <div className="border-t border-border p-5 space-y-5 bg-muted/10">
                  {/* Informações */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Informações</h3>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                      <div><label className={labelCls}>Forma de Envio</label><input value={form.forma_envio || ""} onChange={e => updateForm(emp.id, "forma_envio", e.target.value)} className={inputCls} /></div>
                      <div><label className={labelCls}>Qtd Funcionários</label><input type="number" value={form.qtd_funcionarios || 0} onChange={e => updateForm(emp.id, "qtd_funcionarios", e.target.value)} className={inputCls} /></div>
                      <div><label className={labelCls}>Qtd Pró-labore</label><input type="number" value={form.qtd_pro_labore || 0} onChange={e => updateForm(emp.id, "qtd_pro_labore", e.target.value)} className={inputCls} /></div>
                    </div>
                  </div>

                  {/* Trabalhistas */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Trabalhistas - {competencia}</h3>
                    <div className="space-y-3">
                      {/* Recibos - campo de quantidade */}
                      <div className="grid grid-cols-3 gap-3 items-center">
                        <label className="flex items-center gap-2 text-sm font-medium text-card-foreground cursor-pointer">
                          <input type="checkbox" checked={form.possui_recibos || false} onChange={e => updateForm(emp.id, "possui_recibos", e.target.checked)} className="w-4 h-4 rounded border-border text-primary" /> Recibos
                        </label>
                        {form.possui_recibos ? (
                          <div><label className={labelCls}>Qtd Recibos</label><input type="number" value={form.qtd_recibos || 0} onChange={e => updateForm(emp.id, "qtd_recibos", e.target.value)} className={inputCls} /></div>
                        ) : <div />}
                        <div />
                      </div>
                      {/* VT, VA, VC - checkbox + status + data */}
                      {[
                        { label: "VT", checkKey: "possui_vt", statusKey: "vt_status", dateKey: "vt_data_envio" },
                        { label: "VA", checkKey: "possui_va", statusKey: "va_status", dateKey: "va_data_envio" },
                        { label: "VC", checkKey: "possui_vc", statusKey: "vc_status", dateKey: "vc_data_envio" },
                      ].map((item: { label: string; checkKey: keyof PessoalRecord; statusKey: keyof PessoalRecord; dateKey: keyof PessoalRecord }) => (
                        <div key={item.label} className="grid grid-cols-3 gap-3 items-center">
                          <label className="flex items-center gap-2 text-sm font-medium text-card-foreground cursor-pointer">
                            <input type="checkbox" checked={form[item.checkKey] || false} onChange={e => updateForm(emp.id, item.checkKey, e.target.checked)} className="w-4 h-4 rounded border-border text-primary" /> {item.label}
                          </label>
                          {form[item.checkKey] ? (
                            <>
                              <select value={form[item.statusKey] || "pendente"} onChange={e => updateForm(emp.id, item.statusKey, e.target.value)} className={inputCls}>
                                <option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option>
                              </select>
                              <input type="date" value={form[item.dateKey] || ""} onChange={e => updateForm(emp.id, item.dateKey, e.target.value)} className={inputCls} />
                            </>
                          ) : (<><div /><div /></>)}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Encargos */}
                  <div><h3 className="text-sm font-semibold text-card-foreground mb-3">Encargos - {competencia}</h3>
                    <div className="space-y-3">
                      {([{ label: "INSS", statusKey: "inss_status", dateKey: "inss_data_envio" }, { label: "FGTS", statusKey: "fgts_status", dateKey: "fgts_data_envio" }] as const).map((enc) => (
                        <div key={enc.label} className="grid grid-cols-3 gap-3 items-center">
                          <span className="text-sm font-medium text-card-foreground">{enc.label}</span>
                          <select value={form[enc.statusKey] || "pendente"} onChange={e => updateForm(emp.id, enc.statusKey, e.target.value)} className={inputCls}>
                            <option value="pendente">Pendente</option><option value="gerada">Gerada</option><option value="enviada">Enviada</option>
                          </select>
                          <input type="date" value={form[enc.dateKey] || ""} onChange={e => updateForm(emp.id, enc.dateKey, e.target.value)} className={inputCls} />
                        </div>
                      ))}
                      <div className="grid grid-cols-3 gap-3 items-center">
                        <span className="text-sm font-medium text-card-foreground">DCTF Web</span>
                        <select value={form.dctf_web_gerada ? "sim" : "nao"} onChange={e => updateForm(emp.id, "dctf_web_gerada", e.target.value === "sim")} className={inputCls}>
                          <option value="nao">Não Gerada</option><option value="sim">Gerada</option>
                        </select>
                        {form.dctf_web_gerada ? (
                          <input type="date" value={form.dctf_web_data_envio || ""} onChange={e => updateForm(emp.id, "dctf_web_data_envio", e.target.value)} className={inputCls} />
                        ) : <div />}
                      </div>
                    </div>
                  </div>

                  <div className="flex justify-end"><button onClick={() => handleSave(emp.id)} className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-primary-foreground shadow-md" style={{ background: "var(--gradient-primary)" }}><Save size={14} /> Salvar</button></div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PessoalPage;

import React, { useEffect, useState } from "react";
import { formatDateBR } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { FileBadge, FileText, Download, Eye, Clock, ShieldCheck, Search } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";

const PortalCertidoesPage: React.FC = () => {
    const { userData } = useAuth();
    const [certidoes, setCertidoes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");

    useEffect(() => {
        const loadCertidoes = async () => {
            if (!userData?.empresaId) return;

            const { data, error } = await supabase
                .from("certidoes")
                .select("*")
                .eq("empresa_id", userData.empresaId);

            if (error) {
                toast.error("Erro ao carregar certidões");
            } else {
                setCertidoes(data || []);
            }
            setLoading(false);
        };

        loadCertidoes();
    }, [userData]);

    const filtered = certidoes.filter(c =>
        c.tipo_certidao?.toLowerCase().includes(search.toLowerCase())
    );

    const calcDias = (data?: string | null) => {
        if (!data) return 999;
        return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-inner">
                        <FileBadge size={24} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight">Certidões Negativas (CND)</h1>
                        <p className="text-muted-foreground">Regularidade fiscal da sua empresa</p>
                    </div>
                </div>

                <div className="relative max-w-xs w-full">
                    <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                    <Input
                        placeholder="Buscar certidão..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-9 bg-card/50"
                    />
                </div>
            </div>

            {filtered.length === 0 ? (
                <Card className="border-dashed border-2 bg-muted/20">
                    <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                        <ShieldCheck size={48} className="text-muted-foreground/30 mb-4" />
                        <p className="text-lg font-medium text-muted-foreground">
                            {search ? "Nenhuma certidão corresponde à sua busca." : "Nenhuma certidão anexada no momento."}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filtered.map((cert) => {
                        const dias = calcDias(cert.vencimento);
                        const isVencendo = dias <= 30 && dias >= 0;
                        const isVencido = dias < 0;

                        return (
                            <Card key={cert.id} className="overflow-hidden border-none shadow-md hover:shadow-lg transition-shadow bg-card/50 backdrop-blur-sm">
                                <CardHeader className="pb-2 border-b border-border/10 mb-2">
                                    <div className="flex items-center justify-between">
                                        <CardTitle className="text-base font-bold flex items-center gap-2">
                                            <FileText size={16} className="text-primary" />
                                            {cert.tipo_certidao}
                                        </CardTitle>
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${isVencido ? "bg-destructive/10 text-destructive" :
                                            isVencendo ? "bg-amber-500/10 text-amber-500" :
                                                "bg-green-500/10 text-green-500"
                                            }`}>
                                            {isVencido ? "Vencida" : isVencendo ? "A Vencer" : "Válida"}
                                        </span>
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="space-y-2">
                                        <div className="flex items-center justify-between text-xs">
                                            <span className="text-muted-foreground flex items-center gap-1">
                                                <Clock size={12} /> Validade:
                                            </span>
                                            <span className={`font-semibold ${isVencido ? "text-destructive" : isVencendo ? "text-amber-500" : ""}`}>
                                                {cert.vencimento ? formatDateBR(cert.vencimento) : "Indeterminada"}
                                            </span>
                                        </div>
                                    </div>

                                    <div className="flex gap-2 pt-2 border-t border-border/50">
                                        {cert.arquivo_url ? (
                                            <>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="flex-1 gap-2 text-xs"
                                                    onClick={() => window.open(cert.arquivo_url, "_blank")}
                                                >
                                                    <Eye size={14} /> Ver
                                                </Button>
                                                <Button
                                                    variant="secondary"
                                                    size="sm"
                                                    className="flex-1 gap-2 text-xs"
                                                    onClick={() => {
                                                        const a = document.createElement("a");
                                                        a.href = cert.arquivo_url;
                                                        a.download = `${cert.tipo_certidao}.pdf`;
                                                        a.target = "_blank";
                                                        a.click();
                                                    }}
                                                >
                                                    <Download size={14} /> Baixar
                                                </Button>
                                            </>
                                        ) : (
                                            <div className="w-full py-2 px-3 rounded-lg bg-muted text-center text-[10px] text-muted-foreground italic">
                                                Documento não anexado pela contabilidade
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default PortalCertidoesPage;

import React from "react";
import { useAuth } from "@/contexts/AuthContext";
import {
    Building2, FileText, CheckCircle, AlertCircle,
    ArrowRight, Download, MessageSquare, Clock, Search
} from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";

const PortalDashboardPage: React.FC = () => {
    const { userData } = useAuth();
    const [empresa, setEmpresa] = React.useState<any>(null);
    const [counts, setCounts] = React.useState({ lics: 0, certs: 0, msgs: 0 });

    React.useEffect(() => {
        const load = async () => {
            if (!userData?.empresaId) return;

            // Get company name
            const { data: emp } = await supabase.from("empresas").select("nome_empresa").eq("id", userData.empresaId).single();
            if (emp) setEmpresa(emp);

            // Get counts
            const { count: licCount } = await supabase.from("licencas").select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId);
            const { count: certCount } = await supabase.from("certidoes").select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId);
            const { count: msgCount } = await supabase.from("internal_messages" as any).select("*", { count: 'exact', head: true }).eq("empresa_id", userData.empresaId).eq("lida", false).eq("direcao", "escritorio_para_cliente");

            setCounts({
                lics: licCount || 0,
                certs: certCount || 0,
                msgs: msgCount || 0
            });
        };
        load();
    }, [userData]);

    const stats = [
        { label: "Licenças Ativas", value: counts.lics.toString(), icon: FileText, color: "text-amber-500", bg: "bg-amber-500/10" },
        { label: "Certidões Disponíveis", value: counts.certs.toString(), icon: CheckCircle, color: "text-green-500", bg: "bg-green-500/10" },
        { label: "Mensagens Não Lidas", value: counts.msgs.toString(), icon: MessageSquare, color: "text-blue-500", bg: "bg-blue-500/10" },
    ];

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Bem-vindo, {userData?.nome}!</h1>
                    <p className="text-muted-foreground mt-1 text-lg">
                        Acompanhe a situação da sua empresa em tempo real.
                    </p>
                </div>
                <div className="flex items-center gap-3 bg-card p-4 rounded-2xl border border-border shadow-sm">
                    <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary">
                        <Building2 size={24} />
                    </div>
                    <div>
                        <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">Sua Empresa</p>
                        <p className="font-bold text-card-foreground truncate max-w-[200px]">
                            {empresa?.nome_empresa || "Carregando..."}
                        </p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {stats.map((stat) => (
                    <div key={stat.label} className="card-premium group">
                        <div className="flex flex-row items-center justify-between mb-4">
                            <span className="text-xs font-bold text-muted-foreground uppercase tracking-widest">
                                {stat.label}
                            </span>
                            <div className={`p-2 rounded-xl ${stat.bg} ${stat.color} group-hover:scale-110 transition-transform`}>
                                <stat.icon size={20} />
                            </div>
                        </div>
                        <div className="text-4xl font-black text-card-foreground">{stat.value}</div>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Documentos Recentes */}
                <section className="space-y-4">
