export default PortalDashboardPage;

import React, { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { FileText, Download, Search, Filter, Folder, File, ExternalLink } from "lucide-react";
import { format } from "date-fns";
import { TableSkeleton } from "@/components/PageSkeleton";

const PortalDocumentosPage: React.FC = () => {
    const { userData } = useAuth();
    const [searchTerm, setSearchTerm] = useState("");

    // Fetch documents from various sources (Simplified for portal)
    // In a real scenario, this would probably be a specific 'documentos' table
    // For now, let's show documents from 'licencas', 'certidoes' and 'declaracoes'
    const { data: documentos, isLoading } = useQuery({
        queryKey: ["portal_documentos", userData?.empresaId],
        queryFn: async () => {
            if (!userData?.empresaId) return [];
            
            // Fetch Licenças
            const { data: licencas } = await supabase.from("licencas").select("id, tipo_licenca, numero_processo, created_at").eq("empresa_id", userData.empresaId);
            
            // Fetch Certidões
            const { data: certidoes } = await supabase.from("certidoes").select("id, tipo_certidao, arquivo_url, created_at").eq("empresa_id", userData.empresaId);
            
            const docs = [
                ...(licencas || []).map((l: any) => ({ id: l.id, nome: `Licença: ${l.tipo_licenca}`, info: l.numero_processo, url: null, data: l.created_at, tipo: 'Licença' })),
                ...(certidoes || []).map((c: any) => ({ id: c.id, nome: `Certidão: ${c.tipo_certidao}`, info: '', url: c.arquivo_url, data: c.created_at, tipo: 'Certidão' }))
            ];
            
            return docs.sort((a, b) => new Date(b.data).getTime() - new Date(a.data).getTime());
        },
        enabled: !!userData?.empresaId
    });

    const filteredDocs = documentos?.filter(doc => 
        doc.nome.toLowerCase().includes(searchTerm.toLowerCase()) || 
        doc.tipo.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex flex-col gap-1">
                    <h1 className="text-2xl font-black text-foreground tracking-tight">Meus Documentos</h1>
                    <p className="text-sm text-muted-foreground font-medium">Acesse as licenças, certidões e declarações da sua empresa.</p>
                </div>
                <div className="relative w-full sm:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
                    <input 
                        type="text" 
                        placeholder="Buscar documentos..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 bg-card border border-border rounded-xl text-sm focus:ring-2 focus:ring-primary outline-none transition-all"
                    />
                </div>
            </div>

            {isLoading ? (
                <TableSkeleton rows={6} />
            ) : !filteredDocs || filteredDocs.length === 0 ? (
                <div className="module-card flex flex-col items-center justify-center py-16 text-center border-dashed border-2">
                    <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mb-4">
                        <Folder size={32} className="text-muted-foreground opacity-20" />
                    </div>
                    <h3 className="font-bold text-foreground">Nenhum documento disponível</h3>
                    <p className="text-sm text-muted-foreground mt-1 max-w-xs">Os documentos disponibilizados pela contabilidade aparecerão aqui.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {filteredDocs.map((doc, idx) => (
                        <div key={idx} className="module-card group hover:border-primary/50 transition-all">
                            <div className="flex items-start justify-between mb-4">
                                <div className="p-3 rounded-2xl bg-primary/10 text-primary shadow-inner">
                                    <FileText size={24} />
                                </div>
                                <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground bg-muted px-2 py-1 rounded-lg">
                                    {doc.tipo}
                                </span>
                            </div>
                            <h3 className="font-bold text-foreground line-clamp-1 mb-1" title={doc.nome}>{doc.nome}</h3>
                            <p className="text-xs text-muted-foreground mb-4">{doc.info || doc.tipo}</p>
                            
                            <div className="flex items-center justify-between pt-4 border-t border-border/50">
                                <span className="text-[10px] font-medium text-muted-foreground">
                                    {format(new Date(doc.data), 'dd/MM/yyyy')}
                                </span>
                                {doc.url ? (
                                    <a 
                                        href={doc.url} 
                                        target="_blank" 
                                        rel="noopener noreferrer"
                                        className="flex items-center gap-1.5 text-xs font-black text-primary hover:underline group-hover:translate-x-0.5 transition-transform"
                                    >
                                        <Download size={14} /> DOWNLOAD
                                    </a>
                                ) : (
                                    <span className="text-[10px] text-muted-foreground italic">Arquivo indisponível</span>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default PortalDocumentosPage;

import React, { useEffect, useState } from "react";
import { formatDateBR } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { ScrollText, FileText, Download, Eye, Clock, ShieldCheck, AlertCircle } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";

const PortalLicencasPage: React.FC = () => {
    const { userData } = useAuth();
    const [licencas, setLicencas] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadLicencas = async () => {
            if (!userData?.empresaId) return;

            const { data, error } = await supabase
                .from("licencas")
                .select("*")
                .eq("empresa_id", userData.empresaId);

            if (error) {
                toast.error("Erro ao carregar licenças");
            } else {
                setLicencas(data || []);
            }
            setLoading(false);
        };

        loadLicencas();
    }, [userData]);

    const calcDias = (data?: string | null) => {
        if (!data) return 999;
        return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000);
    };

    const licencaLabels: Record<string, string> = {
        alvara: "Alvará de Funcionamento",
        vigilancia_sanitaria: "Vigilância Sanitária",
        corpo_bombeiros: "Corpo de Bombeiros",
        meio_ambiente: "Meio Ambiente"
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-inner">
                    <ScrollText size={24} />
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Licenças Municipais</h1>
                    <p className="text-muted-foreground">Documentação e alvarás da sua empresa</p>
                </div>
            </div>

            {licencas.length === 0 ? (
                <Card className="border-dashed border-2 bg-muted/20">
                    <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                        <ShieldCheck size={48} className="text-muted-foreground/30 mb-4" />
                        <p className="text-lg font-medium text-muted-foreground">Nenhuma licença cadastrada no momento.</p>
                        <p className="text-sm text-muted-foreground max-w-xs">
                            Sua equipe de contabilidade irá cadastrar as licenças assim que estiverem disponíveis.
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {licencas.map((lic) => {
                        const dias = calcDias(lic.vencimento);
                        const isVencendo = dias <= 30 && dias >= 0;
                        const isVencido = dias < 0;

                        return (
                            <Card key={lic.id} className="overflow-hidden border-none shadow-md hover:shadow-lg transition-shadow bg-card/50 backdrop-blur-sm">
                                <CardHeader className="pb-2">
                                    <div className="flex items-center justify-between">
                                        <CardTitle className="text-lg font-bold flex items-center gap-2">
                                            <FileText size={18} className="text-primary" />
                                            {licencaLabels[lic.tipo_licenca] || lic.tipo_licenca}
                                        </CardTitle>
                                        {lic.status && (
                                            <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${lic.status === "definitiva" ? "bg-green-500/10 text-green-500" :
                                                lic.status === "com_vencimento" ? "bg-amber-500/10 text-amber-500" :
                                                    "bg-blue-500/10 text-blue-500"
                                                }`}>
                                                {lic.status}
                                            </span>
                                        )}
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="flex flex-col gap-2">
                                        {lic.vencimento && (
                                            <div className="flex items-center justify-between text-sm">
                                                <span className="text-muted-foreground flex items-center gap-1">
                                                    <Clock size={14} /> Vencimento:
                                                </span>
                                                <span className={`font-semibold ${isVencido ? "text-destructive" : isVencendo ? "text-amber-500" : ""}`}>
                                                    {formatDateBR(lic.vencimento)}
                                                    {dias !== 999 && ` (${dias}d)`}
                                                </span>
                                            </div>
                                        )}
                                        {lic.numero_processo && (
                                            <div className="flex items-center justify-between text-sm">
                                                <span className="text-muted-foreground flex items-center gap-1">
                                                    <AlertCircle size={14} /> Processo:
                                                </span>
                                                <span className="font-medium">{lic.numero_processo}</span>
                                            </div>
                                        )}
                                    </div>

                                    <div className="flex gap-2 pt-2 border-t border-border/50">
                                        {lic.file_url ? (
                                            <>
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    className="flex-1 gap-2"
                                                    onClick={() => window.open(lic.file_url, "_blank")}
                                                >
                                                    <Eye size={16} /> Visualizar
                                                </Button>
                                                <Button
                                                    size="sm"
                                                    className="flex-1 gap-2"
                                                    onClick={() => {
                                                        const a = document.createElement("a");
                                                        a.href = lic.file_url;
                                                        a.download = `${licencaLabels[lic.tipo_licenca] || "Licenca"}.pdf`;
                                                        a.target = "_blank";
                                                        a.click();
                                                    }}
                                                >
                                                    <Download size={16} /> Baixar
                                                </Button>
                                            </>
                                        ) : (
                                            <div className="w-full py-2 px-3 rounded-lg bg-muted text-center text-xs text-muted-foreground italic">
                                                Documento físico não anexado ainda
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default PortalLicencasPage;

import { useEffect, useState } from "react";
import { formatDateBR } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { UserCircle, Building2, MapPin, Scale, FileSignature, Briefcase, Zap, Save, Lock, ArrowRight } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";

const PortalPerfilPage: React.FC = () => {
    const { userData, user } = useAuth();
    const [empresa, setEmpresa] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [newPassword, setNewPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [changingPass, setChangingPass] = useState(false);

    useEffect(() => {
        const loadEmpresa = async () => {
            if (!userData?.empresaId) return;

            const { data, error } = await supabase
                .from("empresas")
                .select("*")
                .eq("id", userData.empresaId)
                .single();

            if (error) {
                toast.error("Erro ao carregar dados da empresa");
            } else {
                setEmpresa(data);
            }
            setLoading(false);
        };

        loadEmpresa();
    }, [userData]);

    const handleUpdatePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newPassword !== confirmPassword) {
            toast.error("As senhas não coincidem!");
            return;
        }
        if (newPassword.length < 6) {
            toast.error("A senha deve ter pelo menos 6 caracteres.");
            return;
        }

        setChangingPass(true);
        const { error } = await supabase.auth.updateUser({ password: newPassword });

        if (error) {
            toast.error("Erro ao alterar senha: " + error.message);
        } else {
            toast.success("Senha alterada com sucesso!");
            setNewPassword("");
            setConfirmPassword("");
        }
        setChangingPass(false);
    };

    if (loading) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    const endereco = empresa?.endereco as any || {};

    return (
        <div className="space-y-8 animate-fade-in pb-12">
            <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-inner">
                    <UserCircle size={24} />
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Perfil da Empresa</h1>
                    <p className="text-muted-foreground">Confira seus dados cadastrais e gerencie sua conta</p>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
                {/* Main Info */}
                <div className="xl:col-span-2 space-y-6">
                    <Card className="border-none shadow-md bg-card/50 backdrop-blur-sm overflow-hidden">
                        <div className="h-2 w-full bg-primary" />
                        <CardHeader>
                            <CardTitle className="text-xl font-bold flex items-center gap-2">
                                <Building2 size={20} className="text-primary" /> Dados Cadastrais
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Razão Social</p>
                                <p className="font-semibold">{empresa?.nome_empresa || "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">CNPJ</p>
                                <p className="font-semibold">{empresa?.cnpj || "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Data de Abertura</p>
                                <p className="font-semibold">{empresa?.data_abertura ? formatDateBR(empresa.data_abertura) : "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Porte</p>
                                <p className="font-semibold uppercase">{empresa?.porte_empresa || "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Regime Tributário</p>
                                <p className="font-semibold text-primary">{empresa?.regime_tributario?.replace("_", " ").toUpperCase() || "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Email de Acesso</p>
                                <p className="font-semibold opacity-70">{user?.email}</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-none shadow-md bg-card/50 backdrop-blur-sm">
                        <CardHeader>
                            <CardTitle className="text-xl font-bold flex items-center gap-2">
                                <MapPin size={20} className="text-primary" /> Endereço
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <div className="md:col-span-2 space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Logradouro</p>
                                <p className="font-semibold">{endereco.logradouro || "—"}, {endereco.numero || "S/N"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Bairro</p>
                                <p className="font-semibold">{endereco.bairro || "—"}</p>
                            </div>
                            <div className="space-y-1">
                                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Cidade/UF</p>
                                <p className="font-semibold">{endereco.cidade || "—"} / {endereco.estado || "—"}</p>
