                    </div>
                    <div className="flex items-center gap-2">
                      <button onClick={() => toggleAdmin(idx)} className="p-2 rounded-lg hover:bg-muted transition-colors text-muted-foreground hover:text-warning" title="Alternar administrador"><Crown size={15} /></button>
                      <button onClick={() => removeSocio(idx)} className="p-2 rounded-lg hover:bg-destructive/10 transition-colors text-muted-foreground hover:text-destructive" title="Remover"><Trash2 size={15} /></button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === "licencas" && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><ScrollText size={20} className="text-primary" /> Licenças Municipais</h2>
            <div className="space-y-4">
              {licencas.map((licenca) => (
                <div key={licenca.tipo_licenca} className="p-5 bg-muted/30 rounded-xl border border-border space-y-4">
                  <div className="flex items-center gap-2"><FileText size={16} className="text-primary" /><h3 className="font-semibold text-card-foreground">{licencaLabels[licenca.tipo_licenca]}</h3></div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    <div><label className={labelCls}>Status</label><select value={licenca.status || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "status", e.target.value)} className={inputCls}><option value="">Não definido</option><option value="definitiva">Definitiva</option><option value="dispensada">Dispensada</option><option value="com_vencimento">Com Vencimento</option><option value="em_processo">Em Processo</option></select></div>
                    {licenca.status === "com_vencimento" && <div><label className={labelCls}>Data de Vencimento</label><input type="date" value={licenca.vencimento || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "vencimento", e.target.value)} className={inputCls} /></div>}
                    {licenca.status === "em_processo" && <div><label className={labelCls}>Nº do Processo</label><input value={licenca.numero_processo || ""} onChange={e => updateLicenca(licenca.tipo_licenca, "numero_processo", e.target.value)} className={inputCls} placeholder="Número do processo" /></div>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "configuracoes" && (
          <div className="space-y-8">
            <h2 className="text-lg font-semibold text-card-foreground flex items-center gap-2"><Settings size={20} className="text-primary" /> Configurações Gerais</h2>
            <div className="space-y-4">
              <h3 className="font-medium text-card-foreground">Módulos Ativos</h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 p-4 bg-muted/30 rounded-xl border border-border">
                {AVAILABLE_MODULES.map(mod => (
                  <label key={mod.id} className="flex items-center gap-2 text-sm cursor-pointer p-2 hover:bg-muted rounded-lg transition-colors">
                    <input type="checkbox" checked={modulosAtivos.includes(mod.id)} onChange={e => { if (e.target.checked) setModulosAtivos(prev => [...prev, mod.id]); else setModulosAtivos(prev => prev.filter(m => m !== mod.id)); }} className="w-4 h-4 rounded border-border text-primary focus:ring-primary" />
                    {mod.label}
                  </label>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SocietarioEmpresaPage;

import { RealtimeChannel } from "@supabase/supabase-js";
import React, { useState, useEffect } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { 
  Building2, Search, Filter, ChevronDown, 
  Plus, History, Activity, Star, RefreshCw
} from "lucide-react";

import { toast } from "sonner";
import { useSocietario } from "@/hooks/useSocietario";
import { EmpresaTable } from "@/components/societario/EmpresaTable";
import { SocietarioStats } from "@/components/societario/SocietarioStats";
import { NovoProcessoForm } from "@/components/societario/NovoProcessoForm";
import { ProcessoCard } from "@/components/societario/ProcessoCard";
import { TableSkeleton, PageHeaderSkeleton } from "@/components/PageSkeleton";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";
import { syncCompanyClients } from "@/lib/sync-clients";
import { tipoProcessoLabels, passosConfig } from "@/constants/societario";
import { Empresa, Processo } from "@/types/societario";
import { List } from "lucide-react";

const SocietarioPage: React.FC = () => {
  const navigate = useNavigate();
  const { 
    empresas, processos, isLoading, 
    deleteProcesso, updateProcesso, getPaginatedEmpresas
  } = useSocietario();

  const [searchParams] = useSearchParams();
  const [activeMainTab, setActiveMainTab] = useState<"empresas" | "processos">((searchParams.get("view") as any) || "empresas");
  const [activeTab, setActiveTab] = useState<"ativas" | "paralisadas" | "baixadas" | "mei" | "entregue">((searchParams.get("aba") as any) || "ativas");
  const [search, setSearch] = useState("");
  const [filterSituacao, setFilterSituacao] = useState(searchParams.get("situacao") || "todas");
  const [filterRegime, setFilterRegime] = useState(searchParams.get("regime") || "todos");
  const [showFilters, setShowFilters] = useState(!!searchParams.get("regime") || !!searchParams.get("situacao"));
  const [showNovoProcesso, setShowNovoProcesso] = useState(false);
  const [expandedProcesso, setExpandedProcesso] = useState<string | null>(null);
  const [processTab, setProcessTab] = useState<Record<string, 'timeline' | 'historico'>>({});
  const [processoToDelete, setProcessoToDelete] = useState<{ id: string, nome: string } | null>(null);

  const [novoProcessoData, setNovoProcessoData] = useState({ 
    tipo: 'abertura', 
    nome_empresa: '', 
    empresa_id: null as string | null,
    numero_processo: '', 
    data_inicio: new Date().toISOString().split('T')[0],
    eventos: [] as string[]
  });

  const [pagination, setPagination] = useState({
    pageIndex: 0,
    pageSize: 10,
  });

  const [paginatedData, setPaginatedData] = useState<{ data: Empresa[]; count: number }>({ data: [], count: 0 });
  const [isFetchingPage, setIsFetchingPage] = useState(false);

  useEffect(() => {
    // Sync URL params to state if they change externally (e.g. clicking dashboard chart)
    const view = searchParams.get("view");
    if (view === "empresas" || view === "processos") setActiveMainTab(view);
    
    const regime = searchParams.get("regime");
    if (regime) {
      setFilterRegime(regime);
      setShowFilters(true);
    }
    
    const situacao = searchParams.get("situacao");
    if (situacao) {
      setFilterSituacao(situacao);
      setShowFilters(true);
    }

    const aba = searchParams.get("aba");
    if (aba) setActiveTab(aba as any);
  }, [searchParams]);

  React.useEffect(() => {
    // Reset to page 0 if filters change
    setPagination(prev => ({ ...prev, pageIndex: 0 }));
  }, [search, filterSituacao, filterRegime, activeTab]);

  React.useEffect(() => {
    const fetchPage = async () => {
      setIsFetchingPage(true);
      try {
        const result = await getPaginatedEmpresas(
           pagination.pageIndex, 
           pagination.pageSize, 
           search, 
           // activeTab acts as situacao filter if nothing else is selected in the regular filter dropdown
           filterSituacao !== 'todas' ? filterSituacao : activeTab, 
           filterRegime
        );
        setPaginatedData(result);
      } catch (err) {
        toast.error("Erro ao carregar empresas");
      } finally {
        setIsFetchingPage(false);
      }
    };
    
    // Debounce search
    const timeout = setTimeout(() => {
        fetchPage();
    }, 300);

    return () => clearTimeout(timeout);
  }, [pagination.pageIndex, pagination.pageSize, search, filterSituacao, filterRegime, activeTab]);

  React.useEffect(() => {
    let isMounted = true;
    let channel: RealtimeChannel;

    const setupRealtime = async () => {
      const { supabase } = await import("@/integrations/supabase/client");
      channel = supabase
        .channel('schema-db-changes')
        .on(
          'postgres_changes',
          { event: '*', schema: 'public', table: 'empresas' },
          (payload) => {
            if (isMounted) {
               // Force a refetch of the current page
               setPagination(prev => ({ ...prev }));
            }
          }
        )
        .subscribe();
    }
    
    setupRealtime();

    return () => {
      isMounted = false;
      if (channel) {
        channel.unsubscribe();
      }
    };
  }, []);

  const handleCreateProcesso = async () => {
    // Basic validation
    if (novoProcessoData.tipo === 'alteracao' && !novoProcessoData.empresa_id) {
      toast.error("Selecione a empresa para alteração"); return;
    }
    if (novoProcessoData.tipo !== 'alteracao' && !novoProcessoData.nome_empresa) {
      toast.error("Preencha o nome da empresa"); return;
    }
    
    let finalNome = novoProcessoData.nome_empresa;
    if (novoProcessoData.tipo === 'alteracao' && novoProcessoData.empresa_id) {
      finalNome = empresas.find(e => e.id === novoProcessoData.empresa_id)?.nome_empresa || '';
    }

    const { data: { user } } = await (await import("@/integrations/supabase/client")).supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await (await import("@/integrations/supabase/client")).supabase.from("processos_societarios" as any).insert([{
      ...novoProcessoData,
      empresa_id: novoProcessoData.empresa_id || null,
      nome_empresa: finalNome,
      current_step: 'envio_dbe_at'
    }]).select().single();

    if (error) {
      toast.error("Erro ao criar: " + error.message);
    } else {
      const inserted = (data as any) as { id: string };
      await (await import("@/integrations/supabase/client")).supabase.from("processos_societarios_historico" as any).insert({
        processo_id: inserted.id,
        usuario_id: user.id,
        acao: 'PROCESSO_INICIADO',
        detalhes: `Tipo: ${tipoProcessoLabels[novoProcessoData.tipo]}`
      });
      toast.success("Processo iniciado!");
      setShowNovoProcesso(false);
      window.location.reload(); 
    }
  };

  const stats = {
    ativas: empresas.filter(e => e.situacao === "ativa").length,
    paralisadas: empresas.filter(e => e.situacao === "paralisada").length,
    baixadas: empresas.filter(e => e.situacao === "baixada").length,
    entregues: empresas.filter(e => e.situacao === "entregue").length,
    mei: empresas.filter(e => e.regime_tributario === "mei" && ["ativa", "paralisada"].includes(e.situacao || "")).length,
    processosAtivos: processos.filter(p => p.status === 'em_andamento').length,
  };

  if (isLoading) {
    return (
      <div className="space-y-6 animate-fade-in">
        <PageHeaderSkeleton />
        <TableSkeleton rows={8} />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Main Tabs */}
      <div className="flex border-b border-border">
        <button onClick={() => setActiveMainTab("empresas")} className={`pb-3 px-6 text-sm font-bold transition-all border-b-2 ${activeMainTab === "empresas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>
          <div className="flex items-center gap-2 underline-offset-8">
            <Building2 size={18} /> EMPRESAS
          </div>
        </button>
        <button onClick={() => setActiveMainTab("processos")} className={`pb-3 px-6 text-sm font-bold transition-all border-b-2 ${activeMainTab === "processos" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>
          <div className="flex items-center gap-2">
            <Activity size={18} /> PROCESSOS
            {stats.processosAtivos > 0 && <span className="bg-primary text-primary-foreground text-[10px] px-1.5 py-0.5 rounded-full">{stats.processosAtivos}</span>}
          </div>
        </button>
      </div>

      {activeMainTab === "empresas" ? (
        <div className="space-y-6 animate-in slide-in-from-left-2 duration-500">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <h1 className="header-title">Societário</h1>
              <p className="text-muted-foreground mt-1">Gestão de empresas e processos de constituição/alteração.</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <FavoriteToggleButton moduleId="societario" />
              <button
                onClick={async () => {
                  const confirmed = window.confirm("Sincronizar todos os acessos do portal?");
                  if (!confirmed) return;
                  const id = toast.loading("Sincronizando...");
                  try {
                    await syncCompanyClients(() => {});
                    toast.success("Sincronizado!", { id });
                  } catch (e: any) { toast.error(e.message, { id }); }
                }}
                className="button-secondary-premium"
              >
                <RefreshCw size={18} /> Sincronizar Acessos
              </button>
              <button onClick={() => navigate("/societario/nova")} className="button-premium">
                <Plus size={18} /> Nova Empresa
              </button>
            </div>
          </div>

          <SocietarioStats stats={stats} />

          <div className="card-premium !p-4">
            <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center">
              <div className="relative flex-1 w-full flex items-center">
                <Search size={18} className="absolute left-4 text-muted-foreground" />
                <input 
                  type="text" 
                  placeholder="Buscar por nome ou CNPJ..." 
                  value={search} 
                  onChange={(e) => setSearch(e.target.value)} 
                  className="w-full pl-12 pr-4 py-3 border border-border/50 rounded-2xl bg-muted/30 text-foreground text-sm focus:ring-2 focus:ring-primary/20 outline-none transition-all" 
                />
              </div>
              <button 
                onClick={() => setShowFilters(!showFilters)} 
                className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-sm font-bold border ${showFilters ? "border-primary bg-primary/10 text-primary" : "border-border text-muted-foreground hover:text-foreground hover:bg-muted"}`}
              >
                <Filter size={18} /> Filtros <ChevronDown size={14} className={showFilters ? "rotate-180" : ""} />
              </button>
            </div>
            {showFilters && (
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mt-6 pt-6 border-t border-border/50 animate-in fade-in slide-in-from-top-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Regime</label>
                  <select value={filterRegime} onChange={(e) => setFilterRegime(e.target.value)} className="w-full px-4 py-2 border rounded-xl bg-background text-sm">
                    <option value="todos">Todos</option>
                    <option value="simples">Simples Nacional</option>
                    <option value="lucro_presumido">Lucro Presumido</option>
                    <option value="lucro_real">Lucro Real</option>
                    <option value="mei">MEI</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Situação</label>
                  <select value={filterSituacao} onChange={(e) => setFilterSituacao(e.target.value)} className="w-full px-4 py-2 border rounded-xl bg-background text-sm">
                    <option value="todas">Todas</option>
                    <option value="ativa">Ativa</option>
                    <option value="paralisada">Paralisada</option>
                    <option value="baixada">Baixada</option>
                    <option value="entregue">Entregue</option>
                  </select>
                </div>
                <div className="flex items-end">
                  <button onClick={() => { setSearch(""); setFilterSituacao("todas"); setFilterRegime("todos"); }} className="text-xs text-primary font-black uppercase tracking-widest px-4 py-2">Limpar</button>
                </div>
              </div>
            )}
          </div>

          <div className="flex border-b border-border overflow-x-auto no-scrollbar pt-2">
            {["ativas", "mei", "paralisadas", "baixadas", "entregue"].map(t => (
              <button key={t} onClick={() => setActiveTab(t as any)} className={`px-6 py-3 text-xs font-black uppercase tracking-wider border-b-2 transition-all whitespace-nowrap ${activeTab === t ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}>{t === "entregue" ? "ENTREGUES" : t.toUpperCase()}</button>
            ))}
          </div>

          <EmpresaTable 
            empresas={paginatedData.data} 
            totalCount={paginatedData.count} 
            pagination={pagination} 
            setPagination={setPagination}
            isLoading={isFetchingPage}
            onInlineEdit={async (id, field, value) => {
              try {
                const { error } = await (await import("@/integrations/supabase/client")).supabase.from("empresas").update({ [field]: value }).eq("id", id);
                if (error) throw error;
                toast.success("Empresa atualizada!");
                // Force fetch page again to get updated item
                setPagination(prev => ({ ...prev }));
              } catch (e: any) {
                toast.error("Erro ao atualizar: " + e.message);
              }
            }}
          />
        </div>
      ) : (
        <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h3 className="text-xl font-black text-card-foreground flex items-center gap-3">
                <div className="p-2 rounded-xl bg-primary/10 text-primary"><History size={24} /></div>
                Processos Societários
              </h3>
            </div>
            <div className="flex items-center gap-4">
              <button onClick={() => setShowNovoProcesso(true)} className="button-premium">
                <Plus size={20} /> Novo Processo
              </button>
            </div>
          </div>

          {showNovoProcesso && (
            <NovoProcessoForm 
              empresas={empresas}
              novoProcessoData={novoProcessoData}
              setNovoProcessoData={setNovoProcessoData}
              onSubmit={handleCreateProcesso}
              onCancel={() => setShowNovoProcesso(false)}
            />
          )}

          {processos.length === 0 ? (
            <div className="card-premium text-center py-24 text-muted-foreground">Nenhum processo em andamento</div>
          ) : (
            <div className="space-y-6">
              {processos.map(p => (
                <ProcessoCard 
                  key={p.id}
                  processo={p}
                  isExpanded={expandedProcesso === p.id}
                  onToggleExpand={() => setExpandedProcesso(expandedProcesso === p.id ? null : p.id)}
                  onDelete={(id, nome) => setProcessoToDelete({ id, nome })}
                  activeTab={processTab[p.id] || 'timeline'}
                  onTabChange={(tab) => setProcessTab({ ...processTab, [p.id]: tab })}
                  onUpdatePasso={(id, campo, value) => updateProcesso.mutate({ id, updates: { [campo]: value } })}
                  onUpdateDetalhePasso={(id, stepId, field, value) => {
                    const novosDetalhes = { ...p.detalhes_passos };
                    novosDetalhes[stepId] = { ...novosDetalhes[stepId], [field]: value };
                    updateProcesso.mutate({ id, updates: { detalhes_passos: novosDetalhes } });
                  }}
                  onFinalize={(proc) => {
                    if (proc.tipo === 'alteracao' && proc.empresa_id) {
                      navigate(`/societario/${proc.empresa_id}`, { state: { nome: proc.nome_empresa, processoId: proc.id } });
                    } else {
                      navigate("/societario/nova", { state: { nome: proc.nome_empresa, processoId: proc.id } });
                    }
                  }}
                />
              ))}
            </div>
          )}
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {processoToDelete && (
        <div className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-card w-full max-w-sm rounded-2xl shadow-xl border border-border p-6">
            <h2 className="text-xl font-bold">Excluir Processo?</h2>
            <p className="text-muted-foreground mt-2 text-sm">Ação irreversível para <strong>{processoToDelete.nome}</strong>.</p>
            <div className="mt-6 flex justify-end gap-3">
              <button onClick={() => setProcessoToDelete(null)} className="px-4 py-2 text-sm font-bold">Cancelar</button>
              <button onClick={() => { deleteProcesso.mutate(processoToDelete.id); setProcessoToDelete(null); }} className="px-4 py-2 bg-destructive text-white rounded-xl text-sm font-bold">Sim, Excluir</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SocietarioPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { Calendar, Clock, User, Save, ArrowLeft, ClipboardList } from "lucide-react";
import { toast } from "sonner";

const TarefaFormPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [usuarios, setUsuarios] = useState<{ id: string; nome: string }[]>([]);
    const [form, setForm] = useState({
        data: new Date().toISOString().split('T')[0],
        horario: "09:00",
        usuario_id: "",
        assunto: "",
        informacoes_adicionais: ""
    });

    useEffect(() => {
        const loadUsers = async () => {
            try {
                const { data: profiles } = await supabase.from("profiles").select("id, full_name, nome_completo, user_id").eq("ativo", true);
                if (!profiles) return;

                const userIds = profiles.map(p => p.user_id || p.id);

                const [{ data: roles }, { data: access }] = await Promise.all([
                    supabase.from("user_roles").select("user_id, role").in("user_id", userIds),
                    supabase.from("empresa_acessos").select("user_id").in("user_id", userIds)
                ]);

                const clientIds = new Set([
                    ...(roles?.filter(r => (r.role as any) === 'client').map(r => r.user_id) || []),
                    ...(access?.map(a => a.user_id) || [])
                ]);

                const mapped = profiles
                    .filter(u => !clientIds.has(u.user_id || u.id))
                    .map((u: any) => ({
                        id: u.user_id || u.id,
                        nome: u.nome_completo || u.full_name || "Sem Nome"
                    }));

                setUsuarios(mapped);
            } catch (err) {
                console.error(err);
            }
        };
        loadUsers();
    }, []);

    const handleSave = async () => {
        if (!form.data || !form.usuario_id || !form.assunto) {
            toast.error("Preencha os campos obrigatórios!");
            return;
        }

        setLoading(true);
        try {
            const payload = {
                ...form,
                criado_por: user?.id,
                competencia: form.data.slice(0, 7)
            };

            const { error } = await (supabase.from("tarefas" as any).insert(payload) as any);
            if (error) throw error;

            toast.success("Tarefa interna criada com sucesso!");
            navigate("/tarefas");
        } catch (err: any) {
            toast.error("Erro ao salvar: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    const inputCls = "w-full px-4 py-3 border border-border rounded-xl bg-card text-foreground focus:ring-2 focus:ring-primary outline-none transition-all";
    const labelCls = "block text-sm font-semibold text-muted-foreground mb-1.5 ml-1";

    return (
        <div className="max-w-2xl mx-auto space-y-6 animate-fade-in pb-10">
            <div className="flex items-center gap-4">
                <button
                    onClick={() => navigate("/tarefas")}
                    className="p-2.5 rounded-xl hover:bg-muted transition-colors text-muted-foreground"
                    title="Voltar"
                >
                    <ArrowLeft size={20} />
                </button>
            </div>

            <div className="bg-card border border-border rounded-2xl shadow-sm overflow-hidden p-6 md:p-8 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className={labelCls}>Prazo de Entrega *</label>
                        <div className="relative">
                            <Calendar size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="date"
                                value={form.data}
                                onChange={e => setForm({ ...form, data: e.target.value })}
                                className={inputCls + " pl-11"}
                            />
                        </div>
                    </div>
                    <div>
                        <label className={labelCls}>Horário *</label>
                        <div className="relative">
                            <Clock size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="time"
                                value={form.horario}
                                onChange={e => setForm({ ...form, horario: e.target.value })}
                                className={inputCls + " pl-11"}
                            />
                        </div>
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Responsável pela Tarefa *</label>
                    <div className="relative">
                        <User size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                        <select
                            value={form.usuario_id}
                            onChange={e => setForm({ ...form, usuario_id: e.target.value })}
                            className={inputCls + " pl-11 appearance-none"}
                        >
                            <option value="">Selecione quem receberá a tarefa...</option>
                            {usuarios.map(u => (
                                <option key={u.id} value={u.id}>{u.nome} {u.id === user?.id ? "(Eu)" : ""}</option>
                            ))}
                        </select>
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Assunto *</label>
                    <div className="relative">
                        <ClipboardList size={18} className="absolute left-3.5 top-4 text-muted-foreground" />
                        <input
                            placeholder="Ex: Tarefa interna"
                            value={form.assunto}
                            onChange={e => setForm({ ...form, assunto: e.target.value })}
                            className={inputCls + " pl-11"}
                        />
                    </div>
                </div>

                <div>
                    <label className={labelCls}>Demais Informações</label>
                    <textarea
                        rows={5}
                        placeholder="Detalhes adicionais..."
                        value={form.informacoes_adicionais}
                        onChange={e => setForm({ ...form, informacoes_adicionais: e.target.value })}
                        className={inputCls + " resize-none"}
                    />
                </div>

                <div className="flex gap-4 pt-4 border-t border-border">
                    <button
                        onClick={() => navigate("/tarefas")}
                        className="flex-1 px-6 py-3.5 rounded-xl border border-border text-sm font-bold hover:bg-muted transition-colors disabled:opacity-50"
                        disabled={loading}
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={loading}
                        className="flex-1 button-premium flex items-center justify-center gap-2 shadow-lg disabled:opacity-50"
                    >
                        {loading ? (
                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ) : (
                            <><Save size={20} /> Salvar Tarefa</>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default TarefaFormPage;

import React, { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Search, Calendar, Clock, User, Plus, Save, X, ClipboardList, CheckCircle, Circle, RefreshCw, Trash2, LayoutDashboard, List } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useNavigate } from "react-router-dom";
import KanbanBoard, { KanbanColumn, KanbanItem } from "@/components/KanbanBoard";

interface Tarefa {
    id: string;
    data: string;
    horario: string;
    usuario_id: string;
    criado_por: string;
    assunto: string;
    informacoes_adicionais: string;
    competencia: string;
    usuario_nome?: string;
    status: "em_aberto" | "concluido" | "pendente";
    arquivado: boolean;
}

const TarefasPage: React.FC = () => {
    const { user, userData } = useAuth();
    const navigate = useNavigate();
    const [agendamentos, setAgendamentos] = useState<Tarefa[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [competencia, setCompetencia] = useState(new Date().toISOString().slice(0, 7));
    const [activeTab, setActiveTab] = useState<"geral" | "meus">("geral");
    const [activeSubTab, setActiveSubTab] = useState<"em_aberto" | "concluido" | "pendente" | "arquivados">("em_aberto");
    const [viewMode, setViewMode] = useState<"list" | "kanban">("kanban");

    const loadData = async () => {
        setLoading(true);
        try {
            // Carregar usuários para mapear nomes
            const { data: usersData } = await (supabase.from("profiles").select("id, full_name, user_id") as any);
            const mappedUsers = (usersData || []).map((u: any) => ({
                id: u.user_id || u.id,
                nome: u.full_name || "Sem Nome"
            }));

            // Carregar tarefas
            const { data: agendaData } = await (supabase
                .from("tarefas" as any)
                .select("*")
                .eq("competencia", competencia)
                .order("horario", { ascending: true }) as any);

            const now = new Date();

            const enrichedData = (agendaData || []).map((a: any) => {
                let currentStatus = a.status || "em_aberto";
                let isOverdue = false;

                if (currentStatus === "em_aberto" && a.data && a.horario) {
                    const scheduledDateTime = new Date(`${a.data}T${a.horario}`);
                    if (scheduledDateTime < now) {
                        currentStatus = "pendente";
                        isOverdue = true;
                    }
                }

                return {
                    ...a,
                    status: currentStatus,
                    arquivado: !!a.arquivado,
                    usuario_nome: mappedUsers.find(u => u.id === a.usuario_id)?.nome || "Não encontrado",
                    _isOverdueDbUpdateNeeded: isOverdue // Flag to update DB later
                };
            });

            // Fire and forget DB updates for newly identified overdue items
            const overdueItems = enrichedData.filter(item => item._isOverdueDbUpdateNeeded);
            if (overdueItems.length > 0) {
                Promise.all(overdueItems.map(item =>
                    supabase.from("tarefas" as any).update({ status: "pendente" } as any).eq("id", item.id) as any
                )).catch(e => console.error("Failed to auto-update overdue tasks", e));
            }

            setAgendamentos(enrichedData);
        } catch (err: any) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, [competencia]);

    // Background job to check for overdue items every minute
    useEffect(() => {
        const interval = setInterval(() => {
            const now = new Date();
            let hasChanges = false;

            setAgendamentos(prev => {
                const updated = prev.map(a => {
                    if (a.status === "em_aberto" && a.data && a.horario) {
                        const scheduledDateTime = new Date(`${a.data}T${a.horario}`);
                        if (scheduledDateTime < now) {
                            hasChanges = true;
                            // Optionally push the update to Supabase
                            supabase.from("tarefas" as any).update({ status: "pendente" } as any).eq("id", a.id).then();
                            return { ...a, status: "pendente" as const };
                        }
                    }
                    return a;
                });
                return hasChanges ? updated : prev;
            });
        }, 60000); // Check every minute

        return () => clearInterval(interval);
    }, []);

    const handleUpdateStatus = async (id: string, newStatus: string) => {
        try {
            const { error } = await (supabase
                .from("tarefas" as any)
                .update({ status: newStatus } as any)
                .eq("id", id) as any);

            if (error) throw error;
            toast.success("Status atualizado!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao atualizar: " + error.message);
        }
    };

    const handleUpdateArquivado = async (id: string, arquivado: boolean) => {
        try {
            const { error } = await (supabase
                .from("tarefas" as any)
                .update({ arquivado } as any)
                .eq("id", id) as any);

            if (error) throw error;
            toast.success(arquivado ? "Tarefa arquivada!" : "Tarefa desarquivada!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao atualizar: " + error.message);
        }
    };

    const handleDeleteAgendamento = async (id: string) => {
        if (!window.confirm("Tem certeza que deseja excluir esta tarefa? Esta ação não pode ser desfeita.")) {
            return;
        }

        try {
            const { error } = await (supabase
                .from("tarefas" as any)
                .delete()
                .eq("id", id) as any);

            if (error) throw error;
            toast.success("Tarefa excluída com sucesso!");
            loadData();
        } catch (error: any) {
            toast.error("Erro ao excluir: " + error.message);
        }
    };

    const filtered = agendamentos.filter(a => {
        const matchSearch = a.assunto.toLowerCase().includes(search.toLowerCase()) ||
            a.usuario_nome?.toLowerCase().includes(search.toLowerCase());

        // Filtragem por Arquivados
        if (activeSubTab === "arquivados") {
            if (!a.arquivado) return false;
        } else {
            if (a.arquivado) return false;
        }

        const isMine = a.usuario_id === user?.id;

        if (activeTab === "geral") {
            if (activeSubTab === "arquivados") return matchSearch;
            return matchSearch;
        } else {
            const matchUser = isMine;
            if (activeSubTab === "arquivados") {
                return matchSearch && matchUser;
            }
            return matchSearch && matchUser && a.status === activeSubTab;
        }
    });

    if (loading && agendamentos.length === 0) {
        return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
    }

    const kanbanColumns: KanbanColumn[] = [
        { id: 'em_aberto', title: 'A Fazer', colorClass: 'bg-blue-500/10 text-blue-500 border-blue-500/20' },
        { id: 'pendente', title: 'Pendente', colorClass: 'bg-amber-500/10 text-amber-500 border-amber-500/20' },
        { id: 'concluido', title: 'Concluído', colorClass: 'bg-green-500/10 text-green-500 border-green-500/20' }
    ];

    const kanbanItems: KanbanItem[] = filtered.map(a => ({
        id: a.id,
        status: a.status,
        renderContent: () => (
            <div className={`
                p-4 space-y-3 transition-all h-full bg-card group relative
                border-l-4 ${a.status === 'concluido' ? 'border-l-green-500 opacity-90' : a.status === 'pendente' ? 'border-l-amber-500' : 'border-l-primary'}
            `}>
                <div className="flex items-start justify-between">
                    <div className="space-y-1 w-full">
                        <div className="flex items-start justify-between gap-2">
                            <h3 className="font-bold text-card-foreground leading-tight text-sm flex-1">{a.assunto}</h3>
                            <button
                                onClick={() => handleDeleteAgendamento(a.id)}
                                className="opacity-0 group-hover:opacity-100 p-1.5 rounded-md text-destructive/70 hover:bg-destructive/10 hover:text-destructive transition-all shrink-0"
                                title="Excluir"
                            >
                                <Trash2 size={14} />
                            </button>
                        </div>
                        <p className="text-xs text-muted-foreground flex items-center gap-1.5 pt-1">
                            <User size={12} className="text-primary/70" /> Para: <span className="text-foreground font-medium">{a.usuario_nome}</span>
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3 pt-2">
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Calendar size={14} className="text-primary" />
                        {format(new Date(a.data + 'T00:00:00'), "dd 'de' MMM", { locale: ptBR })}
                    </div>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Clock size={14} className="text-primary" />
                        {a.horario.slice(0, 5)}
                    </div>
                </div>

                {a.informacoes_adicionais && (
                    <div className="bg-muted/40 p-2.5 rounded-lg text-xs tracking-tight text-foreground/80 border border-border italic line-clamp-3">
                        {a.informacoes_adicionais}
                    </div>
                )}

                {(a.usuario_id === user?.id || userData?.isAdmin) && (
                    <div className="flex flex-wrap items-center gap-1.5 pt-2 border-t border-border mt-auto">
                        {!a.arquivado && (
                            <>
                                {a.status !== 'concluido' ? (
                                    <button
                                        onClick={() => handleUpdateStatus(a.id, 'concluido')}
                                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-green-500/10 text-green-500 text-xs font-bold hover:bg-green-500 hover:text-white transition-all"
                                    >
                                        <CheckCircle size={14} /> Concluir
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleUpdateStatus(a.id, 'em_aberto')}
                                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-muted text-muted-foreground text-xs font-bold hover:bg-muted-foreground hover:text-white transition-all"
                                    >
                                        <Circle size={14} /> Reabrir
                                    </button>
                                )}
                            </>
                        )}

                        {!a.arquivado ? (
                            <button
                                onClick={() => handleUpdateArquivado(a.id, true)}
                                className="flex-1 px-3 py-1.5 rounded-md bg-muted/50 text-muted-foreground text-[11px] font-bold hover:bg-destructive hover:text-white transition-all flex items-center justify-center gap-1.5"
                                title="Arquivar"
                            >
                                <X size={13} /> Arquivar
                            </button>
                        ) : (
                            <button
                                onClick={() => handleUpdateArquivado(a.id, false)}
                                className="w-full flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-md bg-primary/10 text-primary text-[11px] font-bold hover:bg-primary hover:text-white transition-all"
                            >
                                <RefreshCw size={13} /> Desarquivar
                            </button>
                        )}
                    </div>
                )}
            </div>
        )
    }));

    return (
        <div className="space-y-6 animate-fade-in flex flex-col min-h-[calc(100vh-100px)]">
            <div className="flex items-center gap-3 justify-end shrink-0">
                <input
                    type="month"
                    value={competencia}
                    onChange={e => setCompetencia(e.target.value)}
                    className="px-4 py-2.5 border border-border rounded-xl bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none font-semibold"
                />
                <button
                    onClick={() => navigate("/tarefas/novo")}
                    className="button-premium shadow-md"
                >
                    <Plus size={18} /> Nova Tarefa
                </button>
            </div>

            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 shrink-0">
                <div className="flex border-b border-border w-full sm:w-auto overflow-x-auto no-scrollbar">
                    <button
                        className={`px-5 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === "geral" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                        onClick={() => {
                            setActiveTab("geral");
                            if (activeSubTab !== "arquivados") setActiveSubTab("em_aberto");
                        }}
                    >
                        Geral
                    </button>
                    <button
                        className={`px-5 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === "meus" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                        onClick={() => {
                            setActiveTab("meus");
                            if (activeSubTab !== "arquivados") setActiveSubTab("em_aberto");
                        }}
                    >
                        Minhas Tarefas
                    </button>
                </div>

                <div className="flex gap-2 p-1 bg-muted/30 rounded-lg w-fit">
                    {[
                        { id: "em_aberto", label: "Em Aberto", hideOnGeral: true },
                        { id: "concluido", label: "Concluído", hideOnGeral: true },
                        { id: "pendente", label: "Pendente", hideOnGeral: true },
                        { id: "arquivados", label: "Arquivados", hideOnGeral: false }
                    ].map(sub => {
                        if (activeTab === "geral" && sub.hideOnGeral && sub.id !== "em_aberto") return null;
                        const label = activeTab === "geral" && sub.id === "em_aberto" ? "Ativos" : sub.label;
                        return (
                            <button
                                key={sub.id}
                                onClick={() => setActiveSubTab(sub.id as any)}
                                className={`px-4 py-1.5 rounded-md text-xs font-semibold transition-all ${activeSubTab === sub.id ? "bg-card text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                            >
                                {label}
                            </button>
                        );
                    })}
                </div>

                <div className="flex bg-muted p-1 rounded-lg shrink-0">
                    <button
                        onClick={() => setViewMode("list")}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${viewMode === "list" ? "bg-background text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                        title="Ver como Lista"
                    >
                        <List size={16} /> <span className="hidden sm:inline">Lista</span>
                    </button>
                    <button
                        onClick={() => setViewMode("kanban")}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${viewMode === "kanban" ? "bg-background text-foreground shadow-sm" : "text-muted-foreground hover:text-foreground"}`}
                        title="Ver como Quadro (Kanban)"
                    >
                        <LayoutDashboard size={16} /> <span className="hidden sm:inline">Quadro</span>
                    </button>
                </div>
            </div>

            <div className="relative max-w-sm shrink-0">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                <input
                    type="text"
                    placeholder="Buscar tarefa ou usuário..."
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none"
                />
            </div>

            {viewMode === 'kanban' && activeSubTab !== 'arquivados' ? (
                <div className="flex-1 overflow-hidden min-h-[500px]">
                    <KanbanBoard
                        columns={kanbanColumns}
                        items={kanbanItems}
                        onDragEnd={handleUpdateStatus}
                    />
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pb-10">
                    {filtered.length === 0 ? (
                        <div className="col-span-full py-12 text-center text-muted-foreground bg-muted/20 rounded-xl border border-dashed border-border">
                            Nenhuma tarefa encontrada para este período.
                        </div>
                    ) : (
                        filtered.map(a => <React.Fragment key={a.id}>{kanbanItems.find(i => i.id === a.id)?.renderContent()}</React.Fragment>)
                    )}
                </div>
            )}
        </div>
    );
};

