          <div>
            <h2 className="text-lg font-bold text-card-foreground mb-3 uppercase">2. Termo de Responsabilidade, Sigilo e Conformidade (LGPD)</h2>
            <div className="bg-muted/30 rounded-lg p-4 text-sm text-foreground space-y-3 border border-border">
              <p><strong>2.1. Estrita Observância Legal e Ética:</strong> O usuário obriga-se a pautar sua conduta em conformidade com a Lei Geral de Proteção de Dados (Lei nº 13.709/2018 - LGPD), o Código de Ética Profissional do Contador (NBC PG 01) e as resoluções do Conselho Federal de Contabilidade (CFC).</p>
              <p><strong>2.2. Dever de Confidencialidade Perpétua:</strong> Todas as informações custodiadas — incluindo, mas não se limitando a: dados pessoais, dados sensíveis, segredos de negócio, dados financeiros, fiscais e societários de clientes — gozam de proteção por sigilo profissional. Este dever de confidencialidade subsiste de forma perene, mantendo-se íntegro mesmo após a extinção do vínculo jurídico (trabalhista ou contratual) com a AUDIPREVE CONTABILIDADE.</p>
              <p><strong>2.3. Princípios do Tratamento de Dados:</strong> O acesso e o tratamento de dados de clientes deverão observar os princípios da finalidade, necessidade e adequação, limitando-se ao mínimo indispensável para o cumprimento da obrigação profissional específica designada ao usuário.</p>
              <p><strong>2.4. Vedação à Exfiltração de Dados:</strong> É expressamente proibida a reprodução, extração, fotografia, impressão ou transmissão de dados para dispositivos ou ambientes externos (unidades de armazenamento removíveis, e-mails particulares, repositórios em nuvem pessoal ou aplicativos de mensageria instantânea) sem autorização prévia, formal e específica da Diretoria.</p>
              <p><strong>2.5. Protocolo de Incidentes:</strong> O usuário deverá reportar imediatamente ao Encarregado de Dados (DPO) ou à Administração qualquer evidência ou suspeita de vulnerabilidade, vazamento, perda de integridade ou acesso não autorizado por terceiros.</p>
              <p><strong>2.6. Regime de Responsabilidade e Cominações:</strong> A inobservância das obrigações de sigilo e proteção de dados sujeitará o infrator às seguintes esferas de punibilidade:</p>
              <ul className="list-disc list-inside pl-4 space-y-1">
                <li><strong>Esfera Laboral:</strong> Aplicação de medidas disciplinares, culminando na dispensa por justa causa;</li>
                <li><strong>Esfera Civil:</strong> Responsabilização por perdas e danos, danos morais e regressividade em caso de condenações da empresa perante terceiros ou a ANPD;</li>
                <li><strong>Esfera Criminal:</strong> Persecução penal pelos crimes de violação de sigilo profissional (Art. 154 do CP) e invasão de dispositivo informático (Art. 154-A do CP).</li>
              </ul>
              <p><strong>2.7. Tratamento de Dados do Usuário:</strong> Para fins de segurança, auditoria e cumprimento de obrigações legais, o usuário consente com a coleta e o tratamento de seus dados identificadores (Nome, CPF, IP, Geolocalização e Biometria de acesso) pela AUDIPREVE CONTABILIDADE, nos termos do Art. 7º, incisos II e V da LGPD.</p>
            </div>
          </div>
        </div>

        <div className="p-8 border-t border-border space-y-4">
          <label className="flex items-start gap-3 cursor-pointer">
            <input type="checkbox" checked={accepted} onChange={e => setAccepted(e.target.checked)} className="mt-1 rounded border-border" />
            <span className="text-sm text-card-foreground">Li e aceito os <strong>Termos de Uso e Acesso ao Sistema</strong> descritos acima.</span>
          </label>
          <label className="flex items-start gap-3 cursor-pointer">
            <input type="checkbox" checked={acceptedLgpd} onChange={e => setAcceptedLgpd(e.target.checked)} className="mt-1 rounded border-border" />
            <span className="text-sm text-card-foreground">Li e aceito o <strong>Termo de Responsabilidade, Sigilo e Conformidade (LGPD)</strong>, comprometendo-me com o sigilo e a proteção dos dados acessados.</span>
          </label>

          <button onClick={handleAccept} disabled={saving || !accepted || !acceptedLgpd} className="w-full py-3 rounded-lg text-sm font-semibold text-primary-foreground shadow-md disabled:opacity-50 transition-all" style={{ background: "var(--gradient-primary)" }}>
            {saving ? "Processando..." : "Aceitar e Acessar o Sistema"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default TermosPage;

import React, { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import { User, Mail, Lock, Shield, ArrowLeft, Save, ChevronRight, Fingerprint } from "lucide-react";
import { toast } from "sonner";
import { maskCPF } from "@/lib/utils";


const moduleLabels: Record<string, string> = {
    societario: "Societário",
    fiscal: "Fiscal",
    pessoal: "Pessoal",
    certificados: "Certificados",
    certidoes: "Certidões",
    licencas: "Licenças",
    procuracoes: "Procurações",
    vencimentos: "Vencimentos",
    parcelamentos: "Parcelamentos",
    recalculos: "Recálculos",
    honorarios: "Honorários",
    agendamentos: "Agendamentos",
    declaracoes_anuais: "Declarações Anuais",
    declaracoes_mensais: "Declarações Mensais",
};

const UsuarioFormPage: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [form, setForm] = useState({
        nome: "",
        cpf: "",
        email: "",
        isAdmin: false,
        modules: {} as Record<string, boolean>
    });



    const handleCreateUser = async () => {
        if (!form.nome.trim() || !form.email.trim() || !form.cpf.trim()) {
            toast.error("Nome, CPF e e-mail são obrigatórios");
            return;
        }

        setLoading(true);
        try {
            console.log("Chamando Edge Function create-user...");

            const { data: { session } } = await supabase.auth.getSession();
            const token = session?.access_token;

            if (!token) {
                console.error("Token não encontrado na sessão");
                toast.error("Sessão expirada. Por favor, faça login novamente.");
                setLoading(false);
                return;
            }

            const { data, error } = await supabase.functions.invoke("create-user", {
                headers: {
                    Authorization: `Bearer ${token}`
                },
                body: {
                    email: form.email,
                    nome: form.nome,
                    cpf: form.cpf,
                    isAdmin: form.isAdmin,
                    modules: form.modules
                }
            });

            if (error) {
                // Em caso de FunctionsHttpError, o context pode ser o objeto Response original
                const errorContext = (error as any).context;
                if (errorContext instanceof Response) {
                    try {
                        const body = await errorContext.json();
                        if (body.error) throw new Error(body.error);
                    } catch (e: any) {
                        if (e.message && e.message !== "Unexpected end of JSON input") throw e;
                    }
                }

                if (error.message?.includes("Failed to send a request")) {
                    throw new Error("Não foi possível conectar à Edge Function.");
                }
                throw error;
            }

            if (data?.error) throw new Error(data.error);

            toast.success("Usuário criado com sucesso! Um e-mail com link para definição de senha foi enviado.");
            navigate("/configuracoes");
        } catch (err: any) {
            console.error("Erro no cadastro:", err);

            let errorMessage = err.message || "Erro desconhecido";

            if (err.context?.json?.error) {
                errorMessage = err.context.json.error;
            } else if (err.context?.error) {
                errorMessage = err.context.error;
            }

            toast.error("Erro no Cadastro: " + errorMessage);
        } finally {
            setLoading(false);
        }
    };

    const inputCls = "w-full px-4 py-3 border border-border rounded-xl bg-card text-foreground focus:ring-2 focus:ring-primary outline-none transition-all";
    const labelCls = "block text-sm font-semibold text-muted-foreground mb-1.5 ml-1";

    return (
        <div className="max-w-3xl mx-auto space-y-6 animate-fade-in pb-10">
            <div className="flex items-center gap-4">
                <button
                    onClick={() => navigate("/configuracoes")}
                    aria-label="Voltar para configurações"
                    title="Voltar"
                >
                    <ArrowLeft size={20} />
                </button>
            </div>

            <div className="bg-card border border-border rounded-2xl shadow-sm overflow-hidden p-6 md:p-8 space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-4">
                        <h2 className="text-lg font-bold text-card-foreground flex items-center gap-2">
                            <User size={18} className="text-primary" /> Informações Básicas
                        </h2>

                        <div>
                            <label htmlFor="nome" className={labelCls}>Nome Completo *</label>
                            <div className="relative">
                                <User size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    id="nome"
                                    placeholder="Nome do colaborador"
                                    value={form.nome}
                                    onChange={e => setForm({ ...form, nome: e.target.value })}
                                    className={inputCls + " pl-11"}
                                />
                            </div>
                        </div>

                        <div>
                            <label htmlFor="cpf" className={labelCls}>CPF *</label>
                            <div className="relative">
                                <Fingerprint size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    id="cpf"
                                    placeholder="000.000.000-00"
                                    value={form.cpf}
                                    onChange={e => setForm({ ...form, cpf: maskCPF(e.target.value) })}

                                    className={inputCls + " pl-11"}
                                />
                            </div>
                        </div>

                        <div>
                            <label htmlFor="email" className={labelCls}>E-mail *</label>
                            <div className="relative">
                                <Mail size={18} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                                <input
                                    id="email"
                                    type="email"
                                    placeholder="exemplo@email.com"
                                    value={form.email}
                                    onChange={e => setForm({ ...form, email: e.target.value })}
                                    className={inputCls + " pl-11"}
                                />
                            </div>
                        </div>

                        <div className="p-4 bg-info/10 border border-info/20 rounded-xl">
                            <p className="text-sm text-info flex items-center gap-2">
                                <Mail size={16} /> Um convite será enviado para este e-mail para definição de senha.
                            </p>
                        </div>

                        <div className="flex items-center gap-3 p-4 bg-muted/30 rounded-xl border border-border">
                            <input
                                type="checkbox"
                                id="isAdmin"
                                checked={form.isAdmin}
                                onChange={e => setForm({ ...form, isAdmin: e.target.checked })}
                                className="w-5 h-5 rounded border-border text-primary focus:ring-primary cursor-pointer"
                            />
                            <label htmlFor="isAdmin" className="text-sm font-bold text-card-foreground cursor-pointer flex items-center gap-2">
                                <Shield size={16} className={form.isAdmin ? "text-primary" : "text-muted-foreground"} />
                                Este usuário é Administrador?
                            </label>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <h2 className="text-lg font-bold text-card-foreground flex items-center gap-2">
                            <Shield size={18} className="text-primary" /> Módulos Disponíveis
                        </h2>
                        <p className="text-xs text-muted-foreground mb-4">Selecione quais áreas o usuário terá acesso (Admins têm acesso total).</p>

                        <div className="grid grid-cols-1 gap-2">
                            {Object.entries(moduleLabels).map(([key, label]) => (
                                <label
                                    key={key}
                                    className={`flex items-center justify-between p-3 rounded-xl border transition-all cursor-pointer ${form.modules[key] || form.isAdmin
                                        ? "bg-primary/5 border-primary/30 text-primary"
                                        : "bg-card border-border text-muted-foreground hover:border-primary/20"
                                        } ${form.isAdmin ? "opacity-60 cursor-not-allowed" : ""}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <input
                                            type="checkbox"
                                            disabled={form.isAdmin}
                                            checked={form.modules[key] || form.isAdmin}
                                            onChange={e => setForm({ ...form, modules: { ...form.modules, [key]: e.target.checked } })}
                                            className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                                        />
                                        <span className="text-sm font-medium">{label}</span>
                                    </div>
                                    {(form.modules[key] || form.isAdmin) && <ChevronRight size={14} className="text-primary" />}
                                </label>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="flex gap-4 pt-6 border-t border-border">
                    <button
                        onClick={() => navigate("/configuracoes")}
                        className="flex-1 px-6 py-4 rounded-xl border border-border text-sm font-bold hover:bg-muted transition-colors disabled:opacity-50"
                        disabled={loading}
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleCreateUser}
                        disabled={loading}
                        className="flex-1 flex items-center justify-center gap-2 px-6 py-4 rounded-xl text-sm font-bold text-primary-foreground shadow-lg transition-all hover:scale-[1.02] disabled:opacity-50"
                        style={{ background: "var(--gradient-primary)" }}
                    >
                        {loading ? (
                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ) : (
                            <><Save size={20} /> Finalizar Cadastro</>
                        )}
                    </button>
                </div>
            </div>

            <div className="bg-info/5 border border-info/20 rounded-2xl p-4 flex gap-3">
                <Shield size={20} className="text-info shrink-0 mt-0.5" />
                <p className="text-xs text-info/80 leading-relaxed">
                    <strong>Lembrete:</strong> Ao criar um usuário, ele receberá um convite por e-mail para definir sua senha e acessar o sistema. Certifique-se de que a Edge Function do Supabase foi implantada corretamente para processar este cadastro.
                </p>
            </div>
        </div>
    );
};

export default UsuarioFormPage;

import React, { useEffect, useState } from "react";
import { formatCurrency, formatDateBR } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { Clock, AlertTriangle, CheckCircle, Search } from "lucide-react";
import { useEmpresas } from "@/hooks/useEmpresas";
import { LicencaTaxaRecord, CertidaoRecord } from "@/types/administrative";
import { FavoriteToggleButton } from "@/components/FavoriteToggleButton";

interface Vencimento { empresa: string; tipo: string; data: string; diasRestantes: number; status: string; empresa_situacao?: string; empresa_porte?: string; }

const calcDias = (data?: string | null) => { if (!data) return 999; return Math.ceil((new Date(data).getTime() - Date.now()) / 86400000); };
const calcStatus = (dias: number) => dias < 0 ? "vencido" : dias <= 30 ? "próximo" : "em dia";

const licencaLabels: Record<string, string> = { alvara: "Alvará", vigilancia_sanitaria: "Vigilância Sanitária", corpo_bombeiros: "Corpo de Bombeiros", meio_ambiente: "Meio Ambiente" };

const VencimentosPage: React.FC = () => {
  const { empresas, loading } = useEmpresas("vencimentos");
  const [vencimentos, setVencimentos] = useState<Vencimento[]>([]);
  const [filter, setFilter] = useState("todos");
  const [categoryFilter, setCategoryFilter] = useState("todos");
  const [search, setSearch] = useState("");
  const [activeStatusTab, setActiveStatusTab] = useState<"ativas" | "mei" | "paralisadas" | "baixadas" | "entregue">("ativas");

  useEffect(() => {
    const load = async () => {
      const list: Vencimento[] = [];
      const empMap: Record<string, { nome: string; situacao: string; porte: string }> = {};
      empresas.forEach(e => {
        empMap[e.id] = {
          nome: e.nome_empresa,
          situacao: e.situacao || "ativa",
          porte: e.porte_empresa || ""
        };
      });

      // Licencas com vencimento
      const { data: lics } = await supabase.from("licencas").select("*").eq("status", "com_vencimento").not("vencimento", "is", null);
      lics?.forEach(l => {
        const dias = calcDias(l.vencimento);
        const empInfo = empMap[l.empresa_id] || { nome: "—", situacao: "", porte: "" };
        list.push({
          empresa: empInfo.nome,
          tipo: `Licença: ${licencaLabels[l.tipo_licenca] || l.tipo_licenca}`,
          data: l.vencimento!,
          diasRestantes: dias,
          status: calcStatus(dias),
          empresa_situacao: empInfo.situacao,
          empresa_porte: empInfo.porte
        });
      });

      // Certificados
      const { data: certs } = await supabase.from("certificados_digitais").select("*").not("data_vencimento", "is", null);
      certs?.forEach(c => {
        const dias = calcDias(c.data_vencimento);
        const empInfo = empMap[c.empresa_id] || { nome: "—", situacao: "", porte: "" };
        list.push({
          empresa: empInfo.nome,
          tipo: "Certificado Digital",
          data: c.data_vencimento!,
          diasRestantes: dias,
          status: calcStatus(dias),
          empresa_situacao: empInfo.situacao,
          empresa_porte: empInfo.porte
        });
      });

      // Procuracoes
      const { data: procs } = await supabase.from("procuracoes").select("*").not("data_vencimento", "is", null);
      procs?.forEach(p => {
        const dias = calcDias(p.data_vencimento);
        const empInfo = empMap[p.empresa_id] || { nome: "—", situacao: "", porte: "" };
        list.push({
          empresa: empInfo.nome,
          tipo: "Procuração",
          data: p.data_vencimento!,
          diasRestantes: dias,
          status: calcStatus(dias),
          empresa_situacao: empInfo.situacao,
          empresa_porte: empInfo.porte
        });
      });

      // Certidoes
      const { data: certidoes } = await supabase.from("certidoes").select("*").not("vencimento", "is", null);
      (certidoes as unknown as CertidaoRecord[])?.forEach(c => {
        const dias = calcDias(c.vencimento);
        const empInfo = empMap[c.empresa_id] || { nome: "—", situacao: "", porte: "" };
        list.push({
          empresa: empInfo.nome,
          tipo: `Certidão: ${c.tipo_certidao}`,
          data: c.vencimento!,
          diasRestantes: dias,
          status: calcStatus(dias),
          empresa_situacao: empInfo.situacao,
          empresa_porte: empInfo.porte
        });
      });

      // Taxas de Licenças
      const { data: taxas } = await (supabase.from("licencas_taxas" as any).select("*").not("data_vencimento", "is", null));
      (taxas as unknown as LicencaTaxaRecord[])?.forEach((t) => {
        const dias = calcDias(t.data_vencimento);
        const empInfo = empMap[t.empresa_id] || { nome: "—", situacao: "", porte: "" };
        list.push({
          empresa: empInfo.nome,
          tipo: `Taxa: ${licencaLabels[t.tipo_licenca] || t.tipo_licenca}`,
          data: t.data_vencimento!,
          diasRestantes: dias,
          status: calcStatus(dias),
          empresa_situacao: empInfo.situacao,
          empresa_porte: empInfo.porte
        });
      });

      list.sort((a, b) => a.diasRestantes - b.diasRestantes);
      setVencimentos(list);
    };
    if (empresas.length > 0) load();
  }, [empresas]);

  const searchFiltered = vencimentos.filter(v => {
    const matchSearch = !search || v.empresa.toLowerCase().includes(search.toLowerCase()) || v.tipo.toLowerCase().includes(search.toLowerCase());
    const matchStatusFilter = filter === "todos" || v.status === filter;

    // Check if category filter matches (e.g. "Certificado Digital" includes "Certificado" or "Licença")
    const matchCategory = categoryFilter === "todos" || v.tipo.toLowerCase().includes(categoryFilter);

    let matchTab = false;
    if (activeStatusTab === "ativas") {
      matchTab = (v.empresa_situacao === "ativa") && v.empresa_porte !== "mei";
    } else if (activeStatusTab === "mei") {
      matchTab = (v.empresa_situacao === "ativa") && v.empresa_porte === "mei";
    } else if (activeStatusTab === "paralisadas") {
      matchTab = v.empresa_situacao === "paralisada";
    } else if (activeStatusTab === "baixadas") {
      matchTab = v.empresa_situacao === "baixada";
    } else if (activeStatusTab === "entregue") {
      matchTab = v.empresa_situacao === "entregue";
    }

    return matchSearch && matchStatusFilter && matchCategory && matchTab;
  });

  const counts = { vencido: vencimentos.filter(v => v.status === "vencido").length, proximo: vencimentos.filter(v => v.status === "próximo").length, emDia: vencimentos.filter(v => v.status === "em dia").length };

  if (loading) {
    return <div className="flex items-center justify-center h-64"><div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center gap-3 bg-card p-3 rounded-xl border border-border shadow-sm w-full">
        <FavoriteToggleButton moduleId="vencimentos" />
        <div>
          <h2 className="text-lg font-bold text-card-foreground">Gestão de Vencimentos</h2>
          <p className="text-xs text-muted-foreground">Acompanhamento consolidado de todos os despachos próximos ao prazo.</p>
        </div>
      </div>

      <div className="flex border-b border-border overflow-x-auto no-scrollbar">
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "ativas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("ativas")}
        >
          Empresas Ativas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "mei"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("mei")}
        >
          Empresas MEI
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "paralisadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("paralisadas")}
        >
          Empresas Paralisadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "baixadas"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("baixadas")}
        >
          Empresas Baixadas
        </button>
        <button
          className={`px-5 py-3 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeStatusTab === "entregue"
            ? "border-primary text-primary"
            : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          onClick={() => setActiveStatusTab("entregue")}
        >
          Empresas Entregues
        </button>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="stat-card flex items-center justify-between cursor-pointer" onClick={() => setFilter("vencido")}><div><p className="text-xs text-muted-foreground uppercase">Vencidos</p><p className="text-2xl font-bold text-destructive mt-1">{counts.vencido}</p></div><AlertTriangle className="text-destructive" size={22} /></div>
        <div className="stat-card flex items-center justify-between cursor-pointer" onClick={() => setFilter("próximo")}><div><p className="text-xs text-muted-foreground uppercase">Próximos</p><p className="text-2xl font-bold text-warning mt-1">{counts.proximo}</p></div><Clock className="text-warning" size={22} /></div>
        <div className="stat-card flex items-center justify-between cursor-pointer" onClick={() => setFilter("em dia")}><div><p className="text-xs text-muted-foreground uppercase">Em Dia</p><p className="text-2xl font-bold text-success mt-1">{counts.emDia}</p></div><CheckCircle className="text-success" size={22} /></div>
      </div>
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1 max-w-sm"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><input type="text" placeholder="Buscar..." value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-9 pr-4 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:ring-2 focus:ring-primary outline-none" /></div>
        <div className="flex flex-wrap gap-2">
          <select
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value)}
