import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";
// @ts-expect-error
import { decode } from "https://deno.land/x/djwt@v3.0.1/mod.ts";

const allowedModules = ["societario", "fiscal", "pessoal", "certidoes", "certificados", "licencas", "procuracoes", "honorarios", "obrigacoes", "parcelamentos", "recalculos", "vencimentos"];

// @ts-expect-error: Deno
Deno.serve(async (req) => {
  const origin = req.headers.get("origin");
  const corsHeaders = {
    "Access-Control-Allow-Origin": origin || "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  };

  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({
        error: "Não autenticado",
        code: "no_auth_header"
      }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    // @ts-expect-error: Deno
    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    // @ts-expect-error: Deno
    const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseServiceKey) {
      return new Response(JSON.stringify({
        error: "Configuração do servidor incompleta",
        code: "env_vars_missing"
      }), { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
    const token = authHeader.replace("Bearer ", "").trim();

    // Decode JWT for caller ID (more resilient than getUser)
    let callerId: string;
    try {
      const [_header, payload, _signature] = decode(token);
      callerId = (payload as any).sub;
      if (!callerId) throw new Error("ID do chamador não encontrado");
    } catch (err) {
      console.error("Erro ao decodificar token:", err);
      return new Response(JSON.stringify({ error: "Token inválido ou malformado", code: "auth_token_invalid" }), {
        status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    // MANDATORY: Check if the caller is an admin
    const { data: roles, error: rolesError } = await supabaseAdmin.from("user_roles").select("role").eq("user_id", callerId);
    if (rolesError) throw rolesError;
    const isAdminCaller = roles?.some((r: any) => r.role === 'admin');
    if (!isAdminCaller) {
      return new Response(JSON.stringify({ error: "Apenas administradores podem gerenciar usuários." }), {
        status: 403, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    const body = await req.json();
    const { email, nome, cpf, isAdmin: makeAdmin, modules, role, empresa_id, password } = body;

    if (!email) {
      return new Response(JSON.stringify({ error: "Email é obrigatório" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    // Check if user already exists
    const { data: userDataObj, error: listError } = await supabaseAdmin.auth.admin.listUsers();
    if (listError) throw listError;

    const existingUser = userDataObj.users.find((u: any) => u.email === email);
    let userId;

    if (existingUser) {
      const { data: updated, error: updateError } = await supabaseAdmin.auth.admin.updateUserById(existingUser.id, {
        password: password || "Mudar@Audipreve123",
        email_confirm: true,
        user_metadata: {
          full_name: nome,
          nome_completo: nome,
          role: role || (makeAdmin ? 'admin' : 'user'),
          empresa_id: empresa_id
        }
      });
      if (updateError) throw updateError;
      userId = updated.user.id;
    } else {
      const { data: userData, error: createError } = await supabaseAdmin.auth.admin.createUser({
        email,
        password: password || "Mudar@Audipreve123",
        email_confirm: true,
        user_metadata: {
          full_name: nome,
          nome_completo: nome,
          role: role || (makeAdmin ? 'admin' : 'user'),
          empresa_id: empresa_id
        }
      });
      if (createError) throw createError;
      userId = userData.user.id;
    }

    const isClientRole = role === 'client' || !!empresa_id;

    // Profiles upsert - Only safe columns
    const { error: profileError } = await supabaseAdmin.from("profiles").upsert({
      user_id: userId,
      full_name: nome,
      nome_completo: nome,
      cpf: cpf || null,
      profile_completed: isClientRole,
      first_access_done: isClientRole
    }, { onConflict: 'user_id' });

    if (profileError) {
      console.error("Profile upsert error:", profileError);
      // We continue anyway as the user is created
    }

    // --- ENVIO DE E-MAIL VIA RESEND ---
    const RESEND_API_KEY = Deno.env.get("RESEND_API_KEY");
    
    if (RESEND_API_KEY) {
      console.log(`Gerando link de recuperação para ${email}...`);
      
      const resetRedirectUrl = origin ? `${origin}/reset-password` : undefined;
      
      const { data: linkData, error: linkError } = await supabaseAdmin.auth.admin.generateLink({
        type: 'recovery',
        email,
        options: { redirectTo: resetRedirectUrl }
      });

      if (linkError) {
        console.error("Erro ao gerar link de recuperação:", linkError);
      } else if (linkData?.properties?.action_link) {
        const actionLink = linkData.properties.action_link;
        console.log("Enviando e-mail de boas-vindas via Resend...");
        
        try {
          const res = await fetch("https://api.resend.com/emails", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${RESEND_API_KEY}`,
              "X-Entity-Ref-ID": crypto.randomUUID(),
            },
            body: JSON.stringify({
              from: "Audipreve Contabilidade <gestor@audiprevecontabilidade.com.br>",
              to: [email],
              subject: "Ativação de Cadastro - Sistema Audipreve",
              html: `
                <div style="font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; max-width: 600px; margin: auto; padding: 30px; border: 1px solid #f0f0f0; border-radius: 12px; color: #333;">
                  <div style="text-align: center; margin-bottom: 30px;">
                    <img src="https://jnqwvysjpbcpbwhlwgqq.supabase.co/storage/v1/object/public/documentos/logo-audipreve.png" alt="Audipreve" style="width: 140px;" />
                  </div>
                  <h2 style="color: #0284c7; text-align: center; margin-bottom: 20px;">Olá, ${nome}!</h2>
                  <p style="font-size: 16px; line-height: 1.6;">Seja bem-vindo ao <strong>Sistema Audipreve</strong>. Seu cadastro foi concluído com sucesso por um administrador.</p>
                  <p style="font-size: 16px; line-height: 1.6;">Para ativar seu acesso e definir sua senha de segurança, clique no botão abaixo:</p>
                  <div style="text-align: center; margin: 35px 0;">
                    <a href="${actionLink}" style="background-color: #0284c7; color: white; padding: 14px 28px; text-decoration: none; border-radius: 8px; font-weight: bold; display: inline-block; font-size: 16px; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);">
                      Ativar Meu Acesso
                    </a>
                  </div>
                  <p style="font-size: 13px; color: #666; background: #f9f9f9; padding: 15px; border-radius: 6px; border-left: 4px solid #0284c7;">
                    <strong>Dica de Segurança:</strong> Este link é exclusivo para o seu e-mail e expira em breve. Não o compartilhe com ninguém.
                  </p>
                  <hr style="border: none; border-top: 1px solid #eee; margin: 30px 0;" />
                  <p style="font-size: 11px; color: #999; text-align: center; line-height: 1.5;">
                    <strong>Audipreve Contabilidade</strong><br />
                    Este é um e-mail transacional automático referente ao seu cadastro no sistema.<br />
                    Se você não esperava por este e-mail, por favor, ignore-o.
                  </p>
                </div>
              `,
            }),
          });

          if (!res.ok) {
            const errorData = await res.json();
            console.error("Erro no Resend ao enviar boas-vindas:", errorData);
          } else {
            console.log("E-mail de boas-vindas enviado com sucesso!");
          }
        } catch (mailErr) {
          console.error("Exceção ao enviar e-mail via Resend:", mailErr);
        }
      }
    } else {
      console.warn("RESEND_API_KEY não configurada. E-mail de boas-vindas NÃO enviado.");
    }

    // Role assignment
    if (makeAdmin || role === 'admin') {
      const { error: roleErr } = await supabaseAdmin.from("user_roles").upsert({ user_id: userId, role: "admin" }, { onConflict: 'user_id,role' });
      if (roleErr) throw roleErr;
    } else if (role === 'client') {
      const { error: roleErr } = await supabaseAdmin.from("user_roles").upsert({ user_id: userId, role: "client" }, { onConflict: 'user_id,role' });
      if (roleErr) throw roleErr;
    } else {
      // Ensure they have 'user' role at least
      const { error: roleErr } = await supabaseAdmin.from("user_roles").upsert({ user_id: userId, role: "user" }, { onConflict: 'user_id,role' });
      if (roleErr) throw roleErr;
    }

    // Client assignment (empresa_acessos)
    if (role === 'client' || empresa_id) {
      const { error: accessError } = await supabaseAdmin.from("empresa_acessos").upsert({
        user_id: userId,
        empresa_id: empresa_id,
        modulos_permitidos: allowedModules // Default all for now or pass from body
      }, { onConflict: 'user_id,empresa_id' });

      if (accessError) console.error("Access upsert error:", accessError);
    } else if (modules && typeof modules === 'object') {
      // User Module Permissions assignment (for internal users)
      const moduleInserts = Object.entries(modules)
        .filter(([_, isGranted]) => isGranted === true)
        .map(([moduleName, _]) => ({
          user_id: userId,
          module_name: moduleName
        }));

      if (moduleInserts.length > 0) {
        // Clear existing permissions just in case it's an update
        const { error: clrErr } = await supabaseAdmin.from("user_module_permissions").delete().eq("user_id", userId);
        if (clrErr) throw clrErr;

        const { error: modulesError } = await supabaseAdmin.from("user_module_permissions").insert(moduleInserts);
        if (modulesError) {
          console.error("Modules insert error:", modulesError);
          throw modulesError;
        }
      }
    }

    return new Response(JSON.stringify({ success: true, user_id: userId }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });

  } catch (err: any) {
    console.error("create-user error:", err);
    return new Response(JSON.stringify({
      error: "Erro interno",
      details: err.message
    }), {
      status: 400,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

// @ts-expect-error
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";
// @ts-expect-error
import { decode } from "https://deno.land/x/djwt@v3.0.1/mod.ts";

// @ts-expect-error: Deno
Deno.serve(async (req: Request) => {
  const origin = req.headers.get("origin");
  const corsHeaders = {
    "Access-Control-Allow-Origin": origin || "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  };

  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    console.log("Authorization Header present:", !!authHeader);

    if (!authHeader) {
      console.error("Erro: Cabeçalho de autorização ausente");
      return new Response(JSON.stringify({ error: "Cabeçalho de autorização ausente", status: 'error' }), {
        status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    // @ts-expect-error: Deno
    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    // @ts-expect-error: Deno
    const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseServiceKey) {
      console.error("Erro: Variáveis de ambiente SUPABASE_URL ou SUPABASE_SERVICE_ROLE_KEY não configuradas");
      return new Response(JSON.stringify({ error: "Configuração do servidor incompleta", status: 'error' }), {
        status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
    const token = authHeader.replace("Bearer ", "").trim();

    // Decode JWT to get user_id (sub) without hitting Auth database for session
    let userId: string;
    try {
      const [_header, payload, _signature] = decode(token);
      userId = (payload as any).sub;
      if (!userId) throw new Error("ID do usuário não encontrado no token");
    } catch (err) {
      console.error("Erro ao decodificar token:", err);
      return new Response(JSON.stringify({ error: "Token inválido ou malformado", status: 'error' }), {
        status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    // Check if the caller is an admin in the database
    console.log("Checking admin permissions for user:", userId);
    const { data: roles, error: rolesError } = await supabaseAdmin.from("user_roles").select("role").eq("user_id", userId);
    
    if (rolesError) {
      console.error("Erro ao buscar roles:", rolesError);
      return new Response(JSON.stringify({ error: "Falha ao verificar permissões do usuário.", status: 'error' }), {
        status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    const isAdmin = roles?.some((r: any) => r.role === 'admin');
    if (!isAdmin) {
      console.warn("Usuário não tem permissão de admin:", userId);
      return new Response(JSON.stringify({ error: "Apenas administradores podem gerenciar usuários.", status: 'error' }), {
        status: 403, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

    // Parse payload
    const body = await req.json();
    const { action, target_user_id, module, enable } = body;
    console.log("Manage User Action:", action, "Target:", target_user_id);

    if (!action || !target_user_id) throw new Error("Action e target_user_id são obrigatórios.");

    if (action === "toggleModule") {
      if (!module) throw new Error("Module é obrigatório.");
      if (enable) {
        const { error: insErr } = await supabaseAdmin.from("user_module_permissions").insert({ user_id: target_user_id, module_name: module });
        if (insErr) throw insErr;
      } else {
        const { error: delErr } = await supabaseAdmin.from("user_module_permissions").delete().eq("user_id", target_user_id).eq("module_name", module);
        if (delErr) throw delErr;
      }
    }
    else if (action === "toggleAdmin") {
      if (enable) {
        const { error: insErr } = await supabaseAdmin.from("user_roles").insert({ user_id: target_user_id, role: "admin" });
        if (insErr) throw insErr;
      } else {
        const { error: delErr } = await supabaseAdmin.from("user_roles").delete().eq("user_id", target_user_id).eq("role", "admin");
        if (delErr) throw delErr;
      }
    }
    else if (action === "deleteUser") {
      console.log("Deletando usuário:", target_user_id);
      // First, we delete the profile. Cascades should handle the rest in public schema.
      const { error: profileError } = await supabaseAdmin.from("profiles").delete().eq("user_id", target_user_id);
      if (profileError) {
        console.error("Error deleting profile:", profileError);
        throw new Error(`Erro ao excluir perfil: ${profileError.message}`);
      }

      // Then delete the auth user
      const { error: deleteError } = await supabaseAdmin.auth.admin.deleteUser(target_user_id);
      if (deleteError) {
        console.error("Error deleting auth user:", deleteError);
        throw deleteError;
      }
      console.log("Usuário deletado com sucesso.");
    }
    else {
      throw new Error(`Ação desconhecida: ${action}`);
    }

    return new Response(JSON.stringify({ success: true }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });

  } catch (err: any) {
    console.error("manage-user error:", err);
    return new Response(JSON.stringify({ error: err.message, status: 'error' }), {
      status: 400,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

// @ts-expect-error: Deno
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
// @ts-expect-error: Deno
import { createClient } from "https://esm.sh/@supabase/supabase-js@2"
// @ts-expect-error: Deno
import { Resend } from "https://esm.sh/resend@3.2.0"

// @ts-expect-error: Deno
const resend = new Resend(Deno.env.get('RESEND_API_KEY'))

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
}

interface ExpirationAlert {
  empresa_id: string;
  nome_empresa: string;
  email_rfb: string | null;
  documento_tipo: string;
  vencimento: string;
  dias_restantes: number;
  link: string;
}

serve(async (req: Request) => {
  console.log(`${req.method} request received at ${new Date().toISOString()}`)

  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders, status: 200 })
  }

  const authHeader = req.headers.get("Authorization") || req.headers.get("authorization");
  // @ts-expect-error: Deno
  const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

  // Only allow execution if the service key is provided in the header
  // This secures the function against public triggers while allowing Cron/CLI to work
  if (authHeader !== `Bearer ${serviceKey}`) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { 
      status: 401, 
      headers: { ...corsHeaders, "Content-Type": "application/json" } 
    });
  }

  try {
    const { test = false } = await req.json().catch(() => ({ test: false }))
    console.log(`Working in ${test ? 'TEST' : 'NORMAL'} mode`)

    const supabaseClient = createClient(
      // @ts-expect-error: Deno
      Deno.env.get('SUPABASE_URL') ?? '',
      // @ts-expect-error: Deno
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    // Debug: Check if empresa_acessos has any data
    const { count: accessCount } = await supabaseClient.from('empresa_acessos').select('*', { count: 'exact', head: true })
    console.log(`Total rows in empresa_acessos: ${accessCount}`)

    console.log(`--- STEP 1: Fetching expirations (force_all: ${test}) ---`)
    const { data: alerts, error: alertsError } = await supabaseClient.rpc('get_daily_expirations', { p_force_all: test })

    if (alertsError) {
      console.error('Error in get_daily_expirations:', alertsError)
      throw alertsError
    }

    if (!alerts || alerts.length === 0) {
      console.log('No expirations found for today (using 30, 15, 7, 1, 0 days filter).')
      return new Response(JSON.stringify({
        success: true,
        message: 'No alerts today',
        debug: { expirationsFound: 0 }
      }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200
      })
    }

    console.log(`--- STEP 1.5: Using hardcoded templates ---`)
    const companyTemplate = {
      subject: 'Aviso de Vencimento de Documentos - {{nome_empresa}}',
      body_html: 'Olá, informamos que os seguintes documentos da empresa <strong>{{nome_empresa}}</strong> estão próximos ao vencimento:'
    }
    const userTemplate = {
      subject: 'Resumo Diário de Vencimentos - Audipreve',
      body_html: 'Confira os documentos das empresas sob sua gestão que vencem em breve:'
    }

    const expirations = alerts as ExpirationAlert[]
    console.log(`Found ${expirations.length} total expirations.`)

    // 1. Group by Company (for email_rfb)
    console.log('--- STEP 2: Grouping by Company (Direct Email) ---')
    const companyGroups: Record<string, ExpirationAlert[]> = {}
    expirations.forEach(alert => {
      if (alert.email_rfb && alert.email_rfb.includes('@')) {
        if (!companyGroups[alert.email_rfb]) companyGroups[alert.email_rfb] = []
        companyGroups[alert.email_rfb].push(alert)
      } else {
        console.log(`Company "${alert.nome_empresa}" has no valid contact email: "${alert.email_rfb}"`)
      }
    })

    // 2. Group by User (mapping company_id to user emails)
    console.log('--- STEP 3: Grouping by System User (get_company_user_emails) ---')
    const userGroups: Record<string, ExpirationAlert[]> = {}
    for (const alert of expirations) {
      console.log(`Checking users for company: ${alert.nome_empresa} (${alert.empresa_id})`)
      const { data: userEmails, error: rpcError } = await supabaseClient.rpc('get_company_user_emails', { p_empresa_id: alert.empresa_id })

      if (rpcError) {
        console.error(`Error fetching users for company ${alert.empresa_id}:`, rpcError)
        continue
      }

      if (userEmails && userEmails.length > 0) {
        console.log(`Found ${userEmails.length} users linked to ${alert.nome_empresa}:`, userEmails.map((u: any) => u.email).join(', '))
        userEmails.forEach((ue: { email: string }) => {
          if (!userGroups[ue.email]) userGroups[ue.email] = []
          // Check if this alert is already in the user's list (to avoid duplicates if company has multiple docs)
          const alreadyExists = userGroups[ue.email].some(a => a.empresa_id === alert.empresa_id && a.documento_tipo === alert.documento_tipo)
          if (!alreadyExists) userGroups[ue.email].push(alert)
        })
      } else {
        console.log(`No system users found with access to company ${alert.nome_empresa}`)
      }
    }

    console.log(`--- SUMMARY ---`)
    console.log(`Unique Companies to notify: ${Object.keys(companyGroups).length}`)
    console.log(`Unique Users to notify: ${Object.keys(userGroups).length}`)

    const sendEmail = async (to: string, alerts: ExpirationAlert[], isUser: boolean) => {
      console.log(`Attempting to send ${isUser ? 'USER' : 'COMPANY'} email to: ${to}`)

      const template = isUser ? userTemplate : companyTemplate;

      const subject = template.subject.replace(/{{nome_empresa}}/g, alerts[0].nome_empresa)
      const customIntro = template.body_html.replace(/{{nome_empresa}}/g, alerts[0].nome_empresa)

      let rows = ''
      alerts.forEach(a => {
        const color = a.dias_restantes === 0 ? '#ef4444' : a.dias_restantes <= 7 ? '#f97316' : '#3b82f6'
        const statusText = a.dias_restantes === 0 ? 'Vence HOJE' : `Vence em ${a.dias_restantes} dias`

        rows += `
          <tr>
            <td style="padding: 12px; border-bottom: 1px solid #e5e7eb; font-size: 14px;">${isUser ? `<strong>${a.nome_empresa}</strong><br/>` : ''}${a.documento_tipo}</td>
            <td style="padding: 12px; border-bottom: 1px solid #e5e7eb; font-size: 14px;">${new Date(a.vencimento).toLocaleDateString('pt-BR')}</td>
            <td style="padding: 12px; border-bottom: 1px solid #e5e7eb; color: ${color}; font-weight: bold; font-size: 14px;">${statusText}</td>
          </tr>
        `
      })

      const html = `
        <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; color: #374151;">
          <div style="text-align: center; margin-bottom: 20px;">
            <img src="https://jnqwvysjpbcpbwhlwgqq.supabase.co/storage/v1/object/public/documentos/logo-audipreve.png" alt="Audipreve" style="width: 80px; height: auto;" />
          </div>
          ${customIntro}
          <table style="width: 100%; border-collapse: collapse; margin-top: 20px;">
            <thead style="background-color: #f9fafb;">
              <tr>
                <th align="left" style="padding: 12px; border-bottom: 2px solid #e5e7eb;">Documento</th>
                <th align="left" style="padding: 12px; border-bottom: 2px solid #e5e7eb;">Vencimento</th>
                <th align="left" style="padding: 12px; border-bottom: 2px solid #e5e7eb;">Status</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
          <p style="margin-top: 30px;">Este e-mail é um aviso automático. As providências para a renovação já foram tomadas! <br>Entre em contato em caso de dúvidas.<br>
          Atenciosamente, <br>
          Audipreve Contabilidade.</p>
          <hr style="border: 0; border-top: 1px solid #e5e7eb; margin: 30px 0;" />
          <p style="font-size: 12px; color: #9ca3af;">Este é um e-mail automático. Não responder!</p>
        </div>
      `

      try {
        const { data, error } = await resend.emails.send({
          from: 'Audipreve Contabilidade <gestor@audiprevecontabilidade.com.br>',
          to: [to],
          subject: `[Audipreve] ${subject}`,
          html: html
        })

        if (error) {
          console.error(`Resend error sending to ${to}:`, error)
          return { to, success: false, error }
        }

        console.log(`Email sent successfully to ${to}. ID: ${data?.id}`)
        return { to, success: true }
      } catch (err) {
        console.error(`Exception sending to ${to}:`, err)
        return { to, success: false, error: err }
      }
    }

    // Execution
    const results = []

    // Helper for minor delay to respect 5 req/sec limit
    const delay = (ms: number) => new Promise(res => setTimeout(res, ms))

    // Company Emails
    for (const [email, companyAlerts] of Object.entries(companyGroups)) {
      results.push(await sendEmail(email, companyAlerts, false))
      await delay(250) // 250ms delay -> roughly 4 emails per second
    }

    // User Emails
    for (const [email, userAlerts] of Object.entries(userGroups)) {
      results.push(await sendEmail(email, userAlerts, true))
      await delay(250)
    }

    const successCount = results.filter(r => r.success).length
    const failCount = results.length - successCount
    const errors = results.filter(r => !r.success).map(r => ({ to: r.to, error: r.error }))

    return new Response(JSON.stringify({
      success: true,
      companiesNotified: Object.keys(companyGroups).length,
      usersNotified: Object.keys(userGroups).length,
      totalEmailsAttempted: results.length,
      successCount,
      failCount,
      debug: {
        expirationsFound: expirations.length,
        accessRowsFound: accessCount,
        testMode: test,
        errors: errors
      }
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200
    })

  } catch (error: any) {
    console.error("Critical Error in Edge Function:", error)
    return new Response(JSON.stringify({ error: error.message }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 400
    })
  }
})

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.7";

const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

Deno.serve(async (req) => {
    if (req.method === "OPTIONS") {
        return new Response("ok", { headers: corsHeaders });
    }

    try {
        console.log("send-verification-code: [PASSO 1] Início");
        const RESEND_API_KEY = Deno.env.get("RESEND_API_KEY");
        const supabaseUrl = Deno.env.get("SUPABASE_URL");
        const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
        const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY");

        if (!RESEND_API_KEY || !supabaseUrl || !supabaseServiceKey || !supabaseAnonKey) {
            console.error("send-verification-code: [ERRO 500] Env vars faltando");
            return new Response(JSON.stringify({
                error: "Configuração do servidor incompleta (Env vars missing)",
                resend_present: !!RESEND_API_KEY,
                url_present: !!supabaseUrl,
                service_present: !!supabaseServiceKey,
                anon_present: !!supabaseAnonKey
            }), { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        const authHeader = req.headers.get("authorization");
        if (!authHeader) {
            console.warn("send-verification-code: [ERRO 401] Sem header Auth");
            return new Response(JSON.stringify({ error: "Não autenticado (Header Authorization ausente)" }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
        const supabaseUser = createClient(supabaseUrl, supabaseAnonKey, {
            global: { headers: { Authorization: authHeader } }
        });

        console.log("send-verification-code: [PASSO 2] Validando usuário...");
        const { data: { user }, error: authError } = await supabaseUser.auth.getUser();
        if (authError || !user) {
            console.error("send-verification-code: [ERRO 401] Auth check failed:", authError?.message);
            return new Response(JSON.stringify({ error: "Token inválido ou sessão expirada", details: authError?.message }), { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } });
        }

        console.log("send-verification-code: [PASSO 3] Usuário validado:", user.id, user.email);

        const body = await req.json();
        const { action } = body;
        console.log("send-verification-code: [PASSO 4] Ação recebida:", action);

        if (action === "send") {
            const code = Math.floor(100000 + Math.random() * 900000).toString();
            const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString(); // 10 min

            console.log("send-verification-code: [PASSO 5] Salvando código no DB...");
            const { error: dbError } = await supabaseAdmin.from("profiles").update({
                verification_code: code,
                verification_code_expires_at: expiresAt
            }).eq("user_id", user.id);

            if (dbError) {
                console.error("send-verification-code: [ERRO DB]", dbError.message);
                throw new Error("Erro ao salvar código de verificação: " + dbError.message);
            }

            // Enviar email via Resend
            console.log("send-verification-code: [PASSO 6] Enviando e-mail via Resend...");
            if (!user.email) throw new Error("E-mail do usuário não encontrado na sessão.");

            const res = await fetch("https://api.resend.com/emails", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${RESEND_API_KEY}`,
                },
                body: JSON.stringify({
                    from: "Audipreve <gestor@audiprevecontabilidade.com.br>",
                    to: [user.email],
                    subject: `${code} é seu código de verificação Audipreve`,
                    html: `
                        <div style="font-family: sans-serif; max-width: 600px; margin: auto; padding: 20px; border: 1px solid #eee; border-radius: 10px;">
                            <h2 style="color: #333 text-align: center;">Verificação de Segurança</h2>
                            <p>Olá,</p>
                            <p>Você está realizando seu primeiro acesso ou recuperando sua senha no sistema Audipreve. Use o código abaixo para verificar sua identidade:</p>
                            <div style="background: #f4f4f4; padding: 20px; text-align: center; font-size: 32px; font-weight: bold; letter-spacing: 5px; color: #000; border-radius: 8px; margin: 20px 0;">
                                ${code}
                            </div>
                            <p style="font-size: 14px; color: #666;">Este código expira em 10 minutos. Se você não solicitou este acesso, ignore este e-mail.</p>
                            <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;" />
                            <p style="font-size: 12px; color: #999; text-align: center;">Audipreve Contabilidade</p>
                        </div>
                    `,
                }),
            });

            if (!res.ok) {
                const errorData = await res.json();
                console.error("send-verification-code: [ERRO Resend]", errorData);

                // Bypass condition removed to surface actual Resend errors

                throw new Error("Falha ao enviar e-mail: " + (errorData.message || JSON.stringify(errorData)));
            }

            console.log("send-verification-code: [PASSO 7] Sucesso!");
            return new Response(JSON.stringify({ success: true, message: "Código enviado" }), {
                headers: { ...corsHeaders, "Content-Type": "application/json" },
            });
        }

        if (action === "verify") {
            const { code } = body;
            console.log("send-verification-code: [PASSO 5v] Verificando código...");
            const { data: profile, error: selectError } = await supabaseAdmin.from("profiles")
                .select("verification_code, verification_code_expires_at")
                .eq("user_id", user.id)
                .single();

            if (selectError) throw new Error("Erro ao buscar perfil: " + selectError.message);

            if (!profile || profile.verification_code !== code) {
                console.warn("send-verification-code: [ERRO 400] Código incorreto");
                return new Response(JSON.stringify({ error: "Código inválido" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
            }

            if (new Date() > new Date(profile.verification_code_expires_at)) {
                console.warn("send-verification-code: [ERRO 400] Código expirado");
                return new Response(JSON.stringify({ error: "Código expirado" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
            }

            console.log("send-verification-code: [PASSO 6v] Marcando como verificado...");
            const { error: updateError } = await supabaseAdmin.from("profiles").update({
                first_access_done: true,
                verification_code: null,
                verification_code_expires_at: null
            }).eq("user_id", user.id);

            if (updateError) throw updateError;

            console.log("send-verification-code: [PASSO 7v] Verificado com sucesso!");
            return new Response(JSON.stringify({ success: true }), {
                headers: { ...corsHeaders, "Content-Type": "application/json" },
            });
        }

        return new Response(JSON.stringify({ error: "Ação inválida" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });

    } catch (err: any) {
        console.error("send-verification-code: [ERRO FATAL]", err.message);
        return new Response(JSON.stringify({ error: err.message, stack: err.stack }), {
            status: 400,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
    }
});
